INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001813719321', 'Patada de tríceps en polea', 'Cable Tricep Kickback', 'Tríceps', '["### ", "- Configuración: Conecte un accesorio de un solo mango a la polea de la máquina de cable. Seleccione un peso apropiado que permita un movimiento controlado. Párese frente a la máquina, agarre el mango con un agarre por debajo y dé un paso atrás. Inclínese ligeramente hacia adelante a la altura de las caderas, manteniendo la espalda recta y el tronco enganchado. Mantenga la parte superior del brazo paralela al torso con el codo doblado a 90 grados.", "- Conecte un accesorio de un solo mango a la polea de la máquina de cable.", "- Seleccione un peso adecuado que permita un movimiento controlado.", "- Párese frente a la máquina, agarre el mango con la mano hacia abajo y dé un paso atrás.", "- Inclínate ligeramente hacia adelante a la altura de las caderas, manteniendo la espalda recta y el core comprometido.", "- Mantenga la parte superior del brazo paralela al torso con el codo doblado a 90 grados.", "- Ejecución: Extienda el brazo hacia atrás enderezando completamente el codo mientras mantiene la parte superior del brazo inmóvil. Apriete el tríceps en la parte superior del movimiento. Regrese lentamente a la posición inicial con control, permitiendo que el codo se doble nuevamente. Repita el número deseado de repeticiones y cambie de brazo si realiza contragolpes con un solo brazo.", "- Extienda el brazo hacia atrás enderezando completamente el codo mientras mantiene la parte superior del brazo inmóvil.", "- Aprieta tus tríceps en la parte superior del movimiento.", "- Regrese lentamente a la posición inicial con control, permitiendo que el codo se doble nuevamente.", "- Repita hasta el número deseado de repeticiones y cambie de brazo si realiza contragolpes con un solo brazo.", "- Repeticiones y respiración: realiza de 10 a 15 repeticiones por serie. Inhala mientras regresas a la posición inicial y exhala mientras extiendes el brazo hacia atrás.", "- Realiza de 10 a 15 repeticiones por serie.", "- Inhala mientras regresas a la posición inicial y exhala mientras extiendes el brazo hacia atrás.", "### Consejos para una forma adecuada:", "- Mantenga la parte superior del brazo inmóvil para maximizar la participación de los tríceps.", "- Evite utilizar el impulso; centrarse en movimientos controlados.", "- Mantenga una ligera flexión de las rodillas para mayor estabilidad.", "- Involucre su núcleo para evitar un balanceo excesivo.", "- Utilice un peso más ligero para garantizar la técnica adecuada antes de aumentar la resistencia.", "### Errores comunes:", "- Balancear el brazo: reduce la activación del tríceps y convierte el movimiento en un ejercicio basado en el impulso.", "- Usar demasiado peso: conduce a una mala forma y reduce la efectividad.", "- No extenderse completamente: Limita la activación del tríceps y reduce el rango de movimiento.", "- Redondear la espalda: Provoca tensión innecesaria en la zona lumbar.", "- Sostener el mango incorrectamente: Agarrarlo con demasiada fuerza puede generar fatiga en el antebrazo antes de que los tríceps estén completamente trabajados."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001837892935', 'Flexiones hindúes', 'Hindu Push-ups', 'Pecho', '["Posición inicial: comience en una posición de perro boca abajo. Esto es similar a una postura de yoga. Comience con las manos y las rodillas, luego levante las caderas y estire las piernas para formar una V invertida con su cuerpo. Tus manos deben estar separadas al ancho de los hombros y tus pies deben estar separados al ancho de las caderas.", "Descenso (fase de bombardero en picado): desplaza tu peso hacia adelante, bajando la parte superior del cuerpo hacia el suelo mientras mantienes los brazos rectos. Continúa avanzando hasta que tu pecho casi toque el suelo. Tus caderas estarán bajas y tu espalda arqueada, asemejándote a una postura de yoga de perro mirando hacia arriba. A medida que desciendes, asegúrate de mirar hacia arriba y hacia adelante, permitiendo que tu cabeza suba y tu espalda se arquee profundamente.", "Mueva su peso hacia adelante, bajando la parte superior del cuerpo hacia el suelo mientras mantiene los brazos rectos.", "Continúe avanzando hasta que su pecho casi toque el suelo. Tus caderas estarán bajas y tu espalda arqueada, asemejándote a una postura de yoga de perro mirando hacia arriba.", "A medida que desciendes, asegúrate de mirar hacia arriba y hacia adelante, permitiendo que tu cabeza suba y tu espalda se arquee profundamente.", "Ascenso: Desde la posición del perro boca abajo, empuja las caderas hacia atrás y hacia arriba, moviéndolas hacia el techo. Su cabeza debe mirar hacia atrás entre sus piernas. A medida que sus caderas se elevan, doble los codos y baje el pecho hasta la posición inicial. Continúe este movimiento hasta que regrese a la posición del perro hacia abajo.", "Desde la posición del perro boca abajo, empuja las caderas hacia atrás y hacia arriba, moviéndolas hacia el techo. Tu cabeza debe mirar hacia atrás entre tus piernas.", "A medida que las caderas se elevan, doble los codos y baje el pecho hasta la posición inicial.", "Continúe este movimiento hasta que regrese a la posición del perro boca abajo.", "Repetir: repita la secuencia durante el número deseado de repeticiones, manteniendo un flujo suave y controlado entre las diferentes posiciones."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000321875386', 'Encogimiento de hombros de Gittleson', 'Gittleson Shrug', 'Hombros', '["Siéntate en un banco o silla con una mancuerna en una mano.", "Agarre la parte inferior del banco justo detrás de su cadera con su mano libre (la que no sostiene la mancuerna).", "Deje que su hombro lateral cargado baje lo más posible.", "Eleva el hombro hacia la oreja, enfatizando la contracción de los músculos trapecios superiores.", "Realice el número deseado de repeticiones en un lado antes de cambiar al otro."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000298563406', 'Fondos en barra paralela', 'Parallel Bar Dips', 'Tríceps', '["Colócate entre las barras paralelas.", "Agarre las barras firmemente con las palmas hacia adentro.", "Levanta tu cuerpo del suelo, apoyando tu peso con los brazos."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000732765450', 'Máquina de extensión de tríceps', 'Triceps Extension Machine', 'Tríceps', '["Seleccione un peso apropiado que permita un movimiento controlado sin sacrificar la forma.", "Ajuste la altura del asiento de modo que la parte superior de sus brazos descanse cómodamente sobre la almohadilla y los codos se alineen con el punto de giro de la máquina."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001063525317', 'Elevación de pantorrillas de pie con mancuernas', 'Standing Calf Raise With Dumbbell', 'Pantorrillas', '["Posición inicial: Párese erguido con los pies separados a la altura de las caderas, sosteniendo una mancuerna en cada mano, los brazos relajados a los lados, manteniendo una postura y alineación adecuadas.", "Alineación y estabilidad: Involucre los músculos centrales para lograr estabilidad, mantenga los hombros hacia atrás y mantenga una alineación neutra de la columna durante todo el movimiento.", "Movimiento de elevación: levántese lentamente sobre las puntas de los pies levantando los talones lo más alto posible, contrayendo completamente los músculos de la pantorrilla.", "Descenso controlado: baje gradualmente los talones hasta la posición inicial de forma controlada, asegurando una tensión muscular constante.", "Repetir: realice las repeticiones deseadas, generalmente de 10 a 15 repeticiones por serie, enfatizando los movimientos lentos y controlados."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001837892935', 'Flexiones hindúes', 'Hindu Push-ups', 'Pecho', '["Posición inicial: comience en una posición de perro boca abajo. Esto es similar a una postura de yoga. Comience con las manos y las rodillas, luego levante las caderas y estire las piernas para formar una V invertida con su cuerpo. Tus manos deben estar separadas al ancho de los hombros y tus pies deben estar separados al ancho de las caderas.", "Descenso (fase de bombardero en picado): desplaza tu peso hacia adelante, bajando la parte superior del cuerpo hacia el suelo mientras mantienes los brazos rectos. Continúa avanzando hasta que tu pecho casi toque el suelo. Tus caderas estarán bajas y tu espalda arqueada, asemejándote a una postura de yoga de perro mirando hacia arriba. A medida que desciendes, asegúrate de mirar hacia arriba y hacia adelante, permitiendo que tu cabeza suba y tu espalda se arquee profundamente.", "Mueva su peso hacia adelante, bajando la parte superior del cuerpo hacia el suelo mientras mantiene los brazos rectos.", "Continúe avanzando hasta que su pecho casi toque el suelo. Tus caderas estarán bajas y tu espalda arqueada, asemejándote a una postura de yoga de perro mirando hacia arriba.", "A medida que desciendes, asegúrate de mirar hacia arriba y hacia adelante, permitiendo que tu cabeza suba y tu espalda se arquee profundamente.", "Ascenso: Desde la posición del perro boca abajo, empuja las caderas hacia atrás y hacia arriba, moviéndolas hacia el techo. Su cabeza debe mirar hacia atrás entre sus piernas. A medida que sus caderas se elevan, doble los codos y baje el pecho hasta la posición inicial. Continúe este movimiento hasta que regrese a la posición del perro hacia abajo.", "Desde la posición del perro boca abajo, empuja las caderas hacia atrás y hacia arriba, moviéndolas hacia el techo. Tu cabeza debe mirar hacia atrás entre tus piernas.", "A medida que las caderas se elevan, doble los codos y baje el pecho hasta la posición inicial.", "Continúe este movimiento hasta que regrese a la posición del perro boca abajo.", "Repetir: repita la secuencia durante el número deseado de repeticiones, manteniendo un flujo suave y controlado entre las diferentes posiciones."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000961325801', 'Extensión de tríceps lateral en polea', 'Cable Side Triceps Extension', 'Tríceps', '["### Paso 1: Configuración y posición inicial", "- Conecte una empuñadura monomando a una polea de cable alta.", "- Párese de lado de la máquina de cable, con el brazo de trabajo más cercano al cable.", "- Agarre el mango con un agarre por encima de la cabeza y coloque el codo a la altura del hombro, doblado a 90 grados.", "- Coloque la mano opuesta sobre la cadera o el estómago para mayor estabilidad.", "### Paso 2: Ejecución", "- Extiende tu brazo hacia afuera, enderezando el codo hasta que tu brazo esté completamente extendido.", "- Mantenga la parte superior del brazo inmóvil, moviendo solo el antebrazo.", "- Haga una pausa para realizar una breve contracción en la parte superior, apretando el tríceps.", "- Regrese lentamente a la posición inicial, manteniendo el control en todo momento.", "- Repita de 8 a 12 repeticiones por brazo, completando de 3 a 4 series.", "### Consejos para una forma adecuada", "- Mantenga el codo a la altura de los hombros durante todo el movimiento.", "- Involucre su núcleo para lograr estabilidad.", "- Utilice un movimiento controlado, evitando el impulso.", "- No extienda demasiado el brazo para evitar tensión en las articulaciones.", "- Asegúrese de que su muñeca permanezca neutral para evitar molestias.", "### Errores comunes a evitar", "- Dejar caer el codo, reduciendo la activación del tríceps.", "- Usar demasiado peso, comprometer la forma.", "- Depender del impulso, disminuyendo el compromiso muscular.", "- No extender completamente el brazo, lo que limita el rango de movimiento.", "- Girando el torso, reduciendo la concentración en los tríceps."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001981468056', 'Extensión de tríceps con mancuernas', 'Dumbbell Triceps Extension', 'Tríceps', '["Elija una mancuerna con un peso manejable.", "Párese con los pies separados a la altura de los hombros para mayor estabilidad.", "Agarre la mancuerna con ambas manos, colocando las palmas debajo de la placa superior de la mancuerna."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000031982949', 'Extensión de tríceps en polea de rodillas', 'Kneeling Cable Triceps Extension', 'Tríceps', '["Configure la máquina de cable Conecte una barra recta, una barra de curl EZ o una cuerda a la polea alta de una máquina de cable. Seleccione un peso apropiado que permita un movimiento controlado sin comprometer la forma.", "Conecte una barra recta, una barra de curl EZ o una cuerda a la polea alta de una máquina de cable.", "Seleccione un peso apropiado que permita un movimiento controlado sin comprometer la forma.", "Colóquese Arrodíllese en el suelo frente a la máquina de cable, doblando el cuerpo para que los codos queden fijos al banco. Sujete el accesorio con un agarre por encima de la cabeza (con las palmas hacia abajo) y acérquelo a la frente. Mantenga los codos doblados y alineados con los hombros.", "Arrodíllate en el suelo frente a la máquina de cable, doblando el cuerpo para que los codos queden fijos al banco.", "Agarre el accesorio con las palmas hacia abajo y acérquelo a su frente.", "Mantenga los codos doblados y alineados con los hombros.", "Ejecución Involucre su núcleo y estabilice la parte superior de su cuerpo. Extienda los codos hacia adelante empujando el mango o el accesorio de cuerda lejos de su frente hasta que sus brazos estén completamente extendidos. Mantenga la parte superior de los brazos inmóvil mientras mueve solo los antebrazos. Apriete los tríceps al final del movimiento. Regrese lentamente a la posición inicial doblando los codos mientras mantiene el control.", "Involucre su núcleo y estabilice la parte superior de su cuerpo.", "Extienda los codos hacia adelante empujando el mango o la cuerda hacia afuera de su frente hasta que sus brazos estén completamente extendidos.", "Mantenga la parte superior de los brazos inmóviles mientras mueve solo los antebrazos.", "Aprieta tus tríceps al final del movimiento.", "Regrese lentamente a la posición inicial doblando los codos mientras mantiene el control.", "Repetir Realice el número deseado de repeticiones manteniendo la forma adecuada.", "Realice el número deseado de repeticiones manteniendo la forma adecuada."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000031982949', 'Extensión de tríceps en polea de rodillas', 'Kneeling Cable Triceps Extension', 'Tríceps', '["Configure la máquina de cable Conecte una barra recta, una barra de curl EZ o una cuerda a la polea alta de una máquina de cable. Seleccione un peso apropiado que permita un movimiento controlado sin comprometer la forma.", "Conecte una barra recta, una barra de curl EZ o una cuerda a la polea alta de una máquina de cable.", "Seleccione un peso apropiado que permita un movimiento controlado sin comprometer la forma.", "Colóquese Arrodíllese en el suelo frente a la máquina de cable, doblando el cuerpo para que los codos queden fijos al banco. Sujete el accesorio con un agarre por encima de la cabeza (con las palmas hacia abajo) y acérquelo a la frente. Mantenga los codos doblados y alineados con los hombros.", "Arrodíllate en el suelo frente a la máquina de cable, doblando el cuerpo para que los codos queden fijos al banco.", "Agarre el accesorio con las palmas hacia abajo y acérquelo a su frente.", "Mantenga los codos doblados y alineados con los hombros.", "Ejecución Involucre su núcleo y estabilice la parte superior de su cuerpo. Extienda los codos hacia adelante empujando el mango o el accesorio de cuerda lejos de su frente hasta que sus brazos estén completamente extendidos. Mantenga la parte superior de los brazos inmóvil mientras mueve solo los antebrazos. Apriete los tríceps al final del movimiento. Regrese lentamente a la posición inicial doblando los codos mientras mantiene el control.", "Involucre su núcleo y estabilice la parte superior de su cuerpo.", "Extienda los codos hacia adelante empujando el mango o la cuerda hacia afuera de su frente hasta que sus brazos estén completamente extendidos.", "Mantenga la parte superior de los brazos inmóviles mientras mueve solo los antebrazos.", "Aprieta tus tríceps al final del movimiento.", "Regrese lentamente a la posición inicial doblando los codos mientras mantiene el control.", "Repetir Realice el número deseado de repeticiones manteniendo la forma adecuada.", "Realice el número deseado de repeticiones manteniendo la forma adecuada."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000165336616', 'Flexiones de pared', 'Wall Push-up', 'Pecho', '["### ", "- Párese frente a una pared, a aproximadamente 2 a 3 pies de distancia, dependiendo de la longitud de su brazo.", "- Coloque las manos en la pared a la altura de los hombros y ligeramente más separadas que el ancho de los hombros.", "- Mantenga su cuerpo recto desde la cabeza hasta los talones, involucrando su núcleo para mantener una columna neutral.", "- Fase de descenso Doble lentamente los codos y baje el pecho hacia la pared, manteniendo los codos en un ángulo de 45 grados con respecto al cuerpo. Deténgase cuando su pecho esté aproximadamente a una pulgada de distancia de la pared.", "- Doble lentamente los codos y baje el pecho hacia la pared, manteniendo los codos en un ángulo de 45 grados con respecto al cuerpo.", "- Deténgase cuando su pecho esté aproximadamente a una pulgada de la pared.", "- Presionando Phase Empuje con las palmas de las manos para estirar los brazos y regresar a la posición inicial. Mantenga sus movimientos controlados y evite bloquear los codos.", "- Empuja con las palmas de las manos para estirar los brazos y regresa a la posición inicial.", "- Mantenga sus movimientos controlados y evite bloquear los codos.", "- Repetir: Realice el número deseado de repeticiones manteniendo una buena forma.", "### Consejos para una máxima eficacia", "- Ajuste la ubicación de las manos: un agarre más amplio enfatiza el pecho, mientras que un agarre más estrecho se enfoca más en los tríceps.", "- Aumente gradualmente la dificultad: para progresar, aleje los pies de la pared o haga la transición a flexiones inclinadas o en el piso.", "- Respire adecuadamente: inhale mientras desciende y exhale mientras se aleja de la pared.", "- Centrarse en la forma: priorice la buena forma sobre el número de repeticiones para evitar lesiones y maximizar los resultados.", "- Combine con otros ejercicios: combine flexiones de pared con otros ejercicios de peso corporal, como sentadillas o estocadas, para un entrenamiento de cuerpo completo.", "### Errores comunes a evitar", "- Doblar las caderas: mantenga una línea recta desde la cabeza hasta los talones durante todo el movimiento.", "- Codos extendidos: Mantenga los codos en un ángulo de 45 grados para evitar tensiones innecesarias en los hombros.", "- Acelerar el movimiento: Realice el ejercicio lentamente y con control para lograr el máximo compromiso muscular.", "- Parado demasiado cerca o demasiado lejos: Colóquese de manera que pueda realizar la flexión cómodamente sin forzar la espalda ni los hombros.", "- No involucrar el núcleo: Mantenga el núcleo apretado para evitar que la parte baja de la espalda se hunda o se arquee."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000298563406', 'Fondos en barra paralela', 'Parallel Bar Dips', 'Pecho', '["- Colócate entre las barras paralelas.", "- Agarre las barras firmemente con las palmas hacia adentro.", "- Levanta tu cuerpo del suelo, apoyando tu peso con los brazos.", "- Incline ligeramente el torso hacia adelante con la barbilla doblada y las piernas dobladas hacia atrás.", "- Baje el cuerpo doblando los codos, manteniéndolos abiertos hacia afuera en un ángulo de aproximadamente 45 grados.", "- Deténgase cuando la parte superior de sus brazos esté paralela al suelo o ligeramente por debajo.", "- Vuelve a subir a la posición inicial estirando los brazos.", "- Mantenga el torso erguido con las piernas estiradas debajo de usted.", "- Baje el cuerpo doblando los codos, manteniéndolos cerca de los costados.", "- Deténgase cuando la parte superior de sus brazos esté paralela al suelo.", "- Empújate de nuevo hasta la posición inicial.", "### Consejos para una máxima eficacia", "- Ajuste su inclinación: la inclinación hacia adelante apunta al pecho; La postura erguida enfatiza los tríceps.", "- Controle el ritmo: los movimientos lentos y controlados mejoran la participación muscular y previenen lesiones.", "- Calienta adecuadamente: Moviliza tus hombros y muñecas para prepararte para el rango de movimiento requerido.", "- Utilice asistencia si es necesario: los principiantes pueden usar bandas de resistencia o una máquina de inmersión asistida para desarrollar fuerza.", "- Incorporar progresiones: añade peso con un cinturón de fondos o realiza fondos explosivos para aumentar la intensidad.", "### Errores comunes a evitar", "- Falta de rango completo de movimiento: Evite caídas poco profundas; Baje el cuerpo hasta que la parte superior de sus brazos quede paralela al suelo.", "- Codos ensanchados excesivamente: Mantenga los codos en un ángulo de aproximadamente 45 grados para los fondos de pecho y cerca de los costados para los fondos de tríceps.", "- Movimientos oscilantes o bruscos: realice el ejercicio con movimientos controlados para maximizar la activación muscular y reducir el riesgo de lesiones.", "- Ampliando la parte baja de la espalda: Involucre su núcleo para mantener una columna neutral durante todo el movimiento.", "- Ignorar el dolor en las articulaciones: deténgase si siente molestias en los hombros o las muñecas y modifique el ejercicio según sea necesario."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001634261398', 'Extensión de tríceps por encima de la cabeza | Gymstick', 'Overhead Triceps Extension | Gymstick', 'Tríceps', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001354939135', 'Estiramiento de tríceps de pie', 'Standing Triceps Stretch', 'Tríceps', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001981468056', 'Extensión de tríceps con mancuernas', 'Dumbbell Triceps Extension', 'Tríceps', '["### ", "### Paso 1: configuración", "- Elija una mancuerna con un peso manejable.", "- Párese con los pies separados a la altura de los hombros para mayor estabilidad.", "- Agarre la mancuerna con ambas manos, colocando las palmas debajo de la placa superior de la mancuerna.", "### Paso 2: levantar la mancuerna", "- Levanta la mancuerna por encima de tu cabeza, manteniendo los brazos completamente extendidos.", "- Tus codos deben estar cerca de tus orejas, apuntando hacia adelante.", "- Involucre su núcleo y glúteos para estabilizar su cuerpo.", "### Paso 3: Fase de descenso", "- Doble lentamente los codos y baje la mancuerna detrás de la cabeza.", "- Mantenga los codos inmóviles y evite que se abran.", "- Baje el peso hasta que sus antebrazos queden paralelos al suelo o un poco más profundos.", "### Paso 4: Fase de prensado", "- Involucre sus tríceps y presione la mancuerna hacia arriba hasta la posición inicial.", "- Extiende completamente los brazos manteniendo la tensión en los tríceps.", "- Repita para el número deseado de repeticiones.", "### Repeticiones y Series:", "- Principiantes: 3 series de 8 a 10 repeticiones", "- Intermedio: 3 a 4 series de 10 a 12 repeticiones", "- Avanzado: 4 series de 12 a 15 repeticiones"]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001596356266', 'Extensión de tríceps acostado con barra EZ (Skullcrusher)', 'EZ Bar Lying Triceps Extension (Skullcrusher)', 'Tríceps', '["- Configuración Acuéstese en un banco plano con los ojos directamente debajo de la barra. Pies apoyados en el suelo, rodillas dobladas a ~90°. Agarre la barra con un agarre ligeramente más ancho que el ancho de los hombros (muñecas apiladas sobre los codos). Retraiga y presione las escápulas para estabilizar la parte superior de la espalda. Mantenga un arco natural en la parte baja de la espalda.", "- Acuéstese en un banco plano con los ojos directamente debajo de la barra.", "- Pies apoyados en el suelo, rodillas dobladas a ~90°.", "- Agarre la barra con un agarre ligeramente más ancho que el ancho de los hombros (las muñecas apiladas sobre los codos).", "- Retraiga y presione las escápulas para estabilizar la parte superior de la espalda.", "- Mantenga un arco natural en la parte baja de la espalda.", "- Desmontar y descender Desmontar la barra y llevarla sobre el pecho, con los codos completamente extendidos. Inhale, contraiga el core y baje la barra lentamente hasta la parte inferior del pecho (alrededor del nivel de los pezones), manteniendo los codos a ~45° del torso.", "- Retire la barra y colóquela sobre su pecho, con los codos completamente extendidos.", "- Inhale, contraiga su núcleo y baje la barra lentamente hasta la parte inferior de su pecho (alrededor del nivel del pezón), manteniendo los codos a ~45° del torso.", "- Presione Phase Empuje la barra hacia arriba formando un ligero arco hacia sus ojos. Exhale mientras avanza por el pecho y los tríceps, bloqueando los codos en la parte superior.", "- Empuja la barra hacia arriba formando un ligero arco hacia tus ojos.", "- Exhala mientras avanzas por el pecho y los tríceps, bloqueando los codos en la parte superior.", "- Reiniciar y repetir Mantenga la tensión en la parte superior de la espalda y repita las repeticiones prescritas.", "- Mantenga la tensión superior de la espalda y repita las repeticiones prescritas.", "### Consejos para una forma adecuada", "- Mantenga los omóplatos retraídos durante todo el levantamiento para una mejor estabilidad de las articulaciones.", "- No ensanche excesivamente los codos; apunte a una distancia de entre 45° y 60° del cuerpo.", "- Mantenga un impulso firme de los glúteos y las piernas para anclar su base.", "- Mantenga la alineación de la muñeca neutral para evitar tensiones.", "- Bajar la barra bajo control; no lo rebotes contra el cofre.", "### Errores comunes a evitar", "- Dejar que los codos se ensanchen demasiado, lo que aumenta la tensión en la articulación del hombro.", "- Levantando los pies del suelo, reduciendo la estabilidad de la base.", "- Permitir que la parte baja de la espalda se arquee excesivamente, con el riesgo de sufrir estrés lumbar.", "- Hacer rebotar la barra contra el pecho para ganar impulso.", "- Ruta de barra inconsistente, lo que reduce la eficiencia mecánica."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000364551666', 'Extensiones de tríceps tendido en polea', 'Cable Lying Triceps Extensions', 'Tríceps', '["### ", "- Configure el equipo Conecte una barra recta o una barra EZ-curl a una máquina de cable de polea baja. Coloque un banco plano a unos pocos pies de distancia de la pila de cables.", "- Conecte una barra recta o una barra EZ-curl a una máquina de cable de polea baja.", "- Coloque un banco plano a unos metros de distancia de la pila de cables.", "- Posición inicial Acuéstese en el banco con los pies plantados en el suelo. Agarre la barra con un agarre por encima del ancho de los hombros y extienda los brazos de modo que la barra quede por encima de la frente. Mantenga los codos ligeramente doblados pero bloqueados en su posición.", "- Acuéstese en el banco con los pies apoyados en el suelo.", "- Agarre la barra con un agarre por encima de los hombros y extienda los brazos para que la barra quede por encima de su frente.", "- Mantenga los codos ligeramente doblados pero bloqueados en su posición.", "- Ejecución Baje lentamente la barra hacia la frente o ligeramente detrás de ella doblando los codos. Mantenga la parte superior de los brazos inmóviles mientras activa los tríceps. Una vez que alcance un ángulo de 90 grados en los codos, haga una pausa breve. Extienda los brazos hasta la posición inicial empujando la barra hacia arriba, contrayendo completamente los tríceps.", "- Baje lentamente la barra hacia su frente o ligeramente detrás de ella doblando los codos.", "- Mantenga la parte superior de los brazos inmóviles mientras ejercita los tríceps.", "- Una vez que alcance un ángulo de 90 grados en los codos, haga una pausa breve.", "- Extiende tus brazos nuevamente a la posición inicial empujando la barra hacia arriba, contrayendo completamente los tríceps.", "- Repeticiones y series Realice de 3 a 4 series de 8 a 12 repeticiones, dependiendo de sus objetivos de entrenamiento.", "- Realiza de 3 a 4 series de 8 a 12 repeticiones, dependiendo de tus objetivos de entrenamiento.", "### Consejos para una forma adecuada", "- Mantenga los codos estacionarios para maximizar la activación de los tríceps.", "- Utilice un movimiento controlado para evitar el impulso y la tensión innecesaria en las articulaciones.", "- Involucre su núcleo para estabilizar su cuerpo durante todo el movimiento.", "- Baje el peso lentamente y bajo control, asegurando un rango de movimiento completo.", "- No bloquee los codos en la parte superior para evitar una tensión excesiva en las articulaciones.", "### Errores comunes a evitar", "- Ensanchar los codos hacia afuera, lo que reduce el compromiso de los tríceps y genera tensión en los hombros.", "- Uso de peso excesivo, lo que provoca una forma inadecuada y riesgo de lesiones.", "- Permitir que la barra se mueva demasiado hacia adelante, lo que aleja la tensión del tríceps.", "- Acelerar el movimiento, reducir el tiempo bajo tensión y efectividad.", "- Levantar las caderas del banco, lo que puede causar inestabilidad y disminuir la concentración en los tríceps."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000331353310', 'Flexiones de diamante', 'Diamond Push-up', 'Pecho', '["### ", "### Paso 1: Configuración y posición inicial", "- Comience en una posición de tabla alta, manteniendo las manos directamente debajo del pecho.", "- Junte las manos formando un diamante con los dedos pulgar e índice.", "- Mantenga su cuerpo en línea recta desde la cabeza hasta los talones, involucrando su núcleo y glúteos para mantener la estabilidad.", "### Paso 2: Ejecución", "- Baje su pecho hacia la forma de diamante formada por sus manos.", "- Mantenga los codos cerca del cuerpo para maximizar la participación de los tríceps.", "- Bájate hasta que tu pecho casi toque tus manos.", "- Presione hacia atrás hasta la posición inicial extendiendo los brazos completamente.", "- Repita de 3 a 4 series de 10 a 15 repeticiones, dependiendo de su nivel de fuerza.", "### Consejos para una forma adecuada", "- Mantenga su núcleo apretado para evitar que sus caderas se caigan.", "- Baje lentamente para mantener el control y maximizar la participación de los músculos.", "- No ensanches los codos; manténgalos escondidos cerca de sus costados.", "- Respira adecuadamente, inhalando mientras bajas y exhalando mientras empujas hacia arriba.", "- Mantenga una columna neutra para evitar tensiones innecesarias en la espalda.", "### Errores comunes a evitar", "- Caderas caídas o levantar demasiado el trasero, lo que compromete el compromiso central.", "- Codos ensanchados, lo que reduce la activación de los tríceps y aumenta la tensión en los hombros.", "- Rango de movimiento incompleto, lo que limita el desarrollo muscular.", "- Moverse demasiado rápido, lo que reduce la tensión muscular y la efectividad.", "- Manos demasiado separadas, lo que desvía la atención del tríceps."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-002101878272', 'Postura de yoga del tigre', 'Tiger Yoga Pose', 'Tríceps', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001059735116', 'Extensión de tríceps sentado con mancuernas', 'Seated Dumbbell Triceps Extension', 'Tríceps', '["### Paso 1: Configuración y posición inicial", "- Siéntese en un banco con respaldo para garantizar la estabilidad.", "- Sostenga una mancuerna con ambas manos, agarrando el peso por la placa superior o el mango.", "- Levanta la mancuerna por encima de tu cabeza, extendiendo completamente los brazos.", "### Paso 2: Ejecución", "- Baje lentamente la mancuerna detrás de su cabeza doblando los codos.", "- Mantenga la parte superior de los brazos inmóviles mientras permite que los antebrazos se muevan.", "- Baje la mancuerna hasta que sus codos alcancen un ángulo de 90 grados.", "- Involucra tus tríceps para empujar la mancuerna de regreso a la posición inicial.", "- Repita de 8 a 12 repeticiones durante 3 a 4 series.", "### Consejos para una forma adecuada", "- Mantenga los codos cerca de la cabeza para asegurar el compromiso de los tríceps.", "- Mantenga una columna neutra para evitar la tensión en la zona lumbar.", "- Baje la mancuerna de forma controlada para evitar tensiones innecesarias en los codos.", "- Involucre su núcleo para mayor estabilidad.", "- No bloquees los codos en la parte superior, ya que esto puede causar tensión en las articulaciones.", "### Errores comunes a evitar", "- Ensanchar los codos hacia afuera, lo que reduce la activación de los tríceps.", "- Usar peso excesivo, lo que lleva a un control deficiente y posibles lesiones.", "- Redondear la espalda, lo que puede provocar molestias en la zona lumbar.", "- Acelerar el movimiento, reduciendo el tiempo bajo tensión de los músculos.", "- No extender completamente los brazos en la parte superior, limitando la efectividad del ejercicio."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001161271458', 'Fondos entre sillas', 'Dips Between Chairs', 'Pecho', '["- Elija sillas resistentes Utilice dos sillas estables con asientos firmes. Asegúrese de que no se deslicen ni se vuelquen durante el ejercicio.", "- Utilice dos sillas estables con asientos firmes. Asegúrese de que no se deslicen ni se vuelquen durante el ejercicio.", "- Coloque las sillas Coloque las sillas paralelas entre sí, ligeramente más separadas que el ancho de los hombros.", "- Coloque las sillas paralelas entre sí, ligeramente más separadas que el ancho de los hombros.", "- Posición inicial: Párese entre las sillas y coloque las manos en los bordes de los asientos de las sillas. Levante los pies del suelo y extienda las piernas hacia adelante, manteniéndolas rectas o ligeramente dobladas.", "- Párese entre las sillas y coloque las manos en los bordes de los asientos de las sillas.", "- Levanta los pies del suelo y extiende las piernas hacia adelante manteniéndolas rectas o ligeramente flexionadas.", "- Baje el cuerpo Doble lentamente los codos y baje el cuerpo hasta que la parte superior de los brazos quede paralela al suelo. Mantenga los codos cerca del torso y evite abrirlos hacia afuera.", "- Doble lentamente los codos y baje el cuerpo hasta que la parte superior de los brazos quede paralela al suelo.", "- Mantenga los codos cerca del torso y evite abrirlos hacia afuera.", "- Empuje hacia arribaPresione con las manos para extender los brazos y volver a la posición inicial. Evite bloquear los codos en la parte superior.", "- Presione con las manos para extender los brazos y volver a la posición inicial.", "- Evite bloquear los codos en la parte superior.", "- Repetir Realice de 8 a 12 repeticiones durante 3 a 4 series, manteniendo la forma adecuada.", "- Realice de 8 a 12 repeticiones durante 3 a 4 series, manteniendo la forma adecuada.", "### Consejos para una forma adecuada", "- Involucre su núcleo: mantenga sus abdominales contraídos para estabilizar su cuerpo.", "- Mantenga la alineación: evite inclinarse demasiado hacia adelante o hacia atrás; mantenga el torso erguido.", "- Controle el movimiento: concéntrese en movimientos lentos y deliberados de bajar y presionar.", "- Profundidad: baje el cuerpo sólo hasta donde la flexibilidad de sus hombros lo permita.", "- Agarre: Sujete los bordes de la silla con firmeza pero sin tensión excesiva en las muñecas.", "### Errores comunes", "- Uso de sillas inestables: asegúrese de que las sillas sean resistentes y seguras para evitar accidentes.", "- Codos ensanchados: Mantenga los codos cerca del cuerpo para evitar tensión en los hombros.", "- Profundidad excesiva: Bajar demasiado puede estirar demasiado los hombros y provocar lesiones.", "- Caderas caídas: mantenga una línea recta desde la cabeza hasta los pies; no dejes caer tus caderas."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001794703295', 'Trotar en el sitio', 'Run in Place', 'Cardio', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000030283261', 'Fondos en silla', 'Chair Dips', 'Otros', '["### ", "- Configure la posición Busque una silla o banco resistente que pueda soportar el peso de su cuerpo. Siéntese en el borde de la silla y separe las manos a la altura de los hombros, agarrando el borde del asiento con los dedos mirando hacia adelante.", "- Busque una silla o banco resistente que pueda soportar su peso corporal.", "- Siéntese en el borde de la silla y separe las manos a la altura de los hombros, agarrando el borde del asiento con los dedos hacia adelante.", "- Posición inicial Extienda las piernas frente a usted, manteniendo los talones en el suelo. Deslice las caderas fuera de la silla mientras sostiene su peso con los brazos.", "- Extiende las piernas frente a ti, manteniendo los talones en el suelo.", "- Desliza las caderas fuera de la silla mientras soportas tu peso con los brazos.", "- Ejecución Baje lentamente el cuerpo doblando los codos hasta que alcancen un ángulo de 90 grados. Mantenga la espalda cerca de la silla y evite abrir los codos hacia afuera. Haga una breve pausa en la parte inferior, luego empuje con las palmas de las manos para extender los brazos y volver a la posición inicial.", "- Baje lentamente el cuerpo doblando los codos hasta que alcancen un ángulo de 90 grados.", "- Mantenga la espalda pegada a la silla y evite extender los codos hacia afuera.", "- Haga una breve pausa en la parte inferior, luego empuje con las palmas de las manos para extender los brazos y volver a la posición inicial.", "- Repeticiones y series Realice de 3 a 4 series de 10 a 15 repeticiones, dependiendo de su nivel de condición física.", "- Realiza de 3 a 4 series de 10 a 15 repeticiones, dependiendo de tu nivel de condición física.", "### Consejos para una forma adecuada", "- Mantenga los codos doblados para maximizar la participación de los tríceps y reducir la tensión en los hombros.", "- Mantenga el torso recto sin inclinarse excesivamente hacia adelante.", "- Controle el movimiento en lugar de apresurarse en las repeticiones para evitar lesiones.", "- Involucre su núcleo para estabilizar su cuerpo durante todo el ejercicio.", "- No bloquee completamente los codos en la parte superior para evitar tensión en las articulaciones.", "### Errores comunes a evitar", "- Ensanchar los codos hacia afuera, lo que reduce la activación de los tríceps y aumenta la tensión en los hombros.", "- Usar una silla débil o inestable, lo que puede resultar inseguro y provocar lesiones.", "- Bajar demasiado rápido aumenta el riesgo de sufrir lesiones en el hombro o el codo.", "- No profundizar lo suficiente, lo que limita la eficacia del ejercicio.", "- Colocar las manos demasiado separadas reduce el compromiso de los tríceps."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000031982949', 'Extensión de tríceps en polea de rodillas', 'Kneeling Cable Triceps Extension', 'Tríceps', '["- Configure la máquina de cable Conecte una barra recta, una barra de curl EZ o una cuerda a la polea alta de una máquina de cable. Seleccione un peso apropiado que permita un movimiento controlado sin comprometer la forma.", "- Conecte una barra recta, una barra de curl EZ o una cuerda a la polea alta de una máquina de cable.", "- Seleccione un peso apropiado que permita un movimiento controlado sin comprometer la forma.", "- Colóquese Arrodíllese en el suelo frente a la máquina de cable, doblando el cuerpo para que los codos queden fijos al banco. Sujete el accesorio con un agarre por encima de la cabeza (con las palmas hacia abajo) y acérquelo a la frente. Mantenga los codos doblados y alineados con los hombros.", "- Arrodíllate en el suelo frente a la máquina de cable, doblando el cuerpo para que los codos queden fijos al banco.", "- Agarre el accesorio con las palmas hacia abajo y acérquelo a su frente.", "- Mantenga los codos doblados y alineados con los hombros.", "- Ejecución Involucre su núcleo y estabilice la parte superior de su cuerpo. Extienda los codos hacia adelante empujando el mango o el accesorio de cuerda lejos de su frente hasta que sus brazos estén completamente extendidos. Mantenga la parte superior de los brazos inmóvil mientras mueve solo los antebrazos. Apriete los tríceps al final del movimiento. Regrese lentamente a la posición inicial doblando los codos mientras mantiene el control.", "- Involucre su núcleo y estabilice la parte superior de su cuerpo.", "- Extienda los codos hacia adelante empujando el mango o la cuerda hacia afuera de su frente hasta que sus brazos estén completamente extendidos.", "- Mantenga la parte superior de los brazos inmóviles mientras mueve solo los antebrazos.", "- Aprieta tus tríceps al final del movimiento.", "- Regrese lentamente a la posición inicial doblando los codos mientras mantiene el control.", "- Repetir Realice el número deseado de repeticiones manteniendo la forma adecuada.", "- Realice el número deseado de repeticiones manteniendo la forma adecuada.", "### Consejos para una forma adecuada", "- Mantenga los codos en una posición fija para asegurar la activación completa de los tríceps.", "- Evite utilizar el impulso o balancear el peso para completar el movimiento.", "- Involucre su núcleo y mantenga la espalda recta para mantener la estabilidad.", "- Utilice un tempo controlado, asegurando movimientos suaves durante todo el ejercicio.", "- Extienda completamente los brazos sin bloquear los codos para evitar tensión en las articulaciones.", "### Errores comunes a evitar", "- Ensanchar los codos hacia afuera, lo que reduce el compromiso de los tríceps y puede tensar los hombros.", "- Usar peso excesivo, lo que lleva a un control deficiente y una forma inadecuada.", "- No extender completamente los brazos, limitando la efectividad del ejercicio.", "- Inclinarse demasiado hacia adelante, lo que reduce el aislamiento del tríceps.", "- Apresurarse en el movimiento, en lugar de centrarse en un movimiento lento y controlado."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001800430250', 'Curl de martillo sentado', 'Seated Hammer Curl', 'Bíceps', '["Siéntese en un banco o silla con los pies apoyados en el suelo y sostenga una mancuerna en cada mano con un agarre neutral (martillo), con las palmas una frente a la otra.", "Mantenga los codos cerca de los costados y active el núcleo para mantener una posición estable.", "Levanta lentamente las mancuernas hacia tus hombros flexionando los codos, manteniendo las muñecas y los antebrazos en una posición neutral.", "Haga una pausa por un momento en la parte superior del movimiento y luego baje lentamente las mancuernas hasta la posición inicial.", "Repeat for the desired number of repetitions, maintaining control and avoiding swinging the weights or using momentum."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001357855074', 'Curl alterno con mancuernas sentado', 'Seated Alternating Dumbbell Curl', 'Otros', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-002083554082', 'Curl de concentración del cable', 'Cable Concentration Curl', 'Bíceps', '["Configure la máquina de cable: conecte una manija única a una polea baja en la máquina de cable.", "Siéntate en un banco: Siéntate en un banco con los pies apoyados en el suelo y las piernas separadas a la altura de los hombros. Coloque el codo del brazo que trabaja en la parte interna del muslo, con la palma hacia arriba.", "Agarre el mango del cable: Sujete el mango del cable con la palma hacia arriba y deje que el brazo cuelgue hacia abajo, completamente extendido.", "Doble el mango: Manteniendo la parte superior del brazo inmóvil, exhale y doble el mango del cable hacia su hombro mientras mantiene un agarre firme sobre el mango. Mantenga la muñeca recta y concéntrese en contraer los músculos bíceps.", "Baje el mango: Inhale y baje lentamente el mango hasta la posición inicial, manteniendo la parte superior del brazo inmóvil durante todo el movimiento.", "Repetir: Complete el número deseado de repeticiones con un brazo antes de cambiar al otro brazo."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000641145561', 'Curl dedos con barra', 'Barbell Finger Curl', 'Bíceps', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000932361174', 'Press declinado con mancuernas', 'Decline Dumbbell Press', 'Pecho', '["### ", "- Coloque un banco inclinado en un ángulo de 15 a 30 grados.", "- Coge un par de mancuernas y siéntate en el banco con los pies asegurados debajo de las almohadillas de apoyo.", "- Recuéstese con las mancuernas sostenidas al nivel de los hombros, las palmas hacia adelante y los codos doblados en un ángulo de aproximadamente 90 grados.", "- Presione hacia arriba: exhale mientras presiona las mancuernas hacia arriba con un movimiento suave y controlado hasta que sus brazos estén completamente extendidos (pero no bloqueados).", "- Baje lentamente: Inhale mientras baja las mancuernas a la posición inicial, manteniendo el control y asegurándose de que los codos permanezcan ligeramente por debajo del nivel del pecho para un estiramiento profundo.", "- Repita hasta el número deseado de repeticiones.", "### Consejos para la eficacia", "- Centrarse en la forma: priorice la forma adecuada sobre los pesos pesados ​​para maximizar la efectividad y la seguridad.", "- Aprieta en la parte superior: contrae los músculos del pecho en el punto máximo del movimiento para un compromiso óptimo.", "- Tempo controlado: utilice un ritmo lento y controlado para mantener la tensión en los músculos del pecho.", "- Combínelo con press inclinado y plano: combínelo con otras variaciones de press de banca para un desarrollo completo del pecho.", "### Errores comunes", "- Codos ensanchados: Mantenga los codos en un ángulo de 45 grados para reducir la tensión en los hombros.", "- Peso excesivo: usar demasiado peso puede comprometer la forma y aumentar el riesgo de lesiones.", "- Repeticiones apresuradas: realice el movimiento lentamente para maximizar el control y el compromiso.", "- Ángulo de banco incorrecto: asegúrese de que el ángulo de descenso no sea demasiado pronunciado, ya que esto puede reducir la activación del pecho y generar una tensión indebida en los hombros."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001162085363', 'Curl de bíceps unilateral con banda de resistencia', 'One-Arm Biceps Curl With Resistance Band', 'Bíceps', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001663556391', 'Máquina de curl de bíceps', 'Biceps Curl Machine', 'Bíceps', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-002018418128', 'Fondos de tríceps asistidas', 'Assisted Triceps Dips', 'Tríceps', '["### Paso 1: configurar la máquina", "- Ajuste el peso de asistencia en la máquina. Cuanto mayor sea la asistencia, más fácil será el ejercicio.", "- Sube a la plataforma y agarra las barras de inmersión paralelas con un agarre neutral (con las palmas hacia adentro).", "- Coloque las rodillas o los pies sobre la almohadilla, según el diseño de la máquina.", "### Paso 2: Posición inicial", "- Mantenga una postura erguida con el pecho erguido y el core comprometido.", "- Agarre las barras firmemente con los brazos completamente extendidos.", "- Mantenga los codos cerca del cuerpo para apuntar eficazmente a los tríceps.", "### Paso 3: Fase de descenso", "- Baje lentamente el cuerpo doblando los codos mientras los mantiene doblados.", "- Desciende hasta que la parte superior de tus brazos quede paralela al suelo o ligeramente por debajo.", "- Mantenga los hombros estables y evite encogerse de hombros.", "### Paso 4: Fase de prensado", "- Empuja con las palmas de las manos para extender los brazos y llevar el cuerpo a la posición inicial.", "- Concéntrate en involucrar tus tríceps durante el movimiento ascendente.", "- Evite bloquear los codos en la parte superior para mantener la tensión muscular.", "### Paso 5: repita para las repeticiones deseadas", "- Realice de 3 a 4 series de 8 a 15 repeticiones, ajustando la asistencia según sea necesario."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001355195038', 'Curl de bíceps unilateral', 'One Arm Biceps Curl', 'Bíceps', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-002095169985', 'Curl de concentración', 'Concentration Curl', 'Otros', '["Siéntate en un banco o silla con los pies apoyados en el suelo y una mancuerna en una mano.", "Coloque el codo en la parte interna del muslo, con el brazo completamente extendido y la mancuerna colgando hacia abajo.", "Doble el peso hacia el hombro, manteniendo el codo inmóvil y la parte superior del brazo presionada contra el muslo.", "Haga una pausa en la parte superior del movimiento, luego baje lentamente el peso hasta la posición inicial.", "Repita hasta el número deseado de repeticiones, luego cambie al otro brazo y repita."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000524846993', 'Enrollamiento del cable', 'Cable Curl', 'Otros', '["El curl con cable es un ejercicio de aislamiento para el músculo bíceps. Es una acción de tracción que se realiza con una máquina de cable y es apta para principiantes.", "El objetivo principal del movimiento de curl con cable es el músculo bíceps braquial. Puedes conseguir brazos más anchos y gruesos apuntando a la cabeza del bíceps con este exclusivo ejercicio de curling con cable. El cable mantiene la tensión en los bíceps durante la parte de descenso y elevación de cada repetición para que siempre estén enganchados. La tensión constante del cable significa que trabajas duro tus bíceps."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001360561494', 'Curl de camarero', 'Waiter Curl', 'Otros', '["- Posición inicial: Párese erguido con los pies separados a la altura de los hombros, sosteniendo una mancuerna verticalmente frente a usted con ambas manos ahuecando la placa superior.", "- Configuración de agarre: Mantenga los codos cerca del torso y las palmas hacia arriba, sosteniendo la mancuerna desde abajo.", "- Curl la mancuerna: doble los codos para levantar la mancuerna hacia el pecho mientras mantiene las muñecas estables.", "- Apriete en la parte superior: haga una pausa de 1 a 2 segundos, contrayendo el bíceps por completo.", "- Bajar bajo control: Regrese lentamente la mancuerna a la posición inicial sin dejarla caer.", "- Repetir: Realice el número deseado de repeticiones manteniendo la forma estricta.", "### Consejos para una forma adecuada", "- Mantenga los codos doblados para evitar la afectación de los hombros.", "- Mantenga una postura erguida; evite inclinarse hacia atrás.", "- Sujete la mancuerna de forma segura para evitar que se mueva o se tambalee.", "- Muévase lentamente para aumentar la activación muscular y el tiempo bajo tensión.", "- Evite la flexión de la muñeca; mantenga las muñecas en posición neutral por seguridad.", "### Errores comunes", "- Usar demasiado peso, lo que provoca balanceos o un control deficiente.", "- Dejar que los codos se abran, reduciendo el aislamiento del bíceps.", "- Apresurar las repeticiones en lugar de controlar el movimiento.", "- Extenderse demasiado en la parte inferior, ejerciendo presión sobre la articulación del codo.", "- Inclinar la mancuerna, lo que desplaza la carga de manera desigual."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000571698103', 'Dominadas con salto', 'Jumping Pull-up', 'Espalda', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000931396437', 'Curl de piernas con mancuernas declinado', 'Decline Dumbbell Leg Curl', 'Piernas', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001433503355', 'Curl predicador con mancuernas', 'Dumbbell Preacher Curl', 'Otros', '["Siéntate en un banco de curl predicador y toma una mancuerna con una mano.", "Coloque la parte superior del brazo en el banco de modo que quede apoyado y el codo apunte hacia arriba.", "Manteniendo la parte superior del brazo inmóvil, doble la mancuerna hacia el hombro.", "Aprieta los bíceps en la parte superior del movimiento, luego baja lentamente la mancuerna a la posición inicial.", "Repita hasta el número deseado de repeticiones en un brazo antes de cambiar al otro brazo."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000013662021', 'Remo inclinado con mancuernas y agarre inverso', 'Incline Reverse Grip Dumbbell Row', 'Espalda', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000797098209', 'Curl de bíceps sentado con banda de resistencia', 'Seated Bicep Curl With Resistance Band', 'Bíceps', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001797573679', 'Curl de bíceps inclinado en polea', 'Cable Incline Biceps Curl', 'Bíceps', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000890029316', 'Curl de martillo con banda de resistencia', 'Hammer Curl with Resistance Band', 'Otros', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001162085363', 'Curl de bíceps unilateral con banda de resistencia', 'One-Arm Biceps Curl With Resistance Band', 'Bíceps', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001133409604', 'Curl predicador con barra EZ', 'EZ Bar Preacher Curl', 'Otros', '["Ajuste el banco del predicador: Ajuste la altura del banco del predicador de modo que la parte superior de los brazos descanse cómodamente sobre la almohadilla en ángulo. Asegúrese de que su pecho esté en contacto con la almohadilla.", "Seleccione el peso adecuado: seleccione un peso adecuado en la barra EZ que desafíe sus bíceps pero le permita mantener la forma adecuada.", "Sujete la barra EZ: Sujete la barra EZ con un agarre por debajo (con las palmas hacia arriba) y con las manos ligeramente más juntas que el ancho de los hombros.", "Coloque sus brazos: Coloque sus brazos sobre la almohadilla en ángulo, con la parte superior de sus brazos perpendicular al suelo y los codos ligeramente flexionados.", "Flexiona la barra: Manteniendo la parte superior de los brazos inmóviles, exhala y flexiona la barra hacia el pecho, concentrándote en contraer los bíceps. Mantenga la contracción máxima por un segundo.", "Baja la barra: Inhala y baja lentamente la barra hasta la posición inicial, manteniendo el control y la tensión en tus bíceps."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001797573679', 'Curl de bíceps inclinado en polea', 'Cable Incline Biceps Curl', 'Bíceps', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001771273664', 'Curl de bíceps unilateral y cable alto', 'High Cable Single Arm Bicep Curl', 'Bíceps', '["Párese frente a una máquina de cable con la manija unida a la polea más alta. Agarre el asa con una mano y retroceda unos metros.", "Con el brazo completamente extendido y la palma hacia arriba, doble el mango hacia el hombro doblando el codo y contrayendo el bíceps.", "Mantenga la contracción máxima durante un segundo, luego baje lentamente el mango hasta la posición inicial.", "Repita hasta obtener el número deseado de repeticiones, luego cambie de brazo y repita."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001791349116', 'Curl de bíceps en polea de rodillas', 'Cable Kneeling Biceps Curl', 'Bíceps', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001355195038', 'Curl de bíceps unilateral', 'One Arm Biceps Curl', 'Bíceps', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000563947804', 'Bailarina sentada', 'Seated Ballerina Exercise', 'Hombros', '["La movilidad del hombro es importante tanto para fortalecer como para estirar. Este ejercicio puede ayudar a estabilizar y fortalecer los músculos escapulares al mismo tiempo que proporciona rango de movimiento en los hombros y la parte superior de la espalda."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-002042156838', 'Curl predicador de palanca', 'Lever Preacher Curl', 'Otros', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001869251398', 'Curl de martillo', 'Hammer Curl', 'Bíceps', '["Párese o siéntese con una buena postura: sostenga una pesa en cada mano con un agarre neutral, con las palmas una frente a la otra. Tus brazos deben estar completamente extendidos y colgando a los costados.", "Doble un brazo a la vez: exhale y doble un peso hacia su hombro, mientras mantiene el otro peso extendido y colgando a su lado.", "Contrae tus bíceps: en la parte superior del movimiento, aprieta los bíceps para contraer completamente los músculos.", "Baja el peso: Inhala y baja lentamente el peso hasta la posición inicial, manteniendo el codo cerca del cuerpo y manteniendo el control durante todo el movimiento.", "Repite con el otro brazo: Repite el movimiento con el otro brazo, curvando el peso hacia tu hombro mientras mantienes el otro brazo extendido y colgando a tu lado."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001663556391', 'Máquina de curl de bíceps', 'Biceps Curl Machine', 'Bíceps', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001800430250', 'Curl de martillo sentado', 'Seated Hammer Curl', 'Otros', '["Siéntese en un banco o silla con los pies apoyados en el suelo y sostenga una mancuerna en cada mano con un agarre neutral (martillo), con las palmas una frente a la otra.", "Mantenga los codos cerca de los costados y active el núcleo para mantener una posición estable.", "Levanta lentamente las mancuernas hacia tus hombros flexionando los codos, manteniendo las muñecas y los antebrazos en una posición neutral.", "Haga una pausa por un momento en la parte superior del movimiento y luego baje lentamente las mancuernas hasta la posición inicial.", "Repita hasta el número deseado de repeticiones, manteniendo el control y evitando balancear las pesas o usar el impulso."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000306176340', 'Curl inverso con barra', 'Barbell Reverse Curl', 'Otros', '["El curl inverso con barra es uno de los ejercicios de brazos más eficaces dirigidos a las muñecas y los bíceps.", "Este ejercicio puede aumentar su capacidad para levantar pesas más pesadas durante la flexión de bíceps estándar. Además, puede corregir el desequilibrio muscular entre los músculos extensores y flexores. Además, es un ejercicio eficaz para desarrollar brazos más grandes y mejorar la flexibilidad de los bíceps.", "Si fortaleces las muñecas y los antebrazos podrás levantar más peso mientras realizas otros ejercicios. La razón por la que no puede levantar el peso del cuerpo puede deberse a la debilidad de las muñecas y los brazos. Agregar ejercicios de muñeca y antebrazo a su programa de entrenamiento creará flexores de muñeca fuertes."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001869251398', 'Curl de martillo', 'Hammer Curl', 'Otros', '["Párese o siéntese con una buena postura: sostenga una pesa en cada mano con un agarre neutral, con las palmas una frente a la otra. Tus brazos deben estar completamente extendidos y colgando a los costados.", "Doble un brazo a la vez: exhale y doble un peso hacia su hombro, mientras mantiene el otro peso extendido y colgando a su lado.", "Contrae tus bíceps: en la parte superior del movimiento, aprieta los bíceps para contraer completamente los músculos.", "Baja el peso: Inhala y baja lentamente el peso hasta la posición inicial, manteniendo el codo cerca del cuerpo y manteniendo el control durante todo el movimiento.", "Repite con el otro brazo: Repite el movimiento con el otro brazo, curvando el peso hacia tu hombro mientras mantienes el otro brazo extendido y colgando a tu lado."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000192326083', 'Curl dedos con barra sentado', 'Seated Barbell Finger Curl', 'Otros', '["- Siéntese en un banco plano con los pies apoyados en el suelo y las rodillas dobladas a 90 grados.", "- Sostenga una barra con un agarre por debajo (con las palmas hacia arriba), con las manos separadas al ancho de los hombros.", "- Apoye los antebrazos sobre los muslos de modo que las muñecas cuelguen justo por encima de las rodillas.", "- Deje que la barra baje lentamente por sus dedos hasta las yemas.", "- Vuelva a doblar la barra hacia arriba flexionando los dedos y apretando con fuerza en la parte superior.", "- Realice de 10 a 15 repeticiones lentas y controladas, concentrándose en la contracción de los antebrazos.", "### Consejos para una forma adecuada", "- Utilice un peso de ligero a moderado para evitar sobrecargar las delicadas articulaciones de los dedos.", "- Mantenga los antebrazos planos y estables contra los muslos durante todo el movimiento.", "- Muévase lentamente en todo el rango de movimiento, sin sacudidas.", "- Aprieta con fuerza en la parte superior para una máxima activación muscular.", "- Respire constantemente, exhale mientras se curva e inhala mientras suelta.", "### Errores comunes", "- Usar peso excesivo, que puede forzar los dedos y limitar el rango de movimiento.", "- Levantando los antebrazos de los muslos, reduciendo el aislamiento.", "- Realizar repeticiones rápidas o entrecortadas, disminuyendo el control muscular.", "- No permitir que la barra ruede completamente, lo que limita la efectividad de la fase de estiramiento.", "- Despreciando el apretón en la parte superior, lo que minimiza el compromiso muscular."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001195946150', 'Curl con dos brazos en polea en banco inclinado', 'Cable Two Arm Curl on Incline Bench', 'Bíceps', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000486784190', 'Máquina de fondos de tríceps', 'Triceps Dip Machine', 'Tríceps', '["### Paso 1: ajustar la máquina", "- Ajuste la altura del asiento de modo que la parte superior de sus brazos quede alineada con las manijas.", "- Elija un peso que permita una forma adecuada y un movimiento controlado.", "### Paso 2: configuración y posicionamiento", "- Agarre las manijas firmemente.", "- Mantenga los codos pegados al cuerpo.", "- Coloque los pies apoyados en el suelo para estabilizar su posición.", "### Paso 3: Ejecución", "- Presione las manijas hacia abajo, extendiendo completamente los brazos mientras activa los tríceps.", "- Haga una pausa de un segundo en la parte inferior para maximizar la activación muscular.", "- Regrese lentamente a la posición inicial, controlando el peso mientras dobla los codos.", "- Repita durante la cantidad deseada de repeticiones, manteniendo los movimientos controlados y constantes."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000641145561', 'Curl dedos con barra', 'Barbell Finger Curl', 'Bíceps', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001765210970', 'Estiramiento de cadera con rotación sentada', 'Sitting Rotation Hip Stretch', 'Piernas', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001195946150', 'Curl con dos brazos en polea en banco inclinado', 'Cable Two Arm Curl on Incline Bench', 'Hombros', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001390466815', 'Estiramiento del cuello con empuje lateral', 'Side Push Neck Stretch', 'Hombros', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001198071477', 'Elevación frontal con barra', 'Barbell Front Raise', 'Hombros', '["El levantamiento frontal con barra es un ejercicio simple con barra que apunta a las cabezas anterior y lateral de los hombros. Adecuado para todos los niveles, este ejercicio de flexión de hombros es una buena opción para desarrollar fuerza, mejorar la movilidad de los hombros y dar forma a la cabeza de los hombros."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-002075587528', 'Plataforma vibratoria', 'Vibration Plate', 'Espalda', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001192771155', 'Cruce en polea alto', 'High Cable Crossover', 'Pecho', '["Ajuste los cables: Ajuste los cables a la posición más alta en ambos lados de la máquina de cable. Conecte las manijas a cada cable.", "Párese en el centro: Párese en el centro de la máquina, de espaldas a ella. Sostenga las manijas con las palmas hacia abajo.", "Colóquese: dé un paso hacia adelante con una pierna o inclínese ligeramente hacia adelante, manteniendo los pies separados al ancho de los hombros. Tus brazos deben estar extendidos a los lados, paralelos al suelo.", "Cruza las manijas: lentamente acerca ambas manijas, cruzándolas frente a tu cuerpo. Tus brazos deben estar ligeramente doblados a la altura del codo.", "Aprieta tu pecho: haz una pausa por un momento y aprieta los músculos del pecho.", "Regreso a la posición inicial: Baja lentamente las asas hasta la posición inicial, manteniendo los brazos ligeramente flexionados.", "Repetir: Repita el ejercicio durante el número deseado de repeticiones."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000000227386', 'Zancada declinada con mancuernas en banco', 'Decline Bench Dumbbell Lunge', 'Piernas', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000903513484', 'Masaje de hombro posterior con rodillo de espuma (Foam Roller)', 'Foam Roller Posterior Shoulder', 'Hombros', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001408176883', 'Elevaciones de rodillas en banco sentado', 'Leg Pull-in Knee-ups', 'Abdomen', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001048768803', 'Remo con mancuernas', 'Dumbbell Row', 'Espalda', '["Coloque la rodilla izquierda y la mano izquierda sobre un banco, manteniendo la espalda plana y el torso paralelo al suelo.", "Sostenga una mancuerna en su mano derecha, con el brazo completamente extendido hacia el piso y la palma hacia adentro.", "Involucre su núcleo y levante la mancuerna, llevando su codo hacia su cadera.", "Haga una pausa en la parte superior, apretando el omóplato hacia la columna.", "Baja la mancuerna lentamente hasta la posición inicial bajo control.", "Complete las repeticiones y luego cambie de lado."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000223355219', 'Máquina de aperturas con pecho inclinado', 'Incline Chest Fly Machine', 'Pecho', '["### Consejos para una forma adecuada", "- Mantenga la espalda apoyada contra el banco para evitar la tensión lumbar.", "- Mantenga una ligera flexión de los codos durante todo el movimiento.", "- Evite un rango de movimiento excesivo para proteger las articulaciones de los hombros.", "- Controla el tempo, especialmente durante la fase excéntrica (de descenso).", "- Involucre su núcleo para estabilizar su torso durante toda la serie.", "### Errores comunes a evitar", "- Bloquear los codos, lo que aumenta la tensión en las articulaciones.", "- Dejar las manijas demasiado atrás, corre el riesgo de lesionarse el hombro.", "- Arquear la espalda excesivamente, lo que reduce la activación del pecho.", "- Apresurarse en las repeticiones sin centrarse en la contracción muscular.", "- Colocar el asiento demasiado bajo o alto, desviando la atención de la parte superior del pecho."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-002145324490', 'Remo en polea alta de rodillas', 'Kneeling High Pulley Row', 'Espalda', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001080388730', 'Dominadas de arquero (Archer Pull-ups)', 'Archer Pull-up', 'Espalda', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001048768803', 'Remo con mancuernas', 'Dumbbell Row', 'Espalda', '["Coloque la rodilla izquierda y la mano izquierda sobre un banco, manteniendo la espalda plana y el torso paralelo al suelo.", "Sostenga una mancuerna en su mano derecha, con el brazo completamente extendido hacia el piso y la palma hacia adentro.", "Involucre su núcleo y levante la mancuerna, llevando su codo hacia su cadera.", "Haga una pausa en la parte superior, apretando el omóplato hacia la columna.", "Baja la mancuerna lentamente hasta la posición inicial bajo control.", "Complete las repeticiones y luego cambie de lado."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000248045316', 'Golpe derecha (Directo / Cross)', 'Right Cross', 'Cardio', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000943779732', 'Remo con barra en T', 'T-Bar Row', 'Espalda', '["Configure el equipo: Primero, configure la máquina de remo con barra en T con la cantidad adecuada de peso. Si no tienes acceso a una máquina de remo con barra en T, también puedes usar una barra y un accesorio para minas terrestres.", "Colóquese: doble las caderas, mantenga la espalda recta y estírese hacia abajo para agarrar las manijas de la barra en V con un agarre neutral (las palmas una frente a la otra).", "Levante el peso: levante el peso del suelo y déjelo colgar frente a su cuerpo. Esta es tu posición inicial.", "Involucre los músculos de la espalda: tire lentamente del peso hacia el pecho retrayendo los omóplatos y apretando los músculos de la espalda. Mantenga los codos cerca del cuerpo y los antebrazos paralelos al suelo.", "Mantenga la contracción: Mantenga la contracción durante uno o dos segundos, luego baje lentamente el peso a la posición inicial.", "Repetir: Complete el número deseado de repeticiones, luego descanse y repita para series adicionales."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000901602873', 'Sudadera con capucha Cable acostado', 'Lying Cable Pullover', 'Pecho', '["- Configure la máquina de cable: conecte una cuerda o una barra recta a la polea. Acuéstese boca arriba sobre un banco plano o en el suelo.", "- Agarre el mango con los brazos rectos: sostenga la barra o la cuerda por encima de la cabeza con una ligera flexión de los codos. Mantenga los pies apoyados en el banco o las rodillas dobladas sobre el suelo.", "- Tire del cable hacia abajo con los dorsales y los pectorales: baje el mango formando un arco hacia las caderas mientras mantiene los brazos extendidos.", "- Haga una pausa y contraiga en la parte inferior: apriete los dorsales y los músculos del pecho, manteniendo los hombros estables y bajos.", "- Regrese lentamente al inicio: controle el cable mientras tira de sus brazos hacia atrás, manteniendo la tensión en los músculos.", "### Consejos para una forma adecuada", "- Mantenga una ligera flexión de los codos para proteger las articulaciones.", "- Involucre su núcleo para estabilizar su columna durante el movimiento.", "- Evite utilizar el impulso; Realiza repeticiones lentas y controladas.", "- Mantenga los hombros deprimidos y las escápulas estables.", "- Elija un peso que permita un rango completo de movimiento sin compensaciones.", "### Errores comunes", "- Bloquear completamente los codos, lo que puede causar tensión y reducir la activación muscular.", "- Dejando que los hombros se encojan hacia arriba durante el ejercicio.", "- Balancear los brazos o usar el impulso en lugar del control muscular.", "- Arquear excesivamente la zona lumbar al tirar.", "- Moverse demasiado rápido durante la fase excéntrica, perdiendo tensión muscular."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001755538292', 'Estiramiento de muñeca', 'Wrist Stretch', 'Antebrazos', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001076938998', 'Estiramiento de pecho sentado', 'Seated Chest Stretch', 'Pecho', '["### Guía paso a paso", "- Comience en posición sentada: siéntese en el suelo con las piernas dobladas y los pies apoyados en el suelo. Coloque las manos detrás de la espalda, con los dedos hacia el cuerpo.", "- Siéntate en el suelo con las piernas dobladas y los pies apoyados en el suelo.", "- Coloque las manos detrás de la espalda, con los dedos hacia el cuerpo.", "- Realice el estiramiento: empuje el pecho hacia arriba y hacia adelante, abriendo los hombros y el pecho. Mantenga los brazos ligeramente doblados pero estables para evitar una presión excesiva en las muñecas.", "- Empuja tu pecho hacia arriba y hacia adelante, abriendo los hombros y el pecho.", "- Mantenga los brazos ligeramente doblados pero estables para evitar una presión excesiva en las muñecas.", "- Mantenga la posición: mantenga el estiramiento durante 10 a 20 segundos mientras respira profundamente. Sienta el estiramiento suave en el pecho y los hombros sin forzar.", "- Mantenga el estiramiento durante 10 a 20 segundos mientras respira profundamente.", "- Siente el suave estiramiento en tu pecho y hombros sin forzar.", "- Suelte lentamente: relájese y regrese a la posición inicial. Repita de 2 a 3 series, ajustando la intensidad según sea necesario.", "- Relax and return to the starting position.", "- Repita durante 2 a 3 series, ajustando la intensidad según sea necesario.", "### Consejos para una forma adecuada", "- Mantenga los hombros relajados y evite encogerse de hombros.", "- Mantenga una ligera flexión de los codos para reducir la tensión en las articulaciones.", "- Respire profundamente para mejorar la relajación y la eficacia del estiramiento.", "- Ajuste la colocación de las manos para encontrar la posición más cómoda.", "- Evite arquear excesivamente la zona lumbar para evitar molestias.", "### Errores comunes a evitar", "- Extender demasiado la zona lumbar, lo que provoca molestias o tensión.", "- Colocar las manos demasiado cerca reduce la efectividad del estiramiento.", "- Contener la respiración, lo que limita la relajación y la flexibilidad.", "- Forzar el estiramiento, lo que puede provocar tensión muscular o lesiones.", "- Descuidar la postura: asegúrese de que el pecho esté levantado y los hombros echados hacia atrás."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000173264424', 'Face Pull en polea alta', 'Face Pull', 'Hombros', '["Configuración: conecte un mango de cuerda a una máquina de cable o use bandas de resistencia al nivel del pecho o de los ojos.", "Agarre: Sujete las manijas con un agarre por encima de la cabeza, con las palmas hacia abajo.", "Posición: Párese erguido con los pies separados a la altura de los hombros, involucrando su núcleo.", "Ejecución: Tire de la cuerda hacia su cara, con los codos extendidos hacia afuera. Apriete los omóplatos en el punto máximo del movimiento. Regrese lentamente a la posición inicial.", "Tire de la cuerda hacia su cara, con los codos extendidos hacia afuera.", "Apriete los omóplatos en la cima del movimiento.", "Regrese lentamente a la posición inicial."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001952278667', 'Patada de tijera acostada', 'Lying Scissor Kick', 'Abdomen', '["La patada de tijera acostada se dirige a todos los músculos abdominales, especialmente a las regiones inferiores. movimientos. Trabaja los músculos centrales, los músculos de la cadera, los músculos isquiotibiales de las piernas y los aductores. Se le conoce como el mejor método para aumentar la flexibilidad mientras fortalece su núcleo."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-002013229003', 'Dominadas asistidas en máquina', 'Assisted Pull-up', 'Espalda', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001406789871', 'Back Lever (Calistenia)', 'Back Lever', 'Espalda', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001483740595', 'Jalón al pecho inverso', 'Reverse Lat-Pulldown', 'Espalda', '["Configuración: Ajuste el asiento en la máquina de dominadas para que sus muslos queden asegurados debajo de las almohadillas para las piernas. Sujete la barra con un agarre inverso, con las palmas hacia usted y las manos ligeramente más anchas que el ancho de los hombros.", "Ajuste el asiento en la máquina de dominadas para que sus muslos queden asegurados debajo de las almohadillas para las piernas.", "Sujete la barra con un agarre inverso, con las palmas hacia usted y un poco más anchas que el ancho de los hombros.", "Posición del cuerpo: Siéntese con la espalda recta y el pecho erguido. Mantenga los pies apoyados en el suelo. Sostenga la barra con un agarre firme.", "Siéntate con la espalda recta y el pecho erguido.", "Mantenga los pies apoyados en el suelo. Sostenga la barra con un agarre firme.", "Movimiento: Comience con los brazos completamente extendidos por encima de la cabeza. Tire de la barra hacia el pecho bajando los codos hacia abajo y hacia atrás. Concéntrese en apretar los omóplatos mientras baja la barra. Baje la barra de manera controlada hasta la posición inicial sin dejar que la pila de pesas se toque.", "Comience con los brazos completamente extendidos por encima de la cabeza.", "Tire de la barra hacia su pecho bajando los codos hacia abajo y hacia atrás.", "Concéntrate en juntar los omóplatos mientras bajas la barra.", "Baja la barra de forma controlada hasta la posición inicial sin dejar que la pila de pesas se toque.", "Respiración: Inhale mientras extiende los brazos por encima de la cabeza. Exhale mientras tira de la barra hacia abajo.", "Inhala mientras extiendes los brazos por encima de la cabeza.", "Exhala mientras bajas la barra."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001243928767', 'Columpios con pesas rusas', 'Kettlebell Swings', 'Hombros', '["El swing con pesas rusas es un movimiento dinámico; debe fluir continuamente sin detenerse en la parte superior o inferior.", "Párese con los pies entre 6 y 12 pulgadas fuera del ancho de los hombros a cada lado, cada pie apuntando hacia afuera unos 30 grados.", "Mantenga los hombros hacia atrás (retraídos) y hacia abajo para evitar arquear la espalda.", "El movimiento de descenso (backswing) es un movimiento para sentarse en una silla, no un movimiento para ponerse en cuclillas.", "Imagínese pellizcando una moneda entre sus nalgas cuando mueve sus caderas hacia adelante.", "En la parte superior del swing, la pesa rusa debe estar a la altura de los hombros y el cuerpo debe formar una línea recta desde la cabeza hasta los talones."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001438464803', 'Dominadas prónas', 'Pull-Up', 'Espalda', '["### ", "- Agarre una barra de dominadas con las manos separadas a la altura de los hombros y las palmas hacia afuera.", "- Cuélgate de la barra con los brazos completamente extendidos y las piernas estiradas o ligeramente flexionadas.", "- Involucre su núcleo y espalda, luego tire de su pecho hacia la barra.", "- Mueva los codos hacia abajo, apretando los omóplatos.", "- Haga una breve pausa en la parte superior, con la barbilla por encima de la barra.", "- Baja lentamente y con control hasta la posición inicial.", "### Consejos para una forma adecuada", "- Comience desde una posición muerta con extensión completa del brazo.", "- Enganche primero la escápula para iniciar el tirón con la espalda, no solo con los brazos.", "- Evite balancearse o dar saltos si hace repeticiones estrictas.", "- Mantenga el cuello neutral y los hombros hacia abajo.", "- Tire en un camino vertical recto, evitando que el pecho se ensanche.", "### Errores comunes", "- Medias repeticiones sin llegar a la extensión total ni al mentón por encima de la barra.", "- Usar impulso o dar saltos sin querer para engañar al movimiento.", "- Encogerse de hombros en lugar de retraer la escápula.", "- Dejar que las piernas se balanceen, lo que reduce el control.", "- Depender demasiado de los bíceps y descuidar la activación de los dorsales."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000568278415', 'Peso muerto', 'Deadlift', 'Piernas', '["Comience parándose con los pies separados a la altura de los hombros y con los dedos apuntando hacia adelante. La barra debe estar en el suelo frente a ti.", "Inclínese y agarre la barra con las manos ligeramente más separadas que el ancho de los hombros, usando un agarre por encima o mixto (una mano por encima y otra por debajo).", "Doble las rodillas y baje las caderas, manteniendo la espalda recta y el pecho erguido. Mantenga la cabeza y el cuello en una posición neutral y concéntrese en mirar hacia adelante.", "Respira profundamente y fortalece tus músculos centrales. Esto ayudará a estabilizar su columna y protegerá su espalda baja.", "Mantenga la barra cerca de su cuerpo mientras levanta y use las piernas, los glúteos y los músculos de la espalda para impulsar el levantamiento.", "Una vez que hayas levantado la barra hasta la posición de pie, haz una pausa por un momento, luego bájala nuevamente hasta el suelo, manteniendo la espalda recta y el core comprometido."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000864342917', 'Patadas de glúteos de glúteos con banda', 'Banded Glute Kickbacks', 'Espalda', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000826945071', 'Remo invertido (Dominadas australianas)', 'Inverted Row', 'Espalda', '["- Encuentre un entrenador de barra o suspensión Utilice una barra baja en una rejilla para sentadillas, una máquina Smith o correas de suspensión (por ejemplo, TRX). Asegúrese de que el equipo sea resistente.", "- Utilice una barra baja en una rejilla para sentadillas, una máquina Smith o correas de suspensión (por ejemplo, TRX). Asegúrese de que el equipo sea resistente.", "- Ajuste la altura Coloque la barra o las correas al nivel de la cintura o ligeramente más abajo. Cuanto más baja la barra, más difícil será el ejercicio.", "- Coloque la barra o las correas al nivel de la cintura o ligeramente más abajo. Cuanto más baja la barra, más difícil será el ejercicio.", "- Posición inicial Acuéstese debajo de la barra con el pecho alineado directamente debajo de ella. Agarre la barra con un agarre por encima o por debajo, con las manos separadas al ancho de los hombros. Extienda las piernas rectas con los talones en el suelo, manteniendo el cuerpo en línea recta desde la cabeza hasta los talones.", "- Acuéstese debajo de la barra con el pecho alineado directamente debajo de ella.", "- Agarre la barra con un agarre por encima o por debajo, con las manos separadas al ancho de los hombros.", "- Extiende las piernas rectas con los talones en el suelo, manteniendo el cuerpo en línea recta desde la cabeza hasta los talones.", "- Tire hacia arriba Involucra la espalda y el core, luego tira del pecho hacia la barra doblando los codos. Mantén los codos cerca del cuerpo y junta los omóplatos en la parte superior.", "- Involucre la espalda y el core, luego tire del pecho hacia la barra doblando los codos.", "- Mantenga los codos cerca del cuerpo y junte los omóplatos en la parte superior.", "- Lower DownExtiende lentamente los brazos para volver a la posición inicial, manteniendo el cuerpo recto.", "- Extiende lentamente los brazos para volver a la posición inicial, manteniendo el cuerpo recto.", "- Repetir Realice de 8 a 12 repeticiones durante 3 a 4 series, concentrándose en el movimiento controlado.", "- Realice de 8 a 12 repeticiones durante 3 a 4 series, concentrándose en el movimiento controlado.", "### Consejos para una forma adecuada", "- Involucre el núcleo: mantenga los abdominales contraídos para evitar que las caderas se caigan.", "- Columna Neutral: Mantenga una línea recta desde la cabeza hasta los talones durante todo el movimiento.", "- Movimiento controlado: evite sacudidas o utilizar el impulso; Concéntrese en repeticiones lentas y deliberadas.", "- Posición del codo: Mantenga los codos cerca del torso para evitar una tensión excesiva en los hombros.", "- Alineación de la barra: la barra debe tocar tu pecho o acercarse a él en la parte superior del movimiento.", "### Errores comunes", "- Caderas caídas: dejar caer las caderas reduce el compromiso del núcleo y compromete la forma.", "- Rango de movimiento incompleto: no acercar el pecho a la barra limita la activación muscular.", "- Codos ensanchados: Permitir que los codos se ensanchen puede tensar los hombros.", "- Arqueando la espalda baja. Mantenga una columna neutra involucrando el núcleo y los glúteos."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-002013229003', 'Dominadas asistidas en máquina', 'Assisted Pull-up', 'Espalda', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000901121118', 'Remo inclinado con barra', 'Incline Barbell Row', 'Espalda', '["El remo inclinado con barra, que se dirige a toda la cadena de la espalda, se dirige al dorsal ancho, el infraespinoso, el trapecio, los deltoides posteriores y los romboides, por lo que agregar ejercicios como el remo con barra y el remo con barra en T a sus programas de entrenamiento será beneficioso para el desarrollo de los músculos de la espalda."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000436691739', 'Encogimiento de hombros inclinado boca abajo', 'Prone Incline Shrug', 'Hombros', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001241310419', 'Dominadas con agarre inverso', 'Reverse grip Pull-up', 'Espalda', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000753600118', 'Peso muerto rumano', 'Romanian Deadlift', 'Piernas', '["Desarrollar fuerza y ​​​​masa muscular:"]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001063525317', 'Elevación de pantorrillas de pie con mancuernas', 'Standing Calf Raise With Dumbbell', 'Pantorrillas', '["- Posición inicial: Párese erguido con los pies separados a la altura de las caderas, sosteniendo una mancuerna en cada mano, los brazos relajados a los lados, manteniendo una postura y alineación adecuadas.", "- Alineación y estabilidad: Involucre los músculos centrales para lograr estabilidad, mantenga los hombros hacia atrás y mantenga una alineación neutra de la columna durante todo el movimiento.", "- Movimiento de elevación: levántese lentamente sobre las puntas de los pies levantando los talones lo más alto posible, contrayendo completamente los músculos de la pantorrilla.", "- Descenso controlado: baje gradualmente los talones hasta la posición inicial de forma controlada, asegurando una tensión muscular constante.", "- Repetir: realice las repeticiones deseadas, generalmente de 10 a 15 repeticiones por serie, enfatizando los movimientos lentos y controlados.", "### Consejos para una forma adecuada", "- Mantén los movimientos controlados, evitando impulsos o rebotes.", "- Mantenga una columna neutra y una postura erguida durante todo el ejercicio.", "- Manténgase brevemente en la posición superior para maximizar la participación de los músculos.", "- Seleccione el peso de mancuerna adecuado para garantizar la técnica adecuada y evitar lesiones.", "### Errores comunes", "- Uso de peso excesivo: seleccionar mancuernas demasiado pesadas puede comprometer la forma, reducir la activación de la pantorrilla y aumentar el riesgo de lesiones.", "- Rango de movimiento limitado: no levantar completamente los talones o bajarlos por completo disminuye la efectividad y el potencial de desarrollo muscular.", "- Movimientos rápidos y entrecortados: las repeticiones rápidas o los movimientos de rebote aumentan la tensión en los tendones y las articulaciones, lo que reduce la seguridad del ejercicio."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001174983688', 'Deslizamientos en pared para hombros', 'Wall Slides', 'Espalda', '["Párese con la espalda contra la pared, con los pies separados aproximadamente a la altura de las caderas.", "Coloque los brazos contra la pared con los codos doblados en un ángulo de 90 grados y las palmas hacia adelante.", "Desliza suavemente los brazos hacia arriba por la pared, manteniendo el contacto entre las manos, los codos y la pared.", "Mientras desliza los brazos hacia arriba, trate de mantener los omóplatos juntos y hacia abajo.", "Vaya tan lejos como pueda cómodamente sin dolor ni tensión excesiva.", "Haga una pausa por un momento en la parte superior, luego deslice lentamente los brazos hacia abajo hasta la posición inicial.", "Repita el movimiento durante el número deseado de repeticiones."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000331962086', 'Dominadas con lastre', 'Weighted Pull-up', 'Espalda', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000572955547', 'Remo en polea sentado', 'Seated Cable Row', 'Espalda', '["Coloque sus pies firmemente sobre el reposapiés o plataforma proporcionada por la máquina de cable.", "Mantenga la espalda recta y evite encorvarse o doblar los hombros hacia adelante. Involucre sus músculos centrales para ayudar a mantener una buena postura. Esto le ayudará a mantener la estabilidad y evitará que la zona lumbar se doble.", "Antes de comenzar el ejercicio, retrae los omóplatos y mantenlos en esta posición durante todo el movimiento. Esto ayudará a activar los músculos de la parte superior de la espalda y evitará una tensión excesiva en los hombros y el cuello.", "Mientras tiras de las manijas del cable hacia ti, mantén los codos extendidos hacia los lados y junta los omóplatos al final del movimiento. Esto ayudará a activar los músculos de la parte superior de la espalda y evitará una tensión excesiva en los hombros.", "Haga una pausa por un segundo en la parte superior del movimiento y luego suéltelo lentamente hasta la posición inicial. Exhala mientras tiras del cable hacia tu cuerpo e inhala mientras regresas a la posición inicial.", "Repita hasta el número deseado de repeticiones."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000539235411', 'Press de banca con agarre cerrado', 'Close Grip Bench Press', 'Pecho', '["Acuéstate en un banco plano con los pies apoyados en el suelo y la espalda en posición neutra.", "Agarre la barra con fuerza, con las manos separadas un poco menos que el ancho de los hombros.", "Retire la barra y bájela lentamente hacia su pecho mientras mantiene los codos pegados al cuerpo.", "Haga una pausa breve en la parte inferior del movimiento, luego presione la barra hacia arriba hasta la posición inicial, apretando los tríceps en la parte superior.", "Repita hasta obtener el número deseado de repeticiones."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000753600118', 'Peso muerto rumano', 'Romanian Deadlift', 'Piernas', '["Desarrollar fuerza y ​​​​masa muscular:"]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001729997841', 'Máquina de remo', 'Rowing Machine', 'Espalda', '["Posición inicial (The Catch): Siéntese en el asiento con los pies atados. Doble las rodillas, inclínese ligeramente hacia adelante a la altura de las caderas y sostenga el mango con un agarre por encima de la cabeza.", "Fase de impulso: Empuje explosivamente a través de las piernas, extienda las caderas, luego tire del mango hacia la parte superior del abdomen mientras mantiene los codos cerca del cuerpo.", "Posición final: Piernas completamente extendidas, torso ligeramente inclinado hacia atrás, mango tirado justo debajo del pecho.", "Fase de recuperación: primero extienda los brazos hacia adelante, luego gire las caderas y finalmente doble las rodillas para regresar a la captura.", "Mantenga un ritmo constante, coordinando suavemente las piernas, el tronco y los brazos."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001731071304', 'Protracción y retracción escapular', 'Scapular Protraction and Retraction', 'Hombros', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001608637409', 'Supermán (lumbares)', 'Superman', 'Hombros', '["Los ejercicios de Superman son un excelente ejercicio que fortalece el core, la espalda baja, los glúteos y los isquiotibiales.", "Este movimiento fortalece los músculos erectores de la columna que brindan soporte a la columna. Unos músculos fuertes de la espalda pueden prevenir desviaciones posturales que provocan malas posturas y molestias, como la cifosis (“jorobada”). El movimiento de Superman mejora tu postura al extender los músculos de la espalda y reducir la tensión entre la zona lumbar y la zona central. También mejora la fuerza de la espalda baja, lo que facilita mantenerse erguido durante todo el día.", "También es beneficioso para la salud de la espalda baja, ya que algunos dolores lumbares pueden deberse a glúteos débiles y tendones de la corva tensos."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001048768803', 'Remo con mancuernas', 'Dumbbell Row', 'Espalda', '["Coloque la rodilla izquierda y la mano izquierda sobre un banco, manteniendo la espalda plana y el torso paralelo al suelo.", "Sostenga una mancuerna en su mano derecha, con el brazo completamente extendido hacia el piso y la palma hacia adentro.", "Involucre su núcleo y levante la mancuerna, llevando su codo hacia su cadera.", "Haga una pausa en la parte superior, apretando el omóplato hacia la columna.", "Baja la mancuerna lentamente hasta la posición inicial bajo control.", "Complete las repeticiones y luego cambie de lado."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000905488719', 'Elevación lateral con toalla en la pared', 'Lateral Raise with Towel on Wall', 'Espalda', '["Posición inicial: Comience con el brazo que sostiene la toalla descansando cómodamente a su costado. Mantenga una postura natural con su núcleo comprometido.", "Levante con control: manteniendo una ligera flexión en el codo, inicie el movimiento levantando lentamente el brazo hacia un lado al nivel del hombro. Concéntrese en un movimiento controlado y deliberado.", "Compromiso del hombro: Concéntrese en usar los músculos deltoides laterales para levantar el brazo. Evite utilizar el impulso para mover el brazo hacia arriba.", "Posición Paralela: Continúa el movimiento hasta que tu brazo quede paralelo al suelo.", "Sostener y sentir: haga una pausa breve en la posición elevada, sintiendo la contracción en el músculo deltoides lateral. Mantén la estabilidad en todo tu cuerpo.", "Baje con control: baje gradualmente el brazo hasta la posición inicial a su lado. Mantenga la tensión de la toalla durante la fase de descenso.", "Repetición: complete el número deseado de repeticiones en un lado antes de cambiar al otro lado. Concéntrate en la calidad de cada repetición.", "Respiración: Respire naturalmente durante todo el ejercicio, exhalando mientras levanta el brazo e inhalando mientras lo baja."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000035826937', 'Aducciones de cadera en máquina', 'Hip Adduction Machine', 'Piernas', '["Ajusta la máquina: Antes de comenzar, ajusta la máquina a tu altura y selecciona el peso adecuado. Asegúrese de que las almohadillas estén colocadas cómodamente sobre sus piernas y que sus pies estén firmemente sobre los reposapiés.", "Siéntate en la máquina: Siéntate en el asiento con la espalda apoyada en el respaldo y los pies en los reposapiés.", "Coloque sus piernas: Coloque sus piernas de modo que sus rodillas estén dobladas en un ángulo de 90 grados y sus muslos estén ligeramente separados.", "Involucre la parte interna de los muslos: apriete la parte interna de los muslos y empuje las piernas contra la resistencia. Exhala mientras juntas las piernas.", "Liberación: Libere lentamente la resistencia y permita que sus piernas regresen a la posición inicial. Inhala mientras liberas.", "Repetir: Complete el número deseado de repeticiones y series, y ajuste el peso según sea necesario."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001380553741', 'Fondos imposibles (Impossible Dips)', 'Impossible Dips', 'Otros', '["### Paso 1: Configuración y posición inicial", "- Colóquese entre dos barras paralelas a una distancia cómoda al ancho de los hombros.", "- Agarre las barras con firmeza y empújese hacia arriba hasta la posición de inmersión superior.", "- Mantenga las piernas extendidas y rectas y mantenga una posición del cuerpo hueca (involucre su núcleo para evitar la flacidez).", "### Paso 2: Ejecución", "- Baja el cuerpo lentamente y de forma controlada, manteniendo el torso recto y ligeramente inclinado hacia adelante.", "- Mantenga la tensión de todo el cuerpo, asegurándose de que las caderas y las piernas no caigan.", "- Desciende hasta que la parte superior de tus brazos quede paralela a las barras o ligeramente más abajo.", "- Empuje hacia arriba usando los tríceps, los hombros y el core mientras mantiene el cuerpo rígido.", "- Complete de 3 a 5 series de 3 a 8 repeticiones, dependiendo de su nivel de fuerza.", "### Consejos para una forma adecuada", "- Mantén las piernas estiradas y juntas durante todo el movimiento.", "- Involucre su núcleo para evitar que se hunda o pierda el equilibrio.", "- Bájate lentamente, concentrándote en el control más que en la velocidad.", "- Inclínese ligeramente hacia adelante para optimizar la activación muscular en los tríceps y los hombros.", "- Agarre las barras con fuerza para mantener el control y evitar resbalones.", "### Errores comunes a evitar", "- Dejar caer las caderas, lo que reduce el compromiso del core y rompe la forma.", "- Doblar las rodillas, haciendo el movimiento más fácil pero menos efectivo.", "- Utilizar el impulso en lugar de un control estricto, disminuyendo la dificultad del ejercicio.", "- Apresurarse en las repeticiones, lo que puede provocar una mala forma y una reducción de la ganancia de fuerza.", "- No involucrar el core, provocando inestabilidad y dificultando el movimiento."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000344137077', 'Sentadilla hack con barra', 'Barbell Hack Squat', 'Piernas', '["- Coloque una barra detrás de las piernas en el suelo, con los pies separados a la altura de las caderas y los dedos apuntando ligeramente hacia afuera.", "- Póngase en cuclillas con el pecho alto y la columna neutra, agarrando la barra con ambas manos a la altura de los hombros.", "- Involucra tu core y conduce a través de tus talones para levantar la barra en línea recta hacia arriba detrás de tu cuerpo.", "- Extienda completamente las caderas y las rodillas en la parte superior mientras mantiene la barra cerca de la parte posterior de las piernas.", "- Baje la barra bajo control, manteniendo una postura adecuada y repitiendo las repeticiones.", "### Consejos para una forma adecuada", "- Mantenga el torso erguido durante todo el levantamiento para enfatizar los cuádriceps y reducir la tensión en la espalda.", "- Conduce con los talones para activar los glúteos y mantener el equilibrio.", "- Utilice un tempo controlado tanto en el ascenso como en el descenso.", "- Mantenga la barra cerca de su cuerpo para evitar alejar la carga de su centro de masa.", "- Calienta las rodillas y los tobillos para prepararte para la flexión profunda de la rodilla involucrada.", "### Errores comunes", "- Redondear la zona lumbar, lo que aumenta el riesgo de lesiones.", "- Dejar que la barra se aleje de tus piernas, provocando problemas de equilibrio y forma.", "- Usar demasiado peso demasiado pronto, compromete la técnica.", "- Empujar a través de los dedos de los pies, lo que reduce la estabilidad y la activación de los glúteos.", "- No calentar ni movilizar los tobillos, limitando la profundidad y el rango de movimiento."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001867486336', 'Abducción de cadera de pie', 'Standing Hip Abduction', 'Piernas', '["El foco de este ejercicio está en el glúteo medio y el glúteo menor que se encuentra debajo. Si el objetivo es fortalecer y dar forma a la cadera (glúteos superiores y externos), entonces la abducción de cadera es una excelente opción."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000267252431', 'Salto en sentadilla', 'Squat Tuck Jump', 'Piernas', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000759563916', 'Elevaciones de rodillas colgado', 'Hanging Knee Raises', 'Piernas', '["Su propio peso corporal actúa como resistencia que ayuda a aumentar su resistencia y desarrollar su resistencia. Este ejercicio que trabaja los flexores de la cadera mejora los músculos centrales, especialmente los músculos abdominales inferiores. Es uno de los mejores ejercicios para abdominales que activa todo el core ejercitando no sólo los abdominales inferiores sino también los músculos abdominales superiores."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000411945728', 'Sentadilla con barra', 'Barbell Squat', 'Piernas', '["Coloque la barra en una rejilla para sentadillas justo debajo de la altura de los hombros. Pase debajo y apoye la barra sobre los trapecios superiores o los deltoides posteriores.", "Agarre la barra con firmeza, tire de los codos hacia abajo y hacia abajo y levante la barra del soporte.", "Da un paso atrás, separa los pies a la altura de los hombros y refuerza el core.", "Baje el cuerpo empujando las caderas hacia atrás y doblando las rodillas, manteniendo el pecho erguido.", "Desciende hasta que tus muslos queden paralelos al suelo o más abajo si la movilidad lo permite.", "Conduce con los talones para volver a la posición de pie, manteniendo la columna neutra."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000638512730', 'Curl en polea acostado', 'Lying Cable Curl', 'Otros', '["Recuéstese en un banco plano, con los pies apoyados en el suelo y la cabeza y los hombros apoyados en el banco.", "Agarre el cable de la polea baja con un agarre desde abajo, manteniendo las manos separadas al ancho de los hombros.", "Extiende completamente los brazos, de modo que el cable tire del bíceps.", "Flexione lentamente los codos y doble el accesorio del cable hacia los hombros, mientras contrae los bíceps.", "Mantenga las muñecas rectas y los codos cerca de los costados durante todo el movimiento.", "Cuando llegues a la parte superior del curl, concéntrate en apretar los bíceps y mantener la contracción por un momento.", "Baje lentamente el cable hasta la posición inicial, manteniendo la tensión en los bíceps durante todo el movimiento.", "Repita para el número deseado de repeticiones."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001053059234', 'Sentadilla patinadora', 'Skater Squat', 'Piernas', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001037536097', 'Saltos laterales astride', 'Astride Jumps', 'Cardio', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001493928124', 'Sentadilla con peso corporal', 'Bodyweight Squat', 'Piernas', '["Párese con los pies separados a la altura de los hombros y los dedos ligeramente apuntando hacia afuera.", "Apoye su núcleo y mantenga su pecho elevado mientras comienza el movimiento.", "Empuje las caderas hacia atrás y doble las rodillas para ponerse en cuclillas.", "Desciende hasta que tus muslos queden paralelos al suelo o tan bajos como te resulte cómodo.", "Conduce con los talones para volver a levantarte, apretando los glúteos en la parte superior."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000411945728', 'Sentadilla con barra', 'Barbell Squat', 'Piernas', '["### ", "- Coloque la barra en una rejilla para sentadillas justo debajo de la altura de los hombros. Pase debajo y apoye la barra sobre los trapecios superiores o los deltoides posteriores.", "- Agarre la barra con firmeza, tire de los codos hacia abajo y hacia abajo y levante la barra del soporte.", "- Da un paso atrás, separa los pies a la altura de los hombros y refuerza el core.", "- Baje el cuerpo empujando las caderas hacia atrás y doblando las rodillas, manteniendo el pecho erguido.", "- Desciende hasta que tus muslos queden paralelos al suelo o más abajo si la movilidad lo permite.", "- Conduce con los talones para volver a la posición de pie, manteniendo la columna neutra.", "### Consejos para una forma adecuada", "- Apoye su núcleo antes de cada repetición para proteger su espalda baja.", "- Mantenga el pecho erguido y evite inclinarse demasiado hacia adelante.", "- Empuje las rodillas alineadas con los dedos de los pies durante el descenso.", "- Agarre la barra con fuerza para enganchar la parte superior de la espalda y los dorsales.", "- Mantenga la espalda plana y evite arquear la columna.", "### Errores comunes", "- Dejar que las rodillas colapsen hacia adentro, lo que tensiona las articulaciones.", "- Ponerse en cuclillas demasiado superficialmente, lo que reduce el rango de movimiento y la efectividad.", "- Levantar los talones del suelo, lo que reduce la estabilidad.", "- Inclinación excesiva hacia adelante, lo que aumenta el riesgo de tensión en la espalda.", "- Posición inadecuada de la barra, que provoca malestar o inestabilidad."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001867486336', 'Abducción de cadera de pie', 'Standing Hip Abduction', 'Piernas', '["El foco de este ejercicio está en el glúteo medio y el glúteo menor que se encuentra debajo. Si el objetivo es fortalecer y dar forma a la cadera (glúteos superiores y externos), entonces la abducción de cadera es una excelente opción."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001622357626', 'Elevación frontal sentado con mancuernas', 'Seated Dumbbell Front Raise', 'Hombros', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-002101878272', 'Postura de yoga del tigre', 'Tiger Yoga Pose', 'Piernas', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000360567761', 'Sentadilla búlgara (Split) con barra', 'Barbell Bulgarian Split Squat', 'Piernas', '["### Paso 1: configuración y posicionamiento", "- Coloque un banco detrás de usted aproximadamente a la altura de las rodillas.", "- Cargue una barra en la parte superior de la espalda en una posición de barra baja o alta.", "- Párese aproximadamente a dos pies frente al banco con los pies separados a la altura de las caderas.", "- Coloque la parte superior de su pie trasero en el banco y active su núcleo.", "### Paso 2: Ejecución", "- Bájese doblando la rodilla delantera y manteniendo el pecho erguido.", "- Desciende hasta que tu muslo delantero quede paralelo al suelo o ligeramente por debajo.", "- Presione a través del talón delantero para regresar a la posición inicial.", "- Repita para las repeticiones deseadas, luego cambie de pierna."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000166432267', 'Estiramiento de toque de puntas de pie', 'Standing Toe Touch', 'Abdomen', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-002080290959', 'Prensa de piernas', 'Leg Press', 'Piernas', '["Ajuste la posición del asiento: Siéntese en el asiento con la espalda contra el respaldo y los pies apoyados sobre la plataforma. Tus rodillas deben estar dobladas en un ángulo de 90 grados.", "Ajuste el peso: agregue placas de peso a la máquina según el nivel de intensidad deseado. Comienza con un peso que puedas manejar cómodamente y auméntalo gradualmente a medida que avances.", "Colocación de los pies: Coloque los pies separados a la altura de las caderas en la plataforma, con los dedos apuntando hacia adelante o ligeramente hacia afuera. Asegúrese de que sus pies estén colocados firme y seguramente en la plataforma.", "Preparación: Agarre las manijas o soportes laterales de la máquina para mayor estabilidad. Respira profundamente y fortalece tus músculos centrales.", "Ejecución: Empuja contra la plataforma con los pies y extiende las piernas alejando la plataforma de tu cuerpo. Mantenga la espalda contra el asiento durante todo el movimiento y evite bloquear las rodillas en la parte superior del movimiento.", "Bajar el peso: Doble lentamente las rodillas y baje el peso hacia abajo, permitiendo que las rodillas alcancen un ángulo de 90 grados o un poco más sin dejar que el peso toque el suelo por completo.", "Repetir: Completa el número deseado de repeticiones, manteniendo el control y la forma adecuada durante todo el ejercicio."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001949036955', 'Sentadillas con salto', 'Jump Squats', 'Piernas', '["Párese erguido con los pies separados a la altura de los hombros y los brazos a los costados.", "Baje hasta ponerse en cuclillas doblando las rodillas y las caderas hasta que los muslos queden paralelos al suelo.", "Explota hacia arriba, saltando lo más alto que puedas mientras mueves los brazos para ganar impulso.", "Aterriza suavemente doblando las rodillas y absorbiendo el impacto a través de las piernas.", "Reinicie inmediatamente en su siguiente sentadilla y repita para las repeticiones deseadas."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001449510573', 'Sentadilla con mancuernas', 'Dumbbell Squat', 'Piernas', '["### ", "- Configuración: Párese con los pies separados a la altura de los hombros. Puede sostener una mancuerna en cada mano a los costados o usar una sola mancuerna sostenida con ambas manos frente a su pecho (estilo sentadilla en copa).", "- Postura: Mantenga el pecho erguido y los hombros hacia atrás. Mantenga un arco natural en la parte baja de la espalda y active los músculos centrales para lograr estabilidad.", "- Descenso: Comienza el movimiento empujando las caderas hacia atrás, como si estuvieras sentado en una silla. Mantenga las rodillas alineadas con los dedos de los pies y permita que se doblen mientras baja. Es importante mantener la columna neutra durante todo el movimiento.", "- Profundidad: baje el cuerpo hasta que los muslos queden al menos paralelos al suelo, o profundice si puede sin comprometer la forma. Lo ideal es que tus muslos estén paralelos al suelo o por debajo del paralelo para lograr un rango completo de movimiento.", "- Ascenso: empuja los talones y mueve las caderas hacia adelante para volver a levantarte. Mantenga la espalda recta mientras se levanta. Exhala mientras regresas a la posición inicial.", "- Repetición: repita la sentadilla durante el número deseado de repeticiones.", "### Consejos para una forma adecuada", "- Mantén los talones en el suelo y evita que se levanten.", "- Mueva las rodillas alineadas con los dedos de los pies mientras desciende.", "- Mantenga el pecho erguido y los hombros retraídos.", "- Sujete las mancuernas de forma segura y evite el balanceo excesivo.", "- Controle el tempo para maximizar el compromiso muscular.", "### Errores comunes", "- Permitir que las rodillas se doblen hacia adentro, lo que reduce la seguridad de las articulaciones.", "- Inclinarse demasiado hacia adelante, alejando la tensión de las piernas.", "- Usar el impulso para levantar en lugar de la fuerza controlada.", "- No agacharse lo suficientemente profundo, lo que limita la efectividad.", "- Redondear la espalda, lo que aumenta el riesgo de lesiones."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000732891509', 'Peso muerto de sumo', 'Sumo Deadlift', 'Piernas', '["El peso muerto de sumo se enfoca en muchos de los mismos músculos que desarrolla un peso muerto convencional, pero enfatiza más los músculos de la espalda, los isquiotibiales y la cadera. Es el movimiento más popular de fuerza y ​​entrenamiento de fuerza ya que trabaja muchos grupos de músculos.", "Aumenta la testosterona: Se ha demostrado mediante investigaciones que los ejercicios con pesas ayudan a aumentar los niveles de testosterona a corto y largo plazo. Ejercicios como press de banca, sentadillas y peso muerto son los ejercicios más efectivos que aumentan los niveles de testosterona.", "Fortalece la capacidad de agarre. Le permite agarrar un objeto con más firmeza cuando lo sostiene. Además, los estudios demuestran que el peso muerto es un ejercicio eficaz para mejorar la fuerza explosiva y el rendimiento del salto vertical.", "Sumo Deadlift ayuda al desarrollo de los músculos de las piernas, los músculos de la cadera y los músculos centrales, al mismo tiempo que apoya la formación de músculos y fuerza en el cuerpo. Además, agregar peso muerto a tus entrenamientos ayuda a fortalecer tus tendones, ligamentos y huesos.", "El peso muerto de sumo también activa los glúteos y los músculos de la espalda. Los ejercicios funcionales como el peso muerto son aquellos que facilitan las actividades del cuerpo en la vida real.", "Sumo Deadlift se enfoca en todos los músculos responsables de su postura y le permite mantener la espalda recta durante las actividades diarias habituales.", "La forma correcta es muy importante en este ejercicio. Para empezar, hacer mal puede provocar lesiones. Tras algunos intentos con la barra vacía o acompañado de un entrenador, el proceso de adaptación al movimiento puede verse acortado."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000059349919', 'Sentadilla pistola (Pistol Squat)', 'Pistol Squat', 'Piernas', '["El ejercicio de sentadilla con pistola requiere un alto nivel de equilibrio, coordinación, estabilidad básica y fuerza en las piernas. Este movimiento es uno de los ejercicios más difíciles, incluso para deportistas avanzados.", "Los beneficios de la sentadilla con pistola son notables en muchos sentidos. La finalidad de este ejercicio con peso corporal es mejorar el equilibrio, la fuerza y ​​la coordinación. La sentadilla con pistola aumenta la movilidad y la flexibilidad de la articulación del tobillo. Es un gran ejercicio para fortalecer los músculos estabilizadores y aumentar la resistencia de la pierna.", "Los ejercicios con peso corporal son muy eficaces para desarrollar músculos y fuerza, además de mejorar la coordinación y la aptitud funcional. Gracias a la sentadilla Pistol, puedes desarrollar la fuerza y ​​los músculos de una sola pierna por igual y así beneficiar tu estructura atlética general."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000060284583', 'Dragon Flag (Abdominales de Dragón)', 'Dragon Flag', 'Abdomen', '["Configuración: Acuéstese boca arriba sobre un banco resistente o una superficie plana. Asegúrese de que su cabeza esté apoyada, ya sea agarrándose del banco o usando un cojín para el cuello. Coloque sus manos firmemente sobre el banco o agárrese de una superficie estable sobre su cabeza.", "Elevación de piernas: levante las piernas y las caderas del banco o del suelo, manteniéndolas rectas. Tu cuerpo debe formar una línea recta desde tu cabeza hasta tus pies. Involucre sus músculos centrales para estabilizar su cuerpo.", "Descenso controlado: baja lentamente las piernas y las caderas hacia el banco manteniendo una línea recta del cuerpo. Concéntrate en usar tus músculos abdominales para controlar el movimiento. Esta es la parte más desafiante del ejercicio, así que tómate tu tiempo.", "Levanta la bandera: una vez que tus piernas estén cerca del banco o del suelo (pero sin tocarse), invierte el movimiento usando tu fuerza central para levantar las piernas y las caderas hasta la posición inicial.", "Repetir: realice el ejercicio con el número deseado de repeticiones."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000111266387', 'Sentadilla mariquita', 'Sissy Squat', 'Piernas', '["Párese erguido con los pies separados a la altura de las caderas y los talones ligeramente elevados o apoyados.", "Apoye su núcleo y mantenga un pecho alto mientras comienza a inclinarse hacia atrás desde las rodillas.", "Permita que las rodillas avancen sobre los dedos de los pies mientras la parte superior del cuerpo se inclina hacia atrás en línea recta.", "Baja hasta sentir un estiramiento profundo en los cuádriceps o alcanzar tu límite de movilidad.", "Conduce a través de los dedos de los pies para volver a la posición inicial, manteniendo el cuerpo alineado."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000058889457', 'Salto de profundidad a salto de valla (Pliometría)', 'Depth Jump to Hurdle Hop', 'Piernas', '["Coloca los obstáculos: organiza una serie de obstáculos a diferentes alturas en línea recta, dejando suficiente espacio entre ellos para poder aterrizar y saltar entre cada uno de ellos.", "Salto de profundidad: Párese encima de la caja o plataforma pliométrica con los pies separados a la altura de las caderas. Comience bajando de la caja y dejándose caer rápidamente al suelo, permitiendo que sus rodillas se doblen ligeramente para absorber el impacto. Tan pronto como sus pies entren en contacto con el suelo, inmediatamente salte explosivamente, usando sus brazos para generar impulso. El salto de profundidad está diseñado para ser un salto rápido y poderoso, así que asegúrese de no pasar mucho tiempo en el suelo.", "Párese encima de la caja o plataforma pliométrica con los pies separados a la altura de las caderas.", "Comience bajando de la caja y dejándose caer rápidamente al suelo, permitiendo que las rodillas se doblen ligeramente para absorber el impacto.", "Tan pronto como tus pies entren en contacto con el suelo, salta inmediatamente de manera explosiva, usando tus brazos para ganar impulso.", "El salto de profundidad está pensado para ser un salto rápido y potente, así que asegúrate de no pasar mucho tiempo en el suelo.", "Salto de vallas: después del salto de profundidad, haga la transición inmediatamente al salto de vallas. A medida que asciende desde el salto de profundidad, intente superar el primer obstáculo levantando las rodillas en alto. Aterrice en el otro lado de la valla y prepárese rápidamente para el siguiente salto.", "Después del salto de profundidad, haga la transición inmediatamente al salto de vallas.", "A medida que asciendes desde el salto de profundidad, intenta superar el primer obstáculo levantando las rodillas en alto.", "Aterriza al otro lado del obstáculo y prepárate rápidamente para el siguiente salto.", "Repetir: continúe realizando la secuencia de salto de profundidad a salto de vallas durante el número deseado de repeticiones o durante un período de tiempo establecido."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001360616048', 'Elevación lateral a frontal con mancuernas', 'Dumbbell Lateral to Front Raise', 'Espalda', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000775693706', 'Dominadas en Front Lever', 'Front Lever Pull-up', 'Espalda', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000152008292', 'Plancha alta sobre manos', 'High Plank', 'Abdomen', '["- Comience en posición de flexión de brazos, con las manos directamente debajo de los hombros y las piernas extendidas detrás de usted.", "- Involucre su núcleo, apriete sus glúteos y mantenga su cuerpo en línea recta desde la cabeza hasta los talones.", "- Presione firmemente con las manos, manteniendo los hombros activos y estables.", "- Mantenga la posición mientras respira de manera constante, evitando hundirse o arquearse.", "- Comience con 20 a 30 segundos y aumente gradualmente el tiempo a medida que mejora la fuerza.", "### Consejos para una forma adecuada", "- Mantenga la cabeza neutral, sin dejar caer ni estirar el cuello.", "- Apriete los glúteos para proteger la zona lumbar.", "- Involucre los cuádriceps para mantener una línea de cuerpo rígida.", "- Distribuya la presión uniformemente entre los dedos de las manos y los pies.", "- Mantenga una respiración constante sin contener la respiración.", "### Errores comunes", "- Dejar que las caderas se caigan, lo que genera tensión en la parte baja de la espalda.", "- Levantar demasiado las caderas reduce el compromiso del core.", "- Encogimiento de hombros, provocando tensión en el cuello.", "- Bloquear completamente los codos, reduciendo la estabilidad de los hombros.", "- No involucrar al núcleo, lo que lleva a una mala alineación y efectividad."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000100936177', 'Lanzamiento de giros rusos con balón medicinal y compañero', 'Ball Russian Twist throw with partner', 'Espalda', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000997235231', 'Postura del cangrejo', 'Crab Pose', 'Otros', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001386997510', 'Flexiones con rotación', 'Push-up With Rotation', 'Pecho', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001837892935', 'Flexiones hindúes', 'Hindu Push-ups', 'Pecho', '["Posición inicial: comience en una posición de perro boca abajo. Esto es similar a una postura de yoga. Comience con las manos y las rodillas, luego levante las caderas y estire las piernas para formar una V invertida con su cuerpo. Tus manos deben estar separadas al ancho de los hombros y tus pies deben estar separados al ancho de las caderas.", "Descenso (fase de bombardero en picado): desplaza tu peso hacia adelante, bajando la parte superior del cuerpo hacia el suelo mientras mantienes los brazos rectos. Continúa avanzando hasta que tu pecho casi toque el suelo. Tus caderas estarán bajas y tu espalda arqueada, asemejándote a una postura de yoga de perro mirando hacia arriba. A medida que desciendes, asegúrate de mirar hacia arriba y hacia adelante, permitiendo que tu cabeza suba y tu espalda se arquee profundamente.", "Mueva su peso hacia adelante, bajando la parte superior del cuerpo hacia el suelo mientras mantiene los brazos rectos.", "Continúe avanzando hasta que su pecho casi toque el suelo. Tus caderas estarán bajas y tu espalda arqueada, asemejándote a una postura de yoga de perro mirando hacia arriba.", "A medida que desciendes, asegúrate de mirar hacia arriba y hacia adelante, permitiendo que tu cabeza suba y tu espalda se arquee profundamente.", "Ascenso: Desde la posición del perro boca abajo, empuja las caderas hacia atrás y hacia arriba, moviéndolas hacia el techo. Su cabeza debe mirar hacia atrás entre sus piernas. A medida que sus caderas se elevan, doble los codos y baje el pecho hasta la posición inicial. Continúe este movimiento hasta que regrese a la posición del perro hacia abajo.", "Desde la posición del perro boca abajo, empuja las caderas hacia atrás y hacia arriba, moviéndolas hacia el techo. Tu cabeza debe mirar hacia atrás entre tus piernas.", "A medida que las caderas se elevan, doble los codos y baje el pecho hasta la posición inicial.", "Continúe este movimiento hasta que regrese a la posición del perro boca abajo.", "Repetir: repita la secuencia durante el número deseado de repeticiones, manteniendo un flujo suave y controlado entre las diferentes posiciones."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
