INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001853631373', 'Postura de rana', 'Frog Pose', 'Piernas', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-002006100706', 'Flexores inclinados con mancuernas', 'Flexor Incline Dumbbell Curls', 'Otros', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001444810286', 'Flexiones', 'Push-Up', 'Pecho', '["### ", "- Posición inicial: Comience en una posición de tabla alta con las manos ligeramente más separadas que el ancho de los hombros. Mantenga el cuerpo en línea recta desde la cabeza hasta los talones. Involucre su núcleo y mantenga el cuello neutral.", "- Comience en una posición de tabla alta con las manos ligeramente más separadas que el ancho de los hombros.", "- Mantenga su cuerpo en línea recta desde la cabeza hasta los talones.", "- Involucre su núcleo y mantenga su cuello neutral.", "- Fase de descenso: Inhale mientras dobla los codos y baja el pecho hacia el suelo. Mantenga los codos en un ángulo de 45 grados con respecto al torso. Baje hasta que el pecho esté justo por encima del suelo o hasta donde la movilidad lo permita.", "- Inhala mientras doblas los codos y bajas el pecho hacia el suelo.", "- Mantenga los codos en un ángulo de 45 grados con respecto al torso.", "- Baje hasta que su pecho esté justo por encima del suelo o hasta donde la movilidad lo permita.", "- Fase de presión: exhale mientras empuja con las palmas de las manos para volver a la posición inicial. Extienda completamente los brazos mientras mantiene el compromiso central.", "- Exhala mientras empujas con las palmas de las manos para volver a la posición inicial.", "- Extienda completamente los brazos mientras mantiene el compromiso central.", "- Repetición y respiración: realice repeticiones controladas a un ritmo constante para maximizar la participación de los músculos.", "- Realice repeticiones controladas a un ritmo constante para maximizar la participación muscular.", "### Consejos para una forma adecuada:", "- Mantenga su núcleo apretado para evitar que la zona lumbar se hunda.", "- Mantenga una línea corporal recta desde la cabeza hasta los talones.", "- Evite bloquear los codos en la parte superior del movimiento.", "- Coloque sus manos firmemente en el suelo para una mejor estabilidad.", "### Errores comunes:", "- Permitir que las caderas se hunda: esto reduce el compromiso del core y puede tensar la espalda baja.", "- Ensanchar los codos: Mantener los codos demasiado anchos genera tensión en los hombros.", "- Rango de movimiento incompleto: realizar medias repeticiones limita la activación muscular y el aumento de fuerza.", "- Contener la respiración: Respirar adecuadamente garantiza el flujo de oxígeno y una mejor resistencia."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001359311556', 'Declinado flexiones', 'Decline Push-up', 'Pecho', '["### ", "### Guía paso a paso", "- Establezca su posición: Coloque los pies sobre una superficie elevada (banco, escalón o plataforma resistente). Coloque las manos en el suelo separadas al ancho de los hombros. Mantenga el cuerpo en línea recta desde la cabeza hasta los talones.", "- Coloque los pies sobre una superficie elevada (banco, escalón o plataforma resistente).", "- Coloque las manos en el suelo separadas a la altura de los hombros.", "- Mantenga su cuerpo en línea recta desde la cabeza hasta los talones.", "- Baje el cuerpo: active su núcleo y baje lentamente el pecho hacia el suelo. Mantenga los codos en un ángulo de 45 grados con respecto al cuerpo. Mantenga un movimiento controlado sin dejar que las caderas se doblen o se levanten.", "- Involucre su núcleo y baje lentamente su pecho hacia el piso.", "- Mantenga los codos en un ángulo de 45 grados con respecto a su cuerpo.", "- Mantenga un movimiento controlado sin dejar que las caderas se doblen o se levanten.", "- Empuje hacia arriba: presione con las palmas y empújese hacia atrás a la posición inicial. Mantenga el núcleo y los glúteos comprometidos para lograr estabilidad. Extienda completamente los brazos en la parte superior sin bloquear los codos.", "- Presione con las palmas y empújese hacia atrás a la posición inicial.", "- Mantenga el núcleo y los glúteos comprometidos para lograr estabilidad.", "- Extiende completamente los brazos en la parte superior sin bloquear los codos.", "- Repeticiones y series: intente realizar de 3 a 4 series de 10 a 15 repeticiones, ajustando la dificultad según el nivel de condición física.", "- Intente realizar de 3 a 4 series de 10 a 15 repeticiones, ajustando la dificultad según el nivel de condición física.", "### Consejos para una forma adecuada", "- Mantenga su núcleo comprometido para mantener una columna neutral.", "- No dejes que la parte baja de tu espalda se hunda, ya que esto puede causar tensión.", "- Controla la fase de descenso y flexiones para maximizar la activación muscular.", "- Respire adecuadamente: inhale mientras baja, exhale mientras empuja hacia arriba.", "- Elija una altura de descenso adecuada: una elevación más alta aumenta la dificultad.", "### Errores comunes a evitar", "- Dejar que las caderas se doblen o se eleven, lo que reduce la eficacia y tensa la zona lumbar.", "- Colocar las manos demasiado hacia adelante, lo que genera una tensión innecesaria en los hombros.", "- Acelerar el movimiento, reduciendo el tiempo bajo tensión y compromiso muscular.", "- Falta de rango completo de movimiento, lo que impide la activación óptima del pecho.", "- Arquear la zona lumbar, provocando una forma inadecuada y posibles lesiones."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001904636157', 'Elevaciones de piernas y brazos', 'Arm Leg Raises', 'Abdomen', '["Es un ejercicio diseñado para trabajar las caderas, la espalda, los hombros y los músculos centrales y fortalecer la estabilidad general.", "Las elevaciones de brazos y piernas también son un ejercicio que requiere concentración mental, obliga a que los movimientos se realicen en armonía y ayuda a mejorar el equilibrio y la coordinación.", "Este ejercicio, que también se aplica como ejercicio de calentamiento, puede trabajar incluso las fibras musculares más pequeñas desde diferentes ángulos para fortalecer los músculos centrales. También es una forma segura y eficaz de fortalecer y equilibrar los músculos de la columna, la espalda y el cuello. Una estructura sólida de la columna y músculos fuertes de la espalda pueden ayudar a mejorar la postura y aliviar y prevenir el dolor de espalda."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001051605847', 'Elevaciones de piernas colgantes', 'Hanging Leg Raises', 'Abdomen', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-002042230226', 'Dominadas con agarre neutro', 'Neutral Grip Pull-up', 'Espalda', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-002064605840', 'Zancada lateral con barra', 'Barbell Lateral Lunge', 'Espalda', '["Las estocadas laterales con barra desarrollan el equilibrio, la estabilidad y la fuerza. Trabajan la parte interna y externa de los muslos e incluso pueden ayudar a reducir la apariencia de la celulitis."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001664524012', 'Puente de glúteos con bandas', 'Banded Glute Bridge', 'Piernas', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000687279576', 'Puente de glúteos', 'Glute Bridge', 'Piernas', '["El grupo de músculos objetivo del ejercicio del puente de glúteos son los músculos de la cadera. Puedes incluirlo en tu programa de ejercicios para tensar y tonificar los músculos de la cadera, así como mejorar la movilidad de la cadera y fortalecer tu cintura.", "Fortalece los músculos centrales: el ejercicio del puente activa todos los músculos centrales, incluidos el transverso del abdomen, el recto abdominal y los oblicuos. El puente de glúteos te ayudará a estabilizar el centro del cuerpo, los isquiotibiales, la espalda, el vientre y también los glúteos. Aunque el ejercicio se dirige al área de los glúteos, el puente de glúteos hace un gran trabajo al activar y fortalecer los músculos estabilizadores centrales.", "Los ejercicios de puente generalmente son seguros para personas con problemas crónicos de espalda y pueden ayudar a controlar el dolor."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001664524012', 'Puente de glúteos con bandas', 'Banded Glute Bridge', 'Piernas', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001185029592', 'Remo vertical en polea', 'Cable Upright Row', 'Espalda', '["El remo vertical con cable es un ejercicio de aislamiento dirigido al trapecio y los deltoides, que son responsables de agregar ancho a los hombros.", "El remo vertical con cable es uno de los ejercicios efectivos para construir trampas más grandes, pero también es un movimiento en el que es fácil cometer errores. Una de las formas más sencillas de asegurarse de que su forma sea óptima es evitar el uso de mancuernas que sean demasiado pesadas."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001992040558', 'Arrebato de poder', 'Power Snatch', 'Otros', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001299576767', 'Giro con barra sentado', 'Seated Barbell Twist', 'Abdomen', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001500713108', 'Curl de muñeca con mancuernas', 'Dumbbell Wrist Curl', 'Antebrazos', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001059697630', 'Estiramiento de hombros con toalla', 'Towel Shoulder Stretch', 'Hombros', '["### Paso 1: póngase en posición", "- Párese con los pies separados a la altura de los hombros para mayor estabilidad.", "- Sostenga una toalla detrás de su espalda con una mano agarrando el extremo superior y la otra sosteniendo el extremo inferior.", "### Paso 2: realice el estiramiento", "- Tire suavemente de la toalla hacia arriba con la mano superior y lleve la mano inferior a lo largo de la espalda.", "- Mantenga el estiramiento durante 15 a 30 segundos y sienta un estiramiento en los hombros y tríceps.", "- Libera lentamente la tensión, bajando los brazos hasta la posición inicial.", "- Cambie de lado y repita, asegurando una flexibilidad uniforme en ambos hombros.", "### Paso 3: Respiración y Control", "- Respire profundamente mientras mantiene el estiramiento para mejorar la relajación.", "- No fuerces el movimiento; trabaje dentro de su cómodo rango de movimiento."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001755538292', 'Estiramiento de muñeca', 'Wrist Stretch', 'Antebrazos', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001500713108', 'Curl de muñeca con mancuernas', 'Dumbbell Wrist Curl', 'Antebrazos', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001500713108', 'Curl de muñeca con mancuernas', 'Dumbbell Wrist Curl', 'Antebrazos', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000325899796', 'Paseo del granjero', 'Farmer’s Walk', 'Cardio', '["Comience seleccionando dos objetos pesados ​​o pesos de igual peso. Pueden ser mancuernas, pesas rusas, barras, sacos de arena u otros objetos pesados ​​con asas.", "Párese erguido con la columna neutra y el núcleo apretado.", "Levante las pesas, una en cada mano, con un agarre neutral (las palmas una frente a la otra).", "Mantenga una postura erguida, mantenga los hombros hacia atrás y evite inclinarse excesivamente hacia adelante o hacia atrás.", "Camine una distancia predeterminada o durante un tiempo determinado mientras sostiene las pesas a los costados.", "Una vez que llegue al final de la distancia o el tiempo de caminata, coloque las pesas con cuidado."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000759563916', 'Elevaciones de rodillas colgado', 'Hanging Knee Raises', 'Abdomen', '["Su propio peso corporal actúa como resistencia que ayuda a aumentar su resistencia y desarrollar su resistencia. Este ejercicio que trabaja los flexores de la cadera mejora los músculos centrales, especialmente los músculos abdominales inferiores. Es uno de los mejores ejercicios para abdominales que activa todo el core ejercitando no sólo los abdominales inferiores sino también los músculos abdominales superiores."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000725131461', 'Curl en polea sobre la cabeza', 'Overhead Cable Curl', 'Otros', '["Seleccione una máquina de cable asegurándose de que ambas empuñaduras estén colocadas en alto.", "Seleccione el peso apropiado para las repeticiones requeridas. Sujete ambas uniones de cables y tense la tensión, moviéndose hacia el centro.", "Permita que sus brazos estén hacia los lados y en una posición elevada. (Esta es su posición inicial).", "Desde esta posición, genere movimiento flexionando los codos.", "Continúe flexionando hasta que sus antebrazos y la región del bíceps hagan contacto.", "En este punto, comience a invertir lentamente el movimiento de regreso a su posición inicial.", "Esta es una repetición. Continúe hasta completar las repeticiones necesarias."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001195946150', 'Curl con dos brazos en polea en banco inclinado', 'Cable Two Arm Curl on Incline Bench', 'Otros', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001085680103', 'Estiramiento extensor del dedo del pie', 'Toe Extensor Stretch', 'Antebrazos', '["Posición inicial: párese erguido con los pies separados a la altura de las caderas.", "Paso atrás: Extienda una pierna detrás de usted y coloque la parte superior de los dedos de los pies en el suelo con el pie apuntando hacia abajo.", "Cambie el peso hacia adelante: transfiera su peso ligeramente a la pierna delantera, permitiendo que el pie trasero presione suavemente el piso para crear un estiramiento en la parte superior del pie y la espinilla.", "Mantenga la posición: mantenga el torso erguido, los hombros relajados y la columna neutra mientras mantiene el equilibrio.", "Duración: Mantén el estiramiento durante 20 a 30 segundos, respirando profundamente y evitando rebotes.", "Cambiar de lado: regrese a la posición inicial y repita con el pie opuesto."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001500713108', 'Curl de muñeca con mancuernas', 'Dumbbell Wrist Curl', 'Antebrazos', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001755538292', 'Estiramiento de muñeca', 'Wrist Stretch', 'Antebrazos', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-002074383039', 'Bandera humana', 'Human Flag', 'Otros', '["Busque un poste o barra vertical resistente que pueda soportar su peso. Párate al lado del poste y sujétalo con tu mano más fuerte. Tu mano debe estar a la altura del hombro.", "Su mano superior asumirá un agarre por encima de la cabeza y tirará de la barra. Luego, coloque la mano inferior en el extremo inferior del poste con un agarre por debajo. Esta mano empujará la barra y, juntos, estos dos movimientos elevarán gradualmente el torso del suelo.", "Levanta los pies del suelo y coloca las piernas paralelas al suelo. Debes apoyar todo el peso de tu cuerpo sobre las manos y la parte superior del cuerpo.", "Mantén la posición de bandera humana todo el tiempo que puedas antes de volver a bajar lentamente al suelo."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000944587899', 'Zancada hacia adelante en polea', 'Cable Forward Lunge', 'Piernas', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000641145561', 'Curl dedos con barra', 'Barbell Finger Curl', 'Otros', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-002123633189', 'Voltear el neumático', 'Tire Flip', 'Otros', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000115336293', 'Rodillo de muñeca', 'Wrist Roller', 'Antebrazos', '["Párate o siéntate con los brazos extendidos frente a ti, manteniendo los codos cerca del cuerpo y las manos al nivel de los hombros.", "Haga rodar el rodillo de muñeca hacia su cuerpo, usando solo sus muñecas para mover el peso por la cuerda y hacia sus manos.", "Haga una pausa por un momento en la parte superior del movimiento, luego haga rodar lentamente el peso por la cuerda hacia el piso.", "Repita el movimiento durante varias repeticiones, concentrándose en mantener las muñecas estables y comprometidas durante todo el ejercicio."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000671795341', 'Estiramiento de flexión del cuello', 'Neck Flexion Stretch', 'Antebrazos', '["Los estiramientos de cuello también participan en la fisioterapia que tiene como objetivo rehabilitar los músculos, las articulaciones y los huesos del cuello. Los estiramientos de cuello tienen como objetivo aumentar la fuerza, el tono y la flexibilidad de los músculos del cuello. También permite que los ligamentos de las articulaciones del cuello se vuelvan más flexibles y resistan una mayor tensión en el área.", "Cuando la cabeza y los hombros se inclinan hacia adelante debido a una mala postura, algunos músculos del pecho y el cuello pueden acortarse y tensarse con el tiempo, lo que puede perpetuar la mala postura que causa el dolor de cuello. Los ejercicios de estiramiento del cuello pueden ayudar a relajar los músculos posturales y reducir el dolor de cuello."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001386997510', 'Flexiones con rotación', 'Push-up With Rotation', 'Pecho', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000559326653', 'Máquina de press de pecho inclinada', 'Incline Chest Press Machine', 'Pecho', '["Siéntese en la máquina con la espalda firmemente apoyada en el respaldo. Coloque los pies apoyados en el suelo, separados a la altura de los hombros. Mantenga una columna neutra y active los músculos centrales para lograr estabilidad.", "Sujete las manijas o empuñaduras a ambos lados de la máquina. Las palmas de las manos deben mirar hacia adelante y las manos deben estar separadas al ancho de los hombros o un poco más anchas, según su preferencia.", "Posición inicial: Con los brazos flexionados, acerca las asas al pecho. Tus codos deben estar a unos 45 grados o un poco más. Esta es tu posición inicial.", "Movimiento: Empuje las manijas hacia adelante y lejos de su cuerpo, extendiendo los brazos completamente pero sin bloquear los codos. Exhala mientras alejas las manijas.", "Retorno controlado: Lleve lentamente las manijas a la posición inicial, manteniendo el control sobre el movimiento. Inhale mientras regresa a la posición inicial, permitiendo que los músculos del pecho se estiren.", "Repetir: Complete el número deseado de repeticiones según su nivel de condición física y sus objetivos. Trate de realizar un movimiento controlado y suave durante todo el ejercicio."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001386997510', 'Flexiones con rotación', 'Push-up With Rotation', 'Pecho', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000000227386', 'Zancada declinada con mancuernas en banco', 'Decline Bench Dumbbell Lunge', 'Piernas', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001981670431', 'Patada de burro en la en máquina Smith', 'Donkey Kick on Smith Machine', 'Pecho', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000568771063', 'Flexión de rodilla con agarre cerrado', 'Close Grip Knee Push-up', 'Pecho', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000544728029', 'Press de banca en máquina Smith', 'Smith Machine Bench Press', 'Pecho', '["- Coloque un banco plano debajo de la barra de la máquina Smith.", "- Ajuste el banco para que la barra quede alineada con la mitad de su pecho cuando esté acostado.", "- Recuéstese en el banco con los pies apoyados en el suelo y la espalda ligeramente arqueada.", "- Agarre la barra ligeramente más ancha que el ancho de los hombros con las palmas hacia adelante.", "- Desenganche la barra girando las muñecas para soltar los ganchos de seguridad.", "- Fase de descenso: baje lentamente la barra hacia el pecho doblando los codos. Mantenga los codos en un ángulo de aproximadamente 45 grados con respecto al torso. Deténgase cuando la barra esté justo encima del pecho o la toque ligeramente sin rebotar.", "- Baje lentamente la barra hacia su pecho doblando los codos.", "- Mantenga los codos en un ángulo de aproximadamente 45 grados con respecto al torso.", "- Detente cuando la barra esté justo encima de tu pecho o la toque ligeramente sin rebotar.", "- Fase de press: Empuja la barra hacia arriba para volver a la posición inicial. Extiende completamente los brazos pero evita bloquear los codos en la parte superior.", "- Empuja la barra hacia arriba para volver a la posición inicial.", "- Extienda completamente los brazos pero evite bloquear los codos en la parte superior.", "- Repetir: Realiza el número deseado de repeticiones, manteniendo el control durante todo el movimiento.", "### Consejos para una máxima eficacia", "- Ajuste el banco correctamente: asegúrese de que el banco esté alineado correctamente para apuntar eficazmente al pecho.", "- Involucre el núcleo: mantenga su núcleo apretado para mantener la estabilidad y proteger su espalda baja.", "- Controle el movimiento: realice el ejercicio con movimientos lentos y controlados para una máxima activación muscular.", "- Utilice un peso apropiado: comience con un peso manejable para concentrarse en la forma antes de aumentar la resistencia.", "- Experimente con la colocación de las manos: un agarre más amplio se dirige más al pecho, mientras que un agarre más estrecho desplaza el énfasis hacia los tríceps.", "### Errores comunes a evitar", "- Desalineación de la trayectoria de la barra: asegúrese de que la barra baje hacia la mitad de su pecho, no hacia el cuello o el abdomen.", "- Hacer rebotar la barra: evite hacer rebotar la barra contra su pecho, lo que puede provocar lesiones y reducir la eficacia.", "- Arquear la espalda: Mantenga un ligero arco en la parte baja de la espalda, pero evite arquearlo excesivamente para proteger su columna.", "- Bloquear los codos: No bloquee los codos en la parte superior para evitar tensión en las articulaciones.", "- Descuidar el rango completo de movimiento: realice el ejercicio con un rango completo de movimiento para maximizar la participación de los músculos."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000052075680', 'Flexiones inclinadas', 'Incline Push-up', 'Pecho', '["- Elija una superficie elevada Utilice un banco resistente, una encimera o incluso una pared para pendientes más altas. Cuanto menor sea la inclinación, más desafiante será el ejercicio.", "- Utilice un banco resistente, una encimera o incluso una pared para pendientes más altas. Cuanto menor sea la inclinación, más desafiante será el ejercicio.", "- ColóqueseColoque las manos a la altura de los hombros sobre la superficie elevada. Asegúrese de que sus dedos apunten hacia adelante y sus palmas estén planas.", "- Coloque las manos a la altura de los hombros sobre la superficie elevada. Asegúrese de que sus dedos apunten hacia adelante y sus palmas estén planas.", "- Posición inicial Da un paso con los pies hacia atrás hasta que tu cuerpo forme una línea recta desde la cabeza hasta los talones. Involucra tu núcleo y tus glúteos para mantener una columna neutral.", "- Da un paso atrás con los pies hasta que tu cuerpo forme una línea recta desde la cabeza hasta los talones.", "- Involucre su núcleo y glúteos para mantener una columna neutral.", "- Baje su cuerpo Inhale mientras dobla lentamente los codos, bajando el pecho hacia la superficie. Mantenga los codos en un ángulo de 45 grados con respecto al torso, evitando ensancharlos.", "- Inhale mientras dobla lentamente los codos y baja el pecho hacia la superficie.", "- Mantenga los codos en un ángulo de 45 grados con respecto al torso, evitando ensancharlos.", "- Empuje hacia arriba Exhale mientras presiona las manos contra la superficie, estirando los brazos para volver a la posición inicial. Concéntrese en apretar el pecho y los tríceps mientras empuja hacia arriba.", "- Exhala mientras presionas las manos contra la superficie, estirando los brazos para volver a la posición inicial.", "- Concéntrate en apretar el pecho y los tríceps mientras empujas hacia arriba.", "- Repetir Realice de 10 a 15 repeticiones para 2 a 3 series, según su nivel de condición física.", "- Realice de 10 a 15 repeticiones durante 2 a 3 series, según su nivel de condición física.", "### Consejos para una forma adecuada", "- Involucre su núcleo: mantenga sus abdominales contraídos para evitar la flacidez de las caderas o la espalda arqueada.", "- Mantenga la alineación: su cuerpo debe permanecer en línea recta durante todo el movimiento. Evite dejar caer las caderas o encoger los hombros.", "- Controle el movimiento: muévase lenta y deliberadamente para maximizar la participación de los músculos.", "- Ajuste la inclinación: comience con una inclinación más alta (por ejemplo, flexiones de pared) y baje gradualmente la superficie a medida que gane fuerza.", "### Errores comunes a evitar", "- Codos ensanchados Mantenga los codos en un ángulo de 45 grados para reducir la tensión en los hombros.", "- Mantenga los codos en un ángulo de 45 grados para reducir la tensión en los hombros.", "- Caderas caídas Involucre su núcleo y glúteos para mantener una línea corporal recta.", "- Involucre su núcleo y glúteos para mantener una línea corporal recta.", "- Rango de movimiento inconsistente Baje el pecho completamente hacia la superficie para obtener un rango de movimiento completo.", "- Baje el pecho completamente hacia la superficie para lograr un rango de movimiento completo.", "- Acelerar el movimiento Realice el ejercicio lentamente para maximizar la activación muscular y reducir el riesgo de lesiones.", "- Realice el ejercicio lentamente para maximizar la activación muscular y reducir el riesgo de lesiones."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001699135521', 'Flexión de pica', 'Pike Push-up', 'Pecho', '["Mantenga su núcleo apretado para mantener el equilibrio y el control.", "Empuje con las palmas de las manos para enganchar completamente los hombros.", "Mantenga los codos ligeramente doblados para proteger las articulaciones de los hombros.", "Muévase lentamente y con control para maximizar las ganancias de fuerza.", "Involucre sus piernas para mantener su cuerpo estable."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001388664219', 'Estiramiento dinámico del pecho', 'Dynamic Chest Stretch', 'Pecho', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000661270579', 'Levantamiento de pantorrillas con prensa de piernas', 'Leg Press Calf Raise', 'Piernas', '["Configuración: Siéntese en la máquina de prensa de piernas y coloque las puntas de los pies separadas al ancho de los hombros en la parte inferior de la plataforma para los pies, con los talones colgando.", "Ajuste la carga: cargue la máquina con un peso de moderado a pesado que permita un rango completo de movimiento sin rebotar ni bloquear las rodillas.", "Posición inicial: Extienda las rodillas completamente (sin bloquearlas) para estabilizar la posición. Mantenga las piernas rectas y las caderas apoyadas contra la almohadilla.", "Elevar: Presione a través de las puntas de los pies y levante los talones lo más alto posible, involucrando las pantorrillas en el pico de contracción.", "Pausa y contracción: mantenga la posición superior durante 1 a 2 segundos para enfatizar el reclutamiento muscular máximo.", "Baje lentamente: baje los talones bajo control hasta que sienta un estiramiento profundo en las pantorrillas.", "Repetir: realice el número deseado de repeticiones, manteniendo un tempo y una tensión constantes en todo momento."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001699135521', 'Flexión de pica', 'Pike Push-up', 'Pecho', '["- Comience en una posición de flexión con las manos separadas al ancho de los hombros y los pies juntos.", "- Levante las caderas hacia el techo, formando una V invertida (similar a un perro boca abajo en yoga).", "- Mantenga los brazos extendidos y la cabeza en posición neutral entre los brazos.", "- Baje la cabeza hacia el suelo doblando los codos.", "- Mantenga los codos en un ángulo de 45 grados para reducir la tensión en los hombros.", "- Haga una pausa cuando su cabeza esté justo por encima del suelo.", "- Empuja hacia atrás hasta la posición inicial extendiendo los brazos.", "- Repita de 8 a 15 repeticiones para 3 a 4 series.", "### Consejos para una forma adecuada", "- Mantenga su núcleo apretado para mantener el equilibrio y el control.", "- Empuje con las palmas de las manos para enganchar completamente los hombros.", "- Mantenga los codos ligeramente doblados para proteger las articulaciones de los hombros.", "- Muévase lentamente y con control para maximizar las ganancias de fuerza.", "- Involucre sus piernas para mantener su cuerpo estable.", "### Errores comunes a evitar", "- Dejar que los codos se abran demasiado puede provocar tensión en los hombros.", "- No levantar las caderas lo suficiente, esto reduce la activación de los hombros.", "- Acelerar el movimiento: reduce la eficacia y aumenta el riesgo de lesiones.", "- No controlar el descenso puede provocar lesiones en el cuello o la cabeza.", "- Colocar las manos demasiado hacia adelante reduce la efectividad del movimiento."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000597677180', 'Press de banca con mancuernas', 'Dumbbell Bench Press', 'Pecho', '["Configuración: Acuéstese en un banco con los pies firmemente plantados en el suelo. Sostenga una mancuerna en cada mano y apóyela sobre los muslos.", "Acuéstese sobre un banco con los pies firmemente plantados en el suelo.", "Sostenga una mancuerna en cada mano, apoyándola sobre sus muslos.", "Posición inicial: Con un movimiento controlado, suba las mancuernas hasta el nivel de los hombros mientras está sentado en el banco. Esta es tu posición inicial. Tus palmas deben mirar hacia adelante y tus muñecas deben estar en una posición neutral.", "Con un movimiento controlado, suba las mancuernas hasta el nivel de los hombros mientras está sentado en el banco. Esta es tu posición inicial.", "Tus palmas deben mirar hacia adelante y tus muñecas deben estar en una posición neutral.", "Ejecución: Inhale y active los músculos centrales. Baje lentamente las mancuernas hacia el pecho de forma controlada, manteniendo los codos en un ángulo de aproximadamente 45 grados con respecto al cuerpo. La parte superior de tus brazos debe estar paralela al suelo. Baje las mancuernas hasta que los codos estén ligeramente por debajo del nivel del banco o hasta que sienta un suave estiramiento en los músculos del pecho.", "Inhala y activa tus músculos centrales.", "Baje lentamente las mancuernas hacia su pecho de manera controlada, manteniendo los codos en un ángulo de aproximadamente 45 grados con respecto a su cuerpo. La parte superior de tus brazos debe estar paralela al suelo.", "Baje las mancuernas hasta que sus codos estén ligeramente por debajo del nivel del banco o hasta que sienta un suave estiramiento en los músculos del pecho.", "Fase de empuje: exhale y empuje las mancuernas hacia arriba hasta la posición inicial, extendiendo completamente los brazos sin bloquear los codos. Mantenga el pecho contraído y mantenga un ligero arco en la zona lumbar durante todo el movimiento.", "Exhala y empuja las mancuernas hacia arriba hasta la posición inicial, extendiendo completamente los brazos sin bloquear los codos.", "Mantenga el pecho contraído y mantenga un ligero arco en la zona lumbar durante todo el movimiento.", "Repetir: Realice el número deseado de repeticiones, manteniendo la forma y el control adecuados.", "Realice el número deseado de repeticiones, manteniendo la forma y el control adecuados."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000597677180', 'Press de banca con mancuernas', 'Dumbbell Bench Press', 'Pecho', '["Configuración: Acuéstese en un banco con los pies firmemente plantados en el suelo. Sostenga una mancuerna en cada mano y apóyela sobre los muslos.", "Acuéstese sobre un banco con los pies firmemente plantados en el suelo.", "Sostenga una mancuerna en cada mano, apoyándola sobre sus muslos.", "Posición inicial: Con un movimiento controlado, suba las mancuernas hasta el nivel de los hombros mientras está sentado en el banco. Esta es tu posición inicial. Tus palmas deben mirar hacia adelante y tus muñecas deben estar en una posición neutral.", "Con un movimiento controlado, suba las mancuernas hasta el nivel de los hombros mientras está sentado en el banco. Esta es tu posición inicial.", "Tus palmas deben mirar hacia adelante y tus muñecas deben estar en una posición neutral.", "Ejecución: Inhale y active los músculos centrales. Baje lentamente las mancuernas hacia el pecho de forma controlada, manteniendo los codos en un ángulo de aproximadamente 45 grados con respecto al cuerpo. La parte superior de tus brazos debe estar paralela al suelo. Baje las mancuernas hasta que los codos estén ligeramente por debajo del nivel del banco o hasta que sienta un suave estiramiento en los músculos del pecho.", "Inhala y activa tus músculos centrales.", "Baje lentamente las mancuernas hacia su pecho de manera controlada, manteniendo los codos en un ángulo de aproximadamente 45 grados con respecto a su cuerpo. La parte superior de tus brazos debe estar paralela al suelo.", "Baje las mancuernas hasta que sus codos estén ligeramente por debajo del nivel del banco o hasta que sienta un suave estiramiento en los músculos del pecho.", "Fase de empuje: exhale y empuje las mancuernas hacia arriba hasta la posición inicial, extendiendo completamente los brazos sin bloquear los codos. Mantenga el pecho contraído y mantenga un ligero arco en la zona lumbar durante todo el movimiento.", "Exhala y empuja las mancuernas hacia arriba hasta la posición inicial, extendiendo completamente los brazos sin bloquear los codos.", "Mantenga el pecho contraído y mantenga un ligero arco en la zona lumbar durante todo el movimiento.", "Repetir: Realice el número deseado de repeticiones, manteniendo la forma y el control adecuados.", "Realice el número deseado de repeticiones, manteniendo la forma y el control adecuados."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001216361165', 'Flexiones con balón medicinal', 'Medicine Ball Push-Up', 'Pecho', '["### ", "- Coloque un balón medicinal estable en el suelo y colóquelo debajo del centro de su pecho.", "- Agarre la parte superior de la pelota con ambas manos juntas, manteniendo los dedos abiertos para controlarla.", "- Vuelva a colocarse en una tabla con el cuerpo en línea recta y los pies separados a la altura de los hombros para mantener el equilibrio.", "- Apoye el núcleo y los glúteos, manteniendo la columna neutra.", "- Baje el cuerpo lentamente doblando los codos cerca de las costillas. Trate de acercar su pecho a la pelota.", "- Empuje hacia arriba con control, extendiendo los codos completamente mientras mantiene la tensión en todo el cuerpo.", "### Consejos para una forma adecuada", "- Mantenga la alineación del cuerpo: mantenga los hombros, las caderas y los tobillos en línea recta.", "- Mantenga los codos doblados: esto enfatiza los tríceps y protege los hombros.", "- Involucre su núcleo: evita la flacidez o el arqueamiento durante el movimiento.", "- Elija una pelota firme y antideslizante: la estabilidad es crucial para evitar que se vuelque o ruede.", "- Controla el descenso y el ascenso: El movimiento lento mejora la tensión y la seguridad.", "### Errores comunes", "- Dejar que los codos se ensanchen: reduce la concentración del tríceps y puede tensar la articulación del hombro.", "- Usar una pelota inestable: Las pelotas blandas o demasiado redondas aumentan el riesgo de lesiones.", "- Caderas caídas: conduce a una mala postura y tensión en la espalda baja.", "- Apresurarse en las repeticiones: las repeticiones rápidas en una superficie inestable reducen la activación y el control de los músculos.", "- Rango de movimiento inadecuado: No bajar lo suficientemente cerca de la pelota limita la efectividad."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000063530182', 'Declinar vuelo con mancuernas', 'Decline Dumbbell Fly', 'Pecho', '["- Elija un banco declinado", "- Seleccione mancuernas adecuadas", "- Colóquese: recuéstese en el banco con la cabeza más baja que el torso y mancuernas en la mano.", "- Posición inicial Sostenga las mancuernas sobre su pecho con una ligera flexión de los codos. Las palmas deben estar frente a frente y los brazos deben estar perpendiculares al torso.", "- Sostenga las mancuernas por encima de su pecho con una ligera flexión de los codos.", "- Las palmas deben estar enfrentadas y los brazos deben estar perpendiculares al torso.", "- Fase de descenso Baje lentamente las mancuernas hacia afuera formando un arco amplio, manteniendo una ligera flexión de los codos. Baje hasta que sienta un estiramiento en el pecho sin ir más allá de su nivel de comodidad.", "- Baje lentamente las mancuernas hacia afuera formando un arco amplio, manteniendo los codos ligeramente doblados.", "- Baje hasta que sienta un estiramiento en el pecho sin sobrepasar su nivel de comodidad.", "- Fase de levantamiento Apriete los músculos del pecho y lleve las mancuernas a la posición inicial, manteniendo el movimiento del arco. Evite golpear las mancuernas en la parte superior.", "- Aprieta los músculos del pecho y lleva las mancuernas a la posición inicial, manteniendo el movimiento del arco.", "- Evite golpear las mancuernas en la parte superior.", "- RepetirRealice el número deseado de repeticiones con movimientos controlados.", "- Realiza el número deseado de repeticiones con movimientos controlados.", "### Consejos para una máxima eficacia", "- Concéntrese en la forma: mantenga los codos ligeramente doblados y muévase en un arco controlado para evitar tensión en los hombros.", "- Involucre su núcleo: mantenga su núcleo apretado para estabilizar su cuerpo en el banco de descenso.", "- Utilice peso moderado: priorice la técnica sobre el levantamiento de objetos pesados ​​para apuntar eficazmente al pecho.", "- Aprieta en la parte superior: contrae los músculos del pecho en la parte superior del movimiento para maximizar la activación.", "- Combínelo con ejercicios compuestos: combínelo con prensas o flexiones para un entrenamiento integral del pecho.", "### Errores comunes a evitar", "- Usar peso excesivo: comenzar con demasiado peso puede comprometer la forma y aumentar el riesgo de lesiones.", "- Bloquear los codos: los brazos completamente extendidos ejercen una tensión innecesaria en las articulaciones del codo.", "- Bajar demasiado profundo: Extender demasiado el rango de movimiento puede forzar los hombros.", "- Acelerar el movimiento: Realizar el ejercicio demasiado rápido reduce la efectividad y el control.", "- Ángulo de banco incorrecto: usar una pendiente demasiado pronunciada puede desviar la atención del pecho hacia otros músculos."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000559326653', 'Máquina de press de pecho inclinada', 'Incline Chest Press Machine', 'Pecho', '["Siéntese en la máquina con la espalda firmemente apoyada en el respaldo. Coloque los pies apoyados en el suelo, separados a la altura de los hombros. Mantenga una columna neutra y active los músculos centrales para lograr estabilidad.", "Sujete las manijas o empuñaduras a ambos lados de la máquina. Las palmas de las manos deben mirar hacia adelante y las manos deben estar separadas al ancho de los hombros o un poco más anchas, según su preferencia.", "Posición inicial: Con los brazos flexionados, acerca las asas al pecho. Tus codos deben estar a unos 45 grados o un poco más. Esta es tu posición inicial.", "Movimiento: Empuje las manijas hacia adelante y lejos de su cuerpo, extendiendo los brazos completamente pero sin bloquear los codos. Exhala mientras alejas las manijas.", "Retorno controlado: Lleve lentamente las manijas a la posición inicial, manteniendo el control sobre el movimiento. Inhale mientras regresa a la posición inicial, permitiendo que los músculos del pecho se estiren.", "Repetir: Complete el número deseado de repeticiones según su nivel de condición física y sus objetivos. Trate de realizar un movimiento controlado y suave durante todo el ejercicio."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001098719638', 'Press militar con peso corporal', 'Bodyweight Military Press', 'Hombros', '["Comience parándose con los pies separados a la altura de los hombros y los brazos a los costados.", "Levante los brazos hasta el nivel de los hombros, doblando los codos en un ángulo de 90 grados y con las palmas hacia adelante.", "Involucre su núcleo y apriete sus glúteos para mantener la estabilidad durante todo el movimiento.", "Presione lentamente las manos directamente sobre la cabeza, extendiendo los brazos por completo sin bloquear los codos. Imagínese alejando el techo de usted.", "Haga una pausa por un momento en la parte superior, asegurándose de que sus brazos estén completamente extendidos.", "Baje lentamente las manos hasta la posición inicial, manteniendo el control y un ritmo controlado.", "Repita hasta el número deseado de repeticiones."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001798275309', 'Crunch con elevación de piernas', 'Crunch With Leg Raise', 'Cardio', '["Los ejercicios abdominales generalmente están diseñados para fortalecer y desarrollar los músculos centrales del cuerpo. El ejercicio ayuda a fortalecer los músculos centrales, mejorar la postura y aumentar la movilidad y flexibilidad de los músculos.", "Se dirige a los músculos abdominales inferiores y superiores al mismo tiempo: El ejercicio de abdominales con elevación de piernas se dirige al recto abdominal y a los músculos oblicuos, de modo que los músculos abdominales superiores e inferiores se desarrollan simultáneamente."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000388902576', 'Sujeción hueca', 'Hollow Hold', 'Abdomen', '["La sujeción hueca es un movimiento isométrico eficaz que trabaja tanto los músculos centrales más profundos como los músculos abdominales, así como una variedad de otros músculos de todo el cuerpo, incluidos los músculos de la cadera, los cuádriceps y los dorsales."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000828975314', 'Elevación de piernas en silla de capitán', 'Captains Chair Leg Raise', 'Abdomen', '["Este ejercicio que trabaja los flexores de la cadera mejora los músculos centrales, especialmente los músculos abdominales inferiores. Además, los músculos de la espalda, el pecho y el trapecio actúan como estabilizadores durante el ejercicio.", "Según un estudio del American Ejercicio Council, este ejercicio es uno de los más eficaces para fortalecer los oblicuos y el segundo más eficaz para fortalecer los músculos abdominales."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000732765450', 'Máquina de extensión de tríceps', 'Triceps Extension Machine', 'Tríceps', '["### Paso 1: ajustar la máquina", "- Seleccione un peso apropiado que permita un movimiento controlado sin sacrificar la forma.", "- Ajuste la altura del asiento de modo que la parte superior de sus brazos descanse cómodamente sobre la almohadilla y los codos se alineen con el punto de giro de la máquina.", "### Paso 2: configuración y posicionamiento", "- Siéntese erguido con la espalda firmemente apoyada en la almohadilla y los pies apoyados en el suelo.", "- Agarre las manijas en una posición neutral con las palmas hacia el cuerpo.", "- Asegúrese de que sus codos estén alineados con el eje de la máquina para optimizar la eficiencia del movimiento.", "### Paso 3: Ejecución", "- Empuja las manijas hacia abajo, extendiendo los brazos completamente mientras contraes los tríceps.", "- Mantenga la contracción por un segundo en la parte inferior del movimiento.", "- Regrese lentamente a la posición inicial, controlando el peso mientras dobla los codos.", "- Repita para las repeticiones deseadas, manteniendo sus movimientos suaves y controlados."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000171673306', 'Aleteo de piernas (Flutter Kicks) sentado', 'Seated Flutter Kick', 'Abdomen', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001798275309', 'Crunch con elevación de piernas', 'Crunch With Leg Raise', 'Cardio', '["Los ejercicios abdominales generalmente están diseñados para fortalecer y desarrollar los músculos centrales del cuerpo. El ejercicio ayuda a fortalecer los músculos centrales, mejorar la postura y aumentar la movilidad y flexibilidad de los músculos.", "Se dirige a los músculos abdominales inferiores y superiores al mismo tiempo: El ejercicio de abdominales con elevación de piernas se dirige al recto abdominal y a los músculos oblicuos, de modo que los músculos abdominales superiores e inferiores se desarrollan simultáneamente."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000834355435', 'Crunch inverso', 'Reverse Crunch', 'Cardio', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000565977272', 'Bicho muerto (Dead Bug)', 'Dead Bug', 'Abdomen', '["El movimiento del insecto muerto, que se utiliza con frecuencia en Pilates, yoga y entrenamiento abdominal, es un ejercicio diseñado para fortalecer la estabilidad general y el core. Este movimiento es un ejercicio funcional de fortalecimiento del núcleo que trabaja los músculos de la parte inferior y superior del cuerpo.", "Dead Bug también es un ejercicio que requiere concentración mental, obliga a que los movimientos se realicen en armonía y ayuda a mejorar el equilibrio y la coordinación.", "Este ejercicio, que también se aplica como ejercicio de calentamiento, puede trabajar incluso las fibras musculares más pequeñas desde diferentes ángulos para fortalecer los músculos centrales. También es una forma segura y eficaz de fortalecer y equilibrar los músculos de la columna, la espalda y el cuello. Una estructura sólida de la columna y músculos fuertes de la espalda pueden ayudar a mejorar la postura y aliviar y prevenir el dolor de espalda."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001391783546', 'Estiramiento de pared de esquina', 'Corner Wall Stretch', 'Otros', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001174983688', 'Deslizamientos en pared para hombros', 'Wall Slides', 'Hombros', '["Párese con la espalda contra la pared, con los pies separados aproximadamente a la altura de las caderas.", "Coloque los brazos contra la pared con los codos doblados en un ángulo de 90 grados y las palmas hacia adelante.", "Desliza suavemente los brazos hacia arriba por la pared, manteniendo el contacto entre las manos, los codos y la pared.", "Mientras desliza los brazos hacia arriba, trate de mantener los omóplatos juntos y hacia abajo.", "Vaya tan lejos como pueda cómodamente sin dolor ni tensión excesiva.", "Haga una pausa por un momento en la parte superior, luego deslice lentamente los brazos hacia abajo hasta la posición inicial.", "Repita el movimiento durante el número deseado de repeticiones."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-002083554082', 'Curl de concentración del cable', 'Cable Concentration Curl', 'Otros', '["Configure la máquina de cable: conecte una manija única a una polea baja en la máquina de cable.", "Siéntate en un banco: Siéntate en un banco con los pies apoyados en el suelo y las piernas separadas a la altura de los hombros. Coloque el codo del brazo que trabaja en la parte interna del muslo, con la palma hacia arriba.", "Agarre el mango del cable: Sujete el mango del cable con la palma hacia arriba y deje que el brazo cuelgue hacia abajo, completamente extendido.", "Doble el mango: Manteniendo la parte superior del brazo inmóvil, exhale y doble el mango del cable hacia su hombro mientras mantiene un agarre firme sobre el mango. Mantenga la muñeca recta y concéntrese en contraer los músculos bíceps.", "Baje el mango: Inhale y baje lentamente el mango hasta la posición inicial, manteniendo la parte superior del brazo inmóvil durante todo el movimiento.", "Repetir: Complete el número deseado de repeticiones con un brazo antes de cambiar al otro brazo."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001085680103', 'Estiramiento extensor del dedo del pie', 'Toe Extensor Stretch', 'Piernas', '["- Posición inicial: párese erguido con los pies separados a la altura de las caderas.", "- Paso atrás: Extienda una pierna detrás de usted y coloque la parte superior de los dedos de los pies en el suelo con el pie apuntando hacia abajo.", "- Cambie el peso hacia adelante: transfiera su peso ligeramente a la pierna delantera, permitiendo que el pie trasero presione suavemente el piso para crear un estiramiento en la parte superior del pie y la espinilla.", "- Mantenga la posición: mantenga el torso erguido, los hombros relajados y la columna neutra mientras mantiene el equilibrio.", "- Duración: Mantén el estiramiento durante 20 a 30 segundos, respirando profundamente y evitando rebotes.", "- Cambiar de lado: regrese a la posición inicial y repita con el pie opuesto.", "### Consejos para una forma adecuada", "- Utilice una pared o una silla para mantener el equilibrio si es necesario, especialmente si es nuevo en el puesto.", "- Aplique una presión suave; el estiramiento debe sentirse en la parte superior del pie y la espinilla, no en la articulación del tobillo.", "- Mantenga el pie alineado; evite girar los dedos hacia adentro o hacia afuera excesivamente.", "- Realice descalzo o con zapatos blandos para un mejor contacto y retroalimentación con los pies.", "- Mantenga su postura erguida para evitar trasladar la tensión a la zona lumbar.", "### Errores comunes", "- Forzar el estiramiento: una presión excesiva puede provocar tensión o malestar en el tobillo.", "- Torcer el pie: la desalineación reduce la efectividad del estiramiento y puede irritar las articulaciones.", "- Contener la respiración: la respiración ayuda a que los músculos se relajen y mejora la calidad del estiramiento.", "- Rebotar o balancearse: puede reducir la efectividad del estiramiento y aumentar el riesgo de tensión.", "- Ignorar la posición de los pies: asegúrese de que los dedos de los pies estén en punta y apoyados en el suelo, no doblados hacia abajo."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000411500923', 'Estiramiento del pecho con rodillo de espuma', 'Foam Roller Chest Stretch', 'Pecho', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001391783546', 'Estiramiento de pared de esquina', 'Corner Wall Stretch', 'Hombros', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000239960548', 'Estiramiento de rotación del cuello', 'Neck Rotation Stretch', 'Hombros', '["Gire lentamente la cabeza hacia un lado, con el objetivo de acercar la oreja al hombro.", "Mantenga un estiramiento cómodo; Evite forzar la cabeza a una posición extrema.", "Deberías sentir un suave tirón a lo largo del costado de tu cuello. Mantenga esta posición durante 15 a 30 segundos, asegurando una respiración constante y relajada en todo momento.", "Regrese lentamente la cabeza a la posición central y repita el estiramiento en el otro lado.", "Apunta a 2-4 repeticiones en cada lado."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000442103733', 'Alcance del dedo del pie', 'Toe Reaches', 'Abdomen', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001916169449', 'Estiramiento de pantorrilla con cuerda', 'Calf Stretch With Rope', 'Pantorrillas', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000414464555', 'Curl de martillo con botella de agua', 'Water Bottle Hammer Curl', 'Otros', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001185029592', 'Remo vertical en polea', 'Cable Upright Row', 'Espalda', '["El remo vertical con cable es un ejercicio de aislamiento dirigido al trapecio y los deltoides, que son responsables de agregar ancho a los hombros.", "El remo vertical con cable es uno de los ejercicios efectivos para construir trampas más grandes, pero también es un movimiento en el que es fácil cometer errores. Una de las formas más sencillas de asegurarse de que su forma sea óptima es evitar el uso de mancuernas que sean demasiado pesadas."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000302329313', 'Activación isométrica abdominal (Bracing)', 'Abdominal Bracing', 'Abdomen', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001310647719', 'Plancha lateral', 'Side Plank', 'Abdomen', '["Acuéstese sobre su lado derecho, levantándose sobre su antebrazo derecho.", "Coloque su hombro derecho directamente encima de su codo derecho, manteniendo sus hombros, caderas y rodillas en línea recta.", "Apoye su brazo izquierdo a lo largo del costado de su cuerpo.", "Antes de presionar hacia arriba, contraiga los abdominales, aleje los hombros de las orejas y alargue la columna.", "Empuja hacia arriba para que tu cuerpo quede recto... Mantén la posición durante 10 segundos para principiantes y 1 minuto si eres más avanzado. Repita en su lado izquierdo."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000671795341', 'Estiramiento de flexión del cuello', 'Neck Flexion Stretch', 'Hombros', '["Los estiramientos de cuello también participan en la fisioterapia que tiene como objetivo rehabilitar los músculos, las articulaciones y los huesos del cuello. Los estiramientos de cuello tienen como objetivo aumentar la fuerza, el tono y la flexibilidad de los músculos del cuello. También permite que los ligamentos de las articulaciones del cuello se vuelvan más flexibles y resistan una mayor tensión en el área.", "Cuando la cabeza y los hombros se inclinan hacia adelante debido a una mala postura, algunos músculos del pecho y el cuello pueden acortarse y tensarse con el tiempo, lo que puede perpetuar la mala postura que causa el dolor de cuello. Los ejercicios de estiramiento del cuello pueden ayudar a relajar los músculos posturales y reducir el dolor de cuello."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000225409405', 'Estiramiento de extensión del cuello', 'Neck Extension Stretch', 'Hombros', '["Siéntate erguido con los hombros relajados.", "Incline lentamente la cabeza hacia atrás, mirando hacia arriba. Imagine un estiramiento suave a lo largo de la parte posterior de su cuello.", "Mantén la posición durante unos segundos y luego regresa lentamente a la posición inicial.", "Repita unas cuantas veces."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000311388229', 'Estiramiento lateral unilateral en la pared', 'Unilateral Lat Stretch on the Wall', 'Espalda', '["### Posición inicial:", "- Párese frente a una pared con el brazo extendido.", "- Coloque una palma contra la pared aproximadamente a la altura de los hombros o ligeramente por encima.", "- Mueva el pie del mismo lado ligeramente hacia atrás para mayor estabilidad.", "### Iniciar el estiramiento:", "- Doble ligeramente las caderas y las rodillas.", "- Mantenga el brazo recto y presione suavemente la palma contra la pared.", "### Profundizar el movimiento:", "- Empuja tus caderas hacia atrás mientras permites que tu pecho caiga hacia el suelo.", "- Gire el torso ligeramente lejos de la pared para aumentar el estiramiento lateral.", "### Sostenga y respire:", "- Mantener el estiramiento durante el tiempo deseado.", "- Respire lenta y profundamente, concentrándose en relajar la parte superior de la espalda y los hombros.", "### Cambiar de lado:", "- Regrese a la posición inicial.", "- Repite el movimiento en el lado opuesto."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000876887538', 'Elevación de pantorrillas de pie con peso corporal', 'Bodyweight Standing Calf Raise', 'Pantorrillas', '["- Posición inicial: Párese erguido con los pies separados a la altura de las caderas, manteniendo una buena postura con los hombros hacia atrás, el pecho abierto y el core comprometido.", "- Alineación de pies y cuerpo: Coloque los dedos de los pies en el extremo de una plataforma alta y distribuya su peso uniformemente entre ambas piernas.", "- Movimiento de elevación: levántese lentamente sobre las puntas de los pies, levantando los talones del suelo lo más alto posible cómodamente y contrayendo las pantorrillas por completo.", "- Descenso controlado: baje suavemente los talones hasta el suelo, manteniendo el control durante todo el movimiento.", "- Repetir: realice de 15 a 25 repeticiones por serie, enfatizando los movimientos controlados y deliberados.", "### Consejos para una forma adecuada:", "- Mantenga una postura recta, evitando inclinarse hacia adelante o balancearse hacia atrás.", "- Realice movimientos suave y lentamente para maximizar la participación de los músculos.", "- Manténgalo en la parte superior brevemente para activar completamente los músculos de la pantorrilla.", "- Mantenga las rodillas ligeramente dobladas para reducir la tensión en las articulaciones.", "### Errores comunes:", "- Movimiento rápido: rebotar rápidamente o utilizar el impulso reduce la activación muscular y puede provocar lesiones.", "- Rango de movimiento limitado: no levantarse completamente sobre los dedos de los pies limita el compromiso de la pantorrilla.", "- Postura incorrecta: inclinarse hacia adelante o hacia atrás genera una tensión innecesaria en las articulaciones y reduce la efectividad."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000955889053', 'Burpee con flexiones', 'Burpee With Push-Up', 'Cardio', '["- Posición inicial: Párese erguido con los pies separados a la altura de los hombros y los brazos a los costados.", "- Sentadilla: bájese hasta ponerse en cuclillas y coloque las manos planas en el suelo frente a usted.", "- Patada hacia atrás: salte con los pies hacia atrás en una posición de tabla alta, manteniendo el cuerpo en línea recta.", "- Flexiones: realice una flexión controlada, bajando el pecho hacia el suelo y presionando hacia arriba.", "- Regreso: Salta con los pies hacia adelante y vuelve a la posición de sentadilla.", "- Salto explosivo: conduce hacia arriba para realizar un salto vertical, llegando por encima de tu cabeza.", "- Repita durante la cantidad deseada de repeticiones o tiempo.", "### Consejos para una forma adecuada", "- Mantenga su núcleo comprometido durante la tabla y la flexión para evitar que la espalda baja se hunda.", "- Aterriza suavemente durante el salto para reducir la tensión en las articulaciones.", "- Realice la flexión con movimiento controlado; Evite que su pecho colapse.", "- Respira rítmicamente: inhala durante la flexión, exhala mientras saltas.", "### Errores comunes a evitar", "- Dejar caer las caderas durante la plancha o la flexión, lo que puede tensar la zona lumbar.", "- Saltarse el salto y acelerar las repeticiones sin mantener la intensidad.", "- Flexiones superficiales que reducen el compromiso de la parte superior del cuerpo.", "- Mecánica de aterrizaje deficiente, como rodillas rígidas o golpe excesivo del talón."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001811111843', 'Zancada de péndulo', 'Pendulum Lunge', 'Piernas', '["- Posición inicial: Párese erguido con los pies separados a la altura de las caderas y las manos entrelazadas en las caderas o delante del pecho para mantener el equilibrio.", "- Estocada hacia adelante: Da un paso hacia adelante con una pierna, bajando las caderas hasta que el muslo delantero esté casi paralelo al piso, manteniendo el torso erguido.", "- Transición: sin detenerte, empuja el pie delantero y mueve la misma pierna hacia atrás en una estocada inversa.", "- Estocada inversa: baje las caderas nuevamente, con la rodilla trasera doblada hacia el suelo mientras la pierna delantera permanece a 90 grados.", "- Regreso al inicio: Empuje con el talón delantero para regresar a la posición inicial, completando un movimiento pendular completo.", "- Repetir: realice las repeticiones deseadas en una pierna antes de cambiar de lado.", "### Consejos para una forma adecuada", "- Mantenga el torso erguido y el núcleo comprometido durante todo el movimiento.", "- Concéntrese en transiciones suaves entre estocadas hacia adelante y hacia atrás.", "- Dé un paso lo suficientemente hacia adelante y hacia atrás para permitir una alineación adecuada de la rodilla a 90 grados.", "- Mantenga una respiración constante: inhale durante el descenso y exhale durante el ascenso.", "### Errores comunes", "- Acelerar el movimiento: Reduce la estabilidad y aumenta el riesgo de lesiones.", "- Permitir que la rodilla colapse hacia adentro: ejerce presión sobre las articulaciones y reduce la activación muscular.", "- Pasos cortos: Impide el rango completo de movimiento, lo que limita la efectividad."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000584266885', 'Puente lateral con mancuernas de una sola pierna', 'Single Leg Dumbbell Side Bridge', 'Abdomen', '["### Posición inicial:", "- Acuéstese de lado. Coloque su antebrazo en el suelo con el codo directamente debajo del hombro.", "- Mantenga el hombro inferior “empacado” (estable), el cuello neutral y las costillas controladas.", "- Coloque las piernas exactamente como se muestra: una pierna permanece recta con el pie en el suelo (esta es su pierna de apoyo). La otra pierna está doblada por la rodilla y levantada, sin apoyarla en el suelo.", "- Una pierna permanece recta con el pie en el suelo (esta es tu pierna de apoyo).", "- La otra pierna se dobla por la rodilla y se levanta, sin apoyarse en el suelo.", "- Sostenga una mancuerna cerca de su costado/cadera con la mano superior.", "### Construya el pilar de apoyo:", "- Presione el pie de apoyo contra el suelo.", "- Presiona el antebrazo contra el suelo.", "- Levante las caderas para que su cuerpo forme una línea fuerte desde el pie de apoyo → caderas → hombro.", "### Estabilizar y bloquear la alineación:", "- Mantenga la pelvis apilada y nivelada; no permita que las caderas se muevan hacia adelante o hacia atrás.", "- Mantenga la tensión a través del costado del núcleo para resistir la flexión lateral.", "- Mantenga la mancuerna pegada al cuerpo para reducir la rotación no deseada.", "### Sostenga y respire:", "- Respira lentamente sin perder la posición.", "- Mantenga estable el hombro de apoyo y evite encogerse de hombros.", "### Cambiar de lado:", "- Bajar con control.", "- Repita en el lado opuesto."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001168977677', 'Curl de martillo unilateral en polea', 'Cable Single Arm Hammer Curl', 'Otros', '["- Coloque el cable en la posición más baja de la polea y sujete una cuerda o un mango en D.", "- Párese de lado de la máquina, agarre el mango con un agarre neutral (con el pulgar hacia arriba).", "- Aléjese un poco de la máquina y apoye su núcleo, manteniendo el brazo a su costado.", "- Doble el mango hacia arriba, flexionando el codo sin rotar la muñeca ni mover el hombro.", "- Apriete en la parte superior y luego baje lentamente el mango hasta la posición inicial.", "- Realice de 8 a 12 repeticiones por brazo, concentrándose en el control y la simetría.", "### Consejos para una forma adecuada", "- Mantenga el codo pegado al torso durante todo el movimiento.", "- Utilice un agarre neutral con el pulgar apuntando hacia arriba para enfatizar el braquial.", "- No balancee ni gire el torso; manténgase erguido y controlado.", "- Exhala mientras te curvas, inhala mientras regresas al fondo.", "- Concéntrese en el tiempo bajo tensión, especialmente durante la fase de descenso.", "### Errores comunes", "- Aprovechar el impulso o inclinarse hacia atrás para levantar el peso.", "- Dejar que el codo se desplace hacia adelante, alejando la tensión de los músculos objetivo.", "- Rotar la muñeca, lo que cambia el patrón de movimiento y reduce la efectividad.", "- Saltarse la fase excéntrica, perdiendo beneficios de fuerza e hipertrofia.", "- Agarrar demasiado flojo, lo que disminuye el compromiso del antebrazo."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-002012327070', 'Paso detrás del lanzamiento de pelota médica rotacional', 'Step Behind Rotational Med Ball Throw', 'Espalda', '["- Comience de lado hacia una pared sólida o un espacio abierto, sosteniendo un balón medicinal liviano (de 2 a 6 kg).", "- Párese erguido con los pies separados a la altura de los hombros y el balón sostenido a la altura de la cintura.", "- Coloque el pie trasero detrás y a través del pie delantero (como un paso cruzado).", "- Cuando su pie trasero aterrice, gire sus caderas hacia la pared y transfiera su peso hacia adelante.", "- Gire explosivamente el torso y los hombros, soltando la pelota con un movimiento de lanzamiento lateral.", "- Permita una rotación completa de la cadera y los hombros, terminando erguido y equilibrado.", "- Reinicie entre repeticiones y repita en el lado opuesto.", "### Consejos para una forma adecuada", "- Empieza ligero (pelota de 2 a 4 kg) para priorizar la velocidad y la mecánica.", "- Da un paso atrás con control, pero gira explosivamente durante el lanzamiento.", "- Mantener el balón cerca del torso antes de soltarlo para evitar armar el lanzamiento.", "- Termine erguido: no se caiga hacia adelante ni se desplome después del lanzamiento.", "- Exhala con fuerza mientras sueltas la pelota para lograr una mayor participación del core.", "- Utilice una pared que no rebote o un campo abierto para mayor seguridad y fluidez.", "### Errores comunes", "- Armar el lanzamiento sin utilizar las caderas y las piernas.", "- Saltarse el paso atrás, haciéndolo más bien un lanzamiento estacionario.", "- Lanzar demasiado pesado, lo que ralentiza la rotación y reduce la transferencia.", "- Rotación excesiva o pérdida de equilibrio después del lanzamiento.", "- No cambiar de bando, creando asimetrías de fuerza."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001971511897', 'Curl Jefferson con mancuernas', 'Dumbbell Jefferson Curl', 'Espalda', '["- Configuración: Párese sobre una pequeña plataforma o escalón para permitir un mayor rango de movimiento. Sostenga una mancuerna liviana en cada mano con los brazos extendidos frente a los muslos.", "- Descenso controlado: comience metiendo la barbilla y luego flexione lentamente la parte superior, media y baja de la espalda en secuencia. Permita que las mancuernas se muevan hacia abajo a medida que avanza gradualmente a través de cada vértebra.", "- Fase de estiramiento: en la parte inferior, deje que las mancuernas cuelguen naturalmente mientras mantiene una ligera tensión, sintiendo un estiramiento profundo de los isquiotibiales y la columna.", "- Regreso al inicio: invierta lentamente el movimiento para regresar a la posición vertical.", "- Repita: realice las series y repeticiones deseadas, centrándose en el control y la segmentación de la columna.", "### Consejos para una forma adecuada", "- Comienza con mancuernas muy ligeras y progresa gradualmente a medida que mejore la movilidad y el control.", "- Mantenga las rodillas rectas pero no bloqueadas para maximizar la participación de los isquiotibiales.", "- Muévase lentamente, tratando el ejercicio como un entrenamiento de fuerza y ​​movilidad.", "- Mantener el control en todo momento; nunca “dejar caer” a la posición inferior.", "### Errores comunes", "- Volverse demasiado pesado y demasiado pronto: la sobrecarga aumenta el riesgo de lesiones y reduce los beneficios de movilidad.", "- Acelerar el movimiento: el ejercicio debe realizarse lentamente para entrenar la segmentación de la columna.", "- Bloqueo de rodillas: puede reducir la activación de los isquiotibiales y aumentar la tensión en las articulaciones."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000424046044', 'Empuje de placa', 'Plate Push', 'Espalda', '["- Coloque una placa de pesas sobre un piso liso (césped, caucho, madera o baldosas).", "- Adopte una postura atlética baja: caderas hacia atrás, pecho hacia abajo, manos en el borde del plato y brazos extendidos.", "- Involucra tu núcleo y conduce a través de las puntas de tus pies para empujar la placa hacia adelante.", "- Mantenga la espalda plana, la cabeza alineada con la columna y evite doblar los hombros.", "- Continúe presionando para ganar distancia o tiempo, usando pasos cortos y poderosos.", "### Consejos para una forma adecuada", "- Mantenga las caderas bajas para involucrar los glúteos y evitar una tensión excesiva en la columna.", "- Conduce desde las piernas, no desde los brazos; la parte inferior del cuerpo debería hacer la mayor parte del trabajo.", "- Mantenga la tensión central para estabilizar la columna durante todo el empujón.", "- Utilice pasos explosivos pero controlados para mantener la tracción y la potencia.", "- Mire ligeramente hacia adelante, no hacia abajo, para mantener una posición neutral del cuello.", "### Errores comunes", "- Estar demasiado erguido, lo que reduce la potencia y la eficiencia.", "- Redondear la espalda, aumentando el riesgo de lesiones.", "- Usando solo tus brazos, en lugar de piernas y core para generar fuerza.", "- Dejar que los talones se levanten excesivamente, lo que disminuye el impulso y la estabilidad.", "- Mala elección de la superficie, generando demasiada fricción o deslizamiento incontrolado."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000523306200', 'Sentadilla en copa con talón elevado', 'Heel-Elevated Goblet Squat', 'Piernas', '["- Párese con los talones elevados sobre discos de pesas, cuñas para sentadillas o una tabla inclinada, y los dedos de los pies apoyados en el suelo.", "- Sostenga una mancuerna o pesa rusa verticalmente al nivel del pecho con ambas manos (agarre de copa).", "- Mantenga el pecho erguido y el núcleo comprometido mientras comienza a descender.", "- Agáchese lentamente, permitiendo que las rodillas avancen sobre los dedos de los pies mientras mantiene el contacto del talón con la superficie elevada.", "- Baje hasta la profundidad máxima, idealmente hasta que las caderas estén debajo de las rodillas, luego presione hacia arriba a través de la parte media del pie y los talones.", "- Realice de 8 a 12 repeticiones, concentrándose en el control y la postura.", "### Consejos para una forma adecuada", "- Utilice una superficie estable (por ejemplo, placas o cuñas) para elevar los talones de manera uniforme.", "- Mantenga el torso erguido, especialmente al final de la sentadilla.", "- Mantenga la mancuerna cerca de su pecho para evitar inclinarse hacia adelante.", "- Permita que las rodillas se desplacen hacia adelante, especialmente para apuntar a los cuádriceps.", "- Apoye su núcleo durante todo el movimiento para proteger su espalda baja.", "### Errores comunes", "- Levantar los dedos de los pies, lo que desestabiliza la sentadilla y desplaza el peso demasiado hacia atrás.", "- Dejar que el pecho caiga hacia adelante, reduciendo el énfasis en los cuádriceps.", "- Usar una elevación inestable o desigual, con riesgo de desequilibrio o mala mecánica.", "- No agacharse lo suficiente, lo que limita la movilidad y la activación de los cuádriceps.", "- Mantener el peso alejado del pecho, lo que aumenta la tensión en los hombros y la columna."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000174051852', 'Curva hacia adelante', 'Forward Bend', 'Espalda', '["Posición inicial: Párese erguido con los pies separados a la altura de las caderas. Mantenga el peso distribuido uniformemente y el core suavemente enganchado.", "Párese erguido con los pies separados a la altura de las caderas.", "Mantenga su peso distribuido uniformemente y el núcleo enganchado suavemente.", "Inicie el movimiento: Inhale y prepárese alargando la columna. Exhale y gire las caderas, permitiendo que el torso se mueva hacia adelante.", "Inhala y prepárate alargando la columna.", "Exhale y gire las caderas, permitiendo que el torso avance.", "Baje hacia el estiramiento: Deje que sus brazos cuelguen naturalmente hacia el piso. Mantenga las rodillas ligeramente dobladas si la flexibilidad de los isquiotibiales es limitada.", "Deje que sus brazos cuelguen naturalmente hacia el suelo.", "Mantenga las rodillas ligeramente dobladas si la flexibilidad de los isquiotibiales es limitada.", "Sostenga y respire: Relaje el cuello y los hombros. Mantenga la posición mientras respira lenta y profundamente.", "Relaja el cuello y los hombros.", "Mantenga la posición mientras respira lenta y profundamente.", "Vuelva a ponerse de pie: active el núcleo y los glúteos. Gire o gire lentamente hacia la posición inicial.", "Involucre su núcleo y glúteos.", "Gire o gire lentamente hasta la posición inicial."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000781873587', 'Plancha tipo sierra (Body Saw)', 'Body Saw Plank', 'Abdomen', '["- Comience con una plancha de antebrazo con los codos debajo de los hombros, los pies juntos y el core comprometido.", "- Mantenga su cuerpo en línea recta desde la cabeza hasta los talones.", "- Mueva su cuerpo hacia adelante, moviendo los hombros frente a los codos, manteniendo el core apretado.", "- Sierra hacia atrás, volviendo los hombros justo detrás de los codos, sin dejar caer la cadera.", "- Continúe este movimiento controlado hacia adelante y hacia atrás durante 30 a 60 segundos, manteniendo la tensión de todo el cuerpo.", "### Consejos para una forma adecuada", "- Involucre sus glúteos y abdominales para evitar que sus caderas se caigan.", "- Mantenga los movimientos pequeños y controlados, sin balanceos excesivos.", "- Mantenga una columna neutra con la cabeza alineada con el cuerpo.", "- Empuje con los dedos de los pies para iniciar el movimiento de aserrado.", "- Concéntrese en la calidad sobre la velocidad o el rango de movimiento.", "### Errores comunes", "- Dejar caer las caderas durante el movimiento hacia atrás, tensionando la zona lumbar.", "- Empujar demasiado hacia adelante, perdiendo tensión y forma.", "- Contener la respiración, lo que reduce el compromiso central.", "- Encogerse de hombros hacia las orejas en lugar de mantener activas las escápulas.", "- Usar el impulso en lugar de la fuerza central para moverse."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000217928637', 'Salto de longitud burpee', 'Burpee Long Jump', 'Cardio', '["- Posición inicial: Párese erguido con los pies separados a la altura de los hombros. Mantenga el núcleo reforzado y los brazos relajados a los lados.", "- Párese erguido con los pies separados a la altura de los hombros.", "- Mantenga su núcleo reforzado y los brazos relajados a los lados.", "- Fase de burpee: Póngase en cuclillas y coloque las manos en el suelo frente a usted. Salte o retroceda los pies hasta una posición de tabla alta. Realice una flexión (opcional pero común en esta variación).", "- Póngase en cuclillas y coloque las manos en el suelo frente a usted.", "- Salta o retrocede con los pies hasta la posición de tabla alta.", "- Realice una flexión (opcional pero común en esta variación).", "- Vuelva a ponerse en cuclillas: salte o dé un paso hacia adelante con los pies para que aterricen justo fuera de sus manos. Mantenga el pecho elevado mientras se prepara para saltar.", "- Salta o da un paso con los pies hacia adelante para que aterricen justo fuera de tus manos.", "- Mantén el pecho elevado mientras te preparas para saltar.", "- Fase de salto de longitud: mueve los brazos hacia atrás y luego salta explosivamente hacia adelante lo más lejos posible. Aterriza suavemente con las rodillas dobladas y el peso distribuido uniformemente.", "- Mueva los brazos hacia atrás y luego salte explosivamente hacia adelante lo más lejos posible.", "- Aterriza suavemente con las rodillas dobladas y el peso distribuido uniformemente.", "- Restablecer: date la vuelta o camina hacia atrás hasta tu punto de partida. Repita hasta obtener el número deseado de repeticiones o distancia.", "- Date la vuelta o camina hacia atrás hasta tu punto de partida.", "- Repita para la cantidad deseada de repeticiones o distancia.", "### Consejos para una forma adecuada", "- Aterriza silenciosamente con las rodillas dobladas para proteger tus articulaciones.", "- Mantenga su núcleo apretado durante las fases de flexión y salto.", "- Usa tus brazos para ganar impulso en el salto de longitud.", "- Concéntrate en los saltos de calidad, no sólo en la distancia.", "### Errores comunes a evitar", "- Colapsar la zona lumbar durante la plancha/flexión.", "- Aterrizar con las piernas rígidas, lo que aumenta el riesgo de lesiones.", "- Apresurarse por la fase de burpee sin control.", "- Dejar que las rodillas se doblen hacia adentro en el aterrizaje del salto de longitud."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001304437687', 'Bisagra de cadera de PVC', 'PVC Hip Hinge', 'Espalda', '["- Párese con los pies separados a la altura de las caderas y las rodillas ligeramente flexionadas.", "- Sostenga un tubo de PVC verticalmente a lo largo de su columna, usando una mano detrás de su cuello y la otra detrás de su espalda baja.", "- Asegúrese de tres puntos de contacto: la parte posterior de la cabeza, entre los omóplatos y el coxis.", "- Comience la bisagra empujando las caderas hacia atrás, manteniendo la columna recta y el PVC en contacto con los tres puntos.", "- Baje el torso hasta que sienta un estiramiento en los isquiotibiales, luego regrese a la posición inicial impulsando las caderas hacia adelante.", "### Consejos para una forma adecuada", "- Mantenga los tres puntos de contacto en el PVC durante todo el movimiento.", "- Doble solo las caderas, no la cintura ni la columna.", "- Mantenga el pecho erguido y los hombros hacia atrás mientras gira.", "- Cambie su peso a los talones, no a los dedos de los pies.", "- Muévete lentamente y con control para reforzar la técnica adecuada.", "### Errores comunes", "- Perder contacto con el PVC en la zona lumbar o cabeza.", "- Doblar la columna, en lugar de doblar las caderas.", "- Permitir que las rodillas se doblen excesivamente, convirtiendo la bisagra en una sentadilla.", "- Empujar las caderas hacia abajo en lugar de hacia atrás.", "- Apresurar el movimiento, lo que reduce la eficacia del ejercicio."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000786206684', 'Balanceos de piernas de adelante hacia atrás', 'Leg Swings Front to Back', 'Espalda', '["- Párese erguido junto a una pared u objeto resistente para mantener el equilibrio.", "- Cambie su peso a una pierna y levante ligeramente la pierna opuesta del suelo.", "- Gire la pierna levantada hacia adelante, manteniendo la rodilla recta o ligeramente doblada.", "- Permita que la pierna se balancee hacia atrás, creando un arco suave de adelante hacia atrás.", "- Realice de 10 a 15 movimientos por pierna, aumentando el rango de movimiento gradualmente con cada repetición.", "- Cambia de lado y repite con la pierna opuesta.", "### Consejos para una forma adecuada", "- Mantenga el torso erguido y el núcleo comprometido durante todo el movimiento.", "- Comience con un rango pequeño y aumente a medida que su cuerpo se caliente.", "- Evite los cambios bruscos o incontrolados; mantener el movimiento fluido.", "- Mantenga el equilibrio sobre la pierna de apoyo, utilizando apoyo sólo si es necesario.", "- Respire constantemente para mantenerse relajado y concentrado en el movimiento.", "### Errores comunes", "- Arquear la zona lumbar, lo que puede tensar la columna.", "- Balancearse con demasiada fuerza, lo que puede provocar un control deficiente o lesiones.", "- Girar las caderas hacia afuera, reduciendo la efectividad del estiramiento.", "- Inclinarse demasiado hacia adelante o hacia atrás, alterando la alineación del cuerpo.", "- Usar el impulso, en lugar del control muscular, para mover la pierna."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001160528962', 'Vacío abdominal de pie', 'Standing Stomach Vacuum', 'Abdomen', '["- Párese erguido con los pies separados a la altura de los hombros y los hombros relajados.", "- Exhale completamente para eliminar el aire de sus pulmones.", "- Dibuja tu ombligo hacia adentro, hacia tu columna, como si intentaras hacer tu cintura lo más pequeña posible.", "- Mantenga la contracción sin inhalar, manteniendo una postura firme durante 10 a 20 segundos.", "- Inhale lentamente para relajarse y repita el proceso durante 3 a 5 series.", "### Consejos para una forma adecuada", "- Realizar en ayunas, preferiblemente por la mañana.", "- Involucre solo los músculos abdominales, no los glúteos ni la parte superior del cuerpo.", "- Mantenga el pecho elevado y la columna neutra.", "- Respire superficialmente si es necesario mientras mantiene el vacío.", "- Progrese lentamente, aumentando el tiempo de espera a medida que mejora la fuerza.", "### Errores comunes", "- Contener la respiración demasiado tiempo, provocando mareos.", "- Succionando el pecho, en lugar de tirar de la parte inferior del abdomen.", "- Utilizar la tensión de la parte superior del cuerpo, en lugar de aislar el núcleo.", "- Realizarse después de una comida, lo que limita la contracción abdominal.", "- Dejar que la postura colapse, reduciendo la efectividad."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001656950990', 'Muscle-up con lastre', 'Weighted Muscle-Up', 'Espalda', '["- Coloque pesas de forma segura en un cinturón de inmersión, chaleco o mochila. Utilice un peso moderado para comenzar.", "- Agarre la barra un poco más ancha que el ancho de los hombros, con un agarre falso o un agarre por encima de la cabeza estándar.", "- Inicie una dominada poderosa, empujando los codos hacia abajo y hacia atrás agresivamente.", "- Haga una transición explosiva sobre la barra, levantando el pecho y moviendo las muñecas hacia arriba.", "- Presione su cuerpo hacia arriba, terminando en una posición de inmersión bloqueada sobre la barra.", "- Bájese bajo control y repita las repeticiones deseadas o mantenga la posición superior para realizar trabajos de estabilidad.", "### Consejos para una forma adecuada", "- Utilice un agarre falso si es necesario para facilitar la transición sobre la barra.", "- Mantenga el núcleo apretado y evite balancearse durante el tirón.", "- Tira alto y rápido, con el objetivo de llevar la parte superior del pecho por encima de la barra rápidamente.", "- Lleva los codos hacia atrás, no sólo hacia arriba, para guiar la transición.", "- Mantenga el control durante el descenso para proteger hombros y codos.", "### Errores comunes", "- Usar demasiado peso demasiado pronto, lo que compromete la forma.", "- Dar saltos o balanceos excesivos, lo que reduce las ganancias de fuerza.", "- Bajando demasiado, lo que hace que la transición sea casi imposible.", "- No entrenar la transición por separado, lo que provoca paradas a mitad de repetición.", "- Ignorando la movilidad, especialmente en hombros y muñecas."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001622679365', 'Caminata de oso (Bear Crawl)', 'Bear Crawl', 'Abdomen', '["- Comience a cuatro patas, con las manos debajo de los hombros y las rodillas debajo de las caderas.", "- Levante ligeramente las rodillas del suelo, manteniéndolas dobladas a unas 2 o 3 pulgadas del suelo.", "- Apoye su núcleo y mantenga la espalda plana durante todo el movimiento.", "- Avanza avanzando simultáneamente con la mano derecha y el pie izquierdo, luego con la mano izquierda y el pie derecho.", "- Continúe hasta la distancia deseada, manteniendo las caderas bajas y el cuerpo alineado.", "### Consejos para una forma adecuada", "- Mantenga las rodillas cerca del suelo para un compromiso óptimo del núcleo.", "- Muévete lenta y deliberadamente para controlar la posición de tu cuerpo.", "- Mantenga una columna neutra, evitando hundirse o arquearse.", "- Minimiza la rotación del torso para una mejor activación del núcleo.", "- Respire constantemente para mantener la tensión sin fatiga.", "### Errores comunes", "- Las caderas se elevan demasiado, lo que reduce la participación del core.", "- Perder la alineación, lo que hace que la columna se doble o se tuerza.", "- Moverse demasiado rápido, sacrificando control y estabilidad.", "- Dejar que las rodillas se desplacen demasiado hacia adelante o fuera de debajo de las caderas.", "- No reforzar el núcleo, lo que conduce a un control y una compensación deficientes."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001540755135', 'Pull-up de la mitad superior', 'Top Half Pull-up', 'Espalda', '["- Párate sobre una caja o salta para que tu barbilla comience por encima de la barra.", "- Baje hasta la mitad (los codos alcanzan aproximadamente una curva de 90 grados).", "- Haz una pausa breve y luego vuelve a subir hasta que tu barbilla vuelva a sobrepasar la barra.", "- Repita de 3 a 8 repeticiones, manteniendo la tensión y el control en todo momento.", "- Evite la extensión total en la parte inferior; permanecer en la mitad superior del rango.", "### Consejos para una forma adecuada", "- Involucre la escápula y los dorsales durante todo el movimiento.", "- Mantenga los codos ligeramente doblados hacia los costados.", "- Evite la relajación total en la parte inferior del rango medio.", "- Respire constantemente para mantener la estabilidad y el ritmo del núcleo.", "- Utilice un tempo controlado para evitar el uso del impulso.", "### Errores comunes", "- Caer demasiado en una repetición completa, frustrando el propósito de la parcial.", "- Encogerse de hombros, lo que limita el compromiso de los dorsales y romboides.", "- Balancearse o dar saltos, reduciendo el tiempo bajo tensión.", "- Dejar que el núcleo se desconecte, lo que lleva a una mala alineación.", "- Despreciando la pausa en la parte inferior del rango superior."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000752379158', 'Muscle-up asistido por banda', 'Band Assisted Muscle-Up', 'Espalda', '["- Pase una banda de resistencia de forma segura sobre una barra de dominadas y coloque los pies o las rodillas en la banda.", "- Agarre la barra firmemente con las manos ligeramente más anchas que el ancho de los hombros, utilizando un agarre falso si es posible.", "- Involucre su núcleo e inicie una dominada poderosa con velocidad hacia la barra.", "- A medida que su pecho se acerca a la barra, inclínese hacia adelante y lleve los codos hacia la transición.", "- Presione hacia arriba en una posición de inmersión hasta que sus brazos estén completamente extendidos.", "- Baje lentamente, regresando a través de la fase de inmersión y dominadas. Repetir.", "### Consejos para una forma adecuada", "- Utilice fuerza de tracción explosiva: esta es la clave para despejar la barra.", "- Practica el falso agarre, que acorta el recorrido de tracción y mejora el apalancamiento.", "- Mantenga el cuerpo tenso para reducir las fugas de energía durante la transición.", "- Inclínese hacia adelante sobre la barra durante la transición para activar los tríceps desde el principio.", "- Controlar el descenso, especialmente al volver por el chapuzón.", "### Errores comunes", "- Depender demasiado de la banda, en lugar de tirar explosivamente.", "- Utilizar un agarre de dominadas estándar, lo que dificulta la transición.", "- Perder tensión central, lo que reduce la producción de energía.", "- No inclinarse hacia adelante, lo que lleva a transiciones fallidas.", "- Ir demasiado rápido, saltándose los pasos técnicos del movimiento."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000156711703', 'Dominadas excéntricas', 'Eccentric Pull-Up', 'Espalda', '["- Utilice una caja o salte para llegar a la posición superior de dominadas (barbilla por encima de la barra).", "- Involucre sus estabilizadores centrales y escapulares.", "- Baje lentamente el cuerpo en línea recta, tardando entre 3 y 8 segundos en alcanzar la extensión completa del brazo.", "- Controla el descenso sin dejarte caer ni balancearte.", "- Da un paso atrás y repite para las repeticiones deseadas.", "### Consejos para una forma adecuada", "- Mantenga su núcleo reforzado para evitar balancearse o arquearse.", "- Baje lentamente para lograr la máxima participación de los músculos (objetivo de 5 a 8 segundos).", "- Involucre su espalda y brazos durante todo el descenso.", "- Evite bloquear los codos repentinamente en la parte inferior.", "- Utilice una caja o un banco para lograr una altura y seguridad constantes.", "### Errores comunes", "- Apresurar el descenso, lo que resta efectividad.", "- Dejar que el cuerpo se balancee, perdiendo tensión y control muscular.", "- No involucrar la escápula, lo que provoca una mala mecánica del hombro.", "- Caer abruptamente, con riesgo de lesiones o tensión en las articulaciones.", "- Saltarse el descanso adecuado entre repeticiones, lo que lleva a una alteración de la forma."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000624365756', 'Fondos en banco a una pierna y un brazo', 'One-Arm Single-Leg Bench Dips', 'Otros', '["- Siéntese en el borde de un banco plano con las piernas extendidas frente a usted y las manos apoyadas en el banco justo afuera de sus caderas.", "- Levanta una pierna del suelo y extiéndela recta.", "- Coloque la mano opuesta detrás de usted en el banco y levante las caderas de la superficie, sosteniendo su cuerpo con ese brazo y su talón apoyado en el suelo.", "- Baje el cuerpo doblando el codo de trabajo, manteniendo la espalda cerca del banco.", "- Desciende hasta que tu codo forme un ángulo de 90 grados o tan bajo como te permita tu movilidad.", "- Empuja con la palma de la mano para volver a la posición inicial.", "- Repita para las repeticiones, luego cambie de lado para equilibrar el entrenamiento.", "### Consejos para una forma adecuada", "- Mantenga el torso erguido y cerca del banco para reducir la tensión en los hombros.", "- Apoye su núcleo en todo momento para estabilizar su cuerpo y evitar torceduras.", "- Baje lentamente y mantenga el control, especialmente al empujar hacia arriba.", "- Extienda completamente la pierna que no trabaja para aumentar el desafío del equilibrio y el compromiso central.", "- Asegúrese de que su codo permanezca metido hacia adentro, sin extenderse hacia afuera durante la inmersión.", "### Errores comunes", "- Inclinarse demasiado hacia adelante, genera tensión en la parte delantera del hombro.", "- Dejar que el torso gire o gire, lo que reduce el control y el aislamiento muscular.", "- Caer demasiado rápido en el chapuzón, lo que corre el riesgo de lesionarse debido a la falta de control.", "- Ensanchando el codo hacia afuera, reduciendo el compromiso del tríceps y aumentando la tensión articular.", "- Usar impulso en lugar de movimientos estrictos y controlados."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000425050528', 'Empujes de cadera con barra', 'Barbell Hip Thrusts', 'Piernas', '["Siéntate en el suelo con la parte superior de la espalda apoyada en un banco y una barra sobre las caderas.", "Haga rodar la barra para que descanse sobre el pliegue de sus caderas, colocando una almohadilla o toalla debajo para mayor comodidad.", "Doble las rodillas y plante los pies planos, separados a la altura de las caderas.", "Apoye su núcleo y empuje los talones para levantar las caderas hacia arriba.", "En la parte superior, aprieta los glúteos y haz una pausa cuando tu torso esté paralelo al suelo.", "Baje lentamente hacia abajo y repita hasta el número deseado de repeticiones."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001800798876', 'Rotaciones de muñeca', 'Wrist Rotations', 'Antebrazos', '["- Párate o siéntate erguido, manteniendo los hombros relajados.", "- Extienda ambos brazos hacia adelante, con los codos ligeramente doblados o bloqueados según su preferencia.", "- Haga los puños flojos o abra las palmas, luego gire las muñecas en círculos lentos y controlados.", "- Realice de 10 a 15 rotaciones en el sentido de las agujas del reloj y luego invierta la dirección durante 10 a 15 repeticiones en el sentido contrario a las agujas del reloj.", "- Respire naturalmente y evite mover los codos u hombros durante el movimiento.", "### Consejos para una forma adecuada", "- Mueva sólo las muñecas, no los antebrazos ni los hombros.", "- Mantenga el movimiento suave, evitando círculos entrecortados o apresurados.", "- Concéntrese en el rango circular completo, no solo en movimientos rápidos hacia adelante y hacia atrás.", "- Relaje los dedos para evitar tensiones innecesarias.", "- Incluir en calentamientos antes de ejercicios de fuerza o con las manos.", "### Errores comunes", "- Mover los codos o los brazos, en lugar de aislar las muñecas.", "- Girar demasiado rápido, lo que reduce la eficacia del cebado de las articulaciones.", "- Olvidar ambos sentidos, limitando la movilidad y el equilibrio muscular.", "- Tensar los antebrazos, generando fatiga o malestar.", "- Olvidar incluirlo en los calentamientos, especialmente antes de los ejercicios de carga de muñeca."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001945577876', 'Limpio y tirón', 'Clean and Jerk', 'Otros', '["- Colóquese con los pies separados a la altura de las caderas, la barra sobre la mitad del pie y las manos ligeramente más anchas que el ancho de los hombros.", "- Fase limpia: Mantenga la espalda plana y el pecho hacia arriba mientras levanta la barra del suelo. Extiéndase explosivamente a través de las caderas y encoja los hombros, tirando de la barra hacia arriba. Déjese caer debajo de la barra y cógela en una posición frontal con los codos en alto.", "- Mantenga la espalda plana y el pecho hacia arriba mientras levanta la barra del suelo.", "- Extiéndete explosivamente a través de las caderas y encógete de hombros, tirando de la barra hacia arriba.", "- Déjate caer debajo de la barra y cógela en una posición frontal con los codos en alto.", "- Fase de sacudida: Sumérgete ligeramente doblando las rodillas, luego conduce hacia arriba a través de las piernas. Divide o empuja debajo de la barra rápidamente, bloqueando los brazos por encima de la cabeza. Estabiliza y párate erguido para completar el levantamiento.", "- Sumérgete ligeramente doblando las rodillas y luego sube por las piernas.", "- Divida o empuje debajo de la barra rápidamente, bloqueando los brazos por encima de la cabeza.", "- Estabilice y párese erguido para completar el levantamiento.", "### Consejos para una forma adecuada", "- Mantenga la espalda apretada durante el tirón inicial para evitar que se doble.", "- Conduce a través de los talones y extiende las caderas completamente antes del agarre.", "- Practique la movilidad del estante delantero para mantener una posición limpia y segura.", "- Utilice un descenso controlado y un impulso agresivo en la fase de sacudida.", "- Coge la barra con una base sólida, especialmente en el split Jerk.", "### Errores comunes", "- Tirar demasiado pronto, lo que reduce la altura de la barra y altera el tiempo.", "- No extender completamente las caderas antes de caer debajo de la barra.", "- Mala posición de la parrilla delantera, lo que provoca inestabilidad en la limpieza.", "- Acelerar el tirón, sin una secuencia adecuada de inmersión y conducción.", "- No lograr estabilizar la cabeza, especialmente bajo fatiga."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000081880134', 'Plancha completa', 'Full Planche', 'Abdomen', '["- Comience en una posición de flexión: comience en una posición de flexión, con las manos ligeramente más separadas que el ancho de los hombros.", "- Involucre el núcleo y los hombros: empuje los hombros hacia adelante y active el núcleo para evitar que la espalda baja se hunda. Tus brazos deben estar rectos y completamente bloqueados.", "- Levante los pies del suelo: levante lentamente las piernas del suelo, manteniéndolas rectas, hasta que su cuerpo forme una línea recta desde la cabeza hasta los dedos de los pies.", "- Equilibrio y sujeción: mientras levanta las piernas, use las manos y los hombros para ayudar a equilibrar el cuerpo en una posición horizontal. Mantén la mirada hacia adelante y concéntrate en mantener la sujeción.", "- Mantenga la posición: mantenga la plancha completa el mayor tiempo posible, concentrándose en el equilibrio y la alineación adecuada del cuerpo. A medida que desarrolle fuerza, trate de aguantar por períodos más prolongados.", "### Consejos para una forma adecuada", "- Mantenga los brazos rectos: asegúrese de que sus brazos estén completamente extendidos y bloqueados a la altura de los codos para evitar tensiones.", "- Involucre el núcleo: apriete los abdominales y los músculos de la espalda baja para mantener una posición recta del cuerpo.", "- Empuje con las manos: presione las manos contra el suelo para estabilizar los hombros y mantener el equilibrio.", "- Concéntrese en su mirada: mantenga la mirada hacia adelante para ayudar con la alineación del cuerpo y evitar una tensión excesiva en el cuello.", "- Trabajar la movilidad de la muñeca: La flexibilidad de la muñeca es crucial para realizar la Plancha Completa sin molestias.", "### Errores comunes", "- Falta de compromiso del core: No involucrar el core puede provocar flacidez de la espalda baja e inestabilidad en el movimiento.", "- Doblar los codos: Doblar los codos compromete la posición y ejerce una tensión excesiva en los brazos y los hombros.", "- Colocación incorrecta de las manos: Colocar las manos demasiado hacia adelante o hacia atrás puede afectar el equilibrio y dificultar el mantenimiento de la posición.", "- No mantener las piernas rectas: Doblar las rodillas reduce la intensidad del ejercicio y hace que la posición sea inestable.", "- Acelerar la progresión: saltarse las progresiones puede provocar lesiones y dificultades para dominar la plancha completa."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001097895064', 'Sentadilla Plie con peso corporal', 'Bodyweight Plie Squat', 'Piernas', '["- Párese con los pies más anchos que el ancho de los hombros y gire los dedos de los pies hacia afuera en un ángulo de aproximadamente 45 grados.", "- Mantenga el pecho erguido y active el núcleo para sostener la columna.", "- Empuje las rodillas alineadas con los dedos de los pies mientras comienza a descender hasta la posición en cuclillas.", "- Doble las rodillas y baje las caderas hacia abajo hasta que los muslos queden paralelos al suelo o ligeramente más bajos.", "- Haga una breve pausa en la parte inferior, manteniendo la espalda recta y el núcleo reforzado.", "- Conduce con los talones para volver a la posición inicial, apretando los glúteos en la parte superior.", "### Consejos para una forma adecuada", "- Mantenga las rodillas alineadas con los dedos de los pies para evitar tensión en las rodillas.", "- Involucre su núcleo en todo momento para apoyar su espalda baja.", "- Evite inclinarse hacia adelante; Mantenga el pecho elevado y la columna neutra.", "- Baja lentamente con control para activar la parte interna de los muslos y los glúteos.", "- Utilice un espejo para comprobar que sus rodillas se desplacen correctamente sobre sus pies.", "### Errores comunes", "- Dejar que las rodillas se doblen hacia adentro, lo que puede forzar las articulaciones y reducir el compromiso de los aductores.", "- Girar demasiado los pies, lo que puede provocar inestabilidad en los tobillos y las rodillas.", "- Inclinarse excesivamente hacia adelante, alejando la carga de los músculos previstos.", "- Apresurar el movimiento, lo que reduce el control y la activación muscular.", "- No ponerse en cuclillas lo suficientemente profundo, lo que limita las ganancias de movilidad y el compromiso muscular."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001910433251', 'Plancha magra', 'Lean Planche', 'Abdomen', '["- Comience en una posición de flexión: comience en una posición de flexión tradicional con las manos ligeramente más separadas que el ancho de los hombros.", "- Empuje los hombros hacia adelante: mientras involucra los brazos y los hombros, empuje el cuerpo hacia adelante, de modo que los hombros se extiendan más allá de las manos. Tus codos deben permanecer rectos.", "- Involucre su núcleo: apriete los músculos centrales para evitar la flacidez en la parte baja de la espalda, manteniendo su cuerpo en línea recta desde la cabeza hasta los pies.", "- Levante los pies del suelo: comience a levantar los pies del suelo cambiando lentamente más peso sobre las manos y ejerciendo más presión sobre su núcleo. Sólo las puntas de los dedos de los pies deben tocar ligeramente el suelo, proporcionando un apoyo mínimo.", "- Mantenga la posición: mantenga la inclinación hacia adelante, manteniendo su cuerpo lo más horizontal posible. Mantenga esta posición durante un tiempo determinado, con el objetivo de aumentar su sujeción a medida que aumenta su fuerza.", "### Consejos para una forma adecuada", "- Estire los brazos: mantenga los brazos completamente extendidos con los codos bloqueados para evitar tensiones y involucrar los hombros de manera más efectiva.", "- Involucrar el núcleo: Tensa los músculos abdominales para evitar que la parte baja de la espalda se arquee o se hunda.", "- Empuje con las palmas: presione activamente el suelo con las palmas para estabilizar el cuerpo y evitar que se incline hacia adelante.", "- Mantenga su mirada neutral: mire ligeramente hacia adelante para ayudar con la alineación del cuerpo y reducir la tensión en el cuello.", "- Comience con pequeñas inclinaciones: comience con una ligera inclinación y aumente gradualmente el ángulo a medida que desarrolla fuerza en los hombros y el tronco.", "### Errores comunes", "- No activar el core: No activar el core puede hacer que la parte baja de la espalda se hunda, disminuyendo la estabilidad y ejerciendo una tensión innecesaria en la columna.", "- Doblar los codos: Doblar los codos compromete la alineación y hace que el ejercicio sea menos efectivo. Mantenga siempre los brazos rectos.", "- Inclinarse demasiado hacia adelante: Extender demasiado la inclinación puede dificultar el mantenimiento del equilibrio. Concéntrate en movimientos controlados y evita ir más allá de tu capacidad.", "- No utilizar soporte para las muñecas: si las muñecas no están alineadas correctamente, puede provocar tensión e incomodidad. Asegúrese de que sus muñecas estén directamente debajo de sus hombros y que los dedos estén separados para un mejor agarre.", "- Saltarse progresiones: intentar realizar la Lean Planche completa sin aumentar gradualmente la inclinación puede provocar una mala forma y posibles lesiones. Utilice progresiones para desarrollar fuerza con el tiempo."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001286303632', 'Press JM con barra', 'Barbell JM Press', 'Otros', '["Acuéstese en un banco plano con una barra colocada encima de usted sobre una rejilla.", "Agarre la barra con las manos un poco más estrechas que el ancho de los hombros (un agarre cercano).", "Saque la barra y colóquela sobre su pecho, con los brazos completamente extendidos.", "Baje la barra hacia su pecho, pero permita que sus codos se desplacen ligeramente hacia adelante como si realizara una extensión de tríceps.", "Detenga la barra entre 1 y 2 pulgadas por encima de su pecho, asegurándose de que sus codos permanezcan doblados y bajo control.", "Presione la barra hacia atrás a la posición inicial extendiendo los codos completamente.", "Repita para el número deseado de repeticiones."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001699839433', 'Press de hombros con barra sentado', 'Seated Barbell Shoulder Press', 'Hombros', '["### ", "- Siéntese derecho en un banco plano, manteniendo los pies planos y plantados ligeramente más anchos que el ancho de las caderas.", "- Coloque la barra a la altura de los hombros sobre una rejilla y sujétela un poco más ancha que el ancho de los hombros.", "- Retire la barra y llévela al nivel de los hombros con los codos ligeramente por delante de la barra.", "- Involucre su núcleo y glúteos para mantener el equilibrio sin respaldo.", "- Presione la barra por encima de su cabeza, extendiendo los brazos sin inclinarse hacia atrás.", "- Baje la barra bajo control hasta la parte superior del pecho o la línea de los hombros.", "### Consejos para una forma adecuada", "- Siéntese erguido y active su núcleo para evitar arquear la zona lumbar.", "- Agarre el suelo con los pies para crear una base estable para sentarse.", "- Mantenga la caja torácica hacia abajo para evitar una extensión excesiva de la columna.", "- Conduce la barra en línea recta, ligeramente detrás de tu cabeza en la parte superior.", "- Exhala mientras presionas e inhala mientras bajas la barra.", "### Errores comunes", "- Inclinándose demasiado hacia atrás, convirtiendo la prensa en una prensa de pecho inclinada.", "- Usar demasiado peso, lo que compromete la forma sin el soporte.", "- Dejar que los codos se ensanchen, lo que tensa las articulaciones de los hombros.", "- Perder el compromiso central, provocando inestabilidad y mala postura.", "- Hacer rebotar la barra contra el pecho, en lugar de controlar el descenso."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001879418228', 'Sentadilla en máquina Smith', 'Smith Machine Squat', 'Piernas', '["### ", "- Coloque la barra a la altura de la parte superior del pecho y cargue el peso deseado. Coloque los pies ligeramente por delante de la barra.", "- Páse debajo de la barra, colóquela sobre los trapecios superiores y agarre un poco más que el ancho de los hombros.", "- Retire la barra girándola ligeramente, luego apoye su núcleo y manténgase erguido.", "- Baje hasta ponerse en cuclillas doblando las rodillas y las caderas, manteniendo el pecho elevado y las rodillas siguiendo los dedos de los pies.", "- Desciende hasta que tus muslos queden al menos paralelos al suelo o más bajos si la movilidad lo permite.", "- Conduce con los talones para empujar hacia atrás hasta la posición inicial, extendiendo completamente las caderas y las rodillas.", "- Repita para las repeticiones, luego vuelva a colocar la barra girándola nuevamente sobre los ganchos.", "### Consejos para una forma adecuada", "- Mantenga los pies ligeramente hacia adelante: esto compensa la trayectoria fija de la barra y reduce la tensión en las rodillas.", "- Involucre su núcleo: estabilice su columna y mantenga el torso erguido.", "- Empuje con los talones: Ayuda a activar los glúteos y mantener el equilibrio.", "- Coloque la barra en las trampas, no en el cuello: previene la tensión y mantiene una mejor postura.", "- Controla cada repetición: evita rebotar o usar el impulso en la parte inferior.", "### Errores comunes", "- Pararse directamente debajo de la barra: limita la profundidad y ejerce presión sobre las rodillas.", "- Redondear la espalda: un control central débil puede provocar lesiones.", "- Levantar los talones: Indica mal equilibrio y reduce la afectación de los glúteos.", "- Sentadilla demasiado superficial: Limita el compromiso y la progresión de los músculos.", "- Dejar que las rodillas se doblen hacia adentro: aumenta el riesgo de lesiones y debilita la alineación."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001965236422', 'Taladros de 5 puntos', '5 Dot Drills', 'Piernas', '["- Coloque cinco marcadores en el suelo en la secuencia A-B-C-D-E para formar el diseño.", "- Párese en los marcadores iniciales, A y B.", "- Comience con los pies juntos en los marcadores A y B.", "- Salta rápidamente hacia adelante hasta el marcador C, asegurándote de que tu pie izquierdo aterrice exactamente en el marcador.", "- Siguiendo el marcador C, realiza otro salto explosivo, pero esta vez separa los pies. Aterriza con un pie en el marcador D y el otro en el marcador E.", "- Ejecute un salto rápido hacia atrás con ambos pies, aterrizando en el marcador C con el pie izquierdo.", "- Inmediatamente realiza otro salto hacia atrás para volver a la posición inicial, marcadores A y B, con ambos pies juntos.", "- Mantener el control y el equilibrio durante todo el movimiento.", "- Duplica la secuencia, esta vez liderando con la pierna derecha. Esfuércese por ejecutar el ejercicio a la máxima velocidad manteniendo la forma adecuada."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001290454928', 'Sentadilla cosaca con mancuernas', 'Dumbbell Cossack Squat', 'Piernas', '["- Sostenga una mancuerna verticalmente frente a su pecho con ambas manos, como si fuera una copa.", "- Párate con los pies abiertos, los dedos ligeramente hacia afuera y el core comprometido.", "- Cambie su peso hacia un lado, doblando la rodilla de trabajo y empujando las caderas hacia atrás mientras la otra pierna permanece recta.", "- Mantenga el pecho elevado y la mancuerna cerca de su cuerpo para mantener el equilibrio.", "- Baje hasta donde la movilidad lo permita, manteniendo el talón plano sobre la pierna doblada y el pie ligeramente girado hacia afuera.", "- Empuje a través del talón de la pierna doblada para volver a ponerse de pie, luego repita del otro lado.", "### Consejos para una forma adecuada", "- Mantenga el torso erguido: evite colapsar hacia adelante apuntalando el núcleo y levantando el pecho.", "- Mantenga el contacto con los pies: mantenga el talón de la pierna en cuclillas apoyado en el suelo en todo momento.", "- Utilice una postura amplia: una postura más amplia permite un descenso lateral más profundo y seguro.", "- Mantenga la mancuerna cerca: esto agrega resistencia y ayuda con el contrapeso.", "- Controla el descenso: Muévete lentamente para mantener el control y proteger las rodillas y las caderas.", "### Errores comunes", "- Redondear la espalda: a menudo causado por dejar que la mancuerna se desplace hacia adelante o por un compromiso débil del core.", "- Levantar el talón demasiado pronto: Mantenga el talón de la pierna doblada en el suelo para lograr estabilidad y compromiso total.", "- Inclinarse demasiado hacia adelante: esto desplaza el peso de los glúteos hacia la columna.", "- Acelerar el movimiento: las repeticiones rápidas reducen el control y aumentan el riesgo de lesiones.", "- No calentar: las caderas frías y los aductores son más propensos a sufrir tensiones durante el movimiento lateral profundo."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000306923619', 'Zancada de reverencia', 'Curtsy Lunge', 'Piernas', '["Colóquese con los pies separados a la altura de las caderas y mantenga las manos frente al pecho para ayudar a mantener el equilibrio.", "Da un paso en diagonal detrás de ti con el pie izquierdo, cruzándolo por detrás de la pierna derecha como si estuvieras haciendo una reverencia.", "Doble ambas rodillas, bajando el cuerpo hasta que el muslo derecho quede paralelo al suelo y la rodilla izquierda casi toque el suelo.", "Empuja con el talón derecho para volver a la posición inicial. Mantenga el torso erguido y el pecho elevado durante todo el movimiento.", "Continúe alternando lados para el número deseado de repeticiones."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000620201598', 'Sentadilla en copa con mancuernas', 'Dumbbell Goblet Squat', 'Piernas', '["- Sostenga una mancuerna verticalmente con ambas manos debajo de la parte superior (el extremo con peso), cerca de su pecho.", "- Párese con los pies separados a la altura de los hombros y los dedos ligeramente hacia afuera.", "- Involucre su núcleo y mantenga su pecho elevado durante todo el movimiento.", "- Empuje las caderas hacia atrás y doble las rodillas, bajando hasta hacer una sentadilla profunda mientras mantiene la mancuerna al nivel del pecho.", "- Mantenga los codos dentro de las rodillas a medida que alcanza la profundidad máxima y evite dejar que las rodillas colapsen hacia adentro.", "- Conduce con los talones para volver a la posición de pie, extendiendo completamente las caderas en la parte superior.", "### Consejos para una forma adecuada", "- Mantenga la mancuerna cerca de su pecho para mantener el equilibrio y la postura erguida.", "- Empuje las rodillas alineadas con los dedos de los pies para evitar el colapso en valgo.", "- Apoye su núcleo durante todo el movimiento para lograr estabilidad.", "- Mantenga una columna neutral y evite inclinarse demasiado hacia adelante.", "- Profundice lo suficiente como para sentir un estiramiento en las caderas y los glúteos mientras mantiene el control.", "### Errores comunes", "- Dejar que la mancuerna se desplace hacia adelante, lo que desplaza el peso y tensiona la zona lumbar.", "- Las rodillas se hunden hacia adentro, lo que reduce la estabilidad de la rodilla y aumenta el riesgo de lesiones.", "- Redondear la parte baja de la espalda, a menudo causado por una movilidad deficiente de la cadera o un compromiso central.", "- Acelerar el movimiento, reduciendo la activación y el control muscular.", "- Sentadillas poco profundas, que limitan el rango de movimiento y el beneficio."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000872421066', 'Lanzamiento rotacional del balón medicinal', 'Medicine Ball Rotational Throw', 'Espalda', '["Posición inicial: Párese a una distancia de entre dos y cuatro pies de la pared, de cara a ella, con un balón medicinal sostenido con ambas manos. Balón medicinal (elija un peso adecuado según su nivel de condición física y sus objetivos).", "Preparación del movimiento: lleve el balón medicinal a la parte trasera de la cadera. Este movimiento inicial implica una rotación del torso mientras cargas la pelota en tu cadera trasera, preparándote para el lanzamiento explosivo.", "Transferencia de peso: transfiera su peso desde la cadera trasera a la cadera delantera. Este cambio dinámico de peso es un componente crucial para generar potencia en el lanzamiento.", "Rotación de cadera: rota tus caderas explosivamente mientras lanzas la pelota contra la pared. La rotación explosiva de la cadera es un elemento clave para generar potencia en este ejercicio. Enfatice el poder generado desde las caderas, no solo los brazos.", "Atrapar y repetir: después de que la pelota rebote en la pared, cógela con ambas manos. Tómate un momento para descansar y luego repite el movimiento."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001334508181', 'Aducción de cadera en plancha lateral', 'Side Plank Hip Adduction', 'Abdomen', '["### ", "### Guía paso a paso", "- Configuración: Colóquese junto a un banco o una superficie elevada. Acuéstese de costado con la pierna superior apoyada en el banco. Apóyese en el antebrazo o la mano, manteniendo la columna neutra.", "- Colóquese junto a un banco o una superficie elevada.", "- Acuéstese de costado con la pierna superior apoyada en el banco.", "- Apóyate sobre tu antebrazo o mano, manteniendo la columna neutra.", "- Involucre su núcleo y levante: presione a través de la pierna superior y levante las caderas en una posición de tabla lateral. La pierna inferior debe colgar debajo del banco. Mantenga su cuerpo en línea recta desde la cabeza hasta los pies.", "- Presione a través de la pierna superior y levante las caderas hasta adoptar una posición de tabla lateral.", "- La pierna de abajo debe colgar debajo del banco.", "- Mantenga su cuerpo en línea recta desde la cabeza hasta los pies.", "- Realice la aducción de la cadera: levante la pierna de abajo hacia la pierna de arriba usando la fuerza interna del muslo. Manténgala brevemente en la parte superior para maximizar la activación muscular. Baje lentamente la pierna de abajo bajo control.", "- Levante la pierna de abajo hacia la pierna de arriba usando la fuerza de la parte interna del muslo.", "- Mantén presionado brevemente en la parte superior para maximizar la activación muscular.", "- Baje lentamente la pierna de abajo bajo control.", "- Repeticiones y series: Realice de 3 a 4 series de 8 a 12 repeticiones por lado, dependiendo de su nivel de condición física.", "- Realiza de 3 a 4 series de 8 a 12 repeticiones por lado, dependiendo de tu nivel de condición física.", "### Consejos para una forma adecuada", "- Involucre su núcleo durante todo el movimiento para mantener el equilibrio.", "- Evite las caderas caídas; mantenga el cuerpo en línea recta desde los hombros hasta los pies.", "- Muévase de manera controlada para maximizar la participación de los músculos y prevenir lesiones.", "- Respire adecuadamente: exhale al levantar la pierna, inhale al bajar.", "- Ajusta la dificultad: si la versión completa es demasiado desafiante, comienza con la rodilla apoyada en el banco en lugar de tu pie.", "### Errores comunes a evitar", "- Dejar caer las caderas: esto reduce la activación del núcleo y los aductores.", "- Usar impulso en lugar de movimiento controlado.", "- Descuidar el compromiso central, lo que lleva a una falta de estabilidad.", "- Comenzando con dificultad excesiva; modifique si es necesario para mantener la forma adecuada.", "- Conteniendo la respiración: respire siempre rítmicamente para apoyar la resistencia muscular."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001371074037', 'Zancada de rodilla alta sobre bosu ball', 'High Knee Lunge on Bosu Ball', 'Piernas', '["- Dale la vuelta a la Bosu Ball para que el lado plano quede hacia arriba.", "- Levante un pie y párese en el centro de la Bosu Ball, asegurándose de que su pie esté centrado en la plataforma.", "- Baje su cuerpo a una posición de estocada inversa.", "- Mientras empuja hacia arriba desde la posición de estocada, levante la rodilla trasera hacia el pecho, llevándola tan alto como le resulte cómodo.", "- La inestabilidad de la superficie activará los músculos estabilizadores. Durante todo el movimiento, mantenga el equilibrio sobre la Bosu Ball. Utilice los músculos centrales y de las piernas para estabilizarse.", "- Después de completar el movimiento con una pierna, retroceda al suelo y cambie a la otra pierna, repitiendo la estocada y el levantamiento alto de la rodilla.", "- Realice el ejercicio durante un número específico de repeticiones o duración de tiempo.", "### Consejos para una forma adecuada", "- Mantenga el pie delantero centrado en el BOSU para mayor estabilidad.", "- Involucre su núcleo durante todo el movimiento para mantener el equilibrio.", "- Levante la rodilla con control, no con impulso, para activar los flexores de la cadera.", "- Asegúrese de que su rodilla delantera permanezca alineada con los dedos de los pies durante la fase de estocada.", "- Utilice los brazos como contrapeso, especialmente durante el impulso de rodilla.", "### Errores comunes", "- Inclinarse demasiado hacia adelante, generando tensión innecesaria en la rodilla o la espalda baja.", "- No retroceder lo suficiente, lo que limita el alcance y la efectividad.", "- Usar el impulso durante la elevación de la rodilla en lugar del control muscular.", "- Perder el equilibrio debido a una mala colocación del pie BOSU o a un movimiento apresurado.", "- Si no se involucran los glúteos, se reducen los beneficios generales de fuerza."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001579547433', 'Empuje de cadera con mancuernas a una pierna', 'Single-Leg Dumbbell Hip Thrust', 'Piernas', '["Configuración: Siéntese en el suelo con la parte superior de la espalda apoyada contra un banco o una superficie elevada. Coloque una mancuerna sobre las caderas y sosténgala de forma segura. Doble las rodillas con un pie apoyado en el suelo y la otra pierna extendida y recta.", "Siéntese en el suelo con la parte superior de la espalda apoyada contra un banco o una superficie elevada.", "Coloque una mancuerna sobre sus caderas y sosténgala firmemente.", "Doble las rodillas con un pie apoyado en el suelo y la otra pierna extendida y recta.", "Posicionamiento del cuerpo: Involucre su núcleo y glúteos antes de comenzar el movimiento. Mantenga la barbilla doblada y la mirada hacia adelante.", "Involucre su núcleo y glúteos antes de comenzar el movimiento.", "Mantenga la barbilla recogida y la mirada hacia adelante.", "Movimiento de empuje: conduzca a través del talón del pie plantado, empujando las caderas hacia arriba. Apriete los glúteos en la parte superior y asegúrese de que las caderas estén completamente extendidas. Mantenga una columna neutra sin arquear demasiado la zona lumbar.", "Conduce a través del talón de tu pie plantado, empujando tus caderas hacia arriba.", "Aprieta los glúteos en la parte superior y asegúrate de que las caderas estén completamente extendidas.", "Mantenga una columna neutra sin arquear demasiado la zona lumbar.", "Fase de descenso: baje lentamente las caderas hasta la posición inicial bajo control. Repita el número deseado de repeticiones y luego cambie de pierna.", "Baje lentamente las caderas hasta la posición inicial bajo control.", "Repita hasta el número deseado de repeticiones, luego cambie de pierna.", "Repeticiones y series: Realice de 3 a 4 series de 8 a 12 repeticiones por pierna, dependiendo de su nivel de condición física.", "Realiza de 3 a 4 series de 8 a 12 repeticiones por pierna, dependiendo de tu nivel de condición física."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000731084701', 'Círculos con las piernas de pie', 'Standing Leg Circles', 'Piernas', '["- Párese erguido con los pies separados a la altura de los hombros y las manos en las caderas o extendidas para mantener el equilibrio.", "- Cambie su peso a una pierna y levante ligeramente el pie opuesto del suelo.", "- Dibuja pequeños círculos en el aire con la pierna levantada, moviéndola hacia adelante, hacia afuera y luego hacia atrás con un movimiento lento y controlado.", "- Realice de 8 a 10 círculos en una dirección y luego invierta la dirección.", "- Cambia de pierna y repite.", "### Consejos para una forma adecuada", "- Mantenga la parte superior del cuerpo erguida y evite inclinarse.", "- Involucre su núcleo para mantenerse equilibrado y estable.", "- Utilice movimientos lentos y controlados en lugar de impulso.", "- Comience con círculos pequeños y aumente gradualmente el alcance.", "- Utilice una pared o una silla como apoyo si es necesario, especialmente para principiantes.", "### Errores comunes", "- Balancear la pierna en lugar de controlar el movimiento.", "- Inclinarse excesivamente hacia un lado, reduciendo los beneficios del equilibrio.", "- Acelerar el movimiento, lo que reduce el compromiso muscular.", "- Olvidar invertir la dirección conduce a un desarrollo desequilibrado.", "- No mantener activada la pierna de apoyo, perderse el entrenamiento de estabilidad."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001468920317', 'Curl Zottman sentado', 'Seated Zottman Curl', 'Otros', '["- Posición sentada: comience sentándose en un banco o silla con la espalda recta y los pies apoyados en el suelo. Esta posición sentada ayuda a estabilizar su cuerpo, aislando los músculos que desea trabajar.", "- Agarre en supinación: sostenga una mancuerna en cada mano con las palmas hacia arriba (agarre en supinación). Comienza con los brazos completamente extendidos, colgando a los costados.", "- Fase de flexión: doble las mancuernas hacia los hombros mientras mantiene la parte superior de los brazos inmóviles. Mientras levantas las pesas, tus palmas deben permanecer hacia arriba.", "- Fase de pronación: en la parte superior del curl, cuando los bíceps estén completamente contraídos, gire las muñecas en la parte superior del movimiento girando las palmas hacia abajo en un agarre en pronación.", "- Regreso a la posición inicial: comience a bajar las mancuernas lentamente hasta la posición inicial, mientras mantiene las palmas hacia abajo. Una vez que sus brazos estén completamente extendidos, gire las muñecas hacia la posición con las palmas hacia arriba y repita el movimiento durante la cantidad deseada de repeticiones.", "### Consejos para una forma adecuada:"]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001359781994', 'Burpee de focas de la Marina', 'Navy Seal Burpee', 'Cardio', '["- Comience desde una posición de pie con los pies separados a la altura de los hombros.", "- Ponte en cuclillas, coloca las manos en el suelo y patea los pies hacia atrás hasta colocarlos en posición de flexión.", "- Realice una flexión y luego lleve la rodilla derecha hacia el codo derecho.", "- Realice una segunda flexión y luego lleve la rodilla izquierda hacia el codo izquierdo.", "- Realice una tercera flexión, luego salte con los pies hacia adelante para volver a la posición en cuclillas.", "- Explota hacia arriba dando un salto, extendiendo la mano por encima de tu cabeza.", "- Aterriza suavemente y repite.", "### Consejos para una forma adecuada", "- Mantenga su núcleo reforzado durante cada flexión y movimiento de rodilla.", "- Controla tu respiración, exhalando durante el esfuerzo e inhalando al bajar.", "- Mantenga los codos en un ángulo de 45 grados durante las flexiones para proteger sus hombros.", "- Mantenga una columna neutra durante las flexiones y los saltos.", "- Aterrice suavemente para reducir el impacto en las articulaciones.", "### Errores comunes", "- Apresurarse en las repeticiones, lo que compromete la forma y aumenta el riesgo de lesiones.", "- Dejar que las caderas se hundan durante las flexiones, lo que genera tensión en la zona lumbar.", "- Saltarse los impulsos de rodilla, lo que reduce la activación del núcleo.", "- Profundidad inconsistente en flexiones o sentadillas.", "- Descuidar el salto, lo que reduce la intensidad metabólica."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000330980901', 'Zancada caminando con mancuernas', 'Dumbbell Walking Lunge', 'Cardio', '["- Sostenga una mancuerna en cada mano, con los brazos extendidos a los lados y las palmas hacia adentro.", "- Párese erguido con los pies separados a la altura de las caderas y active su núcleo.", "- Da un gran paso hacia adelante con la pierna derecha, bajando ambas rodillas hasta que la rodilla trasera quede justo por encima del suelo.", "- Mantenga el pecho erguido y la rodilla delantera directamente por encima del tobillo.", "- Empuja con el talón delantero para levantarte y lleva la pierna trasera hacia adelante para dar el siguiente paso.", "- Continúe alternando piernas mientras camina hacia adelante durante la cantidad deseada de repeticiones o distancia.", "### Consejos para una forma adecuada", "- Mantenga su núcleo comprometido para mantener el equilibrio y la estabilidad.", "- Da un paso lo suficientemente ancho como para que la rodilla delantera no pase los dedos del pie.", "- Mantenga el torso erguido para evitar inclinarse hacia adelante.", "- Controle su ritmo para garantizar la forma adecuada y la activación muscular.", "- Utilice un paso firme y evite apresurarse al dar los pasos.", "### Errores comunes", "- Dejar que las rodillas se doblen hacia adentro, lo que puede dañar la articulación.", "- Dar un paso demasiado corto y ejercer presión sobre la rodilla delantera.", "- Balancear las mancuernas, lo que altera el equilibrio y la postura.", "- Inclinarse excesivamente hacia adelante, desviando el énfasis de las piernas.", "- Permitir que la rodilla trasera caiga al suelo, aumentando el riesgo de lesiones."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000007667569', 'Zancada estática', 'Static Lunge', 'Piernas', '["- Párese con los pies separados a la altura de las caderas.", "- Da un paso hacia adelante con un pie y luego da un paso más grande hacia atrás con el otro pie. Sus pies deben colocarse de manera que cuando baje el cuerpo hacia la estocada, ambas rodillas formen ángulos de 90 grados.", "- Mantenga el torso erguido con el pecho levantado y los hombros relajados. Su núcleo debe estar comprometido para lograr estabilidad.", "- Baje el cuerpo doblando ambas rodillas simultáneamente.", "- Mantenga la posición baja por un momento y luego empuje con el talón del pie delantero para regresar a la posición inicial.", "- Repita el movimiento durante el número deseado de repeticiones en una pierna antes de cambiar a la otra pierna.", "### Consejos para una forma adecuada", "- Mantenga la rodilla delantera alineada con los dedos del pie, sin dejar que se colapse hacia adentro.", "- Mantenga una postura erguida con el pecho levantado y la espalda recta.", "- Involucre su núcleo para lograr equilibrio y estabilidad.", "- Empuja el talón de tu pie delantero para activar los glúteos.", "- Mantenga ambos pies apoyados en el suelo para obtener un apoyo adecuado.", "### Errores comunes", "- Dejar que la rodilla delantera pase los dedos del pie, lo que puede tensar la rodilla.", "- Inclinarse hacia adelante, reduciendo la efectividad de la estocada.", "- Colocar los pies demasiado juntos, lo que afecta la estabilidad.", "- Permitir que el talón trasero se levante, lo que hace perder el equilibrio.", "- Acelerar el movimiento, en lugar de utilizar un movimiento controlado."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000216938185', 'Boxeo de sombras', 'Shadow Boxing', 'Cardio', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000612204680', 'Zancada de poder', 'Power Lunge', 'Piernas', '["Párese con los pies separados a la altura de las caderas.", "Mantenga las manos en las caderas o a los costados para mantener el equilibrio."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000041128797', 'Curl de concentración con barra de pie', 'Standing Barbell Concentration Curl', 'Otros', '["- Comience parándose con los pies separados a la altura de los hombros.", "- Sostenga una barra con ambas manos usando un agarre supinado (con las palmas hacia adelante), con las manos ligeramente más separadas que el ancho de los hombros.", "- Incline la parte superior del cuerpo hacia adelante a la altura de las caderas hasta que quede casi paralela al suelo. Esta inclinación hacia adelante ayuda a aislar los bíceps y a activar los músculos estabilizadores.", "- Coloque los codos sobre los muslos o las rodillas como apoyo, permitiendo que los brazos cuelguen hacia abajo, completamente extendidos.", "- Con la parte superior de los brazos inmóviles, doble la barra hacia el pecho flexionando los codos.", "- Aprieta tus bíceps en la parte superior del movimiento.", "- Baje lentamente la barra hasta la posición inicial, extendiendo completamente los brazos.", "### Consejos para una forma adecuada", "- Elimine el balanceo del cuerpo manteniendo el torso fijo durante todo el levantamiento.", "- Utilice un peso moderado para mantener una forma estricta y evitar reclutar otros músculos.", "- Mantenga la muñeca en posición neutra; evite doblarla hacia adelante o hacia atrás.", "- Exhale mientras curva la barra e inhale mientras baja.", "- Concéntrese en apretar los músculos en lugar de simplemente mover el peso.", "### Errores comunes", "- Usar el impulso: balancear la barra reduce el aislamiento del bíceps.", "- Ensanchando el codo: Mantenga el codo doblado hacia un lado para mantener la alineación.", "- Extender demasiado en la parte inferior: Evite bloquear completamente para mantener la tensión en el músculo.", "- Ir demasiado pesado: El peso excesivo compromete el control y la forma."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000442354200', 'Buenos días con mancuernas', 'Dumbbell Good Morning', 'Espalda', '["### ", "- Sostenga una mancuerna horizontalmente sobre la parte superior de la espalda, no sobre el cuello, agarrando cada extremo con ambas manos.", "- Párese erguido con los pies separados a la altura de las caderas, las rodillas ligeramente flexionadas y el núcleo comprometido.", "- Gire las caderas, empujándolas hacia atrás mientras mantiene la columna neutra y el pecho hacia arriba.", "- Baje el torso hasta que esté casi paralelo al suelo o sienta un estiramiento profundo en los isquiotibiales.", "- Impulsa las caderas hacia adelante para volver a la posición inicial, apretando los glúteos en la parte superior.", "- Repita durante la cantidad deseada de repeticiones, manteniendo el control y la postura en todo momento.", "### Consejos para una forma adecuada", "- Mantenga la espalda plana durante todo el movimiento para proteger su columna.", "- Involucre su núcleo para estabilizar el torso y evitar que se doble.", "- Utilice una ligera flexión de las rodillas para mantener la tensión en los isquiotibiales.", "- Muévete lentamente y con control para concentrarte en la activación muscular.", "- Comience con un peso liviano para dominar el patrón de movimiento de la bisagra de la cadera.", "### Errores comunes", "- Redondear la zona lumbar, lo que aumenta el riesgo de lesiones.", "- Dejar que las rodillas se bloqueen, lo que limita la movilidad y puede provocar tensión.", "- Inclinar la cabeza hacia arriba, lo que altera la alineación de la columna.", "- Sostener la mancuerna en el cuello, lo que ejerce presión sobre la columna cervical.", "- Doblar la cintura en lugar de las caderas, lo que reduce la activación de la cadena posterior."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001630900314', 'Soporte de rana', 'Frog Stand', 'Otros', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
