INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000494068986', 'Press de hombros de pie con mancuernas', 'Standing Dumbbell Shoulder Press', 'Hombros', '["- Párese erguido con los pies separados a la altura de los hombros y las rodillas ligeramente dobladas.", "- Sostenga una mancuerna en cada mano a la altura de los hombros con las palmas hacia adelante.", "- Apoye su núcleo y mantenga el pecho erguido y la columna neutral.", "- Presione las mancuernas sobre su cabeza, extendiendo los brazos sin arquear la espalda.", "- Baje las mancuernas bajo control hasta el nivel de los hombros para completar una repetición.", "- Repita para las repeticiones deseadas, manteniendo una postura estable durante toda la serie.", "### Consejos para una forma adecuada", "- Involucre su núcleo para evitar inclinarse o arquear demasiado la parte baja de la espalda.", "- Aprieta tus glúteos para estabilizar la pelvis y proteger tu columna.", "- Mantenga las muñecas apiladas directamente sobre los codos.", "- Presione las mancuernas ligeramente hacia atrás, no solo hacia arriba, para alinearlas con la mecánica de los hombros.", "- Exhala mientras presionas, inhala mientras bajas.", "### Errores comunes", "- Arquear excesivamente la zona lumbar, lo que genera tensión en la columna.", "- Presionar de manera desigual, provocando un desequilibrio muscular.", "- Permitir que los codos se abran demasiado, con el riesgo de sufrir tensión en los hombros.", "- Usar el impulso de las piernas, lo que reduce el compromiso de la parte superior del cuerpo.", "- Empezar con las mancuernas demasiado delante, lo que puede tensar los hombros."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001173616557', 'Salto en sentadilla búlgaro (Split)', 'Bulgarian Split Squat Jump', 'Piernas', '["Párese frente al banco o dé un paso con los pies separados a la altura de los hombros.", "Coloque el pie izquierdo detrás de usted en el banco o escalón, manteniendo el pie derecho apoyado en el suelo.", "Baje el cuerpo doblando la rodilla y la cadera derechas, manteniendo el pie izquierdo elevado detrás de usted.", "Salta explosivamente con tu pie derecho, agachándote hasta que tu pierna forme un ángulo de 90 grados.", "Baje su cuerpo nuevamente a una posición de 90 grados, luego repita el salto durante la cantidad deseada de repeticiones."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001500280163', 'Zancada con peso corporal', 'Bodyweight Lunge', 'Piernas', '["- Párese erguido con los pies separados a la altura de las caderas.", "- Mantenga su núcleo comprometido y los hombros relajados.", "- Da un gran paso hacia adelante con un pie, asegurándote de que el talón aterrice primero.", "- Mantenga la parte superior del cuerpo erguida, con el pecho elevado y la mirada hacia adelante.", "- Baje el cuerpo doblando ambas rodillas hasta que el muslo delantero quede paralelo al suelo.", "- Asegúrese de que la rodilla trasera quede justo por encima del suelo.", "- Verifique que su rodilla delantera esté directamente encima de su tobillo, formando un ángulo de 90 grados.", "- Evite permitir que la rodilla se extienda más allá de los dedos de los pies para evitar tensiones innecesarias.", "- Empuja con el talón delantero y activa los músculos de las piernas para volver a la posición inicial.", "- Mantenga su peso centrado y distribuido uniformemente entre ambas piernas.", "- Da un paso adelante con el pie opuesto y repite la estocada en el otro lado.", "- Intente realizar el mismo número de repeticiones en cada pierna para mantener el equilibrio y la simetría.", "### Consejos:", "- Permitir que la rodilla delantera se doble hacia adentro: asegúrese de que su rodilla permanezca alineada con su tobillo durante todo el movimiento.", "- Inclinarse demasiado hacia adelante: Mantenga una postura erguida, con el pecho elevado y los hombros relajados.", "- Zancada excesiva: Da un paso cómodo hacia adelante, evitando una longitud excesiva que comprometa el equilibrio y la estabilidad.", "- Descuidar la pierna trasera: Mantenga activa la pierna trasera y evite que se desplome hacia el suelo.", "### Modificaciones para diferentes niveles de condición física:", "- Principiantes: comience con estocadas estacionarias, donde da un paso hacia adelante pero mantiene el movimiento restringido a un rango de movimiento más pequeño. (ejemplo estocada caminando)", "- Intermedio: Progrese a estocadas caminando, donde da un paso adelante y continúa el movimiento alternando las piernas en un movimiento de caminar.", "- Avanzado: agregue resistencia sosteniendo mancuernas o usando un chaleco con peso mientras realiza estocadas."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001353992565', 'Postura del guerrero inverso (Viparita Virabhadrasana)', 'Reverse Warrior Pose (Viparita Virabhadrasana)', 'Otros', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001560921204', 'Postura del guerrero humilde', 'Humble Warrior Pose', 'Otros', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001293111150', 'Lanzamiento de balón medicinal hacia atrás', 'Backward Medicine Ball Throw', 'Espalda', '["Comience parándose con los pies separados a la altura de los hombros, las rodillas ligeramente dobladas y el core comprometido.", "Mantenga un agarre firme de la pelota y asegúrese de que sus muñecas estén rectas.", "Extienda los brazos hacia arriba, elevando completamente el balón medicinal por encima de su cabeza.", "Desde esta posición por encima de la cabeza, lanza con fuerza y ​​explosivamente el balón medicinal hacia atrás.", "Mientras lanzas la pelota hacia atrás, deja que tus brazos sigan el movimiento, extendiéndolos completamente.", "Mantenga una postura recta y active los músculos centrales para brindar estabilidad durante el lanzamiento.", "Recupere el balón medicinal y repita el ejercicio hasta el número deseado de repeticiones."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001534595020', 'Press con mancuernas', 'Dumbbell Push Press', 'Hombros', '["- Posición inicial: Párese con los pies separados a la altura de los hombros. Sostenga una mancuerna en cada mano, con los brazos doblados en un ángulo de 90 grados y las palmas una frente a la otra. Las mancuernas deben colocarse justo fuera de los hombros. Esta es tu posición inicial.", "- Párese con los pies separados a la altura de los hombros.", "- Sostenga una mancuerna en cada mano, con los brazos doblados en un ángulo de 90 grados y las palmas una frente a la otra.", "- Las mancuernas deben colocarse justo por fuera de los hombros. Esta es tu posición inicial.", "- Sumerge las rodillas: Comience el movimiento doblando ligeramente las rodillas, iniciando una pequeña inmersión.", "- Comience el movimiento doblando ligeramente las rodillas, iniciando una pequeña inmersión.", "- Empuje explosivo (fase de conducción): Empuja explosivamente hacia arriba con las piernas. Este impulso de las piernas genera la fuerza necesaria para levantar las mancuernas por encima de la cabeza. Simultáneamente, presione las mancuernas directamente sobre los hombros, extendiendo los brazos completamente en la parte superior del movimiento.", "- Empuja explosivamente hacia arriba con las piernas. Este impulso de las piernas genera la fuerza necesaria para levantar las mancuernas por encima de la cabeza.", "- Al mismo tiempo, presione las mancuernas directamente sobre sus hombros, extendiendo los brazos completamente en la parte superior del movimiento.", "- Posición superior: en la parte superior del movimiento, los brazos deben estar completamente extendidos por encima de la cabeza. Las muñecas deben estar apiladas sobre los hombros y las palmas aún deben estar una frente a la otra.", "- En la parte superior del movimiento, los brazos deben estar completamente extendidos por encima de la cabeza.", "- Tus muñecas deben estar apiladas sobre tus hombros y tus palmas aún deben estar una frente a la otra.", "- Baje las mancuernas: baje las mancuernas a la posición inicial doblando los codos y controlando el descenso. Mantenga una buena forma y control mientras baja las mancuernas.", "- Baja las mancuernas hasta la posición inicial doblando los codos y controlando el descenso.", "- Mantenga una buena forma y control mientras baja las mancuernas.", "- Repetir: realice la cantidad deseada de repeticiones, generalmente dentro de un rango de repeticiones específico según sus objetivos de acondicionamiento físico y el peso que está usando.", "- Realice la cantidad deseada de repeticiones, generalmente dentro de un rango de repeticiones específico según sus objetivos de acondicionamiento físico y el peso que está usando.", "### Consejos:", "- Asegure la forma adecuada: mantenga un núcleo estable, mantenga la espalda recta y evite arquear o redondear la columna.", "- Utiliza un peso adecuado: Comienza con un peso que te permita realizar el ejercicio con buena técnica. Aumente gradualmente el peso a medida que se fortalezca.", "- Tempo controlado: mantenga un ritmo controlado y constante durante las fases de ascenso (presionando las mancuernas) y descenso (bajando las mancuernas) del ejercicio. Evite movimientos bruscos.", "- Calentamiento: Priorice los ejercicios de calentamiento de hombros y el trabajo de movilidad para preparar sus hombros para las demandas del push press."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
