INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000227620532', 'Peso muerto sumo con mancuernas', 'Dumbbell Sumo Deadlift', 'Piernas', '["Configuración: Párese con los pies más separados que el ancho de los hombros y los dedos de los pies apuntando ligeramente hacia afuera. La postura más amplia es una característica clave del peso muerto de sumo. Coloque una mancuerna en el suelo entre sus pies. Puede utilizar una o dos mancuernas, según sus preferencias y el peso con el que se sienta cómodo.", "Párate con los pies más separados que el ancho de los hombros, con los dedos apuntando ligeramente hacia afuera. La postura más amplia es una característica clave del peso muerto de sumo.", "Coloca una mancuerna en el suelo entre tus pies. Puede utilizar una o dos mancuernas, según sus preferencias y el peso con el que se sienta cómodo.", "Agarre las mancuernas: doble las caderas y las rodillas para bajar el cuerpo. Mantenga la espalda recta, el pecho erguido y el core comprometido. Sujete las mancuernas con ambas manos con un agarre por encima de la cabeza (con las palmas una frente a la otra) entre las piernas.", "Doble las caderas y las rodillas para bajar el cuerpo. Mantenga la espalda recta, el pecho erguido y el core comprometido.", "Sujete las mancuernas con ambas manos usando un agarre por encima de la cabeza (con las palmas una frente a la otra) entre las piernas.", "Levantar: Mientras exhala, levántese impulsando los talones, extendiendo las caderas y las rodillas simultáneamente. Mantenga las mancuernas cerca de su cuerpo mientras las levanta. Asegúrese de mantener una columna neutra durante todo el movimiento. No redondees la zona lumbar.", "Mientras exhala, levántese impulsando los talones, extendiendo las caderas y las rodillas simultáneamente. Mantenga las mancuernas cerca de su cuerpo mientras las levanta.", "Asegúrese de mantener una columna neutra durante todo el movimiento. No redondees la zona lumbar.", "Finalizar: En la parte superior del movimiento, manténgase erguido con las caderas completamente extendidas y los hombros hacia atrás. Haga una pausa por un momento y luego invierta el movimiento doblando las caderas y las rodillas para bajar las mancuernas al suelo. Controle el descenso para evitar golpear las pesas contra el suelo.", "En la parte superior del movimiento, mantente erguido con las caderas completamente extendidas y los hombros hacia atrás.", "Haga una pausa por un momento y luego invierta el movimiento doblando las caderas y las rodillas para bajar las mancuernas al suelo.", "Controla el descenso para evitar golpear las pesas contra el suelo.", "Repetir: Realice el número deseado de repeticiones y luego regrese con cuidado las mancuernas a la posición inicial.", "Realice el número deseado de repeticiones y luego regrese con cuidado las mancuernas a la posición inicial."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000113727069', 'Encogimiento de hombros', 'Overhead Shrug', 'Hombros', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000113456674', 'Sentadilla por encima de la cabeza', 'Overhead Squat', 'Piernas', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000890498465', 'Caminata por la pared (Wall Walk)', 'Wall Walk', 'Cardio', '["### Paso 1: Colóquese en una posición de flexión", "- Acuéstese boca abajo en el suelo con los pies apoyados en la pared.", "- Coloque las manos ligeramente más separadas que el ancho de los hombros en una posición de flexión.", "- Mantenga su núcleo comprometido y las piernas rectas.", "### Paso 2: sube los pies por la pared", "- Presione con las manos y comience a caminar con los pies por la pared.", "- Al mismo tiempo, acerque las manos a la pared.", "- Mantenga una línea corporal recta sin arquear la espalda.", "### Paso 3: alcanzar la posición de parada de manos", "- Continúe moviéndose hasta que su pecho esté cerca de la pared y sus brazos estén completamente extendidos.", "- Mantenga esta posición brevemente mientras mantiene el control.", "### Paso 4: caminar de regreso hacia abajo", "- Aleje lentamente las manos de la pared mientras baja los pies al suelo.", "- Mantenga su núcleo apretado y evite que su cuerpo colapse.", "- Regrese a la posición inicial de flexión.", "### Repeticiones y series", "- Los principiantes pueden comenzar con tres a cinco repeticiones con control total.", "- Los atletas avanzados pueden realizar múltiples series o aumentar el tiempo bajo tensión en la posición de parada de manos."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001732204808', 'Puente De Glúteos Con Barra Dos Piernas En Banco', 'Barbell Glute Bridge Two Legs on Bench', 'Piernas', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001442308876', 'Transporte Zercher', 'Zercher Carry', 'Otros', '["- Coloque una barra en una rejilla para sentadillas a la altura de la cintura.", "- Sube a la barra, dobla los brazos y coloca la barra en la curva de los codos. Mantenga los puños juntos y los codos debajo de la barra.", "- Levante la barra manteniéndose erguido, apuntalando su núcleo y manteniendo su pecho alto.", "- Camine hacia adelante con pasos pequeños y controlados, manteniéndose erguido y evitando inclinarse hacia atrás o curvar la columna.", "- Continúe caminando durante una distancia o tiempo determinados, luego baje la barra con cuidado hacia el estante o sobre las almohadillas.", "### Consejos para una forma adecuada", "- Mantenga los codos doblados y pegados al cuerpo durante toda la caminata.", "- Aprieta tu núcleo con fuerza antes de cada paso.", "- Mantenga una postura erguida, evitando inclinarse hacia atrás para compensar la carga.", "- Utilice una toalla o almohadilla si es necesario para reducir la presión sobre los codos.", "- Comience ligero para concentrarse en la forma antes de progresar con la carga.", "### Errores comunes", "- Dejar que la barra se hunda relajando el núcleo o la parte superior de la espalda.", "- Inclinarse excesivamente hacia atrás, ejerciendo presión sobre la columna lumbar.", "- Mantener la barra demasiado baja, lo que puede alterar el equilibrio y estresar los hombros.", "- Zancadas excesivas, lo que hace que la caminata sea inestable e ineficiente.", "- Descuidar la respiración, lo que reduce la tensión central y el control."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000412766800', 'Montar bicicleta al aire libre', 'Riding Outdoor Bicycle', 'Cardio', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000524273606', 'Peso muerto con mancuernas', 'Dumbbell Deadlift', 'Piernas', '["Configuración: Párese con los pies separados a la altura de las caderas. Coloque una mancuerna a cada lado de sus pies. Las mancuernas deben colocarse paralelas a sus pies, de modo que las manijas queden perpendiculares a su cuerpo.", "Párese con los pies separados a la altura de las caderas. Coloca una mancuerna a cada lado de tus pies.", "Las mancuernas deben colocarse paralelas a tus pies, de modo que los mangos queden perpendiculares a tu cuerpo.", "Postura: Doble las caderas y las rodillas para bajar. Mantenga la espalda recta, el pecho hacia arriba y los hombros hacia atrás. Sujete las mancuernas con un agarre firme, con las palmas hacia el cuerpo. Tus manos deben estar justo fuera de tus rodillas.", "Doble las caderas y las rodillas para bajar.", "Mantenga la espalda recta, el pecho hacia arriba y los hombros hacia atrás.", "Sujete las mancuernas con un agarre firme, con las palmas hacia el cuerpo. Tus manos deben estar justo fuera de tus rodillas.", "Levantamiento: Empuje con los talones y levante las mancuernas enderezando las caderas y las rodillas. Mantenga una columna neutra durante todo el movimiento. No doble la espalda. Mantenga las mancuernas cerca de su cuerpo mientras las levanta. Párese completamente erguido con el pecho hacia afuera y los hombros hacia atrás.", "Empuja con los talones y levanta las mancuernas enderezando las caderas y las rodillas.", "Mantenga la columna neutra durante todo el movimiento. No redondees tu espalda.", "Mantenga las mancuernas cerca de su cuerpo mientras las levanta.", "Párese completamente erguido con el pecho hacia afuera y los hombros hacia atrás.", "Bajar: invierta el movimiento empujando primero las caderas hacia atrás y luego doblando las rodillas para bajar las mancuernas al suelo. Mantenga las mancuernas cerca de su cuerpo y mantenga una buena forma.", "Invierta el movimiento empujando primero las caderas hacia atrás y luego doblando las rodillas para bajar las mancuernas al suelo.", "Mantén las mancuernas cerca de tu cuerpo y mantén una buena forma.", "Repetición: repita el levantamiento durante el número deseado de repeticiones. Exhale mientras levanta las mancuernas e inhale mientras las baja.", "Repita el levantamiento durante el número deseado de repeticiones.", "Exhala mientras levantas las mancuernas e inhala mientras las bajas."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-002018983591', 'Elevación de tronco (Log Lift)', 'Log Lift', 'Otros', '["- Párese con los pies separados al ancho de los hombros y coloque las manos sobre el tronco o la barra, manteniendo el agarre separado al ancho de los hombros.", "- Mantenga la espalda recta, doble las rodillas y levante el tronco, llevándolo hasta la cintura.", "- Con el tronco apoyado sobre su cintura, respire profundamente, apriete su núcleo y use sus piernas para empujar hacia arriba, levantando el tronco hasta su hombro.", "- Una vez que el tronco esté sobre su hombro, sosténgalo firmemente, manteniendo el codo cerca del costado y manténgase de pie.", "- Haga una pausa de unos segundos y luego baje el tronco hasta la cintura, manteniendo el control del peso durante todo el movimiento."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000917409784', 'Martillo para neumáticos', 'Tire Sledge Hammer', 'Otros', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
