INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000221426388', 'Elevaciones de brazos laterales', 'Side Arm Raises', 'Hombros', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001806304709', 'Ergómetro de esquí', 'Ski Ergometer', 'Otros', '["Posición inicial: Párese frente a la máquina con los pies separados a la altura de los hombros. Agarre las manijas firmemente con ambas manos.", "Involucre el núcleo y las caderas: incline ligeramente las caderas, mantenga las rodillas suaves y active los músculos centrales.", "Movimiento de tracción: mueva las manijas hacia abajo con un movimiento fuerte usando dorsales, hombros, tríceps y core. Doble ligeramente las rodillas y active la parte inferior del cuerpo para generar más potencia.", "Finalizar: Extienda los brazos completamente hacia abajo cerca de los muslos mientras mantiene la postura erguida y controlada.", "Recuperación: Regresar las manijas suavemente a la posición inicial, manteniendo el ritmo y el control."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000520405715', 'Extensión de tríceps en polea a un brazo', 'One Arm Cable Triceps Pushdown', 'Tríceps', '["- Configure el equipo Coloque una manija única en la polea alta de una máquina de cable. Seleccione un peso apropiado que permita un movimiento controlado.", "- Conecte una sola manija a la polea alta de una máquina de cable.", "- Seleccione un peso apropiado que permita un movimiento controlado.", "- ColóquesePárate con los pies separados al ancho de los hombros para mantener el equilibrio.Agarra el mango con un agarre por encima de la cabeza (con la palma hacia abajo).Mantén el codo cerca del torso y mantén las rodillas ligeramente dobladas.", "- Párese con los pies separados a la altura de los hombros para mantener el equilibrio.", "- Agarre el mango con la palma hacia abajo.", "- Mantenga el codo cerca del torso y mantenga las rodillas ligeramente dobladas.", "- EjecuciónExhale mientras empuja el mango hacia abajo extendiendo el codo por completo. Mantenga la muñeca en posición neutral y evite doblarla durante el movimiento. Baje el mango hasta que su brazo esté completamente extendido pero no bloqueado. Haga una breve pausa en la parte inferior para maximizar el compromiso de los tríceps. Inhale mientras regresa lentamente a la posición inicial con control.", "- Exhale mientras empuja el mango hacia abajo extendiendo el codo por completo.", "- Mantenga la muñeca neutral y evite doblarla durante el movimiento.", "- Baje la manija hasta que su brazo esté completamente extendido pero no bloqueado.", "- Haga una breve pausa en la parte inferior para maximizar la participación de los tríceps.", "- Inhala mientras regresas lentamente a la posición inicial con control.", "- Repetir Realice el número deseado de repeticiones antes de cambiar de brazo.", "- Realice el número deseado de repeticiones antes de cambiar de brazo.", "### Consejos para una forma adecuada", "- Mantenga una columna neutra y evite inclinarse hacia adelante o hacia atrás.", "- Mantenga el codo inmóvil para asegurarse de que los tríceps hagan el trabajo.", "- Utilice un movimiento controlado en lugar de depender del impulso.", "- Involucre sus músculos centrales para estabilizar su cuerpo.", "- Ajuste el peso en consecuencia para mantener la forma adecuada durante toda la serie.", "### Errores comunes a evitar", "- Usar demasiado peso, lo que puede provocar una forma inadecuada y una reducción de la activación del tríceps.", "- Dejar que el codo se desplace hacia adelante o hacia afuera, reduciendo la efectividad del ejercicio.", "- Depender del impulso en lugar del compromiso muscular controlado.", "- Doblar excesivamente la muñeca, lo que puede provocar tensión y reducir la eficiencia.", "- No extender completamente el codo, limitando la activación del tríceps."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001511498407', 'Caminando', 'Walking', 'Cardio', '["Caminar es una de las actividades físicas más sencillas. Esta sencilla actividad te permite trabajar muchos grupos de músculos grandes y pequeños de la parte inferior del cuerpo. Además, caminar consume algo de energía y, si tu objetivo es quemar calorías, puedes crear un mayor déficit calórico caminando junto con tu dieta nutricional."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001433963109', 'Tijeras para brazos', 'Arm Scissors', 'Hombros', '["Posición inicial: Párese erguido con los pies separados a la altura de las caderas.", "Extienda los brazos: Estire los brazos hacia los lados a la altura de los hombros.", "Cruzar: balancee los brazos sobre el pecho, superponiendo uno sobre el otro como si fueran tijeras.", "Regresar y repetir: abra los brazos hacia los lados y repita durante 15-20 repeticiones."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000148439703', 'Caminar a paso ligero', 'Briskly Walking', 'Cardio', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000483372975', 'Pull-in de pierna de banco sentado', 'Seated Bench Leg Pull-in', 'Abdomen', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-002128365536', 'Flexión lateral del cuello con peso', 'Weighted Lateral Neck Flexion', 'Espalda', '["Sujete firmemente el arnés para la cabeza a su cabeza y sujete una placa de pesas.", "Acuéstese de costado en un banco inclinado con la cabeza extendida hacia el extremo.", "Baje la placa de pesas suspendida por el arnés para la cabeza sobre el suelo.", "Baje la cabeza hasta que sienta un leve estiramiento en el lado opuesto del cuello."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001229773819', 'Colgar con barra limpia', 'Barbell Hang Clean', 'Otros', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001811812806', 'Sprint', 'Sprint', 'Cardio', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001079530081', 'Correr', 'Running', 'Cardio', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001406173796', 'Crunch en polea de pie', 'Standing Cable Crunch', 'Cardio', '["Coloque la máquina de cable en una posición alta y sujete una cuerda o mango al cable.", "Párese de espaldas a la máquina con los pies separados a la altura de los hombros.", "Agarre la cuerda o el asa con ambas manos, colocándolas cerca de las orejas o las sienes.", "Aléjese uno o dos pasos de la máquina para crear tensión en el cable.", "Colóquese de modo que sus codos apunten hacia los lados y la parte superior de su cuerpo esté erguida.", "Inicie el movimiento doblándose por la cintura y llevando los codos y la cabeza hacia abajo, hacia las rodillas.", "Mientras haces abdominales, concéntrate en contraer los músculos abdominales y exhalar.", "Mantenga la posición de abdominales brevemente, apretando los abdominales.", "Regrese lentamente a la posición inicial extendiendo el torso hacia arriba, permitiendo que los brazos se extiendan por completo.", "Repita hasta el número deseado de repeticiones."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000337065031', 'Press de hombros en máquina Smith', 'Smith Machine Shoulder Press', 'Hombros', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001745019437', 'Escalador de montaña de cuerpo cruzado', 'Cross Body Mountain Climber', 'Abdomen', '["Comience en una posición de tabla alta con las manos directamente debajo de los hombros y el cuerpo formando una línea recta desde la cabeza hasta los talones.", "Involucre sus músculos centrales llevando su ombligo hacia su columna y manteniendo un núcleo estable durante todo el ejercicio.", "Levanta el pie derecho del suelo y lleva la rodilla derecha hacia el codo izquierdo, cruzando el cuerpo en diagonal.", "Mientras acercas la rodilla, involucra tu core y mantén una posición de tabla fuerte.", "Extiende tu pierna derecha hacia la posición inicial mientras repites simultáneamente el movimiento en el otro lado.", "Levanta el pie izquierdo del suelo y lleva la rodilla izquierda hacia el codo derecho, cruzando el cuerpo en diagonal.", "Repita durante la cantidad deseada de repeticiones o siga un período de tiempo establecido para su entrenamiento."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001169608148', 'Elevación lateral con mancuernas', 'Dumbbell Lateral Raise', 'Espalda', '["### ", "- Posición inicial: Párese erguido con los pies separados a la altura de los hombros, sosteniendo las mancuernas a los costados con las palmas hacia adentro.", "- Prepárese y alinee: active los músculos centrales y doble ligeramente las rodillas para mantener la estabilidad.", "- Movimiento: Levante las mancuernas hacia los costados, manteniendo una ligera flexión de los codos y las muñecas rectas. Levanta las mancuernas hasta que tus brazos lleguen al nivel de los hombros, paralelos al suelo.", "- Retorno controlado: baje las pesas lenta y suavemente hasta la posición inicial mientras mantiene el control y la tensión en los hombros.", "- Repetir: continúe durante la cantidad deseada de repeticiones, generalmente de 10 a 12 repeticiones.", "### Consejos para una forma adecuada:", "- Mantenga su núcleo comprometido y la columna neutral durante todo el movimiento.", "- No se balancee ni utilice el impulso; Levante pesas lentamente y con movimientos controlados.", "- Mantenga los codos ligeramente doblados para evitar tensión en las articulaciones.", "- Concéntrese en levantar los codos en lugar de las muñecas para enfatizar la activación del deltoides.", "### Errores comunes:", "- Levantar demasiado peso: elegir pesas pesadas a menudo resulta en una mala forma y un uso excesivo del impulso, lo que reduce la efectividad y aumenta el riesgo de lesiones.", "- Levantar mancuernas demasiado alto: evite levantar mancuernas por encima del nivel de los hombros para evitar tensiones innecesarias en las articulaciones de los hombros.", "- Flexión excesiva del codo: Demasiada flexión de los codos reduce la carga de trabajo en los hombros y desplaza la tensión a otros lugares. Mantenga sólo una ligera curvatura."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001173493663', 'Círculos de brazos', 'Arm Circles', 'Hombros', '["Párese erguido con los pies separados a la altura de las caderas y los brazos extendidos a los lados a la altura de los hombros.", "Involucre su núcleo y mantenga su columna neutral para mantener una buena postura.", "Comience a hacer pequeños círculos hacia adelante con los brazos, aumentando gradualmente el tamaño.", "Realice durante 20 a 30 segundos, luego invierta la dirección durante el mismo período.", "Baja los brazos y sacúdelos después de completar ambas direcciones."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000818094778', 'Press de hombros con mancuernas', 'Dumbbell Shoulder Press', 'Hombros', '["### ", "- Posición inicial: Siéntese en un banco con respaldo o párese con los pies separados a la altura de las caderas. Sostenga una mancuerna en cada mano a la altura de los hombros con las palmas hacia adelante o ligeramente hacia adentro.", "- Prepárese y alinee: active su núcleo, mantenga la columna neutral y retraiga los omóplatos ligeramente.", "- Presione sobre la cabeza: presione las mancuernas hacia arriba y ligeramente hacia adentro hasta que sus brazos estén completamente extendidos sin bloquear los codos.", "- Baja bajo control: baja lentamente las mancuernas hasta la altura de los hombros manteniendo el control y la tensión.", "### Consejos para una forma adecuada", "- Mantenga sus muñecas neutrales y alineadas con sus antebrazos.", "- Evite arquear demasiado la zona lumbar; refuerce el núcleo para mantener la integridad de la columna.", "- Presione formando un ligero arco en lugar de hacerlo directamente sobre la cabeza para mayor comodidad en las articulaciones.", "### Errores comunes", "- Inclinarse hacia atrás excesivamente y convertir el press en un press de pecho inclinado.", "- Usar el impulso para “rebotar” las mancuernas sobre tu cabeza.", "- Ensanchar demasiado los codos, estresando las articulaciones de los hombros."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001983780032', 'Elevación lateral del cable', 'Cable Lateral Raise', 'Espalda', '["### ", "- Para comenzar: párese junto a una máquina de cable con la polea en la posición más baja. Agarre el mango del lado opuesto con la mano más alejada de la polea, manteniendo la palma hacia adentro.", "- Establece tu postura: mantén el core comprometido, el pecho elevado y los hombros relajados. Mantenga una ligera flexión del codo durante todo el levantamiento.", "- Levante el peso: levante el brazo hacia un lado hasta que el codo alcance la altura del hombro, manteniendo la muñeca alineada con el codo.", "- Pausa y baja: haz una breve pausa en la parte superior, luego baja lentamente la manija hacia tu costado con control. Repita para las repeticiones deseadas.", "### Consejos para una forma adecuada", "- Mantenga los trapecios relajados y evite encogerse de hombros mientras levanta.", "- Dirija el movimiento con el codo, no con la mano, para activar el deltoides lateral.", "- Utilice un peso más ligero con un ritmo controlado para evitar el impulso.", "### Errores comunes", "- Usar peso excesivo, lo que lleva a balancearse o a tener mala forma.", "- Doblar demasiado el codo y convertir la elevación en una elevación frontal.", "- Encogerse de hombros y activar los trapecios superiores en lugar de aislar los deltoides."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001273707785', 'Máquina de olas a pie', 'Walk Wave Machine', 'Cardio', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000581983824', 'Flexión del cuello acostado con peso (arnés de cuello)', 'Weighted Lying Neck Flexion (Neck Harness)', 'Hombros', '["Configure su equipo: Utilice un arnés para el cuello diseñado para levantamiento de pesas. Conecte de forma segura una pequeña placa de pesas a la cadena del arnés. Asegúrese de que el arnés se ajuste cómodamente alrededor de su cabeza sin causar molestias.", "Utilice un arnés para el cuello diseñado para levantamiento de pesas. Conecte de forma segura una pequeña placa de pesas a la cadena del arnés.", "Asegúrese de que el arnés se ajuste cómodamente alrededor de su cabeza sin causar molestias.", "Prepare el banco: Coloque un banco de ejercicios con una inclinación de 45 grados. Siéntese en el banco e inclínese hacia atrás para que la parte superior de su espalda quede apoyada mientras su cabeza se extiende más allá del borde del banco.", "Coloque un banco de ejercicios con una inclinación de 45 grados.", "Siéntese en el banco e inclínese hacia atrás para que la parte superior de su espalda quede apoyada mientras su cabeza se extiende más allá del borde del banco.", "Posición inicial: Coloque el arnés para el cuello en su cabeza, asegurándose de que esté centrado. Deje que su cabeza cuelgue ligeramente hacia atrás en una posición neutral.", "Coloque el arnés para el cuello en su cabeza, asegurándose de que esté centrado.", "Deje que su cabeza cuelgue ligeramente hacia atrás en una posición neutral.", "Ejecute el movimiento: Flexione el cuello hacia adelante, llevando la barbilla hacia el pecho en un movimiento lento y controlado. Haga una breve pausa en la parte superior del movimiento para contraer completamente los músculos del cuello. Regrese lentamente la cabeza a la posición inicial, resistiendo el peso a medida que baja.", "Flexiona el cuello hacia adelante, llevando la barbilla hacia el pecho con un movimiento lento y controlado.", "Haga una pausa breve en la parte superior del movimiento para contraer completamente los músculos del cuello.", "Regrese lentamente la cabeza a la posición inicial, resistiendo el peso a medida que baja.", "Repeticiones: realice de 2 a 4 series de 8 a 15 repeticiones según su nivel de condición física y sus objetivos.", "Realice de 2 a 4 series de 8 a 15 repeticiones según su nivel de condición física y sus objetivos."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000678958746', 'Remo con mancuernas inclinado de 45 grados', '45 Degree Incline Dumbbell Row', 'Espalda', '["### ", "- Posición inicial: ajuste un banco inclinado a un ángulo de 45 grados. Acuéstese boca abajo en el banco con el pecho firmemente presionado contra él. Sostenga las mancuernas con los brazos extendidos directamente debajo de los hombros, con las palmas hacia adentro.", "- Alineación y agarre: Mantenga el cuello neutral, la columna alineada y el núcleo ligeramente enganchado para estabilizar el cuerpo.", "- Movimiento de tracción: tire de las mancuernas hacia arriba, doblando los codos y retrayendo los omóplatos, levantándolas hasta que los codos se alineen con el torso o ligeramente más arriba.", "- Descenso controlado: Baja lentamente las mancuernas hasta la posición inicial, extendiendo completamente los brazos sin liberar la tensión de los hombros.", "- Repetir: complete de 8 a 12 repeticiones controladas por serie, concentrándose en movimientos suaves y deliberados.", "### Consejos para una forma adecuada:", "- Enganche los omóplatos apretándolos en la parte superior del movimiento.", "- Evite el impulso excesivo o el balanceo; levantar pesas con movimiento controlado.", "- Mantenga una posición neutral del cuello y la columna en todo momento.", "- Utilice un peso manejable para garantizar la técnica y la activación muscular adecuadas.", "### Errores comunes:", "- Levantar demasiado peso: el peso excesivo genera impulso, mala forma y activación muscular reducida.", "- Redondear los hombros: Permitir que los hombros se doblen hacia adelante puede comprometer la postura y reducir la efectividad.", "- Rango de movimiento incompleto: no contraer completamente los músculos de la espalda limita el desarrollo muscular potencial."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001564428609', 'Prensa detrás del cuello en máquina Smith', 'Smith Machine Behind The Neck Press', 'Hombros', '["- Posición inicial: siéntese en un banco vertical o párese dentro de la máquina Smith, colocándose de modo que la barra descanse detrás de su cabeza, justo por encima de la altura de los hombros.", "- Agarre y postura: Sujete la barra con un agarre por encima de la cabeza ligeramente más ancho que el ancho de los hombros. Involucre su núcleo y mantenga el torso erguido.", "- Movimiento de presión: Empuja la barra hacia arriba extendiendo completamente los brazos, manteniendo la cabeza ligeramente hacia adelante para evitar el contacto.", "- Descenso controlado: baje lentamente la barra detrás del cuello hasta que los codos formen un ángulo de aproximadamente 90 grados, manteniendo la tensión controlada en los hombros.", "- Repetir: complete las repeticiones deseadas, generalmente de 8 a 12 repeticiones por serie.", "### Consejos para una forma adecuada:", "- Realice siempre este ejercicio de forma lenta y bajo control.", "- Evite el uso de pesos excesivamente pesados ​​para mantener la seguridad de los hombros.", "- Mantenga el núcleo tenso y la columna neutra para garantizar la estabilidad.", "- Asegúrese de que la barra se desplace verticalmente a lo largo de los rieles de la máquina Smith.", "### Errores comunes:", "- Peso excesivo: usar una carga demasiado pesada puede tensar las articulaciones de los hombros y provocar lesiones.", "- Ruta de barra incorrecta: Permitir que la barra se desplace hacia adelante o hacia atrás fuera de la ruta guiada aumenta el riesgo de lesiones.", "- Movimiento rápido: realizar el ejercicio demasiado rápido reduce la activación muscular y aumenta el potencial de lesiones."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001492037371', 'Curl de muñeca neutro sentado con mancuernas', 'Dumbbell Seated Neutral Wrist Curl', 'Antebrazos', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000595909406', 'Press militar de pie con agarre cerrado', 'Standing Close Grip Military Press', 'Hombros', '["Párese con los pies separados a la altura de los hombros.", "Agarre la barra con un agarre ligeramente más estrecho que el ancho de los hombros. Las palmas de las manos deben mirar hacia adelante y los codos deben estar ligeramente por delante de la barra.", "Levante la barra del soporte o límpiela hasta el nivel de los hombros y manténgala allí con la parte superior de los brazos paralela al suelo. Esta es tu posición inicial.", "Respire profundamente, refuerce su núcleo y active sus glúteos para lograr estabilidad.", "Presione la barra hacia arriba de manera controlada extendiendo los brazos por encima de la cabeza. Mantenga los codos apuntando hacia adelante y las muñecas en posición neutral.", "Continúe presionando hasta que sus brazos estén completamente extendidos y la barra esté directamente sobre su cabeza. Asegúrese de mantener la forma adecuada y evite arquear excesivamente la zona lumbar.", "Haga una breve pausa en la parte superior y luego baje lentamente la barra a la posición inicial doblando los codos y bajándola bajo control.", "Repita hasta el número deseado de repeticiones."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000926648027', 'Curl de muñeca inverso con barra', 'Barbell Reverse Wrist Curl', 'Antebrazos', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001189378361', 'Press de hombros con palanca', 'Lever Shoulder Press', 'Hombros', '["- Posición inicial: Siéntese erguido en la máquina de prensa de hombros con palanca, asegurándose de que su espalda esté firmemente contra la almohadilla. Ajuste la altura del asiento de modo que las manijas queden al nivel de los hombros.", "- Agarre y alineación: Sujete las manijas de la máquina con un agarre por encima de la cabeza. Tus brazos deben estar hacia los lados, mirando hacia adelante, con los codos colocados directamente debajo de tus manos.", "- Movimiento de presión: presione las manijas hacia arriba extendiendo los codos completamente, empujando a través de los hombros hasta que los brazos queden rectos por encima de la cabeza, pero evite bloquear los codos por completo.", "- Descenso controlado: baje lentamente las manijas hasta el nivel de los hombros, manteniendo el control y la tensión durante todo el movimiento.", "- Repetir: realice el ejercicio de 8 a 12 repeticiones por serie, asegurando movimientos suaves y controlados.", "### Consejos para una forma adecuada:", "- Mantenga la espalda plana contra la almohadilla durante todo el ejercicio.", "- Evite bloquear los codos completamente en la posición superior para mantener la tensión y proteger las articulaciones.", "- Exhale durante el movimiento de presión hacia arriba e inhale durante la fase de descenso.", "- Elija un peso manejable para mantener el control y la técnica adecuada.", "### Errores comunes:", "- Arquear la espalda: El arqueamiento excesivo de la espalda puede provocar tensión en la zona lumbar; mantenga la alineación adecuada involucrando su núcleo.", "- Uso de peso excesivo: demasiado peso a menudo resulta en una mala forma y un mayor riesgo de lesiones.", "- Rango de movimiento parcial: no extender o bajar completamente los mangos limita la activación muscular y la efectividad general."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000244923808', 'Extensión de cuello acostado con peso (arnés de cuello)', 'Weighted Lying Neck Extension (Neck Harness)', 'Hombros', '["Configure su equipo: use un arnés para el cuello con un accesorio de cadena para pesas. Coloque una pequeña placa de pesas en la cadena, asegurándose de que esté segura.", "Utilice un arnés para el cuello con una cadena para colocar pesas.", "Coloque una pequeña placa de peso en la cadena, asegurándose de que esté segura.", "Ajuste el banco: coloque un banco inclinado en un ángulo de 45 grados. Este ángulo permite que su cabeza se mueva libremente durante el ejercicio mientras mantiene su cuerpo apoyado.", "Coloque un banco inclinado en un ángulo de 45 grados.", "Este ángulo permite que su cabeza se mueva libremente durante el ejercicio mientras mantiene su cuerpo apoyado.", "Póngase en posición: Acuéstese boca abajo en el banco inclinado con el pecho y el abdomen apoyados. Deje que su cabeza se extienda más allá del borde superior del banco. Coloque el arnés para el cuello sobre su cabeza, ajustándolo para que quede ceñido y cómodo.", "Acuéstese boca abajo en el banco inclinado con el pecho y el abdomen apoyados.", "Deje que su cabeza se extienda más allá del borde superior del banco.", "Coloque el arnés para el cuello en su cabeza, ajustándolo para que quede ceñido y cómodo.", "Posición inicial: permita que la cabeza cuelgue ligeramente hacia adelante, dejando que el peso cree un estiramiento natural en la parte posterior del cuello. Mantenga el cuerpo quieto, con las manos agarrando los lados del banco para mayor estabilidad.", "Deje que su cabeza cuelgue ligeramente hacia adelante, dejando que el peso cree un estiramiento natural en la parte posterior de su cuello.", "Mantenga el cuerpo quieto, con las manos agarrando los lados del banco para mayor estabilidad.", "Realice el movimiento: Extienda lentamente el cuello hacia arriba, levantando la cabeza y el peso adjunto. Continúe el movimiento hasta que la cabeza esté alineada con la parte superior de la espalda (evite extender demasiado). Haga una breve pausa en la parte superior para contraer completamente los músculos del cuello.", "Extienda lentamente el cuello hacia arriba, levantando la cabeza y el peso adjunto.", "Continúe el movimiento hasta que su cabeza esté alineada con la parte superior de su espalda (evite extenderse demasiado).", "Haga una breve pausa en la parte superior para contraer completamente los músculos del cuello.", "Regreso a la posición inicial: Baje la cabeza hacia la posición inicial de manera lenta y controlada, resistiendo el tirón del peso.", "Baje la cabeza hacia la posición inicial de manera lenta y controlada, resistiendo el tirón del peso.", "Repeticiones y series: realice de 8 a 15 repeticiones por serie. Complete de 2 a 4 series, ajustándolas según su nivel de condición física y sus objetivos.", "Realice de 8 a 15 repeticiones por serie.", "Complete de 2 a 4 series, ajustándolas según su nivel de condición física y sus objetivos."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001946560016', 'Press militar con barra (press superior)', 'Barbell Military Press (Overhead press)', 'Hombros', '["Deltoides (hombros): el press militar con barra se dirige principalmente a la cabeza anterior (frontal) de los deltoides. Al realizar el ejercicio, el movimiento implica presionar la barra sobre la cabeza en un plano vertical, lo que enfatiza la activación de los deltoides anteriores. Sin embargo, es importante tener en cuenta que las cabezas lateral (lateral) y posterior (trasera) de los deltoides también contribuyen al movimiento como músculos secundarios, proporcionando estabilidad y asistencia. Si bien los deltoides anteriores son el foco principal, el press militar con barra involucra las tres cabezas de los deltoides en diversos grados.(1)", "Tríceps braquial: los músculos tríceps ubicados en la parte posterior de la parte superior del brazo ayudan a extender el codo durante el movimiento de presión.", "Trapecio: El trapecio superior, que corre a lo largo de la parte superior de la espalda y el cuello, participa en la estabilización y el soporte de la cintura escapular durante el movimiento.", "Romboides: Los romboides, ubicados entre los omóplatos, ayudan a retraer y estabilizar las escápulas durante el ejercicio.", "Serrato Anterior: Los músculos serrato anterior, ubicados a los lados de la caja torácica, ayudan a estabilizar y prolongar las escápulas durante la fase ascendente del ejercicio.", "Músculos centrales: los músculos del núcleo, incluidos los abdominales y los oblicuos, desempeñan un papel en la estabilización del tronco y el mantenimiento de una postura adecuada durante todo el movimiento."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000688717901', 'Estiramiento lateral del cuello', 'Side Neck Stretch', 'Hombros', '["Los estiramientos de cuello también participan en la fisioterapia que tiene como objetivo rehabilitar los músculos, las articulaciones y los huesos del cuello. Los estiramientos de cuello tienen como objetivo aumentar la fuerza, el tono y la flexibilidad de los músculos del cuello. También permite que los ligamentos de las articulaciones del cuello se vuelvan más flexibles y resistan una mayor tensión en el área.", "Cuando la cabeza y los hombros se inclinan hacia adelante debido a una mala postura, algunos músculos del pecho y el cuello pueden acortarse y tensarse con el tiempo, lo que puede perpetuar la mala postura que causa el dolor de cuello. Los ejercicios de estiramiento del cuello pueden ayudar a relajar los músculos posturales y reducir el dolor de cuello."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001903267007', 'Flexión de mentón', 'Chin Tuck', 'Hombros', '["Los estiramientos de cuello también participan en la fisioterapia que tiene como objetivo rehabilitar los músculos, las articulaciones y los huesos del cuello. Los estiramientos de cuello tienen como objetivo aumentar la fuerza, el tono y la flexibilidad de los músculos del cuello. También permite que los ligamentos de las articulaciones del cuello se vuelvan más flexibles y resistan una mayor tensión en el área.", "Cuando la cabeza y los hombros se inclinan hacia adelante debido a una mala postura, algunos músculos del pecho y el cuello pueden acortarse y tensarse con el tiempo, lo que puede perpetuar la mala postura que causa el dolor de cuello. Los ejercicios de estiramiento del cuello pueden ayudar a relajar los músculos posturales y reducir el dolor de cuello."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000516158929', 'Estiramiento del cuello diagonal', 'Diagonal Neck Stretch', 'Hombros', '["Gira el cuello en diagonal hacia el lado derecho en un ángulo de 45 grados.", "Incline lentamente la cabeza hacia el pecho mientras mantiene la rotación lateral.", "Deberías sentir un ligero estiramiento en el costado y la parte posterior del cuello.", "Mantenga esta posición durante 15 a 30 segundos mientras mantiene una respiración constante y relajada.", "Regrese lentamente la cabeza a la posición neutral y repita el estiramiento en el otro lado.", "Apunta a 2-4 repeticiones por lado."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001426784436', 'Cinta de correr manual', 'Manual Treadmill', 'Cardio', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001434128212', 'Máquina elíptica', 'Elliptical Machine', 'Cardio', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001888902621', 'Estiramiento del cuello por delante y por detrás', 'Front and Back Neck Stretch', 'Espalda', '["Mantenga la cabeza en una posición neutral en todo momento.", "Inclina la cabeza hacia atrás lo más que puedas.", "Entrelaza tus dedos y coloca tus manos sobre tu frente.", "Intenta llevar lentamente la cabeza hacia adelante como si intentaras tocar tu pecho con la barbilla y resiste con las manos y los brazos.", "Mantén la posición durante 10-15 segundos y regresa a la posición inicial y luego inclina la cabeza hacia adelante para revertir el movimiento, juntando las manos detrás de la cabeza para sostenerlas. Haga esto de 3 a 4 veces."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000758227688', 'Cinta de correr inclinada', 'Incline Treadmill', 'Cardio', '["Comience calentando con 3 a 5 minutos de caminata plana.", "Aumente gradualmente la inclinación entre un 5 y un 12 por ciento, dependiendo de su nivel de condición física.", "Mantenga un ritmo constante al caminar o trote ligero mientras mantiene la postura erguida.", "Evite inclinarse hacia adelante y deje que sus glúteos e isquiotibiales hagan el trabajo.", "Utilice la inclinación durante 15 a 30 minutos, luego bájela y enfríe durante 3 a 5 minutos."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001665040988', 'Saltar la cuerda', 'Jump Rope', 'Cardio', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001299048902', 'Elevación en 6 direcciones con mancuernas', 'Dumbbell 6 Way Raise', 'Hombros', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000994331878', 'Extensión cervical en decúbito prono', 'Prone Cervical Extension', 'Hombros', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001925852934', 'Rueda de andar', 'Treadmill', 'Cardio', '["Súbase a la caminadora con el cinturón estacionario. Enganche la llave de seguridad.", "Comience con un calentamiento caminando a ritmo lento durante 3 a 5 minutos.", "Aumente la velocidad al ritmo deseado para caminar, trotar o correr.", "Ajuste la inclinación según sea necesario para simular colinas y aumentar la intensidad.", "Mantenga una postura erguida y balancee los brazos de forma natural.", "Enfríe reduciendo gradualmente la velocidad durante los últimos 3 a 5 minutos."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000989228083', 'Bicicleta estacionaria', 'Stationary Bike', 'Cardio', '["Ajuste la altura del asiento para que la rodilla se doble ligeramente en la parte inferior del pedaleo.", "Siéntese erguido con un agarre firme en el manillar y los pies firmemente en los pedales.", "Empiece a pedalear lentamente para calentar músculos y articulaciones.", "Aumente la resistencia o la velocidad según sea necesario, según su tipo de entrenamiento.", "Mantenga una respiración y una postura constantes mientras conduce.", "Enfríe bajando la resistencia y pedaleando suavemente durante 3 a 5 minutos."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000974272811', 'Estiramiento del cuello de rodillas', 'Kneeling Neck Stretch', 'Hombros', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001408345080', 'Elevaciones laterales con soporte de pecho con mancuernas', 'Dumbbell Chest Supported Lateral Raises', 'Pecho', '["La elevación lateral con apoyo del pecho es un ejercicio de fortalecimiento de los hombros que se dirige a los deltoides laterales y posteriores. Además, debido a la posición del movimiento, permite trabajar los músculos trapecios.", "La posición del ángulo que establezca en este ejercicio es importante porque si baja la inclinación, el enfoque estará completamente en los músculos deltoides posteriores, y si eleva la inclinación completamente, el objetivo estará en los músculos deltoides laterales. Se recomienda ajustar la inclinación según el grupo de músculos que quieras enfatizar en este ejercicio."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001776286446', 'Máquina escaladora de escaleras', 'Stair Climber Machine', 'Cardio', '["Suba con cuidado a la máquina, comenzando con la velocidad más baja.", "Sujete ligeramente los pasamanos para mantener el equilibrio y mantenga una postura erguida.", "Sube paso a paso, impulsando los talones y activando los glúteos.", "Concéntrate en el movimiento controlado, evitando pasos cortos o apresurados.", "Aumente la velocidad o la duración gradualmente según su nivel de condición física y sus objetivos.", "Enfríe disminuyendo la velocidad durante los últimos 2 o 3 minutos antes de bajarse de manera segura."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001052852497', 'Elevación lateral en 4 direcciones con mancuernas', 'Dumbbell 4 Way Lateral Raise', 'Espalda', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000698153296', 'Curl con mancuernas a dos brazos', 'Double Arm Dumbbell Curl', 'Otros', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001338094178', 'Extensión de espalda sentada', 'Seated Back Extension', 'Espalda', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000298317535', 'Encogimiento de hombros detrás de la espalda con barra', 'Behind The Back Barbell Shrug', 'Espalda', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000666384287', 'Patada de glúteos inverso de la en máquina Smith', 'Smith Machine Reverse Kickback', 'Espalda', '["Ajuste la altura de la barra de la máquina Smith a la altura de la cadera.", "Acuéstese boca abajo en el banco, de espaldas a la máquina, con los pies separados a la altura de las caderas y las manos debajo del banco para apoyarse.", "Manteniendo la espalda recta y el core comprometido, levante ambas piernas detrás de usted lo más que pueda mientras aprieta los glúteos.", "Baje lentamente las piernas hasta la posición inicial y repita hasta el número deseado de repeticiones."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000924001836', 'Encogimiento de hombros', 'Cable Shrug', 'Hombros', '["Es un ejercicio aislado que desarrolla los músculos del cuello. Fortalecer los músculos trapecios ayuda a estabilizar el cuello y la espalda, así como a reducir la tensión en los músculos del cuello y los hombros. Si está buscando aumentar la fuerza de los músculos de los hombros, el cuello o la parte superior de la espalda, o si desea mejorar su postura, puede agregar el encogimiento de hombros con cables a su rutina de ejercicios."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001151015126', 'Encogimiento de hombros inclinado con mancuernas', 'Dumbbell Incline Shrug', 'Hombros', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000619448031', 'Estiramientos dinámicos de muñeca', 'Dynamic Wrist Stretches', 'Antebrazos', '["Mejora el rango de movimiento de las articulaciones: mejora la flexibilidad y la libertad de movimiento tanto en flexión como en extensión.", "Calienta músculos y tendones: aumenta el flujo sanguíneo y la temperatura en antebrazos y manos.", "Prepara las muñecas para soportar cargas: Ideal antes del levantamiento de pesas, yoga, calistenia o escalada.", "Reduce el riesgo de lesiones: previene problemas de uso excesivo como tendinitis, esguinces o pinzamientos.", "Mejora la eficiencia del agarre: mejora la preparación neuromuscular para ejercicios de tracción y sujeción.", "Admite tolerancia a tareas repetitivas: útil para trabajadores, escritores o artistas que pasan largas horas usando sus manos.", "Apoya la función general de las extremidades superiores: moviliza estructuras clave vinculadas a la mecánica del codo, el hombro y la mano."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001306220615', 'Encogimiento de hombros con palanca', 'Lever Shrug', 'Hombros', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000411675333', 'Encogimiento de hombros con barra', 'Barbell Shrug', 'Hombros', '["El objetivo del ejercicio de encogimiento de hombros con barra son los músculos trapecios. El encogimiento de hombros con barra es el ejercicio más importante para desarrollar fuerza en los músculos trapecios, ya que activa completamente las fibras musculares de la parte superior de la espalda.", "Un músculo trapecio fuerte y tenso sostiene su cuello evitando que su cabeza caiga hacia adelante y le permite mantenerse erguido."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000839140537', 'Elevación frontal alterna con mancuernas', 'Alternating Dumbbell Front Raise', 'Hombros', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000252373094', 'Elevación frontal en polea a dos brazos', 'Two Arm Cable Front Raise', 'Hombros', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001104318518', 'Elevación frontal con mancuernas a dos brazos', 'Two Arm Dumbbell Front Raise', 'Hombros', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001449780968', 'Encogimiento de hombros con mancuernas', 'Dumbbell Shrug', 'Hombros', '["Comience con un peso liviano: es importante comenzar con un peso liviano que pueda controlar cómodamente con la forma adecuada. A medida que se sienta cómodo con el ejercicio, puede aumentar gradualmente el peso.", "Párese derecho: Párese con los pies separados a la altura de los hombros y mantenga la espalda recta y los hombros relajados.", "Sujeta las mancuernas correctamente: Sostén una mancuerna en cada mano con las palmas hacia tu cuerpo. Tus brazos deben estar rectos a los costados.", "Levante los hombros: levante lentamente los hombros hacia las orejas lo más alto posible, manteniendo los brazos rectos. Asegúrate de usar la escápula y los trapecios para levantar el peso, no los bíceps ni el cuello.", "Mantenga la posición superior: Mantenga la posición superior por un momento, asegurándose de contraer completamente las trampas.", "Baja las mancuernas: baja lentamente las mancuernas hasta la posición inicial, manteniendo los brazos rectos.", "Repita para obtener la cantidad deseada de repeticiones: intente realizar 3-4 series de 10-15 repeticiones."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001690174814', 'Elevación frontal con mancuernas', 'Dumbbell Front Raise', 'Hombros', '["El levantamiento frontal con mancuernas es un ejercicio aislado que se dirige a la parte frontal y lateral de los hombros. Adecuado para todos los niveles, este ejercicio de flexión de hombros es una buena opción para desarrollar fuerza, mejorar la movilidad de los hombros y dar forma a la cabeza de los hombros."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001221043908', 'Elevación lateral inclinada con mancuernas unilateral', 'Leaning Single Arm Dumbbell Lateral Raise', 'Espalda', '["La elevación lateral inclinada con mancuernas con un solo brazo es un ejercicio de aislamiento que fortalece todo el hombro. En comparación con la elevación lateral con mancuernas, la elevación lateral con mancuernas inclinada pone el deltoides lateral bajo tensión durante una mayor parte del rango de movimiento, lo que hace que cada repetición sea más efectiva. La posición inclinada crea apalancamiento al tiempo que maximiza el aislamiento de los hombros durante todo el movimiento. También coloca una mayor sobrecarga en la parte superior del movimiento."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001850952748', 'Press sentado detrás del cuello', 'Seated Behind Neck Press', 'Hombros', '["La prensa de cuello es un ejercicio eficaz para desarrollar los músculos del hombro, aumentar la estabilidad del hombro y el rango de movimiento, pero ejerce presión sobre los músculos del manguito rotador que estabilizan las articulaciones del hombro. Por eso es más importante realizar el movimiento correcto que levantar demasiado peso."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000447654394', 'Prensa media Arnold', 'Half Arnold Press', 'Hombros', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000210111630', 'Elevación frontal del cable', 'Cable Front Raise', 'Hombros', '["El levantamiento frontal con cable es el ejercicio de fortalecimiento y desarrollo del hombro más popular dirigido al deltoides anterior.", "El ejercicio de elevación frontal con máquinas de cable proporciona tensión constante y resistencia continua mientras se levanta y baja el peso. Debido a que el crecimiento muscular y las ganancias de fuerza dependen directamente de cuánto se estira el músculo durante el ejercicio, las máquinas de cable cansan los músculos más rápido y proporcionan una mayor ganancia de fuerza.", "El ejercicio frontal con cable fortalece los músculos estabilizadores de los hombros y mejora el equilibrio muscular."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000326812799', 'Máquina de aperturas deltográfica trasera', 'Rear Delt Fly Machine', 'Hombros', '["Una máquina de deltoides traseros es una excelente manera de trabajar el deltoides posterior, los romboides y el trapecio medio. Trabajar los músculos deltoides posterior y escapular puede aumentar significativamente la estabilidad del hombro, y trabajar estos músculos puede tener un efecto positivo en la postura del hombro.", "El ejercicio deltoides posterior te ayudará a desarrollar una espalda y unos hombros definidos. Es uno de los mejores ejercicios que debes hacer si quieres tener un músculo de la espalda definido y más definido."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001917416376', 'Elevación lateral con mancuernas sentado', 'Seated Dumbbell Lateral Raise', 'Espalda', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001349568034', 'Elevación lateral trasera con mancuernas sentado', 'Seated Rear Lateral Dumbbell Raise', 'Espalda', '["El levantamiento lateral trasero con mancuernas sentado es un ejercicio de pesas libres que se dirige principalmente a los hombros traseros. Es un ejercicio eficaz que puedes incluir en tu programa para aislar los músculos posteriores del hombro y fortalecer los músculos del manguito rotador."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001654453008', 'Encogimiento de hombros sin agarre de palanca', 'Lever Gripless Shrug', 'Hombros', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000995307341', 'Press Arnold', 'Arnold Press', 'Hombros', '["Posición inicial: Siéntese en un banco con respaldo o párese erguido. Sostenga las mancuernas a la altura de los hombros con las palmas hacia el cuerpo.", "Siéntese en un banco con respaldo o párese erguido.", "Sostenga las mancuernas a la altura de los hombros con las palmas hacia el cuerpo.", "Presione y gire: mientras presiona las mancuernas sobre su cabeza, gire las muñecas hacia afuera para que las palmas miren hacia adelante en la parte superior del movimiento.", "Mientras presionas las mancuernas sobre tu cabeza, gira las muñecas hacia afuera para que las palmas miren hacia adelante en la parte superior del movimiento.", "Bajar y restablecer: baje las mancuernas a la posición inicial mientras gira las muñecas hacia adentro y regrese las palmas hacia el pecho.", "Baje las mancuernas a la posición inicial mientras gira las muñecas hacia adentro y devuelva las palmas hacia el pecho."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000566487058', 'Elevación lateral inclinada', 'Bent Over Lateral Raise', 'Espalda', '["También conocido como Flyes inversos, el levantamiento lateral inclinado es un excelente ejercicio de espalda para equilibrar la fuerza de los hombros. Este ejercicio trabaja el deltoides posterior (parte posterior del hombro) y el trapecio y romboides en la parte superior y media de la espalda entre los omóplatos."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000383983684', 'Elevación lateral en polea inclinado', 'Leaning Cable Lateral Raise', 'Espalda', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001762934197', 'Cable Delt Fly Trasero', 'Cable Rear Delt Fly', 'Hombros', '["El cable delt fly es un excelente ejercicio de fortalecimiento que trabaja eficazmente muchos músculos, incluidos el hombro, el manguito rotador y el trapecio. Al afectar los músculos infraespinoso y subescápula que cubren la escápula, puede ayudar a protegerlo de dolencias causadas por la debilidad muscular, como el trastorno de la postura y la protrusión de la escápula. Además, fortalecer estos músculos mediante el ejercicio del deltoides trasero con cable ayudará a mejorar la mala postura, promoverá una postura erguida y mejorará el equilibrio.", "El ejercicio con cable deltoides traseros te ayudará a desarrollar una espalda y unos hombros definidos. Es uno de los mejores ejercicios que debes hacer si quieres tener un músculo de la espalda definido y más definido."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001145586625', 'Giros de codo a rodilla', 'Elbow To Knee Twists', 'Abdomen', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
