INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000222793850', 'Anuvitasana | Postura de flexión hacia atrás de pie', 'Anuvittasana | Standing Backbend Pose', 'Espalda', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000266383898', 'Anjaneyasana | Postura de zancada baja', 'Anjaneyasana | Low Lunge Pose', 'Piernas', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000552455128', 'Elevación lateral del brazo doblado', 'Bent Arm Lateral Raise', 'Espalda', '["Posición inicial: Párese con los pies separados a la altura de los hombros. Sostenga una mancuerna en cada mano, con las palmas hacia el cuerpo. Deje que los brazos cuelguen a los costados.", "Párese con los pies separados a la altura de los hombros.", "Sostenga una mancuerna en cada mano, con las palmas hacia el cuerpo.", "Deja que tus brazos cuelguen a los costados.", "Posición del brazo doblado: Doble los codos en un ángulo de 90 grados, de modo que la parte superior de los brazos quede paralela al suelo y los antebrazos perpendiculares.", "Doble los codos en un ángulo de 90 grados, de modo que la parte superior de sus brazos quede paralela al suelo y sus antebrazos perpendiculares.", "Levante las pesas: Manteniendo los codos doblados a 90 grados, levante los brazos hacia los lados hasta que la parte superior de los brazos quede paralela al suelo. Concéntrese en usar los músculos de los hombros para levantar las pesas, no la espalda ni los trapecios.", "Manteniendo los codos doblados a 90 grados, levante los brazos hacia los lados hasta que la parte superior de sus brazos quede paralela al suelo.", "Concéntrese en usar los músculos de los hombros para levantar las pesas, no la espalda ni los trampas.", "Descenso controlado: baje las pesas hasta la posición inicial de forma controlada.", "Baje las pesas hasta la posición inicial de forma controlada.", "Repetir: Realice el número deseado de repeticiones.", "Realiza el número deseado de repeticiones."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
