INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001472865220', 'Ardha Kapotasana – Postura de media paloma', 'Ardha Kapotasana – Half Pigeon Pose', 'Otros', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000337482974', 'Elevación de pantorrillas con banda de resistencia', 'Calf Raise with Resistance Band', 'Pantorrillas', '["- Configuración: Asegure una banda de resistencia a un punto de anclaje bajo detrás de sus pies.", "- Agarre la banda: coloque las manijas en los extremos de la banda y agarre una manija en cada mano, con los brazos rectos y las palmas hacia atrás.", "- Posición inicial: Párese erguido con los pies separados a la altura de las caderas. Mantenga la columna erguida, los hombros ligeramente retraídos y los brazos relajados detrás de usted sosteniendo la banda tensa.", "- Levantar: Presione a través de las puntas de los pies y levante los talones del suelo lentamente, involucrando las pantorrillas a medida que se eleva.", "- Pausa y contracción: en la parte superior del movimiento, apriete las pantorrillas y manténgalas así durante 1 a 2 segundos para enfatizar la contracción máxima.", "- Baje lentamente: descienda bajo control, permitiendo que sus talones regresen justo por debajo del paralelo para un estiramiento completo.", "- Repetir: realice la cantidad deseada de repeticiones mientras mantiene una tensión constante en la banda.", "### Consejos para una forma adecuada", "- Párese erguido y alineado: mantenga la cabeza, los hombros y las caderas apilados verticalmente para una mejor forma y aislamiento de las pantorrillas.", "- Maximice el rango de movimiento: levante lo más alto posible sobre los dedos de los pies, luego bájelo hasta que los talones estén ligeramente por debajo del paralelo si la movilidad lo permite.", "- Mantenga la contracción máxima: hacer una pausa en la parte superior aumenta el tiempo bajo tensión y el reclutamiento de fibras musculares.", "- Evite doblar los brazos: mantenga los codos extendidos para mantener una tensión constante de la banda desde el punto de anclaje.", "- Estabilice con su núcleo: active sus músculos abdominales para evitar inclinarse o balancearse hacia adelante.", "### Errores comunes", "- Usar una banda demasiado suelta, lo que reduce la resistencia efectiva en la parte superior del movimiento.", "- Rebotar el movimiento, eliminando el control y aumentando la tensión articular.", "- Acortar el rango de movimiento, particularmente al no permitir una caída total del talón en la parte inferior.", "- Encogerse de hombros o tensar los trapecios superiores debido a una mala posición del mango.", "- Dejar que los brazos se doblen, lo que disminuye el estiramiento y la tensión en la banda."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
