INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001446691095', 'Toque del dedo del pie push-up', 'Push-up Toe Touch', 'Pecho', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000661285317', 'Remo inclinado con barra', 'Barbell Bent Over Row', 'Espalda', '["Evite arquear la espalda durante el ejercicio, ya que esto puede provocar lesiones. Mantenga la espalda recta y active su núcleo para lograr estabilidad.", "Mantenga la cabeza en una posición neutral, mirando ligeramente hacia adelante, para mantener la alineación adecuada de la columna.", "No utilices el impulso para levantar el peso; Concéntrese en usar los músculos de la espalda y los brazos para realizar el movimiento de remo.", "Puede utilizar un cinturón de levantamiento de pesas para obtener apoyo adicional si es necesario, especialmente al levantar cargas pesadas."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-002110114450', 'Cable jalón con brazo recto', 'Cable Straight Arm Pulldown', 'Espalda', '["El ejercicio de jalones con los brazos estirados es una variación del clásico jalones laterales. Mantener los brazos rectos evita que la parte media de la espalda y los bíceps se hagan cargo del movimiento, por lo que puedes concentrarte en los músculos dorsales que estás tratando de trabajar más directamente.", "Tener una espalda fuerte ayuda a mantener la columna vertebral en la alineación adecuada y permite realizar las tareas cotidianas con un riesgo reducido de lesiones. Además de ayudar a fortalecer la espalda, el ejercicio trabaja secundariamente los tríceps y los hombros."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001329431048', 'Jalón al pecho', 'Lat Pulldown', 'Espalda', '["Comience fijando un manillar ancho al cable.", "Siéntese en la máquina de dominadas con los pies apoyados en el suelo y las rodillas firmemente presionadas contra la almohadilla. Tus muslos deben estar paralelos al suelo.", "Agarre la barra con ambas manos, asegurándose de que las palmas estén de espaldas a usted y que su agarre esté más ancho que el ancho de los hombros.", "Mientras mantiene la espalda recta y el pecho erguido, tire de la barra hacia el pecho contrayendo los músculos de la espalda. Tus codos deben apuntar hacia abajo y permanecer cerca de tu cuerpo.", "Haga una pausa por un segundo cuando la barra llegue a su pecho y luego suéltela lentamente hasta la posición inicial, extendiendo los brazos completamente.", "Repita para el número deseado de repeticiones."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000765066658', 'Remo con barra en T con palanca', 'Lever T-Bar Row', 'Espalda', '["El remo con barra en T es un ejercicio de entrenamiento de fuerza que imita el movimiento de remar en un bote. El objetivo es fortalecer los músculos que acercan los brazos al cuerpo, así como los que mueven los omóplatos hacia la columna. El remo con barra en T puede permitirle levantar más peso. Debido a la naturaleza de este movimiento, puedes aprovechar más peso.", "La barra en T, que se dirige a toda la cadena de la espalda, se dirige al dorsal ancho, el infraespinoso, el trapecio, los deltoides posteriores y los romboides, por lo que agregar ejercicios como remo con barra y remo con barra en T a sus programas de entrenamiento será beneficioso para el desarrollo de los músculos de la espalda."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001808616534', 'Remo con mancuernas inclinadas sobre agarre inverso', 'Dumbbell Bent Over Reverse Grip Row', 'Espalda', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000358498085', 'Máquina de remo sentado', 'Seated Row Machine', 'Espalda', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001818642951', 'Remo en polea a un brazo', 'One Arm Cable Row', 'Espalda', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001079915328', 'Escalada por cuerda sin piernas', 'Legless Rope Climb', 'Espalda', '["Agarre: Comience parándose frente a la cuerda. Levante ambas manos y agarre la cuerda firmemente. Tus manos deben estar separadas aproximadamente al ancho de los hombros y las palmas deben estar enfrentadas.", "Posición del cuerpo hueco: mientras levanta las piernas del suelo, active los músculos centrales para crear una posición de \"cuerpo hueco\".", "Tirón inicial: comience la escalada levantándose usando los brazos y la fuerza central. Es importante involucrar la espalda, los hombros y los brazos para iniciar el tirón.", "Mano sobre mano: Utilice un movimiento de mano sobre mano para agarrar la cuerda alternativamente. Tire hacia abajo con una mano mientras levanta la otra mano. Este movimiento te ayuda a ascender por la cuerda. Recuerde, sus piernas no participan en el movimiento.", "Fuerza central y superior del cuerpo: los músculos centrales son cruciales para mantener la estabilidad y la fuerza de la parte superior del cuerpo impulsará la escalada. Concéntrate en movimientos controlados y mantén la tensión en todo tu cuerpo.", "Subir continuamente: Continúe el movimiento de mano sobre mano mientras mantiene la posición del cuerpo hueco. Utilice sus brazos para generar la potencia de tracción y mantener el agarre de la cuerda.", "Posición superior: sigue subiendo hasta llegar a la parte superior de la cuerda o a la altura deseada. En la cima, puedes usar tus brazos para agarrar la cuerda y estabilizarte si es necesario."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001940336837', 'Abdominales', 'Crunches', 'Cardio', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000424812072', 'Remo inclinado sobre mancuernas', 'Bent Over Dumbbell Row', 'Espalda', '["### ", "- Posición inicial: sostenga una mancuerna en cada mano con las palmas hacia el torso. Párese con los pies separados a la altura de los hombros y las rodillas ligeramente flexionadas.", "- Bisagra de cadera: empuje las caderas hacia atrás e incline el torso hacia adelante hasta formar un ángulo de aproximadamente 45 grados. Mantenga la espalda plana y el núcleo comprometido.", "- Movimiento de remo: tire de las mancuernas hacia la caja torácica empujando los codos hacia atrás, manteniéndolos cerca del cuerpo.", "- Apretar y mantener: en la parte superior del movimiento, apriete los omóplatos durante una breve pausa.", "- Descenso controlado: baje lentamente las mancuernas hasta la posición inicial, manteniendo la forma y el control.", "- Repetir: realice de 8 a 12 repeticiones por serie.", "### Consejos para una forma adecuada", "- Mantenga la espalda recta y evite doblar los hombros.", "- Involucre su núcleo para evitar la tensión en la espalda baja.", "- Mueve las mancuernas de forma suave y controlada sin sacudidas.", "- Lidera el tirón con los codos, no con las manos.", "### Errores comunes", "- Redondear la espalda: coloca una tensión innecesaria en la columna y reduce la eficacia.", "- Usar demasiado peso: conduce a una mala forma y a una dependencia del impulso en lugar del compromiso muscular.", "- Codos ensanchados demasiado anchos: Reduce la activación de los dorsales y puede causar tensión en los hombros."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-002063871881', 'Muscle-up (Fuerza en barra)', 'Muscle-Up', 'Espalda', '["Comience colgando de la barra con los brazos completamente extendidos y las palmas hacia afuera del cuerpo. Su agarre debe estar ligeramente más ancho que el ancho de los hombros.", "Comience con una dominada potente, utilizando los músculos de la espalda y los brazos para levantar el cuerpo hacia la barra. Utilice un agarre falso (muñecas giradas sobre la barra) para ayudar con la fase de transición.", "Una vez que su pecho alcance la altura de la barra, comience a girar las muñecas hacia adelante y lleve los codos hacia las caderas. Esto te permitirá hacer la transición de tu cuerpo sobre la barra.", "A medida que realiza la transición, mantenga su núcleo apretado y active sus tríceps para impulsarse hacia la posición de inmersión. Concéntrate en la potencia explosiva en tu dominada y en la fase de transición del levantamiento muscular.", "En la posición de inmersión, los brazos deben estar completamente extendidos con los hombros bloqueados y el cuerpo debe estar en una posición hueca con los pies ligeramente por delante de usted. Mantenga su núcleo apretado durante todo el movimiento para ayudar a mantener el control y la estabilidad.", "Baje desde la posición de inmersión, invirtiendo el movimiento de regreso a la posición inicial."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000095783936', 'Remo con barra con agarre inverso', 'Reverse Grip Barbell Row', 'Espalda', '["Configuración: Párese con los pies separados a la altura de los hombros, los dedos de los pies apuntando hacia adelante y la barra frente a usted en el piso. Para el remo con barra con agarre inverso, agarre la barra por debajo (con las palmas hacia arriba), con las manos colocadas ligeramente más separadas que el ancho de los hombros.", "Doble las caderas: doble las caderas mientras mantiene la espalda recta. Baja el torso hasta que quede casi paralelo al suelo. Mantenga las rodillas ligeramente flexionadas durante todo el movimiento.", "Agarre la barra: bájese y agarre la barra con el agarre por debajo. Tus brazos deben estar completamente extendidos y tu agarre debe ser firme.", "Posición inicial: la espalda debe estar plana, el pecho hacia afuera y los omóplatos hacia atrás y hacia abajo. Esta es la posición inicial.", "El remo: tire de la barra hacia la parte superior del abdomen o la parte inferior del pecho mientras mantiene los codos cerca del cuerpo. Concéntrate en juntar los omóplatos en la parte superior del movimiento para involucrar completamente los músculos de la espalda.", "Baje la barra: baje lentamente la barra hasta la posición inicial mientras mantiene el control. No permitas que el peso te empuje hacia adelante; en cambio, controla el descenso.", "Repetir: Realiza el número deseado de repeticiones."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000418926705', 'Escalador de montaña', 'Mountain Climber', 'Abdomen', '["Los alpinistas son un ejercicio cardiovascular y de fortalecimiento central eficaz. Puede ayudarle a fortalecer y desarrollar los músculos de la parte superior e inferior del cuerpo.", "Al ser un movimiento multifuncional, este ejercicio se dirige no solo a los músculos abdominales sino también a la columna y los glúteos. El alpinista fortalece y tonifica todo el cuerpo, mejora la postura y el equilibrio, reduce la grasa corporal y puede ayudar a acelerar el metabolismo.", "Los alpinistas son beneficiosos para la salud porque combinan la aptitud cardiovascular con el entrenamiento de fuerza. Debido a que las zancadas rápidas aumentan su frecuencia cardíaca, también pueden aumentar su condición cardiovascular."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-002078946534', 'Elevación de piernas', 'Leg Raise', 'Abdomen', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001773360862', 'Abdominales oblicuos en el suelo', 'Oblique Floor Crunches', 'Cardio', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000125731658', 'Curl con barra', 'Barbell Curl', 'Otros', '["Párese derecho con los pies separados al ancho de los hombros y agarre la barra con un agarre por debajo, con las manos separadas al ancho de los hombros.", "Mantén los codos pegados a los costados y levanta la barra hacia el pecho, mientras contraes los bíceps. Asegúrese de mantener los codos fijos y evite balancear el peso.", "Baje lentamente la barra hasta la posición inicial, manteniendo los bíceps enganchados durante todo el movimiento.", "Repita hasta el número deseado de repeticiones."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001783311200', 'Jalón tras nuca en polea', 'Cable Rear Pulldown', 'Espalda', '["Configuración: Utilice una máquina de dominadas con una barra de agarre ancha adjunta. Ajuste la máquina a un peso adecuado. Siéntese en el banco de la máquina frente a la barra y asegure sus muslos debajo de los soportes provistos.", "Utilice una máquina de dominadas con una barra de agarre ancha adjunta.", "Ajuste la máquina a un peso adecuado.", "Siéntese en el banco de la máquina frente a la barra y asegure los muslos debajo de los soportes provistos.", "Agarre: Agarra la barra con ambas manos usando un agarre amplio. En un agarre amplio, las manos se colocan a una distancia mayor que la anchura de los hombros.", "Agarre la barra con ambas manos con un agarre amplio. En un agarre amplio, las manos se colocan a una distancia mayor que la anchura de los hombros.", "Posición del cuerpo: Inclínese ligeramente hacia adelante mientras mantiene la espalda recta. Asegúrese de que sus muslos estén colocados de forma segura debajo de los soportes para estabilizar su cuerpo.", "Inclínese ligeramente hacia adelante mientras mantiene la espalda recta.", "Asegúrese de que sus muslos estén colocados de forma segura debajo de los soportes para estabilizar su cuerpo.", "Movimiento: tire de la barra hacia abajo detrás de la cabeza llevando los codos hacia los lados. Concéntrese en apretar los omóplatos mientras tira de la barra hacia abajo. Baje la barra hasta que esté cerca de la parte posterior del cuello y sienta una contracción en los músculos dorsales.", "Tire de la barra hacia abajo detrás de su cabeza llevando los codos hacia los lados.", "Concéntrate en juntar los omóplatos mientras tiras la barra hacia abajo.", "Baje la barra hasta que esté cerca de la parte posterior de su cuello y sienta una contracción en los músculos dorsales.", "Liberación controlada: permita que el cable levante la barra lentamente. Extienda completamente los brazos y los hombros en la parte superior del movimiento.", "Deje que el cable levante la barra lentamente.", "Extienda completamente los brazos y los hombros en la parte superior del movimiento.", "Repetir: Realiza el número de repeticiones deseado, manteniendo el control durante todo el ejercicio.", "Realiza el número deseado de repeticiones, manteniendo el control durante todo el ejercicio."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001733625150', 'Curl de piernas', 'Leg Curl', 'Piernas', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000738855483', 'Sentadilla Plie con mancuernas', 'Plie Dumbbell Squat', 'Piernas', '["- Párese con los pies más anchos que el ancho de los hombros y gire los dedos hacia afuera en un ángulo de 30 a 45 grados.", "- Sostenga una mancuerna verticalmente con ambas manos, ya sea en posición de copa en el pecho o entre las piernas con el brazo extendido.", "- Involucre su núcleo y mantenga la espalda erguida mientras comienza a ponerse en cuclillas.", "- Doble las rodillas y baje las caderas directamente hacia abajo mientras mantiene el torso erguido.", "- Mueva las rodillas en dirección a los dedos de los pies para activar la parte interna de los muslos.", "- Agáchate hasta que tus muslos queden al menos paralelos o ligeramente por debajo si tu movilidad lo permite.", "- Haga una breve pausa en la parte inferior, luego empuje los talones para volver a la posición inicial, apretando los glúteos.", "### Consejos para una forma adecuada", "- Mantenga la columna neutra y el pecho elevado durante toda la sentadilla.", "- Empuje las rodillas hacia afuera en línea con los dedos de los pies para evitar colapsar hacia adentro.", "- Involucre su núcleo para apoyar su espalda baja y mejorar el equilibrio.", "- Baja con control, especialmente si la mancuerna se sostiene por delante o por debajo.", "- Vaya tan profundo como lo permita su movilidad, apuntando a muslos paralelos o más bajos.", "### Errores comunes", "- Inclinarse demasiado hacia adelante, lo que aleja la carga de los músculos objetivo.", "- Dejar que las rodillas se doblen hacia adentro, lo que reduce el compromiso de los aductores y aumenta el riesgo de lesiones.", "- Mantener la mancuerna demasiado lejos de su cuerpo, lo que puede dañar su espalda.", "- Usar demasiado peso demasiado pronto, comprometiendo la forma y el control.", "- Girar excesivamente los dedos de los pies, lo que puede generar tensión en las rodillas y los tobillos."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001848346621', 'Curl con mancuernas', 'Dumbbell Curl', 'Otros', '["Comience con un peso cómodo: seleccione un peso que pueda levantar cómodamente para la cantidad deseada de repeticiones. Es mejor comenzar con un peso más liviano e ir subiendo, en lugar de usar un peso demasiado pesado y sacrificar la forma.", "Párese con una postura adecuada: párese derecho con los pies separados al ancho de los hombros y los hombros hacia atrás. Esto ayudará a mantener una alineación adecuada y a involucrar su núcleo.", "Sujeta las mancuernas correctamente: Sujeta las mancuernas con un agarre neutro (las palmas hacia adentro) y mantén las muñecas rectas. Evite utilizar un agarre demasiado apretado, ya que esto puede provocar una tensión innecesaria en las muñecas.", "Mantenga los codos cerca de los costados: Mantenga los codos cerca de los costados durante todo el movimiento. Esto ayudará a aislar los bíceps y evitará que se balanceen.", "Doble un brazo a la vez: comience doblando una mancuerna hacia su hombro, manteniendo el codo cerca de su costado. Mientras levantas el peso, concéntrate en apretar el bíceps en la parte superior del movimiento.", "Baje el peso de forma controlada: baje el peso de forma controlada, asegurándose de mantener el codo cerca del costado. Evite dejar que el peso baje rápidamente, ya que esto puede ejercer una tensión innecesaria en las articulaciones.", "Alternar entre brazos: una vez que hayas completado una repetición completa con un brazo, cambia al otro brazo y repite el ejercicio.", "Respire adecuadamente: inhale mientras baja el peso y exhale mientras dobla el peso hacia su hombro."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001136133405', 'Abdominales cruzados en T', 'T-Cross Sit-up', 'Abdomen', '["Trabaja todos los músculos abdominales: el ejercicio de abdominales T-Cross se centra en el recto abdominal y los músculos oblicuos. Es un ejercicio beneficioso para perder grasa y tonificar ya que tiene un efecto intenso sobre los músculos oblicuos."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000899022938', 'Curl de piernas sentado', 'Seated Leg Curl', 'Piernas', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000158465388', 'Declinado abdominales', 'Decline Sit-up', 'Abdomen', '["Los abdominales declinados se dirigen al recto abdominal y a los músculos oblicuos para fortalecer los músculos centrales. Es un ejercicio que puedes aplicar para moldear los músculos abdominales superiores y los músculos abdominales."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-002137835566', 'Crunch de bicicleta', 'Bicycle Crunch', 'Cardio', '["Posición inicial: Acuéstese boca arriba sobre una colchoneta o una superficie cómoda. Coloque las manos detrás de la cabeza, con los codos apuntando hacia afuera. Levante las piernas del suelo y doble las rodillas en un ángulo de 90 grados. Esta es tu posición inicial.", "Acuéstese boca arriba sobre una colchoneta o una superficie cómoda.", "Coloque las manos detrás de la cabeza, con los codos apuntando hacia afuera.", "Levanta las piernas del suelo, doblando las rodillas en un ángulo de 90 grados. Esta es tu posición inicial.", "Ejecución: Levante la cabeza, los hombros y los pies del suelo, activando los músculos centrales. Mientras levanta, acerque el codo derecho y la rodilla izquierda entre sí en un movimiento giratorio. Al mismo tiempo, estire la pierna derecha, manteniéndola elevada sobre el suelo. Simule un movimiento de ciclismo llevando alternativamente el codo izquierdo hacia la rodilla derecha mientras estira la pierna izquierda. Continúe con este movimiento de pedaleo, asegurándose de involucrar su núcleo y evitando tirar del cuello con las manos.", "Levante la cabeza, los hombros y los pies del suelo, activando los músculos centrales.", "Mientras levanta, acerque el codo derecho y la rodilla izquierda con un movimiento giratorio.", "Al mismo tiempo, estire la pierna derecha, manteniéndola elevada por encima del suelo.", "Simule un movimiento de ciclismo llevando alternativamente el codo izquierdo hacia la rodilla derecha mientras estira la pierna izquierda.", "Continúe con este movimiento de pedaleo, asegurándose de involucrar su núcleo y evitando tirar del cuello con las manos.", "Respiración: Exhale mientras gira y lleva el codo a la rodilla opuesta. Inhale mientras cambia al otro lado.", "Exhala mientras giras y llevas el codo a la rodilla opuesta.", "Inhala mientras cambias al otro lado.", "Repetir: continuar el movimiento de pedaleo durante un número específico de repeticiones o una duración determinada.", "Continúe el movimiento de pedaleo durante un número específico de repeticiones o una duración determinada."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000842491260', 'Patada de glúteos con mancuernas', 'Dumbbell Kickback', 'Espalda', '["### ", "- Configure su posición Sostenga una mancuerna en una mano con un agarre neutral. Coloque la mano opuesta en un banco como apoyo. Mantenga los pies separados al ancho de los hombros para mantener el equilibrio.", "- Sostenga una mancuerna en una mano con agarre neutral.", "- Coloque su mano opuesta en un banco como apoyo.", "- Mantenga los pies separados a la altura de los hombros para mantener el equilibrio.", "- Mantenga una postura adecuada Gire las caderas e inclínese ligeramente hacia adelante. Mantenga la espalda recta y active su núcleo. La parte superior de su brazo debe estar paralela al piso, con el codo doblado en un ángulo de 90 grados.", "- Gire las caderas e inclínese ligeramente hacia adelante.", "- Mantenga la espalda recta y active su núcleo.", "- La parte superior de tu brazo debe estar paralela al suelo, con el codo doblado en un ángulo de 90 grados.", "- Realice el movimiento Exhale mientras extiende el brazo completamente hacia atrás, manteniendo el codo inmóvil. Apriete el tríceps en la parte superior del movimiento. Inhale mientras regresa lentamente a la posición inicial con control.", "- Exhale mientras extiende el brazo completamente hacia atrás, manteniendo el codo inmóvil.", "- Aprieta tus tríceps en la parte superior del movimiento.", "- Inhala mientras regresas lentamente a la posición inicial con control.", "- Repetir y cambiar de lado Realice el número deseado de repeticiones antes de cambiar de brazo.", "- Realice el número deseado de repeticiones antes de cambiar de brazo.", "### Consejos para una forma adecuada", "- Mantenga la parte superior del brazo inmóvil para asegurarse de que los tríceps hagan el trabajo.", "- Evite utilizar el impulso moviéndose lentamente y con control.", "- Involucre sus músculos centrales para mantener la estabilidad.", "- Asegure un rango completo de movimiento, extendiendo el brazo por completo.", "- Seleccione un peso apropiado que permita una buena forma sin tensión excesiva.", "### Errores comunes a evitar", "- Balancear la mancuerna, lo que reduce la activación del tríceps.", "- Dejar caer el codo, lo que provoca una participación inadecuada del músculo objetivo.", "- Usar demasiado peso, comprometer la forma y aumentar el riesgo de lesiones.", "- No extender completamente el brazo, limitando la efectividad del ejercicio.", "- Redondear la espalda, lo que puede provocar tensión en la zona lumbar."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001675790227', 'Extensión de piernas', 'Leg Extension', 'Piernas', '["Coloque la máquina de extensión de piernas a su altura adecuada y ajuste el respaldo y el reposapiés para alinearlos con su cuerpo.", "Siéntese en la máquina con la espalda apoyada en el respaldo y los pies firmemente apoyados en el reposapiés. Asegúrese de que sus rodillas estén alineadas con el punto de pivote de la máquina.", "Coloque las piernas debajo de la palanca o rodillo acolchado de la máquina. La almohadilla debe descansar contra la parte delantera de los tobillos, justo encima de los pies.", "Sujete las manijas provistas en la máquina para obtener estabilidad y apoyo durante todo el ejercicio. Mantenga la parte superior del cuerpo relajada y mantenga una buena postura."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001410683927', 'Crunch en polea de rodillas', 'Kneeling Cable Crunch', 'Cardio', '["El primer grupo de músculos que trabaja en este ejercicio es el recto abdominal, los músculos abdominales. También ayuda a trabajar otros músculos centrales. Para aprovechar al máximo este ejercicio, es importante que el movimiento se realice con la forma correcta. Puede que no sea adecuado para principiantes y personas con lesiones de espalda."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001139912061', 'Toque del talón', 'Heel Touch', 'Abdomen', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001539325817', 'Curl con mancuernas inclinado sentado', 'Seated Incline Dumbbell Curl', 'Otros', '["Configure el banco: ajuste el banco a una inclinación de 45 grados y asegúrese de que esté estable y seguro. Siéntate en el banco con la espalda recta y los pies apoyados en el suelo.", "Elija el peso correcto: elija un peso que sea apropiado para su nivel de condición física y sus objetivos. Comience con un peso más liviano y aumente gradualmente a medida que se vuelva más fuerte.", "Agarre las mancuernas: sostenga una mancuerna en cada mano con las palmas hacia arriba. Su agarre debe ser cómodo y firme.", "Coloca tus brazos: Coloca tus brazos de manera que queden completamente extendidos y paralelos al suelo. Mantenga los codos cerca de su cuerpo.", "Curl las mancuernas: levante lentamente una mancuerna hacia su hombro, manteniendo el codo inmóvil. Mientras levantas la mancuerna, gira la palma de tu mano para que mire hacia tu hombro en la parte superior del movimiento. Mientras bajas la primera mancuerna, comienza a levantar la otra mancuerna y gira la otra palma para que también mire hacia tu hombro en la parte superior del movimiento.", "Respira adecuadamente: Inhala mientras bajas las mancuernas y exhala mientras las levantas.", "Controle el movimiento: durante todo el ejercicio, concéntrese en mantener el control y evitar cualquier movimiento de balanceo o sacudida. Utilice un movimiento lento y controlado para involucrar completamente sus músculos."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001574199786', 'Elevación de pantorrilla sentado con barra', 'Barbell Seated Calf Raise', 'Pantorrillas', '["- Configuración: Siéntese en un banco plano con los pies separados a la altura de los hombros sobre una superficie o plataforma elevada (de 2 a 4 pulgadas de alto). Tus rodillas deben estar dobladas aproximadamente a 90 grados.", "- Cargue la barra: coloque con cuidado una barra acolchada sobre la parte inferior de los muslos, justo por encima de las rótulas. Utilice una almohadilla para sentadillas o una toalla para mayor comodidad.", "- Posición inicial: siéntese erguido con la columna neutra, el núcleo reforzado y los dedos de los pies apuntando hacia adelante. Los tacones deben colgar del borde de la plataforma.", "- Levantar: Presione a través de las puntas de los pies y levante los talones lo más alto posible, contrayendo las pantorrillas en la parte superior.", "- Pausa y contracción: mantenga la posición superior durante 1 a 2 segundos para maximizar el compromiso del sóleo.", "- Baje lentamente: descienda bajo control, permitiendo que los talones se hundan debajo de la plataforma para estirar la pantorrilla.", "- Repetir: Complete el número deseado de repeticiones sin rebotes ni sacudidas.", "### Consejos para una forma adecuada", "- Utilice una plataforma estable debajo del antepié para permitir un rango completo de movimiento.", "- Mantenga la columna neutra y evite inclinarse excesivamente hacia adelante durante el levantamiento.", "- Aprieta en la parte superior de cada repetición para activar el sóleo de manera más efectiva.", "- Baje los talones lentamente para beneficiarse de la parte excéntrica del movimiento.", "- No gire los tobillos: mantenga los pies planos y estables durante todo el rango de movimiento.", "### Errores comunes", "- Usar demasiado peso, lo que reduce el rango de movimiento o rebota.", "- No utilizar plataforma, lo que acorta el alcance y limita el tramo en la parte inferior.", "- Saltarse la pausa en la parte superior, lo que reduce el tiempo bajo tensión.", "- Permitir que las rodillas se muevan, lo que reduce la estabilidad y aísla el sóleo de manera menos efectiva.", "- No controlar la fase excéntrica, perdiendo la oportunidad de crecimiento muscular."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000260242501', 'Extensión de tríceps en polea (barra recta)', 'Cable Triceps Pushdown (Straight Bar)', 'Tríceps', '["### ", "- Configure el equipo Conecte una barra recta, una cuerda o una barra en V a la polea alta de una máquina de cable. Seleccione un peso moderado que permita un movimiento controlado.", "- Conecte una barra recta, una cuerda o una barra en V a la polea alta de una máquina de cable.", "- Seleccione un peso moderado que permita un movimiento controlado.", "- ColóquesePárese con los pies separados a la altura de los hombros para mayor estabilidad.Sujete el accesorio con un agarre por encima de la cabeza (con las palmas hacia abajo).Mantenga los codos cerca del torso y dóblelos en un ángulo de 90 grados.", "- Párese con los pies separados a la altura de los hombros para mayor estabilidad.", "- Agarre el accesorio con las manos en pronación (con las palmas hacia abajo).", "- Mantenga los codos cerca del torso y dóblelos en un ángulo de 90 grados.", "- Ejecución Exhale mientras empuja la barra hacia abajo extendiendo los codos por completo. Mantenga las muñecas en posición neutra y los codos inmóviles. Baje el mango hasta que los brazos estén completamente extendidos pero no bloqueados. Haga una breve pausa en la parte inferior para maximizar el compromiso de los tríceps. Inhale mientras regresa lentamente a la posición inicial con control.", "- Exhala mientras empujas la barra hacia abajo extendiendo los codos por completo.", "- Mantenga las muñecas neutrales y los codos estacionarios.", "- Baje la manija hasta que sus brazos estén completamente extendidos pero no bloqueados.", "- Haga una breve pausa en la parte inferior para maximizar la participación de los tríceps.", "- Inhala mientras regresas lentamente a la posición inicial con control.", "- Repetir Realice el número deseado de repeticiones manteniendo la forma adecuada.", "- Realice el número deseado de repeticiones manteniendo la forma adecuada.", "### Consejos para una forma adecuada", "- Mantenga los codos doblados hacia adentro para aislar los tríceps de manera efectiva.", "- Mantenga la columna neutra y evite inclinarse hacia adelante.", "- Involucre sus músculos centrales para mayor estabilidad.", "- Muévase con movimiento controlado en lugar de utilizar el impulso.", "- Seleccione un peso apropiado que permita un rango completo de movimiento.", "### Errores comunes a evitar", "- Usar peso excesivo, lo que lleva a una forma inadecuada y reduce la activación de los tríceps. Ensanchar los codos hacia afuera, lo que desvía la atención de los tríceps. Inclinarse demasiado hacia adelante, lo que reduce la efectividad del ejercicio. Extender demasiado las muñecas, lo que puede causar tensión. No extender completamente los codos, lo que limita el rango de movimiento y la activación muscular.", "- Usar peso excesivo, lo que lleva a una forma inadecuada y una activación reducida del tríceps.", "- Ensanchando los codos hacia afuera, lo que desvía la atención de los tríceps.", "- Inclinarse demasiado hacia adelante, reduciendo la efectividad del ejercicio.", "- Extender demasiado las muñecas, lo que puede provocar tensión.", "- No extender completamente los codos, limitando el rango de movimiento y la activación muscular."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001930878744', 'Extensión de tríceps en polea inverso unilateral', 'One-Arm Reverse Cable Triceps Pushdown', 'Tríceps', '["Configure el equipo Coloque una sola manija en la polea alta de una máquina de cable. Seleccione un peso moderado que permita un movimiento controlado.", "Conecte una sola manija a la polea alta de una máquina de cable.", "Seleccione un peso moderado que permita un movimiento controlado.", "ColóquesePárate con los pies separados al ancho de los hombros para mantener el equilibrio.Agarra el mango con la mano hacia abajo (con la palma hacia arriba).Mantén el codo cerca del torso y la muñeca recta.", "Párese con los pies separados a la altura de los hombros para mantener el equilibrio.", "Agarre el mango con la palma hacia arriba.", "Mantenga el codo cerca del torso y la muñeca recta.", "EjecuciónExhale mientras empuja el mango hacia abajo extendiendo el codo por completo. Mantenga el codo inmóvil y evite movimientos excesivos de la muñeca. Baje el mango hasta que el brazo esté completamente extendido pero no bloqueado. Haga una breve pausa en la parte inferior para enganchar completamente los tríceps. Inhale mientras regresa lentamente a la posición inicial con control.", "Exhale mientras empuja el mango hacia abajo extendiendo el codo por completo.", "Mantenga el codo inmóvil y evite movimientos excesivos de la muñeca.", "Baje la manija hasta que su brazo esté completamente extendido pero no bloqueado.", "Haga una breve pausa en la parte inferior para involucrar completamente el tríceps.", "Inhala mientras regresas lentamente a la posición inicial con control.", "Repetir Realice el número deseado de repeticiones antes de cambiar de brazo.", "Realice el número deseado de repeticiones antes de cambiar de brazo."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001278957422', 'Aperturas de cubierta Pec', 'Pec Deck Fly', 'Pecho', '["Ajuste la máquina: coloque el asiento de modo que las manijas queden al nivel del pecho. Para comenzar, ajuste las almohadillas para los brazos de modo que sus brazos queden ligeramente detrás de su torso.", "Siéntese erguido: coloque los pies planos, con la espalda presionada contra la almohadilla y agarre las manijas o apoye los antebrazos contra las almohadillas (según el tipo de máquina).", "Establezca la posición de los brazos: Mantenga los codos ligeramente doblados para proteger las articulaciones.", "Inicie el movimiento: exhale y junte los brazos frente a su pecho en un movimiento de abrazo. Concéntrate en contraer los músculos del pecho al máximo.", "Regrese con control: invierta lentamente el movimiento hasta que sienta un leve estiramiento en el pecho. Evite dejar que las pesas golpeen o se estiren demasiado."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001130992024', 'Fondos de tríceps', 'Triceps Dips', 'Tríceps', '["### ", "### Usar barras paralelas o una estación de fondos", "- Configure su posición Agarre las barras paralelas con las manos ligeramente más separadas que el ancho de los hombros. Extienda completamente los brazos y apoye el peso de su cuerpo por encima de las barras.", "- Agarre las barras paralelas con las manos ligeramente más separadas que el ancho de los hombros.", "- Extiende completamente los brazos y apoya el peso de tu cuerpo por encima de las barras.", "- Coloque su cuerpo Mantenga el pecho ligeramente hacia adelante y active su núcleo. Doble las rodillas o extienda las piernas rectas, según su comodidad y nivel de dificultad.", "- Mantenga su pecho ligeramente hacia adelante y active su núcleo.", "- Doble las rodillas o extienda las piernas rectas, según su comodidad y nivel de dificultad.", "- Ejecución Inhale mientras baja el cuerpo doblando los codos hasta que la parte superior de los brazos quede paralela al suelo. Mantenga los codos cerca del torso y evite abrirlos hacia afuera. Haga una breve pausa en la parte inferior, asegurando el compromiso completo de los tríceps. Exhale mientras presiona con las palmas para extender los brazos y regresar a la posición inicial.", "- Inhale mientras baja el cuerpo doblando los codos hasta que la parte superior de sus brazos quede paralela al suelo.", "- Mantenga los codos cerca del torso y evite abrirlos hacia afuera.", "- Haga una breve pausa en la parte inferior, asegurando la participación completa de los tríceps.", "- Exhala mientras presionas con las palmas para extender los brazos y volver a la posición inicial.", "- Repetir Realice el número deseado de repeticiones manteniendo la forma adecuada.", "- Realice el número deseado de repeticiones manteniendo la forma adecuada.", "### Consejos para una forma adecuada", "- Mantenga los codos doblados hacia adentro en lugar de dejar que se abran hacia afuera.", "- Involucre su núcleo y glúteos para mantener la estabilidad.", "- Bájese con un movimiento controlado para evitar tensiones articulares innecesarias.", "- Evite bloquear los codos en la parte superior del movimiento.", "- Respira adecuadamente, inhalando mientras bajas y exhalando mientras empujas hacia arriba.", "### Errores comunes a evitar", "- Inclinarse demasiado hacia adelante, lo que hace que la atención se centre en el pecho en lugar de en los tríceps.", "- Ensanchando los codos hacia afuera, reduciendo la activación de los tríceps y aumentando el riesgo de lesiones.", "- No bajar lo suficiente, limitando el rango de movimiento y la efectividad.", "- Usar el impulso, en lugar de movimientos controlados para el compromiso muscular.", "- Bloquear los codos, lo que puede generar una tensión excesiva en las articulaciones."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001158977912', 'Fondos en banco', 'Bench Dips', 'Otros', '["### ", "- Configure su posición Siéntese en el borde de un banco resistente o de una superficie elevada. Coloque las manos junto a las caderas y sujete el banco con los dedos apuntando hacia adelante.", "- Siéntese en el borde de un banco resistente o de una superficie elevada.", "- Coloque sus manos al lado de sus caderas, agarrando el banco con los dedos apuntando hacia adelante.", "- Coloque sus pies Coloque sus piernas en un banco alto. Mantenga las rodillas dobladas a 90 grados con los pies apoyados en el piso para una versión más fácil.", "- Coloque las piernas sobre un banco alto.", "- Mantenga las rodillas dobladas a 90 grados con los pies apoyados en el suelo para una versión más fácil.", "- Ejecución Deslice las caderas fuera del banco, soportando su peso con los brazos. Baje el cuerpo doblando los codos hasta que formen un ángulo de 90 grados. Mantenga los codos cerca del torso y mantenga el control durante todo el movimiento. Presione con las palmas para extender los brazos y volver a la posición inicial.", "- Desliza las caderas fuera del banco, apoyando tu peso con los brazos.", "- Baje el cuerpo doblando los codos hasta que formen un ángulo de 90 grados.", "- Mantenga los codos cerca del torso y mantenga el control durante todo el movimiento.", "- Presione con las palmas para extender los brazos y volver a la posición inicial.", "- Repetir Realice el número deseado de repeticiones manteniendo la forma adecuada.", "- Realice el número deseado de repeticiones manteniendo la forma adecuada.", "### Consejos para una forma adecuada", "- Mantenga los codos metidos hacia adentro en lugar de abrirlos hacia afuera.", "- Bájese con un movimiento controlado para evitar tensiones innecesarias.", "- Involucre su núcleo y glúteos para mantener la estabilidad.", "- Evite bloquear los codos en la parte superior del movimiento.", "- Respire constantemente, exhalando al subir e inhalando al bajar.", "### Errores comunes a evitar", "- Bajar demasiado, lo que puede tensar los hombros.", "- Permitir que los codos se abran hacia afuera, reduciendo la activación de los tríceps.", "- Redondear los hombros, lo que provoca una mala postura y posibles lesiones.", "- Utilizar el impulso, en lugar de controlar el movimiento.", "- Bloquear los codos, lo que puede generar una tensión excesiva en las articulaciones."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001536291873', 'Cruces en polea en la parte superior del pecho', 'Cable Upper Chest Crossovers', 'Pecho', '["Ajuste los cables: Ajuste los cables a la posición más alta en ambos lados de la máquina de cable. Conecte las manijas a cada cable.", "Párese en el centro: Párese en el centro de la máquina, de espaldas a ella. Sostenga las manijas con las palmas hacia abajo.", "Colóquese: dé un paso hacia adelante con una pierna o inclínese ligeramente hacia adelante, manteniendo los pies separados al ancho de los hombros. Tus brazos deben estar extendidos a los lados, paralelos al suelo.", "Cruza las manijas: lentamente acerca ambas manijas, cruzándolas frente a tu cuerpo. Tus brazos deben estar ligeramente doblados a la altura del codo.", "Aprieta tu pecho: haz una pausa por un momento y aprieta los músculos del pecho.", "Regreso a la posición inicial: Baja lentamente las asas hasta la posición inicial, manteniendo los brazos ligeramente flexionados.", "Repetir: Repita el ejercicio durante el número deseado de repeticiones."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001600728816', 'Pullover con mancuernas', 'Dumbbell Pullover', 'Pecho', '["### ", "- Configuración: Acuéstese en un banco plano con solo la parte superior de la espalda y los hombros apoyados. Mantenga los pies apoyados en el suelo.", "- Agarre la mancuerna: sostenga una mancuerna con ambas manos debajo de la placa interior, con los brazos extendidos sobre el pecho.", "- Prepárese y baje: Inhale, fortalezca su núcleo y lentamente arquee la mancuerna hacia atrás y hacia abajo detrás de su cabeza. Mantenga una ligera flexión de los codos.", "- Estiramiento y retorno: una vez que sienta un estiramiento en los dorsales y el pecho, invierta el movimiento tirando de la mancuerna hacia atrás sobre el pecho usando los dorsales o el pecho.", "- Finalizar controlado: exhale en la parte superior y repita para las repeticiones deseadas con un movimiento suave y controlado.", "### Consejos para una forma adecuada", "- Mantenga los codos ligeramente doblados para reducir la tensión en las articulaciones.", "- Baje la mancuerna solo hasta donde pueda controlar sin hiperextender la columna.", "- Conduzca a través de sus dorsales o pecho en el regreso; no se limite a mover el peso hacia atrás.", "- Mantenga la caja torácica baja si desea una mayor activación de los dorsales; permita un ligero arco para enfocar el pecho.", "- Comience ligero para aprender el camino correcto y el control de los hombros.", "### Errores comunes", "- Arquear la zona lumbar, lo que aleja la tensión de los músculos objetivo.", "- Usar un peso demasiado pesado y dejar que el impulso haga el trabajo.", "- Doblar demasiado los codos, convirtiéndolo en una extensión de tríceps.", "- Rango de movimiento incompleto, especialmente en la fase de estiramiento.", "- Perder el control del agarre: siempre asegure firmemente la mancuerna con ambas manos."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001278610491', 'Cruce en polea bajo', 'Low Cable Crossover', 'Pecho', '["Comience configurando la máquina de cable en la configuración más baja y colocando una manija a cada lado.", "Párese en el centro de la máquina de cable con los pies separados a la altura de los hombros y mirando hacia la máquina. Agarre un asa en cada mano y llévelas hasta la altura de los hombros. Esta es la posición inicial.", "Da un paso hacia adelante con un pie, manteniendo las rodillas ligeramente dobladas e inclínate hacia adelante por la cintura manteniendo la espalda recta.", "Tus manos deben terminar a los lados, justo debajo de tus caderas.", "Con una ligera flexión de los brazos, lleve las pesas hacia arriba y hacia la línea media de su cuerpo. Asegúrate de mantener los codos ligeramente doblados durante todo el movimiento.", "Haga una pausa por un momento, luego libere lentamente la tensión y regrese a la posición inicial.", "Repita hasta el número deseado de repeticiones, luego cambie de lado y repita con el otro brazo."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001048757180', 'Aperturas con mancuernas', 'Dumbbell Fly', 'Pecho', '["### ", "- Acuéstese en un banco.", "- Sostenga una mancuerna en cada mano con un agarre neutral (con las palmas una frente a la otra).", "- Extienda los brazos rectos por encima del pecho, manteniendo los codos ligeramente doblados para reducir la tensión en las articulaciones.", "- Baje lentamente las mancuernas formando un arco amplio, manteniendo la ligera flexión de los codos. Tus brazos deben moverse hacia afuera y hacia abajo hasta que estén al nivel de tu pecho o ligeramente por debajo.", "- Concéntrese en sentir un estiramiento en los músculos del pecho sin estirar demasiado ni comprometer la estabilidad del hombro.", "- Invierta el movimiento apretando los músculos del pecho y volviendo a subir las mancuernas en el mismo arco hasta la posición inicial.", "### Consejos para el entrenador:", "- Utilice pesas ligeras a moderadas para mantener el control y evitar forzar los hombros.", "- Evite bloquear los codos o dejar que los brazos caigan demasiado por debajo del nivel del pecho.", "- Concéntrese en un movimiento controlado para maximizar el estiramiento y la contracción."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000850391035', 'Press de banca inclinado con barra', 'Incline Barbell Bench Press', 'Pecho', '["Configure el banco inclinado en el ángulo deseado. (30 a 45 grados)", "Cargue la barra con un peso adecuado para su nivel de condición física y sus objetivos.", "Acuéstate en el banco con los pies firmemente apoyados en el suelo y la cabeza apoyada en el banco.", "Agarre la barra con un agarre ligeramente más ancho que el ancho de los hombros.", "Quita la barra y bájala hasta la parte superior del pecho, con los codos extendidos hacia los lados.", "Presione la barra hacia arriba hasta la posición inicial, exhalando mientras empuja.", "Repita para el número deseado de repeticiones."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001195248463', 'Cruce de cables', 'Cable Crossover', 'Pecho', '["Ajuste las poleas a la altura deseada:", "Polea alta: apunta a la parte inferior del pecho.", "Polea media: trabaja la parte media del pecho.", "Polea baja: involucra la parte superior del pecho.", "Coloque manijas en D a cada polea."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001642631542', 'Press de pecho en polea unilateral', 'One-Arm Cable Chest Press', 'Pecho', '["Ajustar la máquina de cables: Comience ajustando la máquina de cables para que el mango quede a la altura del pecho.", "Colóquese: dé un paso hacia adelante con un pie y mantenga los pies separados a la altura de los hombros. Sostenga el mango con una mano y llévelo hacia su pecho.", "Involucra tu núcleo: Involucra tus músculos centrales para mantener tu torso estable durante todo el ejercicio.", "Empuje la manija: presione la manija hacia adelante hasta que su brazo esté completamente extendido pero no bloqueado. Mantenga el codo cerca del cuerpo y evite torcer el torso.", "Regrese lentamente a la posición inicial: regrese lentamente el mango a su pecho y repita hasta el número deseado de repeticiones.", "Cambie de lado: una vez que haya completado el número deseado de repeticiones, cambie de lado y repita el ejercicio con el otro brazo."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000379011451', 'Fondo de tríceps con palanca', 'Lever Triceps Dip', 'Tríceps', '["### ", "- Configuración: Ajuste la altura del asiento para que sus brazos queden cómodamente colocados en las manijas. Siéntese y coloque los pies apoyados en el piso o en el reposapiés designado. Sujete las manijas firmemente de acuerdo con el diseño de la máquina.", "- Ajuste la altura del asiento para que sus brazos queden cómodamente colocados en las manijas.", "- Siéntese y coloque los pies apoyados en el suelo o en el reposapiés designado.", "- Sujete firmemente las manijas según el diseño de la máquina.", "- Posición inicial: Mantenga el pecho ligeramente inclinado hacia adelante mientras mantiene la espalda recta. Involucre su núcleo y coloque los codos en un ángulo de aproximadamente 90 grados.", "- Mantenga el pecho ligeramente inclinado hacia adelante mientras mantiene la espalda recta.", "- Involucre su núcleo y coloque sus codos en un ángulo de aproximadamente 90 grados.", "- Ejecución: Presione hacia abajo las manijas extendiendo los codos, levantando el cuerpo contra la resistencia. Extienda completamente los brazos en la parte inferior para enganchar los tríceps por completo. Regrese lentamente a la posición inicial con movimientos controlados para mantener la tensión muscular.", "- Presione hacia abajo las manijas extendiendo los codos y levantando el cuerpo contra la resistencia.", "- Extienda completamente los brazos en la parte inferior para enganchar completamente los tríceps.", "- Regrese lentamente a la posición inicial con movimientos controlados para mantener la tensión muscular.", "- Repeticiones y respiración: realice de 10 a 15 repeticiones por serie, dependiendo de su nivel de condición física. Inhale mientras baja y exhale mientras presiona hacia abajo.", "- Realice de 10 a 15 repeticiones por serie, dependiendo de su nivel de condición física.", "- Inhala mientras vuelves a bajar y exhala mientras presionas hacia abajo.", "### Consejos para una forma adecuada:", "- Mantenga los codos cerca del cuerpo para maximizar la activación de los tríceps.", "- Avoid using excessive momentum to push the weight down.", "- Maintain a neutral spine and avoid excessive forward leaning.", "- Control the movement throughout the entire range of motion.", "- Utilice un peso que le permita completar cada repetición con la forma adecuada.", "### Errores comunes:", "- Codos ensanchados: reduce el compromiso de los tríceps y aumenta la tensión en los hombros.", "- Usar demasiado impulso: limita la efectividad del ejercicio al reducir la activación muscular.", "- No extender completamente los brazos: evita la contracción completa del tríceps, lo que reduce la participación de los músculos.", "- Inclinarse demasiado hacia adelante: cambia el enfoque hacia el pecho en lugar de aislar los tríceps.", "- Lifting Too Heavy: Can compromise form and increase injury risk."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-002099367097', 'Extensión de tríceps acostado unilateral', 'One-Arm Lying Triceps Extension', 'Tríceps', '["### ", "- Configuración: Acuéstese en un banco o en el piso con la espalda completamente apoyada. Sostenga una mancuerna en una mano con un agarre neutral o supinado (con la palma hacia arriba). Extienda el brazo recto por encima del hombro.", "- Acuéstese sobre un banco o en el suelo con la espalda totalmente apoyada.", "- Sostenga una mancuerna en una mano con un agarre neutral o supinado (con la palma hacia arriba).", "- Extiende tu brazo recto por encima de tu hombro.", "- Fase de descenso: Doble lentamente el codo para bajar la mancuerna hacia la frente o justo detrás de la cabeza. Mantenga la parte superior del brazo inmóvil y perpendicular al suelo. Evite ensanchar el codo hacia afuera; mantenlo alineado con tu hombro.", "- Doble lentamente el codo para bajar la mancuerna hacia la frente o justo detrás de la cabeza.", "- Mantenga la parte superior del brazo inmóvil y perpendicular al suelo.", "- Evite ensanchar el codo hacia afuera; mantenlo alineado con tu hombro.", "- Fase de levantamiento: active el tríceps para extender el brazo de regreso a la posición inicial. Mantenga el control durante todo el movimiento, evitando movimientos rápidos o bruscos. Extienda completamente el codo, pero sin bloquearlo.", "- Involucre sus tríceps para extender su brazo de regreso a la posición inicial.", "- Mantenga el control durante todo el movimiento, evitando movimientos rápidos o bruscos.", "- Extienda completamente el codo pero no lo bloquee.", "- Repeticiones y respiración: realiza de 8 a 15 repeticiones por brazo, dependiendo de tus objetivos de entrenamiento. Inhala mientras bajas la mancuerna y exhala mientras extiendes el brazo.", "- Realiza de 8 a 15 repeticiones por brazo, dependiendo de tus objetivos de entrenamiento.", "- Inhala mientras bajas la mancuerna y exhala mientras extiendes el brazo.", "### Consejos para una forma adecuada:", "- Mantenga el codo fijo en su lugar para maximizar la activación del tríceps.", "- Baje la mancuerna con control para evitar forzar la articulación del codo.", "- Utilice un peso moderado que permita una forma adecuada sin tensión excesiva.", "- Involucre su núcleo para mantener la estabilidad mientras está acostado en el banco.", "- Realice el ejercicio en un rango completo de movimiento para una activación muscular óptima.", "### Errores comunes:", "- Ensanchar el codo: reduce el aislamiento del tríceps y puede provocar tensión en el hombro.", "- Uso de peso excesivo: compromete la forma y aumenta el riesgo de lesiones.", "- Acelerar el movimiento: Reduce el tiempo bajo tensión, limitando el compromiso muscular.", "- Arquear la espalda baja: puede causar tensión innecesaria en la columna.", "- No controlar la fase excéntrica: bajar el peso demasiado rápido minimiza la activación muscular."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000638815890', 'Extensión de tríceps sobre la cabeza con cuerda y cable', 'Cable Rope Overhead Triceps Extension', 'Tríceps', '["### ", "- Configuración: Conecte el accesorio de cuerda a la polea de la máquina de cable. Párese de espaldas a la máquina y agarre la cuerda con ambas manos usando un agarre neutral (con las palmas una frente a la otra). Dé un paso ligeramente hacia adelante para crear tensión en el cable y coloque los pies separados al ancho de los hombros.", "- Conecte el accesorio de cuerda a la polea de la máquina de cable.", "- Párese de espaldas a la máquina y agarre la cuerda con ambas manos usando un agarre neutral (con las palmas una frente a la otra).", "- Da un paso ligeramente hacia adelante para crear tensión en el cable y separa los pies a la altura de los hombros.", "- Posición inicial: levante los brazos por encima de la cabeza, manteniendo los codos doblados y apuntando hacia adelante. Las manos deben estar detrás de la cabeza y el core debe estar comprometido para mantener la estabilidad.", "- Levanta los brazos por encima de la cabeza, manteniendo los codos doblados y apuntando hacia adelante.", "- Tus manos deben estar detrás de tu cabeza y tu núcleo debe estar comprometido para mantener la estabilidad.", "- Ejecución:Extiende los brazos completamente empujando la cuerda hacia arriba y hacia adelante hasta que los codos queden rectos.Aprieta los tríceps en la parte superior del movimiento para una contracción máxima.Baja lentamente la cuerda hasta la posición inicial, controlando el movimiento para mantener la tensión.", "- Extienda los brazos completamente empujando la cuerda hacia arriba y hacia adelante hasta que los codos queden rectos.", "- Aprieta tus tríceps en la parte superior del movimiento para lograr la máxima contracción.", "- Baje lentamente la cuerda hasta la posición inicial, controlando el movimiento para mantener la tensión.", "- Repeticiones y respiración: realiza de 10 a 15 repeticiones por serie, dependiendo de tus objetivos de entrenamiento. Inhala mientras bajas la cuerda y exhala mientras extiendes los brazos.", "- Realiza de 10 a 15 repeticiones por serie, dependiendo de tus objetivos de entrenamiento.", "- Inhala mientras bajas la cuerda y exhala mientras extiendes los brazos.", "### Consejos para una forma adecuada:", "- Mantenga los codos cerca de la cabeza y evite abrirlos hacia afuera.", "- Mantenga una columna neutral y active su núcleo para lograr estabilidad.", "- Utilice un movimiento controlado para maximizar la participación de los tríceps.", "- Evite el uso de peso excesivo que comprometa su forma.", "- Extiende completamente los codos en la parte superior para activar los tríceps por completo.", "### Errores comunes:", "- Codos ensanchados: reduce el aislamiento del tríceps y aumenta la tensión en los hombros.", "- Inclinarse demasiado hacia adelante: puede desviar la atención del tríceps y causar tensión en la parte baja de la espalda.", "- Usar demasiado impulso: limita la activación muscular y reduce la eficacia.", "- No extender completamente los brazos: Disminuye el compromiso de los tríceps y limita el rango de movimiento.", "- Elegir el peso incorrecto: el peso excesivo puede provocar una forma inadecuada, mientras que una resistencia muy pequeña puede no proporcionar suficiente estimulación muscular."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001234172538', 'Press inclinado con mancuernas', 'Incline Dumbbell Press', 'Pecho', '["Ajuste un banco a un ángulo de inclinación de 30 a 45 grados.", "Toma una mancuerna en cada mano y siéntate en el banco, con los pies apoyados en el suelo.", "Apoye las mancuernas sobre los muslos, luego recuéstese mientras lleva las pesas al nivel de los hombros.", "Coloque las mancuernas con las palmas hacia adelante y los codos doblados a unos 90 grados."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000990903190', 'Aperturas inclinada con mancuernas', 'Incline Dumbbell Fly', 'Pecho', '["Ajuste un banco a un ángulo de inclinación, generalmente de 30 a 45 grados.", "Siéntese en el banco y coloque los pies apoyados en el suelo para mayor estabilidad.", "Sostenga una mancuerna en cada mano con un agarre neutral (con las palmas una frente a la otra).", "Recuéstese en el banco con las mancuernas sostenidas sobre el pecho, los brazos extendidos pero los codos ligeramente doblados."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000755594573', 'Estiramiento de la esfinge', 'Sphinx Stretch', 'Hombros', '["La Esfinge es una maravillosa postura de yoga para abrir la parte superior del cuerpo y ganar más fuerza y ​​movilidad en la parte media de la espalda y la columna torácica. Este movimiento fortalece los músculos erectores de la columna que brindan soporte a la columna. Unos músculos fuertes de la espalda pueden prevenir desviaciones posturales que provocan malas posturas y molestias, como la cifosis (“jorobada”). El movimiento de la esfinge mejora su postura al extender los músculos de la espalda y reducir la tensión entre la zona lumbar y las áreas centrales. También mejora la fuerza de la espalda baja, lo que facilita mantenerse erguido durante todo el día."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001753649966', 'Rotación de pie', 'Standing Rotation', 'Abdomen', '["Un ejercicio dinámico de flexibilidad que puedes realizar antes de empezar a entrenar. Puede ayudarle a aumentar la flexibilidad y el rango de movimiento, incluidos los músculos centrales y abdominales."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000571447382', 'Estiramiento de la parte superior de la espalda', 'Upper Back Stretch', 'Espalda', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000543797779', 'Curl en polea a un brazo', 'One Arm Cable Curl', 'Otros', '["### ", "- Comience conectando un accesorio de cable de un solo mango a la posición más baja de una máquina de cable.", "- Párese de espaldas a la máquina de cable, con los pies separados a la altura de los hombros y las rodillas ligeramente dobladas.", "- Sujete el mango con la palma hacia arriba y párese lo suficientemente lejos de la máquina de cable para que su brazo esté completamente extendido y haya tensión en el cable.", "- Manteniendo el codo pegado al costado, exhale y doble el mango hacia el hombro, contrayendo los músculos del bíceps.", "- Mantenga la contracción por un segundo, luego inhale y baje lentamente el mango hasta la posición inicial, manteniendo la tensión en el cable.", "- Repita hasta el número deseado de repeticiones, luego cambie de brazo y repita.", "### Consejos para una forma adecuada", "- Mantenga el codo fijo cerca de la caja torácica; no dejes que avance.", "- Evite balancearse o utilizar el impulso del cuerpo para levantar el peso.", "- Mantenga una posición neutra de la muñeca para lograr un movimiento suave del cable.", "- Concéntrese en el descenso excéntrico controlado para maximizar la participación de los músculos.", "- Ajuste la altura de la polea para mantener un ángulo de resistencia cómodo.", "### Errores comunes a evitar", "- Permitir que el hombro gire hacia adelante o que el codo se aleje del cuerpo.", "- Usar demasiado peso, lo que reduce el control y aumenta la tensión en las articulaciones.", "- Sacudiendo o balanceando el torso para ayudar al levantamiento.", "- No extender completamente el brazo en la parte inferior de la repetición, lo que reduce el rango de movimiento."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001881939318', 'Press inclinado con mancuernas con agarre inverso', 'Reverse Grip Incline Dumbbell Press', 'Pecho', '["Ajuste el banco a un ángulo de inclinación de 30 a 45 grados.", "Coge un par de mancuernas y siéntate en el banco con los pies apoyados en el suelo.", "Sostenga las mancuernas con agarre inverso (con las palmas hacia usted) y colóquelas al nivel de los hombros con los codos doblados."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000575057088', 'Curl de muñeca unilateral y cable en el suelo', 'Cable One-Arm Wrist Curl On Floor', 'Antebrazos', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001448153306', 'Aperturas en máquina', 'Machine Fly', 'Pecho', '["### ", "- Ajuste la altura del asiento para que las manijas queden al nivel del pecho.", "- Siéntese en la máquina con la espalda firmemente presionada contra la almohadilla.", "- Sujete las manijas o las almohadillas con un agarre neutral (con las palmas hacia adentro).", "- Coloque los brazos doblados a la altura de los codos (mantenga esta flexión durante todo el ejercicio).", "- Exhale mientras junta las manijas o las almohadillas frente a su pecho con un movimiento suave y controlado.", "- Aprieta los músculos del pecho en el punto máximo del movimiento durante una breve pausa.", "- Inhala mientras regresas lentamente a la posición inicial, sintiendo un estiramiento en el pecho.", "- Repita hasta el número deseado de repeticiones.", "### Consejos para la eficacia", "- Apriete en la parte superior: concéntrese en contraer los músculos del pecho al juntar las manijas.", "- Peso moderado: utilice un peso que permita la forma adecuada para todas las repeticiones sin sacrificar el control.", "- Sobrecarga progresiva: aumente gradualmente el peso o las repeticiones para continuar desarrollando fuerza y ​​​​tamaño.", "- Combínelo con ejercicios compuestos: combínelo con prensas y fondos para un entrenamiento de pecho completo.", "### Errores comunes", "- Bloqueo de los codos: Mantenga los codos doblados para evitar tensiones articulares innecesarias.", "- Estiramiento excesivo: evite bajar los brazos demasiado hacia atrás, lo que puede tensar los hombros.", "- Usando Momentum: Realice el movimiento lentamente para mantener la tensión en los músculos del pecho.", "- Altura del asiento incorrecta: ajuste el asiento para alinear las manijas con la mitad de su pecho."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001602840836', 'Patada trasera con palanca', 'Lever Standing Rear Kick', 'Piernas', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000827011937', 'Buenos días (Good Morning)', 'Good Morning', 'Espalda', '["Un buen ejercicio matutino es un movimiento de la bisagra de la cadera que ayuda a fortalecer los glúteos y las piernas al enfocarse en la espalda, los isquiotibiales, los glúteos y los aductores.", "Cuando se hace correctamente, un buen ejercicio matutino es eficaz para fortalecer la espalda y hacerla más flexible. Sin embargo, si acabas de empezar, se recomienda probar el movimiento con peso vacío."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001294017926', 'Extensión de tríceps con barra acostada', 'Lying Barbell Triceps Extension', 'Tríceps', '["### ", "- Configuración: Acuéstese en un banco plano con los pies firmemente plantados en el suelo. Sostenga una barra con un agarre por encima de la cabeza, separada al ancho de los hombros. Extienda los brazos completamente por encima del pecho, manteniendo los codos ligeramente doblados para evitar la tensión en las articulaciones.", "- Acuéstese en un banco plano con los pies firmemente plantados en el suelo.", "- Sostenga una barra con un agarre por encima de la cabeza, separada al ancho de los hombros.", "- Extienda los brazos completamente por encima del pecho, manteniendo los codos ligeramente doblados para evitar tensión en las articulaciones.", "- Fase de descenso: Inhale y baje lentamente la barra hacia la frente doblando los codos. Mantenga los codos inmóviles y apuntando hacia arriba durante todo el movimiento. Baje la barra hasta que esté justo encima de la frente o ligeramente detrás de la cabeza.", "- Inhala y baja lentamente la barra hacia tu frente doblando los codos.", "- Mantenga los codos inmóviles y apuntando hacia arriba durante todo el movimiento.", "- Baje la barra hasta que esté justo encima de su frente o ligeramente detrás de su cabeza.", "- Fase de levantamiento: Exhale y extienda los codos para empujar la barra hacia la posición inicial. Concéntrese en contraer los tríceps mientras estira los brazos. Evite bloquear los codos en la parte superior para mantener la tensión muscular.", "- Exhala y extiende los codos para empujar la barra hacia la posición inicial.", "- Concéntrate en contraer los tríceps mientras estiras los brazos.", "- Evite bloquear los codos en la parte superior para mantener la tensión muscular.", "- Repeticiones y respiración: Realiza de 8 a 12 repeticiones por serie, dependiendo de tu objetivo de entrenamiento. Mantén la respiración controlada durante todo el movimiento.", "- Realiza de 8 a 12 repeticiones por serie, dependiendo de tu objetivo de entrenamiento.", "- Mantener la respiración controlada durante todo el movimiento.", "### Consejos para una forma adecuada:", "- Mantenga los codos en una posición fija para maximizar la activación de los tríceps.", "- Baje la barra de forma lenta y controlada para evitar tensiones innecesarias.", "- Mantenga una posición neutra de la muñeca para reducir la tensión en las articulaciones.", "- Involucre su núcleo para estabilizar su cuerpo durante el ejercicio.", "- Utilice un observador o un peso adecuado para evitar la pérdida de control.", "### Errores comunes:", "- Permitir que los codos se ensanchen: reduce el compromiso de los tríceps y aumenta la tensión en los hombros.", "- Uso de peso excesivo: puede provocar una forma inadecuada y posibles lesiones.", "- Bajar la barra demasiado rápido: aumenta el riesgo de golpearse la cabeza o perder el control.", "- No extenderse completamente: Previene la contracción máxima y reduce la efectividad.", "- Arquear la zona lumbar: puede causar molestias y reducir la estabilidad."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000493935183', 'Extensión de espalda con lastre', 'Weighted Back Extension', 'Espalda', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001755747816', 'Cruce en polea unilateral', 'Single-Arm Cable Crossover', 'Pecho', '["Configure la máquina de cable. Ajuste la polea a la altura de los hombros. Coloque una manija única en la polea y seleccione un peso apropiado.", "Ajuste la polea a la altura de los hombros.", "Coloque una sola manija en la polea y seleccione un peso apropiado.", "PosiciónesePárese con los pies escalonados para mantener el equilibrio. Sujete el mango con una mano y aléjese ligeramente de la máquina para crear tensión en el cable.", "Párese con los pies escalonados para mantener el equilibrio.", "Sujete el mango con una mano y aléjese ligeramente de la máquina para crear tensión en el cable.", "Involucre su núcleo Apriete los músculos abdominales para estabilizar su cuerpo. Mantenga los hombros hacia abajo y hacia atrás para mantener una postura adecuada.", "Apriete los músculos abdominales para estabilizar su cuerpo.", "Mantenga los hombros hacia abajo y hacia atrás para mantener una postura adecuada.", "Realiza el MovimientoComience con el brazo extendido hacia el costado a la altura del hombro. Tire con control del mango frente a su cuerpo, apretando el pecho en el punto máximo. Regrese lentamente a la posición inicial manteniendo la tensión en el cable.", "Comienza con el brazo extendido hacia un lado a la altura del hombro.", "Tire de la manija frente a su cuerpo con control, apretando su pecho en la cima.", "Regrese lentamente a la posición inicial manteniendo la tensión en el cable.", "Repetir Complete el número deseado de repeticiones antes de cambiar al otro brazo.", "Complete el número deseado de repeticiones antes de cambiar al otro brazo."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-002097225216', 'Press de pecho inclinado con palanca', 'Lever Incline Chest Press', 'Pecho', '["- Ajuste el asiento: ajuste la altura del asiento de modo que las manijas queden alineadas con su pecho. Esto es importante para garantizar que la prensa apunte eficazmente a la parte superior del pecho.", "- Elija el peso: seleccione el peso apropiado que pueda controlar en todo el rango de movimiento.", "- Agarre las manijas: siéntese en la máquina con la espalda firmemente contra la almohadilla. Sujete las manijas con las palmas hacia adelante (generalmente, la máquina tiene agarres neutrales o en pronación).", "- Coloque sus pies: Coloque sus pies apoyados en el piso para mayor estabilidad.", "- Presione las manijas hacia arriba: empuje las manijas hacia adelante con un movimiento controlado, extendiendo completamente los brazos sin bloquear los codos.", "- Aprieta en la parte superior: en la cima del movimiento, aprieta brevemente el pecho para maximizar la participación de los músculos.", "- Baje lentamente: lleve lentamente las manijas hacia su pecho, sintiendo un estiramiento en la parte superior del pecho y los hombros.", "- Repetir: realice la cantidad deseada de repeticiones, enfocándose en mantener un movimiento controlado en todo momento.", "### Consejos para la eficacia", "- Conexión mente-músculo: concéntrese en apretar el pecho en la parte superior de cada repetición para maximizar la activación de los músculos pectorales.", "- Tempo controlado: realice el ejercicio con un ritmo lento para mantener una tensión constante en los músculos del pecho, lo que mejora el crecimiento muscular.", "- Rango completo de movimiento: asegúrese de presionar completamente sin bloquear los codos y lleve las manijas hacia su pecho para un estiramiento completo.", "### Errores comunes", "- Extensión excesiva: evite bloquear los codos en la parte superior del movimiento. Esto puede generar una tensión innecesaria en las articulaciones.", "- Demasiado peso: el uso de pesos excesivos puede comprometer la forma y aumentar el riesgo de lesiones. Concéntrate en las repeticiones y la forma controladas.", "- Movimiento apresurado: Evite movimientos rápidos o bruscos. Los movimientos lentos y controlados maximizan la activación muscular y reducen el riesgo de lesiones."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000191386520', 'Sentadilla sumo con barra', 'Barbell Sumo Squat', 'Piernas', '["### ", "- Coloca una barra en tus trapecios superiores en una rejilla para sentadillas y párate debajo de ella con una postura amplia.", "- Coloque los pies más anchos que el ancho de los hombros, con los dedos girados unos 30 grados.", "- Apoye su núcleo y mantenga su pecho erguido mientras quita la barra y da un paso atrás.", "- Baje las caderas hacia abajo, manteniendo las rodillas alineadas con los dedos de los pies.", "- Desciende hasta que tus muslos queden paralelos al suelo o ligeramente por debajo si la movilidad lo permite.", "- Conduce a través de los talones y la parte media del pie para volver a pararte, apretando los glúteos en la parte superior.", "### Consejos para una forma adecuada", "- Mantenga las rodillas sobre los dedos de los pies para evitar la tensión en las rodillas.", "- Mantenga el pecho alto y la columna recta durante todo el movimiento.", "- Apoye su núcleo para sostener su espalda baja.", "- Utilice un agarre cómodo sobre la barra, manteniendo los codos apuntando hacia abajo.", "- Concéntrate en separar el suelo con los pies para enganchar la parte interna de los muslos.", "### Errores comunes", "- Dejar que las rodillas colapsen hacia adentro, lo que reduce el compromiso interno del muslo.", "- Inclinarse demasiado hacia adelante, generando tensión en la zona lumbar.", "- No utilizar un rango completo de movimiento, lo que limita la activación muscular.", "- Redondear la espalda, especialmente bajo carga pesada.", "- Colocar la barra demasiado alta o demasiado baja provocando desequilibrio."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000855718948', 'Sentadilla búlgara (Split) con mancuernas', 'Dumbbell Bulgarian Split Squat', 'Piernas', '["### Paso 1: configuración y posicionamiento", "- Párese aproximadamente a dos pies frente a un banco o escalón, sosteniendo una mancuerna en cada mano a los costados.", "- Coloque el pie trasero sobre el banco con la parte superior del pie apoyada sobre él.", "- Mantenga el pie delantero plantado firmemente, con los dedos apuntando hacia adelante y la postura separada a la altura de las caderas.", "### Paso 2: Ejecución", "- Involucre su núcleo y mantenga su pecho erguido.", "- Baje la rodilla trasera hacia el suelo mientras mantiene la rodilla delantera alineada con los dedos de los pies.", "- Desciende hasta que tu muslo delantero esté paralelo al suelo o ligeramente por debajo, asegurándote de que tu rodilla no pase los dedos de los pies.", "- Empuja con el talón de tu pie delantero para volver a la posición inicial.", "- Realice de 8 a 12 repeticiones por pierna, luego cambie de lado."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000412289574', 'Pinza de mano', 'Hand Gripper', 'Otros', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-002099320765', 'Push Press (Press con impulso)', 'Push Press', 'Hombros', '["Configuración: Párese con los pies separados a la altura de los hombros. Los dedos de los pies deben estar ligeramente hacia afuera. Coloque la barra sobre la parte superior del pecho, justo debajo del cuello. Si usa mancuernas, sostenga una en cada mano a la altura de los hombros con las palmas hacia adelante.", "Párese con los pies separados a la altura de los hombros. Los dedos de tus pies deben estar ligeramente hacia afuera.", "Coloque la barra sobre la parte superior de su pecho, justo debajo de su cuello. Si usa mancuernas, sostenga una en cada mano a la altura de los hombros con las palmas hacia adelante.", "Agarre: Para el press de empuje con barra, su agarre debe ser ligeramente más ancho que el ancho de los hombros. Agarre la barra con las palmas hacia adelante y los codos apuntando hacia abajo. Asegúrese de que sus muñecas estén alineadas con sus antebrazos. Si usa mancuernas, sujételas firmemente con las palmas una frente a la otra.", "Para el press de hombros con barra, el agarre debe ser ligeramente más ancho que el ancho de los hombros. Agarre la barra con las palmas hacia adelante y los codos apuntando hacia abajo. Asegúrese de que sus muñecas estén alineadas con sus antebrazos.", "Si usa mancuernas, sujételas firmemente con las palmas una frente a la otra.", "Posición de la rejilla: levante la barra de la rejilla o límpiela hasta los hombros si comienza desde el suelo. Mantenga los codos ligeramente por delante de la barra y la parte superior de los brazos paralela al suelo. Esta es tu posición inicial.", "Levante la barra de la rejilla o límpiela hasta los hombros si comienza desde el suelo.", "Mantenga los codos ligeramente por delante de la barra y la parte superior de los brazos paralela al suelo. Esta es tu posición inicial.", "Inmersión: Comience doblando ligeramente las rodillas para iniciar una inmersión. Mantenga el torso erguido y el pecho elevado. Mientras se inclina, concéntrese en mantener el peso equilibrado en la parte media del pie y los talones.", "Comience doblando ligeramente las rodillas para iniciar una inmersión. Mantenga el torso erguido y el pecho elevado.", "Mientras te sumerges, concéntrate en mantener el peso equilibrado en la parte media del pie y los talones.", "Impulso: Extienda explosivamente las caderas y las rodillas para generar un impulso hacia arriba. Este movimiento debe ser potente y rápido. Mientras conduces hacia arriba, presiona la barra sobre tu cabeza usando la fuerza de tus hombros y tríceps. Si usa mancuernas, presiónelas sobre la cabeza simultáneamente.", "Extienda explosivamente las caderas y las rodillas para generar un impulso hacia arriba. Este movimiento debe ser potente y rápido.", "Mientras conduces hacia arriba, presiona la barra sobre tu cabeza usando la fuerza de tus hombros y tríceps. Si usa mancuernas, presiónelas sobre la cabeza simultáneamente.", "Bloqueo: Extienda completamente los brazos por encima de la cabeza, bloqueando los codos. Tu cabeza debe moverse ligeramente hacia adelante cuando la barra pasa por tu frente.", "Extienda completamente los brazos por encima de la cabeza, bloqueando los codos. Tu cabeza debe moverse ligeramente hacia adelante cuando la barra pasa por tu frente.", "Regreso: Baje la barra hasta la posición inicial doblando las rodillas y las caderas. Deje que el peso descienda bajo control.", "Baje la barra hasta la posición inicial doblando las rodillas y las caderas. Deje que el peso descienda bajo control.", "Coloque la barra: si usa una barra, colóquela nuevamente sobre los soportes o el suelo.", "Si usa una barra, colóquela sobre los soportes o el suelo."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001339372557', 'Fondos de tríceps en el suelo', 'Triceps Dips on Floor', 'Tríceps', '["- Posición inicial: Siéntese en el suelo con las rodillas dobladas y los pies apoyados en el suelo. Coloque las manos detrás de usted, un poco más anchas que el ancho de los hombros, con los dedos apuntando hacia adelante o ligeramente hacia afuera. Levante las caderas del suelo para que sus brazos soporten el peso de la parte superior del cuerpo.", "- Siéntate en el suelo con las rodillas dobladas y los pies apoyados en el suelo.", "- Coloque las manos detrás de usted, un poco más anchas que el ancho de los hombros, con los dedos apuntando hacia adelante o ligeramente hacia afuera.", "- Levante las caderas del suelo para que sus brazos soporten el peso de la parte superior del cuerpo.", "- Ejecución: Baje lentamente el cuerpo doblando los codos hasta que los tríceps queden paralelos al suelo o ligeramente por debajo. Mantenga los codos cerca del cuerpo para maximizar la activación de los tríceps. Empuje con las palmas y estire los brazos para volver a la posición inicial. Repita el número deseado de repeticiones.", "- Baje lentamente el cuerpo doblando los codos hasta que los tríceps queden paralelos al suelo o ligeramente por debajo.", "- Mantenga los codos cerca del cuerpo para maximizar la activación de los tríceps.", "- Empuja con las palmas y estira los brazos para volver a la posición inicial.", "- Repita hasta el número deseado de repeticiones.", "- Repeticiones y respiración: realice de 10 a 15 repeticiones por serie. Inhale mientras baja el cuerpo y exhale mientras empuja hacia arriba.", "- Realiza de 10 a 15 repeticiones por serie.", "- Inhala mientras bajas el cuerpo y exhala mientras vuelves a subir.", "### Consejos para una forma adecuada:", "- Mantenga los codos apuntando hacia atrás en lugar de extenderse hacia los lados.", "- Evite bloquear los codos en la parte superior del movimiento para evitar tensiones.", "- Involucre su núcleo para mantener la estabilidad durante todo el ejercicio.", "- Muévase lentamente y con control para maximizar la participación de los músculos.", "- Mantenga los hombros bajos y alejados de las orejas para evitar la acumulación de tensión.", "### Errores comunes:", "- No bajar lo suficiente: Reduce el compromiso de los tríceps y limita la efectividad del ejercicio.", "- Uso de Momentum: rebotar hacia arriba y hacia abajo minimiza la activación muscular y aumenta el riesgo de lesiones.", "- Codos ensanchados: desvía la atención del tríceps y puede tensar los hombros.", "- Hombros encorvados: conduce a una mala postura y a una tensión innecesaria en el cuello.", "- Colocación incorrecta de las manos: Las manos demasiado atrás o demasiado juntas pueden causar molestias en la muñeca."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001599064802', 'Jalón al pecho en media rodilla', 'Half Kneeling Lat Pulldown', 'Espalda', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001155356491', 'Press Tate sentado con mancuernas delante y detrás', 'Dumbbell Seated Front and Back Tate Press', 'Espalda', '["- Posición inicial: Siéntese en un banco plano con la espalda recta y los pies firmemente plantados en el suelo. Sostenga una mancuerna en cada mano y tenga las palmas hacia adelante. Levante las mancuernas al nivel de los hombros con los codos doblados aproximadamente a 90 grados.", "- Siéntate en un banco plano con la espalda recta y los pies firmemente plantados en el suelo.", "- Sostenga una mancuerna en cada mano y coloque las palmas hacia adelante.", "- Levante las mancuernas al nivel de los hombros con los codos doblados aproximadamente a 90 grados.", "- Ejecución: Front Tate Press: Extiende los brazos hacia arriba manteniendo las mancuernas delante de tu cabeza. Extienda completamente los codos, luego baje las mancuernas a la posición inicial. Press de espalda Tate: presione las mancuernas por encima de la cabeza pero ligeramente detrás de la cabeza. Controle el movimiento a medida que regresa a la posición inicial. Repita las prensas delanteras y traseras en un patrón alterno para el número deseado de repeticiones.", "- Front Tate Press: Extienda los brazos hacia arriba mientras mantiene las mancuernas frente a su cabeza. Extiende completamente los codos y luego baja las mancuernas a la posición inicial.", "- Back Tate Press: presione las mancuernas por encima de la cabeza pero ligeramente detrás de la cabeza. Controla el movimiento mientras regresas a la posición inicial.", "- Repita las prensas delanteras y traseras en un patrón alterno para el número deseado de repeticiones.", "- Repeticiones y respiración: Realice de 8 a 12 repeticiones por serie. Inhale mientras baja las mancuernas y exhale mientras las presiona sobre su cabeza.", "- Realiza de 8 a 12 repeticiones por serie.", "- Inhala mientras bajas las mancuernas y exhala mientras las presionas sobre tu cabeza.", "### Consejos para una forma adecuada:", "- Mantenga su núcleo comprometido para mantener la estabilidad durante todo el movimiento.", "- Mueve las mancuernas de forma controlada para maximizar la activación del tríceps.", "- Evite arquear la zona lumbar manteniendo una postura fuerte y erguida.", "- Asegúrese de que sus codos permanezcan doblados en un ángulo constante durante la prensa.", "- No apresures el movimiento; céntrese en un ritmo suave y constante.", "### Errores comunes:", "- Uso de peso excesivo: puede provocar una forma inadecuada y aumentar el riesgo de lesiones.", "- Inclinarse demasiado hacia adelante o hacia atrás: reduce la estabilidad y aleja la tensión del tríceps.", "- Bloquear los codos: puede tensar las articulaciones y reducir la participación de los músculos.", "- Dejar caer las mancuernas demasiado rápido: aumenta el riesgo de perder el control y posibles lesiones.", "- No involucrar el Core: conduce a inestabilidad y ejecución inadecuada del ejercicio."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001313671711', 'Peso muerto rumano con mancuernas', 'Dumbbell Romanian Deadlift', 'Piernas', '["Párese con los pies separados a la altura de las caderas y sostenga un par de mancuernas frente a los muslos con las palmas hacia el cuerpo.", "Involucre su núcleo, mantenga el pecho elevado y mantenga una ligera flexión de las rodillas durante todo el movimiento.", "Comience el movimiento flexionando las caderas, empujando los glúteos hacia atrás mientras mantiene la espalda recta.", "Baje las mancuernas a lo largo de la parte delantera de sus piernas, manteniendo una ligera flexión de las rodillas y manteniendo las pesas cerca de su cuerpo.", "Continúe bajando las mancuernas hasta que sienta un estiramiento en los isquiotibiales o hasta que alcance un rango de movimiento cómodo.", "Haga una pausa breve en la parte inferior del movimiento, luego invierta el movimiento impulsando las caderas hacia adelante y apretando los glúteos.", "Regrese a la posición inicial levantándose erguido, manteniendo su núcleo comprometido y manteniendo una columna neutral."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000618366905', 'Saltos de energía', 'Power Skips', 'Cardio', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000670010598', 'Gatos plyo', 'Plyo Jacks', 'Cardio', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001450389327', 'Máquina de sentadillas Hack', 'Hack Squats Machine', 'Piernas', '["Suba a la plataforma y coloque la espalda plana contra la almohadilla con los hombros debajo de las almohadillas de soporte.", "Coloque los pies separados a la altura de los hombros con los dedos ligeramente hacia afuera en la plataforma para los pies.", "Desbloquee las manijas de seguridad, apoye su núcleo y comience a bajar el trineo doblando las rodillas.", "Desciende hasta que tus muslos queden paralelos o ligeramente por debajo mientras mantienes los talones planos y las rodillas alineadas.", "Empuja con los talones para extender las piernas y vuelve a la posición inicial sin bloquear las rodillas.", "Repita para las repeticiones deseadas, manteniendo el control y la tensión durante todo el movimiento."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
