INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001399162561', 'Abducción lateral de cadera con palanca', 'Lever Side Hip Abduction', 'Piernas', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001708037924', 'Elevación de piernas con palanca', 'Lever Standing Leg Raise', 'Abdomen', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001455862612', 'Zancada con mancuernas', 'Dumbbell Lunge', 'Piernas', '["Desarrolla tamaño y fuerza en cuádriceps, glúteos e isquiotibiales. Las estocadas con mancuernas son uno de los ejercicios eficaces para la parte inferior del cuerpo que mejoran por completo la fuerza, la estabilidad y el equilibrio de las piernas. Las estocadas con mancuernas se dirigen con mayor intensidad a los cuádriceps y los músculos de la cadera, pero también afectan a los tendones de las rodillas, los muslos y el core.", "Las estocadas con mancuernas son un ejercicio fácil de realizar para principiantes. Puede ayudar a fortalecer los músculos de las piernas, tensar los músculos de la cadera y quemar calorías para perder peso.", "Aprieta el trasero. Las estocadas con mancuernas son uno de los mejores ejercicios que pueden ayudarte a conseguir unos glúteos más firmes y tonificados actuando sobre los músculos más profundos de los glúteos."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000197536414', 'Zancada trasera con mancuernas', 'Dumbbell Rear Lunge', 'Piernas', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000589815935', 'Aducción de cadera lateral con palanca', 'Lever Side Hip Adduction', 'Piernas', '["La aducción de cadera con palanca es un ejercicio de aislamiento eficaz para la parte interna de la cadera que desarrolla fuerza y ​​​​músculo en los aductores responsables de la rotación de la articulación de la cadera."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000405593689', 'Zancada con barra', 'Barbell Lunge', 'Piernas', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001314061414', 'Zancada lateral', 'Side Lunge', 'Piernas', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-002108247596', 'Sentadilla de sumo con peso corporal', 'Bodyweight Sumo Squat', 'Piernas', '["### ", "- Párese con los pies más separados que el ancho de los hombros y los dedos de los pies ligeramente hacia afuera.", "- Apoye su núcleo y mantenga su pecho elevado durante todo el movimiento.", "- Baje el cuerpo doblando las rodillas y las caderas, hundiendo las caderas hacia abajo.", "- Desciende hasta que tus muslos queden paralelos al suelo o tan bajos como te permita la movilidad.", "- Conduce con los talones para volver a la posición inicial, apretando los glúteos en la parte superior.", "### Consejos para una forma adecuada", "- Mantenga el torso erguido para evitar inclinarse hacia adelante.", "- Empuje las rodillas hacia afuera en línea con los dedos de los pies durante el descenso.", "- Involucre su núcleo para mantener el equilibrio y proteger su espalda baja.", "- Baje con control y haga una breve pausa en la parte inferior para una mayor activación muscular.", "- Mantenga una presión uniforme sobre los pies para evitar que se incline hacia adelante.", "### Errores comunes", "- Dejar que las rodillas se doblen hacia adentro, lo que reduce la efectividad y aumenta el riesgo de lesiones.", "- Estar demasiado estrecho, lo que desvía el énfasis de los músculos objetivo.", "- Redondear la espalda inclinándose demasiado hacia adelante.", "- Subir a los dedos de los pies, lo que disminuye la activación de los glúteos y los isquiotibiales.", "- Ir demasiado rápido, sacrificando control y rango de movimiento."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000071363472', 'Pliométrico de lúpulo en zigzag', 'Zig Zag Hops Plyometric', 'Piernas', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001556004817', 'Aducción de cadera en polea', 'Cable Hip Adduction', 'Piernas', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001825815525', 'Upavistha Konasana', 'Upavistha Konasana', 'Piernas', '["La Upavistha Konasana es una postura de yoga desafiante. La asana forma un ángulo que le da un gran estiramiento al cuerpo, especialmente a la parte inferior del cuerpo. Estira las piernas, las caderas, los hombros y los músculos de la ingle, fortalece la espalda y mejora la postura. Estirar el cuerpo aumenta la flexibilidad de los músculos y reduce el riesgo de lesiones y previene el dolor muscular."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000178430546', 'Estiramiento de isquiotibiales sentado', 'Seated Hamstring Stretch', 'Piernas', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000957046505', 'Almeja acostada de lado', 'Side Lying Clam', 'Piernas', '["La almeja acostada de lado es un ejercicio sencillo que comienza a tonificar las caderas y los muslos. Este ejercicio trabaja los músculos de la cadera más pequeños y menos conocidos. También enseña la estabilidad pélvica a medida que la pierna gira hacia adentro y hacia afuera en la cadera."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000456676987', 'Peso muerto con palanca', 'Lever Deadlift', 'Piernas', '["Es adecuado para principiantes. Dado que este ejercicio se realiza en una máquina y mientras lo hace no necesita concentrarse en equilibrar los músculos, le permite agregar más peso para ganar más músculo.", "El peso muerto es uno de los ejercicios compuestos más eficaces. Se expresa como un ejercicio de fuerza básico en deportes de fuerza como el levantamiento de pesas. Es el movimiento más popular de fuerza y ​​entrenamiento de fuerza ya que trabaja muchos grupos de músculos.", "Aumenta la testosterona: Se ha demostrado mediante investigaciones que los ejercicios con pesas ayudan a aumentar los niveles de testosterona a corto y largo plazo. Ejercicios como press de banca, sentadillas y peso muerto son los ejercicios más efectivos que aumentan los niveles de testosterona.", "Fortalece la capacidad de agarre. Le permite agarrar un objeto con más firmeza cuando lo sostiene. Además, los estudios demuestran que el peso muerto es un ejercicio eficaz para mejorar la fuerza explosiva y el rendimiento del salto vertical.", "El peso muerto ayuda al desarrollo de los músculos de las piernas, los músculos de la cadera y los músculos centrales, al mismo tiempo que apoya la formación de músculos y la fuerza en el cuerpo. Además, agregar peso muerto a tus entrenamientos ayuda a fortalecer tus tendones, ligamentos y huesos.", "El peso muerto también activa tus glúteos y músculos de la espalda. Los ejercicios funcionales como el peso muerto son aquellos que facilitan las actividades del cuerpo en la vida real.", "El peso muerto se dirige a todos los músculos responsables de la postura y le permite mantener la espalda recta durante las actividades diarias habituales.", "La forma correcta es muy importante en este ejercicio. Para empezar, hacer mal puede provocar lesiones. Tras algunos intentos con la barra vacía o acompañado de un entrenador, el proceso de adaptación al movimiento puede verse acortado."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001459590637', 'Estiramiento del cuádriceps de rodillas', 'Kneeling Quad Stretch', 'Piernas', '["Se aplica para estirar los músculos cuádriceps. Estirar los músculos con regularidad puede mejorar su flexibilidad y rendimiento, y también prevenir lesiones y rigidez."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000029201554', 'Paso de velocidad lateral', 'Lateral Speed Step', 'Espalda', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000775448305', 'Peso muerto a una pierna con pesa rusa', 'Kettlebell Single Leg Deadlift', 'Piernas', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001924362865', 'Estiramiento de ingle/aductor sentado', 'Seated Groin / Adductor Stretch', 'Piernas', '["El estiramiento de la ingle del aductor sentado forma un ángulo que le da un gran estiramiento al cuerpo, especialmente a la parte inferior del cuerpo. Estira las piernas, las caderas, los hombros y los músculos de la ingle, fortalece la espalda y mejora la postura. Estirar el cuerpo aumenta la flexibilidad de los músculos y reduce el riesgo de lesiones y previene el dolor muscular."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001413237261', 'Elevación de rodilla con zancada inversa', 'Reverse Lunge Knee Lift', 'Piernas', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001582648065', 'Estiramiento de los isquiotibiales acostado', 'Lying Hamstring Stretch', 'Piernas', '["Los estiramientos de los isquiotibiales ayudarán a mantener los músculos flexibles y móviles. La mejor manera de mantener estos músculos relajados y flexibles es incluyendo estiramientos dinámicos en tu calentamiento y estiramientos estáticos en tu rutina de vuelta a la calma. Estirar los isquiotibiales con regularidad puede mejorar su flexibilidad y rendimiento, y también prevenir lesiones y rigidez. El estiramiento dinámico previo al entrenamiento mejora la circulación, prepara los músculos para el movimiento y aumenta temporalmente su rango de movimiento."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000851043442', 'Patada de glúteos del burro del cable', 'Cable Donkey Kickback', 'Espalda', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000723873575', 'Levantamiento de pantorrillas en sentadilla', 'Hack Squat Calf Raise', 'Piernas', '["- Configuración: Párese dentro de la máquina de sentadillas con los hombros debajo de las almohadillas y los pies colocados en lo alto de la plataforma para los pies. Mantenga los dedos de los pies apuntando hacia adelante o ligeramente hacia afuera.", "- Coloque los pies para un estiramiento completo: las puntas de los pies deben descansar sobre el borde de la plataforma para que los talones puedan moverse libremente en un estiramiento profundo sin resbalar.", "- Desbloquee la máquina: Extienda las piernas completamente para levantar el carro y soltar las manijas de seguridad.", "- Comience a levantar: con las rodillas completamente extendidas, presione los pies delanteros para levantar los talones lo más alto posible.", "- Pausa y contracción: manténgalo en la parte superior durante 1 a 2 segundos, enfatizando una contracción máxima en las pantorrillas.", "- Baje lentamente: deje que los talones caigan por debajo del nivel de la plataforma para lograr un estiramiento completo del gastrocnemio y el sóleo.", "- Repetir: realice la cantidad deseada de repeticiones, manteniendo el control en todo momento.", "### Consejos para una forma adecuada", "- Mantenga las rodillas rectas pero no bloqueadas para enfatizar los gastrocnemios.", "- Evite doblar las caderas o las rodillas; esto mantiene la atención en las pantorrillas, no en los cuádriceps.", "- Muévase lenta y deliberadamente, especialmente durante la fase excéntrica (de descenso).", "- Asegúrese de que los pies estén colocados de forma segura; use suelas de goma o cinta adhesiva si es necesario.", "- Apriete en la parte superior durante 1 a 2 segundos para maximizar el reclutamiento de fibras musculares.", "### Errores comunes a evitar", "- Dejar que las rodillas se doblen, lo que aleja la carga del gemelo.", "- Utilizar un rango de movimiento parcial, limitando el estiramiento y la contracción.", "- Rebotar en el fondo, lo que elimina la tensión muscular y corre el riesgo de sufrir tensión en las articulaciones.", "- Permitir que los pies resbalen, lo que puede reducir la eficacia o provocar lesiones.", "- Sobrecarga demasiado pronto, comprometiendo el control y la estabilidad."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001417046787', 'Abducción de cadera en puente', 'Bridge Hip Abduction', 'Piernas', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001458537709', 'Máquina de patada de glúteos', 'Glute Kickback Machine', 'Espalda', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000300571580', 'Sentadilla de reverencia', 'Curtsy Squat', 'Piernas', '["### Paso 1: configuración y posicionamiento", "- Párate erguido con los pies separados a la altura de las caderas y mantén el core comprometido.", "- Junte las manos en las caderas o delante del pecho para mantener el equilibrio.", "### Paso 2: Ejecución", "- Coloque la pierna derecha en diagonal detrás de la pierna izquierda, bajando las caderas hasta quedar en cuclillas.", "- Mantenga la rodilla delantera alineada con los dedos de los pies y baje la rodilla trasera cerca del suelo.", "- Presione con el talón de su pie delantero para regresar a la posición inicial.", "- Repita en el lado opuesto y continúe alternando piernas."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000600460782', 'Sentadilla con copa en polea', 'Cable Goblet Squat', 'Piernas', '["Conecte una barra recta o un mango de cuerda a la polea inferior de una máquina de cable.", "Colóquese frente a la máquina y agarre el mango con ambas manos, sujetándolo a la altura del pecho.", "Retroceda un poco para que el peso tire hacia adelante, luego párese con los pies separados a la altura de los hombros.", "Apoye su núcleo y comience la sentadilla doblando las caderas y las rodillas simultáneamente.", "Baja el cuerpo hasta que los muslos queden paralelos al suelo o ligeramente por debajo, manteniendo el pecho erguido.", "Conduce con los talones para volver a la posición inicial, manteniendo la tensión del cable en todo momento.", "Repita para las repeticiones, asegurando el control y un torso erguido durante el movimiento."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001540704578', 'Sentadilla con salto Split', 'Split Jump Squat', 'Piernas', '["Comience en una posición de estocada con el pie derecho hacia adelante y el pie izquierdo hacia atrás. Mantenga los pies separados a la altura de los hombros y los dedos de los pies apuntando hacia adelante.", "Salta explosivamente y cambia la posición de tus pies en el aire, de modo que tu pie izquierdo ahora esté al frente y tu pie derecho atrás.", "Aterriza suavemente en el suelo con el pie izquierdo hacia adelante y el pie derecho hacia atrás, bajando el cuerpo nuevamente a una posición de estocada.", "Repita el movimiento durante el número deseado de repeticiones o tiempo, alternando entre cada pierna."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001631743804', 'Aperturas del muslo (estiramiento del aductor mayor)', 'Thigh fly (Adductor Magnus Stretch)', 'Pecho', '["### The Thigh Fly como estiramiento estático:", "- Posición inicial: Acuéstese boca arriba con las piernas juntas, levantadas hacia el techo. Asegúrese de que sus caderas estén firmemente ancladas al suelo.", "- Movimiento de estiramiento: abra lentamente las piernas hacia los lados tanto como le resulte cómodo, sintiendo un estiramiento a lo largo de la parte interna de los muslos. Mantenga esta posición durante 10 a 15 segundos mientras respira de manera constante.", "- Regreso a la posición inicial: Vuelva a juntar suavemente las piernas y regrese a la posición inicial.", "- Repeticiones: repita el estiramiento durante 2 a 4 repeticiones, tomando breves períodos de descanso entre ellas si es necesario.", "### El Muslo Fly como movimiento dinámico:", "- Posición inicial: comience en la misma posición inicial que el estiramiento estático.", "- Movimiento continuo: abra las piernas hacia los lados y luego vuelva a cerrarlas con un movimiento fluido sin detenerse en la posición estirada.", "- Repeticiones: realice el Thigh Fly dinámico durante el número especificado de repeticiones sin descansar entre cada repetición.", "- Respiración: Inhala mientras abres las piernas y exhala mientras las cierras.", "### Consejos para una forma adecuada", "- Mantén la cadera anclada al suelo durante todo el movimiento.", "- Muévase lentamente y con control para maximizar el estiramiento y activar los músculos de manera efectiva.", "- Respire profunda y constantemente durante todo el ejercicio.", "- Si siente molestias o tensión, reduzca el rango de movimiento o detenga el ejercicio.", "### Errores comunes a evitar", "- Arqueando la parte baja de la espalda: asegúrese de que su espalda permanezca plana sobre el suelo para evitar tensiones.", "- Uso del impulso: realice el movimiento con control en lugar de depender del impulso.", "- Extender demasiado: Evite separar demasiado las piernas, ya que esto puede provocar tensión muscular.", "- Conteniendo la respiración: Mantenga una respiración constante para mejorar la relajación y la eficacia."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000329942887', 'Sentadilla cosaca', 'Cossack Squat', 'Piernas', '["Párese con los pies bien separados y los dedos ligeramente hacia afuera.", "Cambie su peso hacia un lado, doblando la rodilla mientras mantiene recta la pierna opuesta.", "Mantenga el pecho alto y el torso erguido mientras se agacha lo más bajo posible con la pierna doblada.", "Permita que el talón de la pierna estirada se levante ligeramente si la flexibilidad es limitada.", "Empuje a través de la pierna doblada para regresar a la posición inicial, luego repita en el otro lado."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001443674731', 'Elevación alternativa de piernas en el suelo tumbado', 'Alternate Lying Floor Leg Raise', 'Abdomen', '["Se dirige a los músculos abdominales inferiores y superiores al mismo tiempo: la elevación alterna de las piernas en el suelo actúa sobre el recto abdominal y los músculos oblicuos, de modo que los músculos abdominales superiores e inferiores se desarrollan simultáneamente."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001306615993', 'Fondos de pecho', 'Chest Dips', 'Pecho', '["- Posiciónate: Coloca tus manos sobre las barras paralelas, manteniendo los brazos rectos y el cuerpo ligeramente inclinado hacia adelante. Tus pies deben estar separados del suelo y tu cuerpo debe estar en una posición erguida o ligeramente inclinada hacia adelante, dependiendo de tu concentración.", "- Agarre: Sujete las barras firmemente con las palmas hacia adentro y los codos ligeramente doblados para comenzar.", "- Posición de las piernas: Mantenga las piernas dobladas a la altura de las rodillas y los pies juntos para mayor estabilidad, o extiéndalas para mayor dificultad.", "- Baje el cuerpo: baje lentamente el cuerpo doblando los codos y manteniendo la parte superior del cuerpo ligeramente inclinada hacia adelante. Bájate hasta que la parte superior de tus brazos quede paralela al suelo o ligeramente por debajo.", "- Involucre el pecho: concéntrese en apretar los músculos del pecho mientras baja el cuerpo. Esta inclinación hacia adelante enfatiza más el pecho que los tríceps.", "- Press Up: Empújese hacia arriba estirando los brazos y volviendo a la posición inicial.", "- Repetir: Realiza el número deseado de repeticiones, manteniendo el control durante todo el movimiento.", "### Consejos para la eficacia", "- Lento y controlado: realice cada repetición lentamente y con control para maximizar la participación de los músculos. Concéntrese en estirar en la parte inferior y apretar en la parte superior.", "- Conexión mente-músculo: concéntrese en sentir los músculos del pecho trabajando durante todo el movimiento, especialmente durante la fase de descenso.", "- Utilice la sobrecarga progresiva: a medida que se fortalezca, puede agregar peso usando un cinturón de inmersión para continuar progresando y desarrollando músculo.", "- Calienta adecuadamente: asegúrate de que tus hombros y pecho estén calientes antes de realizar fondos para evitar lesiones.", "### Errores comunes a evitar", "- No inclinarse lo suficiente hacia adelante: para activar el pecho, asegúrese de inclinarse ligeramente hacia adelante mientras baja el cuerpo. Esto ayuda a apuntar a los músculos del pecho. Si te mantienes demasiado erguido, la atención se centrará en los tríceps.", "- Codos ensanchados: Mantenga los codos cerca del cuerpo para reducir la tensión en los hombros y prevenir lesiones.", "- No profundizar lo suficiente: asegúrese de bajar lo suficiente (al menos hasta que la parte superior de sus brazos quede paralela al piso) para maximizar el compromiso del pecho y la activación muscular.", "- Bloquear los codos en la parte superior: evite bloquear los codos en la parte superior del movimiento, lo que puede generar una tensión innecesaria en las articulaciones."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000307665109', 'Levantamiento de pantorrilla a una pierna en máquina Hack', 'Hack Machine One-Leg Calf Raise', 'Pantorrillas', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000364197810', 'Elevación de pantorrilla a una pierna', 'Single Leg Calf Raise', 'Pantorrillas', '["Configuración: Párese cerca de un banco, estante u otro soporte para mantener el equilibrio. Coloque la punta de un pie sobre una superficie elevada (como un escalón o un plato) con el talón colgando.", "Coloque la pierna que no trabaja: levante el pie opuesto del suelo, doblando la rodilla para que no ayude.", "Comience con un estiramiento completo: permita que el talón caiga por debajo del escalón para sentir un estiramiento en la pantorrilla de la pierna que trabaja.", "Levante a través del antepié: presione a través de la punta del pie y levante el talón lo más alto posible con un movimiento controlado.", "Pausa y contracción: apriete la pantorrilla en la parte superior durante 1 a 2 segundos.", "Baje lentamente: deje que el talón regrese por debajo del escalón en un descenso lento y controlado para enfatizar la carga excéntrica.", "Repetir: realice la cantidad deseada de repeticiones, luego cambie de lado."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000200356598', 'Elevación de pantorrilla sentado con palanca', 'Lever Seated Calf Raise', 'Pantorrillas', '["### ", "- Configuración: Siéntese en la máquina con las rodillas dobladas a 90 grados y los pies colocados a la altura de los hombros en la plataforma para los pies. La almohadilla para los muslos debe descansar firmemente sobre los muslos, justo por encima de las rodillas.", "- Ajustar carga: cargue el peso deseado en los brazos de palanca. Comience de manera conservadora y concéntrese en el rango completo de movimiento.", "- Posición inicial: Suelte el mecanismo de seguridad. Deje que los talones bajen lentamente para sentir un estiramiento profundo en las pantorrillas.", "- Elevar: Presione a través de las puntas de los pies para levantar los talones lo más alto posible, concentrándose en una fuerte contracción en el sóleo.", "- Pausa y contracción: manténgalo en la parte superior durante 1 a 2 segundos, contrayendo completamente las pantorrillas sin rebotar.", "- Bajar bajo control: Deje que sus talones regresen a la posición inicial bajo un control lento y deliberado para un estiramiento excéntrico completo.", "- Repetir: realice la cantidad deseada de repeticiones manteniendo una forma estricta.", "### Consejos para una forma adecuada", "- Evite los rebotes: utilice movimientos lentos y deliberados, especialmente al final de la repetición.", "- Mantenga las rodillas y las caderas quietas: no use el impulso ni mueva los muslos hacia arriba para ayudar al levantamiento.", "- Controle lo excéntrico: enfatice la fase de descenso para obtener un beneficio hipertrófico adicional.", "- Utilice un rango completo de movimiento: permita un estiramiento completo y una elevación completa del talón.", "- Pausa en la parte superior: manténgalo presionado brevemente durante 1 a 2 segundos para mejorar la conexión mente-músculo con el sóleo.", "### Errores comunes", "- Acelerar las repeticiones y aprovechar el impulso, reduciendo la tensión en el sóleo.", "- Rango de movimiento parcial, lo que limita el desarrollo de la pantorrilla.", "- Dejar que las rodillas se levanten de la almohadilla, lo que disminuye la eficiencia mecánica.", "- Usar demasiado peso, comprometer el control y aumentar el riesgo de lesiones.", "- Descuidar el control excéntrico, perder un estímulo clave para el crecimiento muscular."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001964232221', 'Flexión pliométrica con caída (Drop Push-Up)', 'Drop Push-Up', 'Pecho', '["- Coloca dos bancos o cajas resistentes paralelos entre sí, dejando suficiente espacio para que puedas moverte cómodamente entre ellos.", "- Asegúrate de que los bancos o cajas sean estables y no se vuelquen durante el ejercicio.", "- Colócate de manera que puedas colocar las manos en los bancos y los pies en el suelo.", "- Haz una flexión", "- Tu cuerpo debe formar una línea recta.", "- Comience el ejercicio realizando una flexión regular. Baje el pecho hacia el banco doblando los codos.", "- Mantenga su cuerpo en línea recta y mantenga la forma adecuada de flexión de brazos. Tu pecho debe acercarse al banco sin tocarlo.", "- Durante la fase de aterrizaje, soltarás las manos de los bancos y apuntarás a aterrizar con las manos en el suelo.", "- Mientras desciendes hacia el suelo, retira las manos del banco y dirígelas hacia el suelo para lograr un aterrizaje suave.", "- Aterriza con control para minimizar cualquier impacto discordante en tus muñecas y hombros.", "- Después de completar la flexión en el suelo, levántate explosivamente con la mayor fuerza posible.", "- Utilice su pecho, tríceps y hombros para generar la fuerza hacia arriba.", "- Vuelva a colocar las manos en los bancos en la posición inicial.", "- Realice el ejercicio durante el número deseado de repeticiones.", "### Consejos para la eficacia", "- Primero domine las flexiones: asegúrese de poder realizar flexiones estándar con la forma adecuada antes de intentar hacer flexiones de brazos.", "- Concéntrese en el control: durante la fase de caída, controle su descenso para minimizar el impacto y prevenir lesiones.", "- Explota con poder: empuja hacia arriba explosivamente durante la fase de flexión para maximizar el beneficio pliométrico.", "- Calienta a fondo: prepara tus muñecas, hombros y abdomen con estiramientos dinámicos para reducir el riesgo de tensión.", "- Progrese gradualmente: comience con menos repeticiones o versiones modificadas, como dejarse caer desde una posición de rodillas, si es un principiante."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000385386282', 'Crunch con lastre', 'Weighted Crunch', 'Cardio', '["El movimiento Weighted Crunch es un ejercicio avanzado que se aplica con la ayuda de un peso para moldear, tensar y fortalecer los músculos abdominales. En este ejercicio que haces con peso, puedes tener más interacción con los músculos del sixpack."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000713336453', 'Aperturas en polea tumbado', 'Lying Cable Fly', 'Pecho', '["- Coloque el banco: coloque un banco plano en el centro de una máquina cruzada de cables o cerca de dos sistemas de poleas ajustables.", "- Ajuste las poleas: coloque las poleas del cable ligeramente por debajo o a la misma altura que sus hombros cuando esté acostado.", "- Coloque manijas: coloque manijas de un solo agarre en cada polea.", "- Agarre las manijas: Acuéstese en el banco y sostenga las manijas con las palmas hacia adentro (agarre neutral).", "- Posición inicial: Extienda los brazos hacia arriba para que las manijas se junten por encima de su pecho. Mantenga los codos ligeramente doblados para reducir la tensión en las articulaciones. Las muñecas deben permanecer neutrales (no dobladas).", "- Extiende tus brazos hacia arriba para que las manijas se encuentren por encima de tu pecho.", "- Mantenga los codos ligeramente doblados para reducir la tensión en las articulaciones.", "- Tus muñecas deben permanecer neutrales (no dobladas).", "- Fase de descenso: baje lentamente los brazos hacia los lados formando un arco amplio. Mantenga los codos ligeramente doblados y concéntrese en sentir el estiramiento en el pecho. Baje hasta que los brazos estén alineados con el torso o justo debajo del nivel de los hombros.", "- Baja lentamente los brazos hacia los lados formando un amplio arco.", "- Mantenga los codos ligeramente doblados y concéntrese en sentir el estiramiento en el pecho.", "- Baje hasta que sus brazos estén alineados con su torso o justo debajo del nivel de los hombros.", "- Fase de elevación: Apriete los músculos del pecho y lleve los brazos a la posición inicial de forma controlada. Evite que las manijas choquen en la parte superior; mantener la tensión en los cables.", "- Aprieta los músculos del pecho y lleva los brazos a la posición inicial de forma controlada.", "- Evite que las manijas choquen en la parte superior; mantener la tensión en los cables.", "- Repetir: Realiza el número deseado de repeticiones, manteniendo el control durante todo el movimiento.", "### Consejos para la eficacia", "- Concéntrese en la forma: utilice pesas livianas inicialmente para garantizar una técnica adecuada y un rango completo de movimiento.", "- Conexión mente-músculo: Concéntrese en apretar los músculos del pecho en la parte superior del movimiento para una activación máxima.", "- Controla los cables: evita que los cables tiren de tus brazos demasiado rápido durante la fase de descenso.", "- Ajuste la altura de la polea: experimente con alturas de polea para apuntar a diferentes partes del cofre.", "### Errores comunes a evitar", "- Extender demasiado los brazos: Enderezar completamente los codos puede ejercer una tensión excesiva en las articulaciones. Mantenga una ligera curvatura.", "- Rango de movimiento limitado: no bajar los brazos por completo reduce el estiramiento y la efectividad del ejercicio.", "- Movimientos apresurados: realizar el ejercicio demasiado rápido puede provocar una mala forma y una disminución del compromiso muscular.", "- Arqueando la espalda: Mantenga la parte baja de la espalda en contacto con el banco para evitar tensiones y mantener la forma adecuada.", "- Asas que chocan: Dejar que las asas choquen en la parte superior reduce la tensión en los músculos del pecho."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000674911128', 'Crianza de crías en burro', 'Donkey Calf Raise', 'Pantorrillas', '["- Posición de los pies: Párese con las puntas de los pies sobre un borde elevado o bloque, con los talones colgando. Los dedos de los pies deben apuntar rectos o ligeramente hacia afuera.", "- Alineación del torso: inclínese hacia adelante a la altura de las caderas hasta aproximadamente 90°, manteniendo la columna neutra. Sostenga las empuñaduras o la superficie de apoyo para estabilizar.", "- Comience con un estiramiento profundo: permita que los talones desciendan lentamente hasta que sienta un estiramiento completo en las pantorrillas.", "- Levantar: Conduzca a través de las puntas de los pies para elevar los talones lo más alto posible, manteniendo las rodillas extendidas.", "- Contraer y mantener: haga una pausa en la parte superior durante 1 a 2 segundos, apretando las pantorrillas con fuerza.", "- Bajar bajo control: baje lentamente los talones hasta la posición estirada.", "- Repetir: realice el número deseado de repeticiones manteniendo un control y una postura estrictos.", "### Consejos para una forma adecuada", "- Mantenga una posición con la cadera articulada y la espalda plana durante todo el movimiento.", "- Evite doblar la rodilla, ya que esto desplaza la tensión del gemelo al sóleo.", "- Utilice un rango completo de movimiento, enfatizando tanto el estiramiento profundo como la contracción completa.", "- Aprieta en la parte superior, en lugar de rebotar durante las repeticiones.", "- Sostenga las manijas de soporte ligeramente; son para brindar estabilidad, no para impulsarse hacia arriba.", "### Errores comunes a evitar", "- Acelerar el movimiento, lo que minimiza la carga excéntrica y la tensión de estiramiento.", "- Doblar las rodillas, lo que disminuye la activación de los gastrocnemios y limita el rango.", "- Depender del impulso, especialmente en la parte inferior, aumenta el riesgo para el tendón de Aquiles.", "- Permitir que la parte superior del cuerpo se redondee, reduciendo la alineación de la columna y la seguridad de la carga.", "- Colocación desalineada del pie, que puede forzar los tobillos y reducir el compromiso de las pantorrillas."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001884730362', 'Crunch lateral sentado', 'Seated Side Crunch', 'Cardio', '["Los abdominales laterales sentado en la pared son un ejercicio avanzado desarrollado para dar forma, tensar y fortalecer los músculos oblicuos. Para llevar el ejercicio a un nivel superior, puedes dificultar el movimiento tomando una pesa en la mano. Además, el ejercicio puede ayudar a aumentar la resistencia de los músculos de las piernas al proporcionar una contracción isométrica."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001164006772', 'Fondo de pecho asistida', 'Assisted Chest Dip', 'Pecho', '["- Establezca la resistencia: ajuste el contrapeso de la máquina a un nivel apropiado. Un peso más alto proporciona más asistencia, facilitando el ejercicio.", "- Colóquese: coloque las rodillas o los pies en la plataforma de asistencia y agarre las manijas firmemente con las palmas hacia adentro o ligeramente hacia adelante.", "- Inclínese hacia adelante: para enfatizar el pecho, incline ligeramente el torso hacia adelante, manteniendo los hombros hacia abajo y los codos ligeramente ensanchados (en un ángulo de aproximadamente 45 grados).", "- Baje el cuerpo: doble lentamente los codos para bajar el cuerpo hasta que la parte superior de los brazos quede paralela al suelo o ligeramente por debajo.", "- Presione hacia arriba: empújese hacia atrás hasta la posición inicial, concentrándose en involucrar su pecho y tríceps.", "- Repetir: Realizar el número deseado de repeticiones con control.", "### Consejos para la eficacia", "- Progrese gradualmente: disminuya gradualmente el nivel de asistencia con el tiempo para desarrollar fuerza y ​​trabajar hacia fondos sin ayuda.", "- Concéntrese en la forma: mantenga el núcleo contraído, los hombros hacia abajo y el pecho comprometidos durante todo el movimiento.", "- Respiración: Exhala mientras presionas hacia arriba e inhala mientras bajas el cuerpo.", "- Estiramiento y calentamiento: caliente los hombros, el pecho y los tríceps antes de realizar fondos para evitar tensiones o lesiones.", "### Errores comunes a evitar", "- Inclinación insuficiente hacia adelante: Mantener el torso demasiado erguido desplaza la atención hacia los tríceps en lugar del pecho.", "- Codos ensanchados: Los codos excesivamente ensanchados pueden aumentar la tensión en los hombros. Mantenlos en un ángulo de 45 grados.", "- Movimiento apresurado: realizar fondos demasiado rápido reduce la participación de los músculos y aumenta el riesgo de lesiones. Utilice movimientos lentos y controlados.", "- Configuración de resistencia inadecuada: usar demasiada o muy poca ayuda puede comprometer la forma. Elige un nivel que te desafíe pero que permita la técnica adecuada."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001704086965', 'Salto hacia atrás', 'Backward Jump', 'Espalda', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000286957966', 'Elevación de pantorrillas de pie en la máquina de press de banca', 'Standing Calf Raise on the Bench Press Machine', 'Pecho', '["- Configuración: Súbase a la plataforma de la máquina con las puntas de los pies firmemente en el borde y los talones colgando.", "- Posición: Párese erguido y agarre las manijas laterales para lograr equilibrio y estabilidad.", "- Posición inicial: mantenga el núcleo comprometido, la espalda recta y las piernas casi rectas (pero no bloqueadas).", "- Levante los talones: presione las puntas de los pies para levantar los talones lo más alto posible. Concéntrate en contraer las pantorrillas en la parte superior.", "- Haga una pausa y apriete: mantenga la posición superior durante 1 a 2 segundos para maximizar la participación de los músculos.", "- Bajar bajo control: baje lentamente los talones por debajo del nivel de la plataforma para estirarse por completo antes de repetir.", "### Consejos para una forma adecuada", "- Mantenga su núcleo apretado para mantener una postura erguida y evite arquear la espalda baja.", "- Evite bloquear las rodillas: una ligera flexión mantiene la tensión en las pantorrillas.", "- Utilice un rango completo de movimiento, bajando completamente los talones y levantándose completamente sobre los dedos de los pies.", "- Controlar el descenso; no bajes los talones rápidamente.", "- Concéntrate en la conexión mente-músculo, especialmente durante la pausa en la cima.", "### Errores comunes", "- Usar el impulso: rebotar hacia arriba y hacia abajo reduce la activación muscular y aumenta el riesgo de lesiones.", "- Rango de movimiento parcial: no subir o bajar completamente los talones limita el estiramiento y la contracción.", "- Rodillas bloqueadas: Esto aleja la tensión de las pantorrillas y puede estresar las articulaciones.", "- Repeticiones apresuradas: los movimientos rápidos y descontrolados minimizan el tiempo de los músculos bajo tensión.", "- Inclinarse hacia adelante: Reduce la efectividad y ejerce una tensión innecesaria en la espalda."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000789960619', 'Salto de tijera', 'Jumping jack', 'Piernas', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001253594418', 'Elevación de pantorrilla en burro con palanca', 'Lever Donkey Calf Raise', 'Pantorrillas', '["- Configure la máquina: ajuste la altura de la palanca acolchada para que descanse de forma segura en la parte baja de la espalda o las caderas cuando se agache.", "- Posición de los pies: Párese sobre el bloque de pantorrillas con las puntas de los pies apoyadas y los talones colgando. Los pies deben estar separados a la altura de las caderas o un poco más estrechos.", "- Alineación del torso: Inclínese hacia adelante a la altura de las caderas hasta formar un ángulo de aproximadamente 90°, manteniendo la columna neutra. La palanca acolchada debe descansar sobre el sacro o la parte superior de los glúteos, no sobre la columna.", "- Posición inicial: deje caer los talones por debajo del nivel de la plataforma para lograr un estiramiento completo de las pantorrillas.", "- Inicie el movimiento: presione a través de las puntas de los pies para levantar la palanca haciendo una flexión plantar de los tobillos. Mantenga las rodillas rectas durante todo el movimiento.", "- Contracción máxima: en la parte superior, haga una pausa de 1 a 2 segundos mientras aprieta activamente las pantorrillas.", "- Descenso controlado: baje lentamente la palanca hasta que los talones estén por debajo del paralelo para estirar el músculo por completo.", "- Repetir: realice la cantidad deseada de repeticiones con tempo controlado y rango de movimiento completo.", "### Consejos para una forma adecuada", "- Mantenga las rodillas completamente extendidas para maximizar la activación de los gastrocnemios.", "- Concéntrese en el ritmo: utilice un estiramiento de 2 segundos, un levantamiento de 1 segundo y una excéntrica de 2 segundos.", "- Utilice una columna neutra en todo momento. Evite redondear la espalda o hiperextender el cuello.", "- Coloque los pies en el medio de la plataforma para evitar resbalones y mantener la presión sobre las puntas de los pies.", "- Aprieta las pantorrillas con fuerza en la parte superior para aumentar el tiempo bajo tensión y desarrollar la conexión mente-músculo.", "### Errores comunes a evitar", "- Doblar las rodillas, lo que desplaza el énfasis hacia el sóleo.", "- Redondear la columna, especialmente bajo cargas pesadas.", "- Rebotar en la parte inferior, lo que reduce el tiempo bajo tensión y corre el riesgo de sufrir una lesión en el tendón de Aquiles.", "- Usar demasiado peso, lo que lleva a repeticiones cortas e incompletas.", "- Estar demasiado erguido, reduciendo el estiramiento mecánico del gastrocnemio."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001100398052', 'Estiramiento de los isquiotibiales con las piernas cruzadas de pie', 'Standing Cross Leg Hamstring Stretch', 'Piernas', '["- Posición inicial: Párese erguido con ambos pies juntos y los brazos a los costados.", "- Cruza las piernas: coloca el pie derecho sobre el izquierdo para cruzar las piernas. Mantenga ambos pies apoyados en el suelo y las rodillas ligeramente dobladas o rectas dependiendo de la flexibilidad.", "- Inclínese hacia adelante: Gire lentamente las caderas e inclínese hacia adelante, alcanzando los dedos de los pies o el piso. Deje que la cabeza cuelgue y mantenga la columna relajada.", "- Mantén el estiramiento: agarra tus tobillos, espinillas o el piso, donde tu flexibilidad lo permita. Mantenga esta posición durante 20 a 30 segundos mientras respira profundamente.", "- Cambiar de lado: regrese lentamente a la posición inicial, luego cambie la pierna cruzada y repita el estiramiento en el otro lado.", "### Consejos para una forma adecuada", "- Mantenga la espalda relajada y permita que la columna se alargue de forma natural.", "- No bloquees tus rodillas; una curva suave evita tensiones innecesarias.", "- Evite movimientos de rebote o sacudidas; El estiramiento debe ser lento y controlado.", "- Exhale profundamente mientras se inclina hacia adelante para ayudar a relajar los músculos.", "- Concéntrese en la bisagra de la cadera, no en la flexión de la espalda, para apuntar correctamente a los isquiotibiales.", "### Errores comunes", "- Redondear demasiado la espalda: esto reduce la eficacia del estiramiento de los isquiotibiales y puede forzar la columna.", "- Rebotar para profundizar: los estiramientos estáticos deben mantenerse, no rebotar.", "- Bloquear las rodillas: esto puede tensar las articulaciones y reducir la participación de los músculos.", "- Estirarse demasiado: intentar tocar el suelo antes de desarrollar flexibilidad puede provocar lesiones.", "- Respiración incorrecta: contener la respiración puede aumentar la tensión y reducir la eficacia del estiramiento."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001861205878', 'Salto amplio a una pierna', 'Single Leg Broad Jump', 'Piernas', '["Los saltos son un ejercicio pliométrico. Los ejercicios pliométricos son movimientos aeróbicos explosivos que aumentan la velocidad, la rapidez y la potencia y trabajan todo el cuerpo.", "El salto apunta a los músculos abdominales, los músculos de la cadera y los flexores de la cadera y también trabaja los muslos, los tendones de las rodillas y los cuádriceps.", "Los saltos son beneficiosos para la salud porque combinan el acondicionamiento cardiovascular con el trabajo de fuerza. Dado que los saltos elevan tu frecuencia cardíaca, también pueden mejorar tu condición cardiovascular."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001057614139', 'Inclinar pierna y levantar cadera', 'Incline Leg Hip Raise', 'Abdomen', '["La elevación de cadera con piernas inclinadas es un ejercicio diseñado para moldear, tensar y fortalecer los músculos abdominales. Con este ejercicio realizado en el banco inclinado, podrás concentrarte más en los músculos abdominales inferiores y fortalecer los músculos centrales."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001488146710', 'Molino (Windmill) de peso corporal', 'Bodyweight Windmill', 'Abdomen', '["Un ejercicio dinámico de flexibilidad que puedes realizar antes de empezar a entrenar. Puede ayudarle a aumentar la flexibilidad y el rango de movimiento, incluidos los músculos de la espalda, los hombros, los brazos, las piernas y los abdominales."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001457813319', 'Plancha de frontal a lateral', 'Front to Side Plank', 'Abdomen', '["Las planchas de frente a lado son un ejercicio cardiovascular y de fortalecimiento central eficaz. Puede ayudarle a fortalecer y desarrollar los músculos de la parte superior e inferior del cuerpo.", "Al ser un movimiento multifuncional, este ejercicio se dirige no solo a los músculos abdominales sino también a la columna y los glúteos. Plank fortalece y tonifica todo el cuerpo, mejora la postura y el equilibrio, reduce la grasa corporal y puede ayudar a acelerar el metabolismo."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001472819972', 'Crunch agrupado (Tuck Crunch)', 'Tuck Crunch', 'Cardio', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000857876740', 'Estiramiento de ambas piernas (Pilates)', 'Double Leg Stretch', 'Abdomen', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000924914606', 'Flexión lateral de tronco del banco', 'Bench Side Bend', 'Abdomen', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001268304117', 'Flexión lateral de tronco con mancuernas', 'Dumbbell Side Bend', 'Abdomen', '["Este ejercicio, dirigido a los músculos oblicuos, es muy útil para tensar y desarrollar la grasa abdominal. Puede trabajar más músculos objetivo aumentando el peso según su nivel de condición física."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-002062309017', 'Plancha de araña', 'Spider Plank', 'Abdomen', '["Spider Plank es un entrenamiento abdominal de alta intensidad que trabaja los músculos centrales. Además de ser beneficioso para reafirmar y fortalecer, puede mejorar la postura y el equilibrio, reducir la grasa corporal y ayudar a acelerar el metabolismo.", "También es un ejercicio eficaz que aumenta la estabilidad en las zonas del core, la columna y la cadera proporcionando una contracción isométrica. Puedes agregarlo a tus entrenamientos para moldear y fortalecer los músculos de la cadera, el abdomen y las piernas."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001992579520', 'Abdominales con lastre', 'Weighted Sit-ups', 'Abdomen', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001412024862', 'Cuarto de abdominales', 'Quarter Sit-up', 'Abdomen', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001573147462', 'Elevación de rodillas acostado', 'Lying Knee Raise', 'Abdomen', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-002020750465', 'Crunch del piso', 'Floor Crunch', 'Cardio', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001385233312', 'Toque del dedo del pie con giro de cangrejo (Crab Twist) (Crab Twist) (Crab Twist) (Crab Twist) (Crab Twist) (Crab Twist) (Crab Twist) (Crab Twist) (Crab Twist) (Crab Twist) (Crab Twist) (Crab Twist) (Crab Twist)', 'Crab Twist Toe Touch', 'Abdomen', '["El toque de cangrejo con los dedos del pie es un ejercicio abdominal avanzado. El contacto contrastante de las manos y las piernas entre sí activa intensamente tanto los músculos abdominales como los oblicuos. Este ejercicio, que trabaja la armonía de los músculos y la mente, puede ayudar a aumentar la coordinación del movimiento.", "Además, los músculos de los hombros y las piernas actúan como estabilizadores en la parte isométrica del movimiento, mientras que los flexores de la cadera participan en la parte dinámica del movimiento."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-002098974563', 'Remo vertical con barra Ez', 'Ez Bar Upright Row', 'Espalda', '["El remo vertical con barra EZ es un ejercicio de la parte superior del cuerpo que se dirige predominantemente al trapecio y los deltoides, que son responsables de agregar ancho a los hombros. Por lo general, se realiza utilizando una barra estándar o una barra EZ.", "El remo vertical con barra EZ es uno de los ejercicios efectivos para construir trampas más grandes, pero también es un movimiento en el que es fácil cometer errores. Una de las formas más sencillas de asegurarse de que su forma sea óptima es evitar el uso de mancuernas que sean demasiado pesadas."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000372201720', 'Carrera de zancada corta', 'Short Stride Run', 'Cardio', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000145508598', 'Máquina de elevación lateral', 'Lateral Raise Machine', 'Espalda', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000840156210', 'Press de martillo inclinado con mancuernas', 'Incline Dumbbell Hammer Press', 'Pecho', '["Ajuste el banco: coloque el banco inclinado en un ángulo de 30 a 45 grados.", "Seleccione mancuernas: elija un peso que le permita mantener la forma adecuada.", "Colóquese: siéntese en el banco con los pies apoyados en el suelo y la espalda totalmente apoyada.", "Agarre: Sostenga las mancuernas con un agarre neutral (martillo), con las palmas una frente a la otra."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001008553828', 'Plancha inversa', 'Reverse Plank', 'Abdomen', '["La plancha inversa es un entrenamiento de cuerpo completo muy eficaz que se dirige a todos los grupos de músculos principales del cuerpo. La plancha inversa fortalece y tonifica todo el cuerpo, mejora la postura y el equilibrio, reduce la grasa corporal y puede ayudar a acelerar el metabolismo. Si tiene problemas de espalda y lumbares, una plancha invertida realizada correctamente podría aliviar el dolor fortaleciendo los músculos centrales. Sin embargo, si no lo estás haciendo bien y sientes dolor de cuello o espalda durante el ejercicio, comienza primero con una variación más fácil, como una plancha normal."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000041100147', 'Hiperextensión', 'Hyperextension', 'Espalda', '["Los ejercicios de hiperextensión son un excelente ejercicio que fortalece el core, la espalda baja, los glúteos y los isquiotibiales.", "El movimiento de hiperextensión mejora su postura al extender los músculos de la espalda y reducir la tensión entre la zona lumbar y las áreas centrales. También mejora la fuerza de la espalda baja, lo que facilita mantenerse erguido durante todo el día.", "También es beneficioso para la salud de la espalda baja, ya que algunos dolores lumbares pueden deberse a glúteos débiles y tendones de la corva tensos."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001528290924', 'Elevación lateral trasera unilateral tumbado con mancuernas', 'Dumbbell Lying One-Arm Rear Lateral Raise', 'Espalda', '["La elevación lateral trasera con un brazo acostado con mancuernas es un ejercicio que se utiliza para fortalecer los músculos laterales y posteriores del hombro y los grupos de músculos más pequeños adjuntos a ellos. Levantar demasiado peso en este movimiento puede no ser saludable, hacer el ejercicio con pesas livianas y con muchas repeticiones puede ser más beneficioso para los músculos deltoides y del manguito rotador."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000427311709', 'Aperturas en polea invertida doblada', 'Bent Over Reverse Cable Fly', 'Pecho', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001758394615', 'Separación de banda', 'Band Pull-Apart', 'Hombros', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001733011844', 'Elevación inversa con barra inclinada', 'Bent-Over Barbell Reverse Raise', 'Hombros', '["La elevación inversa con barra inclinada es un ejercicio isola que se dirige a la parte posterior y a los lados de los hombros. Adecuado para todos los niveles, este entrenamiento de hombros es una buena opción para desarrollar fuerza, mejorar la movilidad del hombro y dar forma a los músculos posteriores del hombro."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001423190241', 'Brazo redondo con lastre', 'Weighted Round Arm', 'Hombros', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000453289663', 'Máquina de press de pecho interior', 'Inner Chest Press Machine', 'Pecho', '["Posición inicial: Comience con las manijas cerca de su pecho.", "Comience con las asas cerca de su pecho.", "Press Phase Empuje las manijas hacia adelante y ligeramente hacia adentro, extendiendo completamente los brazos sin bloquear los codos. Concéntrese en apretar los músculos del pecho al final del movimiento.", "Empuje las manijas hacia adelante y ligeramente hacia adentro, extendiendo completamente los brazos sin bloquear los codos.", "Concéntrate en apretar los músculos del pecho al final del movimiento.", "Fase de retorno Lleve lentamente las manijas a la posición inicial mientras mantiene el control. Evite que las pesas vuelvan a golpear la pila.", "Lleve lentamente las manijas a la posición inicial mientras mantiene el control.", "Evite que las pesas vuelvan a golpear la pila.", "Repetir: realice el número deseado de repeticiones, manteniendo un tempo constante."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001305201538', 'Prensa Scott', 'Scott Press', 'Hombros', '["Sostenga una mancuerna en cada mano y comience con los brazos al nivel de los hombros, doblados en ángulos de aproximadamente 90 grados. Con las palmas una frente a la otra.", "Realice un movimiento de rotación como con Arnold Press.", "Antes de que las mancuernas alcancen la parte superior del movimiento, gírelas ligeramente hacia arriba y hacia afuera, baje las muñecas a la posición inicial (con las palmas una frente a la otra) y repita el movimiento.", "Repita el movimiento durante el número deseado de repeticiones."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000352626024', 'Elevación lateral en polea a dos brazos', 'Two Arm Cable Lateral Raise', 'Espalda', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-002015273283', 'Elevación frontal de la placa de pesas', 'Weight Plate Front Raise', 'Espalda', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001348570150', 'Press de hombros en polea', 'Cable Shoulder Press', 'Hombros', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000875764477', 'Elevación frontal con doble cable', 'Double Cable Front Raise', 'Hombros', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000513022982', 'Extensión de cadera de pie', 'Standing Hip Extension', 'Piernas', '["La extensión de cadera de pie es un ejercicio sencillo que ayuda a desarrollar y fortalecer los músculos de la cadera. Incorporar una banda de resistencia en estos ejercicios de extensión de cadera ayudará a aumentar la resistencia contra la que trabaja su cuerpo."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001685056007', 'Elevación del deltoides posterior con barra', 'Barbell Rear Delt Raise', 'Hombros', '["El levantamiento del deltoides trasero con barra es un ejercicio con barra que se dirige principalmente a los hombros laterales y posteriores. Es un ejercicio eficaz que puedes incluir en tu programa para aislar los músculos posteriores del hombro y fortalecer los músculos del manguito rotador.", "También activa los músculos trapecios y puede beneficiar las molestias causadas por la debilidad muscular, como la postura postural y la protrusión del omóplato, al afectar los músculos infraespinoso y subescápula que cubren la escápula."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000517046026', 'Sentadilla con Landmine para presionar', 'Landmine Squat to Press', 'Piernas', '["Es un ejercicio funcional avanzado que aumenta la fuerza, la resistencia y el rendimiento. La prensa de minas terrestres ayuda a mejorar la coordinación, la resistencia muscular y el equilibrio. Le ayudan a ganar fuerza en la parte superior e inferior del cuerpo trabajando los músculos centrales, los cuádriceps, los glúteos y los hombros."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001256718351', 'Cable de transmisión trasera', 'Cable Rear Drive', 'Otros', '["- Configure la máquina de cable Coloque una manija única en la polea alta de una máquina de cable. Seleccione un peso apropiado que le permita mantener el control y la forma adecuada.", "- Conecte una sola manija a la polea alta de una máquina de cable.", "- Seleccione un peso apropiado que le permita mantener el control y la forma adecuada.", "- ColóquesePárate con el costado mirando hacia la máquina de cable.Agarra el mango con un agarre por encima de la mano usando la mano más alejada.Coloca la mano cerca del hombro opuesto con el codo doblado.Mantén los pies separados al ancho de los hombros y activa el core para lograr estabilidad.", "- Párese con el costado hacia la máquina de cable.", "- Agarre el mango con un agarre por encima de la cabeza con la mano más alejada.", "- Coloque su mano cerca de su hombro opuesto con el codo doblado.", "- Mantenga los pies separados a la altura de los hombros y active el núcleo para lograr estabilidad.", "- EjecuciónComience extendiendo el brazo hacia atrás con un movimiento controlado. Mantenga el codo en su lugar mientras mueve solo el antebrazo. Extienda completamente el brazo hasta que el tríceps esté completamente contraído. Haga una breve pausa al final del movimiento antes de volver a la posición inicial. Mantenga un movimiento lento y controlado durante todo el ejercicio.", "- Comience extendiendo el brazo hacia atrás con un movimiento controlado.", "- Mantenga el codo en su lugar mientras mueve solo el antebrazo.", "- Extiende completamente el brazo hasta que el tríceps esté completamente contraído.", "- Haga una breve pausa al final del movimiento antes de volver a la posición inicial.", "- Mantenga un movimiento lento y controlado durante todo el ejercicio.", "- Repetir Complete el número deseado de repeticiones antes de cambiar al otro brazo.", "- Complete el número deseado de repeticiones antes de cambiar al otro brazo.", "### Consejos para una forma adecuada", "- Mantenga el codo fijo en una posición para garantizar la participación completa del tríceps.", "- Mantenga una postura recta con el core comprometido para evitar movimientos innecesarios.", "- Controle el movimiento y evite sacudidas o utilizar el impulso para mover el peso.", "- Extienda el brazo por completo pero sin bloquear el codo para evitar tensión en las articulaciones.", "- Utilice un peso de ligero a moderado para centrarse en la contracción muscular en lugar de simplemente levantar cargas más pesadas.", "### Errores comunes a evitar", "- Permitir que el codo se mueva hacia adelante o hacia afuera, lo que reduce la activación del tríceps.", "- Usar demasiado peso, lo que lleva a un control deficiente y a una forma comprometida.", "- Inclinar excesivamente el torso, en lugar de mantener una postura estable.", "- No extender completamente el brazo, limitando la efectividad del ejercicio.", "- Apresurarse en las repeticiones, en lugar de utilizar movimientos lentos y controlados para maximizar la participación de los músculos."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000867061654', 'Escapción con mancuernas', 'Dumbbell Scaption', 'Hombros', '["La escapción con mancuernas es un ejercicio de aislamiento que favorece el desarrollo de los músculos del hombro y especialmente del músculo supraespinoso. Al apuntar a los músculos estabilizadores, protege la articulación del hombro y los ligamentos que la rodean. Sin embargo, también se utiliza para fortalecer el hombro y prevenir lesiones en los manguitos rotadores. Se recomienda realizarlo con poco peso en lugar de levantar demasiado peso."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000211483143', 'Rotación Externa Cubana Con Mancuernas', 'Dumbbell Cuban External Rotation', 'Hombros', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000220340792', 'Press de hombros unilateral y mancuernas', 'Dumbbell One Arm Shoulder Press', 'Hombros', '["Párese con los pies separados a la altura de los hombros y sostenga una mancuerna en una mano al nivel de los hombros con la palma hacia adelante. Mantenga su núcleo comprometido y su pecho erguido.", "Presione la mancuerna hacia arriba y por encima de su cabeza, estirando el brazo por completo.", "Haga una pausa breve en la parte superior del movimiento, luego baje lentamente la mancuerna hasta el nivel de los hombros.", "Repita hasta el número deseado de repeticiones, luego cambie de lado y repita con el otro brazo."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000212877821', 'Prensa W con mancuernas', 'Dumbbell W Press', 'Hombros', '["Dumbbell W Press es un ejercicio de aislamiento que apoya el desarrollo de los músculos del hombro y especialmente del músculo deltoides anterior y lateral. Se recomienda realizarlo con poco peso en lugar de levantar demasiado peso.", "Muchos de los movimientos que trabajan el mismo grupo de músculos pueden parecer similares, pero se enfocan en diferentes partes de los músculos porque están en diferentes ángulos. Si desea desarrollar mejores músculos específicamente, tenga en cuenta que es más beneficioso incluir ejercicios que se centren en diferentes aspectos de su programa de entrenamiento."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001555422483', 'Press de hombros en máquina Smith de pie', 'Standing Smith Machine Shoulder Press', 'Hombros', '["Coloque la barra de la máquina Smith a una altura adecuada. La barra debe estar al nivel de tus hombros cuando estés de pie.", "Párese con los pies separados a la altura de los hombros, de cara a la máquina Smith. Colóquese debajo de la barra, asegurándose de que esté equilibrada y estable.", "Sujete la barra con un agarre por encima de la cabeza, ligeramente más ancha que el ancho de los hombros. Tus palmas deben mirar hacia adelante.", "Involucre su núcleo y mantenga una postura adecuada durante todo el ejercicio, con el pecho levantado y los hombros hacia atrás.", "Comienza doblando los codos y bajando la barra hacia los hombros, con los antebrazos perpendiculares al suelo.", "Presione la barra hacia arriba extendiendo los brazos completamente y exhalando mientras levanta.", "Haga una pausa breve en la parte superior del movimiento, asegurándose de que sus brazos estén completamente extendidos pero no bloqueados.", "Baje la barra nuevamente bajo control, inhalando mientras desciende y repita hasta el número deseado de repeticiones."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001052478689', 'Aperturas hacia arriba con mancuernas', 'Dumbbell Upward Fly', 'Pecho', '["Configuración: Párese con los pies separados a la altura de los hombros. Sostenga una mancuerna en cada mano, con las palmas hacia adelante. Para comenzar, elija un peso adecuado para su nivel de condición física.", "Párese con los pies separados a la altura de los hombros.", "Sostenga una mancuerna en cada mano, con las palmas hacia adelante. Para comenzar, elija un peso adecuado para su nivel de condición física.", "Posición inicial: Comience con los brazos extendidos hacia los costados y las mancuernas cerca de los muslos.", "Comience con los brazos extendidos hacia los costados y las mancuernas cerca de los muslos.", "El movimiento: Inhale y levante lentamente ambas mancuernas hacia adelante y hacia arriba en un arco amplio. Mientras levanta, concéntrese en apretar los músculos de la parte superior del pecho. Continúe levantando hasta que las mancuernas se encuentren frente a su pecho, o ligeramente por encima del nivel del pecho. Haga una breve pausa en la parte superior del movimiento, sintiendo la contracción en la parte superior del pecho.", "Inhale y levante lentamente ambas mancuernas hacia adelante y hacia arriba formando un amplio arco.", "Mientras levantas, concéntrate en apretar los músculos de la parte superior del pecho.", "Continúe levantando hasta que las mancuernas se encuentren frente a su pecho, o ligeramente por encima del nivel del pecho.", "Haga una pausa breve en la parte superior del movimiento y sienta la contracción en la parte superior del pecho.", "Regreso a la posición inicial: Exhale mientras baja lentamente las mancuernas a lo largo del mismo arco amplio hasta la posición inicial, con los brazos extendidos a los lados.", "Exhale mientras baja lentamente las mancuernas a lo largo del mismo arco amplio hasta la posición inicial, con los brazos extendidos a los lados."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001049828989', 'Press de hombros alterno con mancuernas de pie', 'Standing Alternating Dumbbell Shoulder Press', 'Hombros', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001227411329', 'Flexiones de pared con agarre estrecho', 'Narrow Grip Wall Push-Up', 'Pecho', '["- Párese frente a una pared, aproximadamente a 1 o 2 pies de distancia, según su nivel de comodidad y fuerza.", "- Coloque las manos en la pared a la altura del pecho, un poco más juntas que el ancho de los hombros.", "- Involucre su núcleo y mantenga su cuerpo en línea recta desde la cabeza hasta los talones.", "- Posición inicial: con los brazos rectos pero no bloqueados, mantenga el cuello y la columna en posición neutra.", "- Fase de descenso: doble lentamente los codos, manteniéndolos cerca del cuerpo mientras el pecho se mueve hacia la pared.", "- Pausa: deténgase cuando sus codos formen un ángulo de 90 grados o lo más cerca que pueda llegar cómodamente.", "- Fase de empuje: Empuje con las palmas de las manos para estirar los brazos y volver a la posición inicial.", "- Repetir: Realice el número deseado de repeticiones con movimiento controlado.", "### Consejos para una máxima eficacia", "- Progrese gradualmente: comience más cerca de la pared y aumente la distancia a medida que gana fuerza.", "- Involucre el núcleo: apriete los abdominales durante todo el movimiento para evitar que se arqueen o se caigan.", "- Controle su respiración: inhale mientras desciende hacia la pared y exhale mientras empuja hacia la posición inicial.", "- Combínelo con otros ejercicios: combínelo con flexiones o fondos tradicionales para un entrenamiento integral de la parte superior del cuerpo.", "### Errores comunes a evitar", "- Espalda caída o arqueada: mantenga su núcleo comprometido para mantener una línea recta desde la cabeza hasta los talones.", "- Codos extendidos: asegúrese de que sus codos permanezcan cerca de su cuerpo para apuntar a los tríceps de manera efectiva.", "- Colocación inadecuada de las manos: Las manos deben estar un poco más juntas que el ancho de los hombros para lograr la forma adecuada.", "- Acelerar el movimiento: realice el ejercicio lentamente y con control para maximizar la activación muscular."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001910611692', 'Rotación externa del hombro del cable', 'Cable External Shoulder Rotation', 'Hombros', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-002005495529', 'Press cubano con mancuernas', 'Dumbbell Cuban Press', 'Hombros', '["El press cubano es uno de los ejercicios integrales destinados a desarrollar la fuerza funcional en los hombros y el manguito rotador. A menudo se utiliza como movimiento avanzado para entrenar los músculos del manguito rotador. Este ejercicio trabaja todas las posiciones de la cabeza de los músculos del hombro, al mismo tiempo que estimula los músculos de la parte superior de la espalda y el pecho.", "El manguito rotador es el grupo de músculos y tendones que mantienen la cabeza del hueso de la parte superior del brazo firmemente dentro de la cavidad del hombro. El propósito de este ejercicio es fortalecer los músculos del manguito conectados con el hombro y proteger la salud del hombro.", "Es muy importante realizar el movimiento con la técnica adecuada, y levantar exceso de peso puede ser más perjudicial que beneficioso, por lo que se recomienda poco peso. Puedes practicar el ejercicio con la ayuda de una barra, mancuerna o un palo vacío."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000599005731', 'Elevación lateral inclinada con mancuernas', 'Incline Dumbbell Side Lateral Raise', 'Espalda', '["La elevación lateral inclinada con un solo brazo es un ejercicio dirigido a la cabeza lateral de los músculos del hombro. Muchos de los movimientos que trabajan el mismo grupo de músculos pueden parecer similares, pero se enfocan en diferentes partes de los músculos porque están en diferentes ángulos. Si desea desarrollar mejores músculos específicamente, tenga en cuenta que es más beneficioso incluir ejercicios que se centren en diferentes aspectos de su programa de entrenamiento."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001331947870', 'Rotación interna del hombro del cable', 'Cable Internal Shoulder Rotation', 'Hombros', '["Los ejercicios de rotación son ejercicios diseñados para fortalecer los músculos del manguito rotador conectados a los músculos del hombro. Fortalecer los músculos del manguito rotador con estos ejercicios antes del entrenamiento de hombros es beneficioso para la salud de su hombro.", "Para renovar todo el músculo para lograr un mejor equilibrio muscular y estabilidad de las articulaciones, debe trabajarlo en un rango completo de movimiento. Realizar ejercicios de hombro diseñados para fortalecer los músculos y mejorar el rango de movimiento del hombro reducirá la tensión en la articulación, haciéndola menos susceptible a inflamaciones articulares como tendinitis y bursitis."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001780328712', 'De pie Estiramiento hacia arriba Rotación de espalda Estiramiento', 'Standing Reach Up Back rotation Stretch', 'Espalda', '["Puede utilizar este ejercicio para estirar más de un grupo de músculos. Especialmente al estirar los músculos de la espalda, los músculos del pecho, los hombros y los tríceps también ganarán flexibilidad. Agregar estiramientos a su entrenamiento general ayudará a aumentar la movilidad y flexibilidad de sus músculos."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000774087732', 'Elevación del deltoides posterior acostado de lado con mancuernas', 'Dumbbell Side Lying Rear Delt Raise', 'Hombros', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001649529989', 'Estiramiento de hombros a través del pecho', 'Across Chest Shoulder Stretch', 'Pecho', '["Los estiramientos de hombros pueden ayudar a aliviar la tensión muscular, el dolor y la tirantez en el cuello y los hombros. Incluir ejercicios y estiramientos específicos para los hombros en su programa de entrenamiento general puede ayudar a aumentar la movilidad y flexibilidad de los hombros. Estos movimientos también pueden fortalecer los hombros, mejorar su función y prevenir lesiones.", "Además, este movimiento de estiramiento beneficia los tríceps y los músculos de la espalda."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001699265055', 'Estiramiento de hombros detrás de la espalda', 'Shoulder Stretch Behind The Back', 'Espalda', '["- Párate en una postura neutral con los pies separados a la altura de los hombros.", "- Levante un brazo por encima y doble el codo para alcanzar la espalda.", "- Al mismo tiempo, lleve el otro brazo detrás de la espalda desde abajo, con el objetivo de tocar o superponer los dedos.", "- ¿Se tocan o están a punto de tocarse? ¿Se superponen? ¿Un lado se siente más apretado que el otro?", "- Cambie de lado y observe sus resultados.", "- Sostenga una toalla o banda de resistencia con ambas manos detrás de la espalda.", "- Utilice la toalla para ayudar a estirar los brazos si juntar las manos le resulta difícil.", "- Siga la misma técnica anterior, asegurando un estiramiento controlado.", "### Prueba de flexibilidad del hombro", "- Los dedos se superponen / Excelente", "- Los dedos se tocan / Bien", "- Las yemas de los dedos no se tocan, pero están a menos de 5 cm (2 pulgadas) de distancia. / Justo", "- Las yemas de los dedos están separadas por más de dos pulgadas (5 cm). / Pobre", "### Consejos para una máxima eficacia", "- Comience gradualmente: comience con un rango de movimiento más pequeño y aumente a medida que mejore su flexibilidad.", "- Combínelo con otros estiramientos de hombros: combine este estiramiento con movimientos como estiramientos inversos de hombros o estiramientos asistidos para una rutina integral.", "- Incorporar en los descansos laborales: utilice este estiramiento durante largos períodos de estar sentado para reducir la tensión y mejorar la postura.", "- Respire profundamente: respire lenta y profundamente durante el estiramiento para ayudar a relajar los músculos y mejorar la flexibilidad.", "### Errores comunes a evitar", "- Arqueando la espalda: Mantenga su núcleo comprometido para evitar un arqueo excesivo en la columna lumbar.", "- Encorvar los hombros: asegúrese de que los hombros estén hacia atrás y hacia abajo, en lugar de encogerse de hombros hacia arriba.", "- Usando Momentum: Realice el estiramiento lentamente y con control para evitar movimientos bruscos que puedan tensar los músculos.", "- Forzar el rango de movimiento: estírese sólo hasta un punto cómodo; Evite extender demasiado los hombros."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001200077127', 'Limpieza y press con barra', 'Barbell Clean and Press', 'Hombros', '["El músculo principal que se trabaja en una limpieza y prensa son los hombros, pero el movimiento también trabaja los tríceps, los trapecios, la espalda media y baja, los abdominales, los cuádriceps, los glúteos, los isquiotibiales y las pantorrillas. Es un ejercicio de cuerpo completo, que no sólo se puede realizar para hipertrofia, sino también para fuerza. Este ejercicio te permite desarrollar resistencia y resistencia cardiovascular, así como resistencia muscular e incluso fuerza. Es el movimiento más popular de fuerza y ​​entrenamiento de fuerza ya que trabaja muchos grupos de músculos.", "Fortalece la capacidad de agarre. Le permite agarrar un objeto con más firmeza cuando lo sostiene. Además, los estudios demuestran que el clean and press es un ejercicio eficaz para mejorar la fuerza explosiva y el rendimiento del salto vertical.", "La limpieza y prensa con barra ayuda al desarrollo de los músculos de las piernas, los músculos de la cadera y los músculos centrales, al mismo tiempo que apoya la formación de músculos y fuerza en el cuerpo. Además, agregar clean y press a tus entrenamientos ayuda a fortalecer tus tendones, ligamentos y huesos.", "La limpieza y el press con barra también activan los glúteos y los músculos de la espalda. Los ejercicios funcionales como clean y press son aquellos que facilitan las actividades del cuerpo en la vida real.", "La limpieza y el press con barra se dirigen a todos los músculos responsables de la postura y le permiten mantener la espalda recta durante las actividades diarias habituales.", "La forma correcta es muy importante en este ejercicio. Para empezar, hacer mal puede provocar lesiones. Tras algunos intentos con la barra vacía o acompañado de un entrenador, el proceso de adaptación al movimiento puede verse acortado."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001579646010', 'Aleteo de piernas (Flutter Kicks) de glúteos en banco', 'Bench Glute Flutter Kicks', 'Piernas', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
