INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001050000559', 'en máquina Smith inclinada sobre fila', 'Smith Machine Bent Over Row', 'Espalda', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001357408737', 'Paso hacia arriba + giro opuesto del codo a la rodilla', 'Step Up + Opposite Elbow to Knee Twist', 'Abdomen', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000603616046', 'Limpieza energética', 'Power Clean', 'Otros', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001213444717', 'Paso lateral', 'Lateral Step-up', 'Espalda', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001663882207', 'Carrera velocista asistida por banda', 'Band Assisted Sprinter Run', 'Cardio', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000814345874', 'Elevación con barra', 'Barbell Step-Up', 'Piernas', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001634806581', 'Dominadas con agarre cerrado', 'Close Grip Chin Up', 'Espalda', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001765725626', 'Flexiones de tríceps en plancha (Body Ups)', 'Body Ups', 'Otros', '["- Posición inicial Comience en una posición de plancha con el antebrazo con los codos directamente debajo de los hombros. Mantenga los pies separados a la altura de las caderas y mantenga una línea recta desde la cabeza hasta los talones. Involucre el núcleo y los glúteos para estabilizar el cuerpo.", "- Comience en una posición de plancha con el antebrazo con los codos directamente debajo de los hombros.", "- Mantenga los pies separados a la altura de las caderas y mantenga una línea recta desde la cabeza hasta los talones.", "- Involucre su núcleo y glúteos para estabilizar su cuerpo.", "- EjecuciónPresione a través de sus antebrazos y empuje la parte superior de su cuerpo hacia arriba hasta que sus codos estén completamente extendidos. Mantenga su núcleo apretado y mantenga el control durante todo el movimiento. Baje lentamente hasta la posición inicial sin colapsar su torso. Repita hasta el número deseado de repeticiones mientras mantiene la forma adecuada.", "- Presione con los antebrazos y empuje la parte superior del cuerpo hacia arriba hasta que los codos estén completamente extendidos.", "- Mantenga su núcleo apretado y mantenga el control durante todo el movimiento.", "- Baje lentamente hasta la posición inicial sin colapsar el torso.", "- Repita hasta el número deseado de repeticiones manteniendo la forma adecuada.", "### Consejos para una forma adecuada", "- Mantenga una alineación recta del cuerpo desde la cabeza hasta los talones durante todo el movimiento.", "- Involucre su núcleo y glúteos para evitar un movimiento excesivo de la cadera.", "- Mantenga los codos cerca del cuerpo para maximizar la participación de los tríceps.", "- Utilice movimientos controlados en lugar de depender del impulso.", "- Concéntrese en una distribución uniforme del peso entre ambos brazos para evitar desequilibrios.", "### Errores comunes a evitar", "- Permitir que las caderas se hundan, lo que reduce la activación del núcleo y puede tensar la zona lumbar.", "- Depender del impulso en lugar del compromiso muscular controlado.", "- Ensanchar los codos hacia afuera, lo que puede disminuir la activación de los tríceps y aumentar la tensión en los hombros.", "- Contener la respiración, en lugar de mantener una respiración constante para mejorar el rendimiento.", "- No extender completamente los codos, limitando la efectividad del ejercicio."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000299128197', 'Estiramiento de glúteos acostado', 'Lying Glute Stretch', 'Piernas', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000002137561', 'Hiperextensión del piso', 'Floor Hyperextension', 'Hombros', '["Este movimiento fortalece los músculos erectores de la columna que brindan soporte a la columna. Unos músculos fuertes de la espalda pueden prevenir desviaciones posturales que provocan malas posturas y molestias, como la cifosis (“jorobada”). El movimiento de hiperextensión del piso mejora su postura al extender los músculos de la espalda y reducir la tensión entre la zona lumbar y las áreas centrales. También mejora la fuerza de la espalda baja, lo que facilita mantenerse erguido durante todo el día."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-002074683417', 'Círculos unilateral', 'Single Arm Circles', 'Hombros', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001305568729', 'Pájaro / vuelos posteriores en polea tendido', 'Lying Cable Reverse Fly', 'Hombros', '["El objetivo del ejercicio de vuelo inverso con cable tumbado son los músculos de la espalda y los hombros. Es un excelente ejercicio de fortalecimiento que trabaja eficazmente muchos músculos, incluidos el hombro, el manguito rotador y el trapecio. Al afectar el músculo infraespinoso que cubre la escápula, puede ayudar a protegerlo de dolencias causadas por la debilidad muscular, como el trastorno de la postura y la protrusión de la escápula. Además, fortalecer estos músculos mediante el ejercicio de vuelo inverso con cable ayudará a mejorar la mala postura, promoverá una postura erguida y mejorará el equilibrio.", "El ejercicio de vuelo inverso con cable te ayudará a desarrollar una espalda y unos hombros definidos. Es uno de los ejercicios que debes hacer si quieres tener el músculo del hombro definido y más desmenuzado."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000372334045', 'Pullover con barra', 'Barbell Pullover', 'Pecho', '["- Acuéstese en un banco plano, sosteniendo la barra sobre su pecho con una ligera flexión de los codos.", "- Inhale profundamente, contraiga su núcleo y baje la barra formando un arco detrás de su cabeza, manteniendo los brazos casi rectos.", "- Baje hasta que sienta un estiramiento profundo en los dorsales y el pecho; evite ir demasiado lejos si la movilidad del hombro es limitada.", "- Exhala y tira de la barra hacia atrás sobre tu pecho usando tu pecho y tus dorsales.", "- Controla el movimiento en todo momento, especialmente al volver a la posición inicial.", "- Repita para el número deseado de repeticiones.", "### Consejos para una forma adecuada", "- Utilice un ancho de agarre moderado para lograr un compromiso equilibrado del pecho y los dorsales.", "- Mantenga los codos ligeramente doblados, no bloqueados ni extendidos hacia afuera.", "- Mantenga la extensión torácica (parte superior de la espalda ligeramente arqueada).", "- Controle la fase excéntrica para lograr el máximo estiramiento y seguridad.", "- Detenga el descenso si siente molestias en el hombro; nunca fuerce el rango de movimiento.", "### Errores comunes a evitar", "- Arqueando la zona lumbar, ejerciendo presión sobre la columna lumbar.", "- Dejar que la barra caiga demasiado detrás de la cabeza, corre el riesgo de sufrir tensión en el hombro.", "- Usar impulso en lugar de movimiento controlado.", "- Bloquear los codos, lo que transfiere la carga al tríceps y la articulación del codo.", "- Descuidar el control de la respiración, reduciendo la estabilidad central y la tensión."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000078949162', 'Curl de piernas acostado con mancuernas', 'Lying Dumbbell Leg Curl', 'Piernas', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-002144603562', 'Hiperextensión en banco plano', 'Flat Bench Hyperextension', 'Espalda', '["Los ejercicios de hiperextensión son un excelente ejercicio que fortalece el core, la espalda baja, los glúteos y los isquiotibiales.", "El movimiento de hiperextensión mejora su postura al extender los músculos de la espalda y reducir la tensión entre la zona lumbar y las áreas centrales. También mejora la fuerza de la espalda baja, lo que facilita mantenerse erguido durante todo el día.", "También es beneficioso para la salud de la espalda baja, ya que algunos dolores lumbares pueden deberse a glúteos débiles y tendones de la corva tensos."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000232954399', 'Máquina de press de pecho declinada', 'Decline Chest Press Machine', 'Pecho', '["- Ajuste el asiento de modo que las manijas queden al nivel del pecho cuando esté sentado.", "- Siéntese en la máquina con la espalda firmemente apoyada en el respaldo y los pies apoyados en el suelo.", "- Sujete las manijas con un agarre neutral o en pronación, según el diseño de la máquina.", "- Posición inicial: Sostenga las manijas con los brazos extendidos pero los codos ligeramente doblados para evitar bloquearse. Involucre su núcleo y mantenga los hombros hacia abajo y hacia atrás.", "- Sostenga las manijas con los brazos extendidos pero los codos ligeramente doblados para evitar bloquearse.", "- Involucre su núcleo y mantenga los hombros hacia abajo y hacia atrás.", "- Fase de descenso: Lleve lentamente las manijas hacia su pecho, manteniendo el control y manteniendo los codos en un ángulo natural (no ensanchados).", "- Lleve lentamente las manijas hacia su pecho, manteniendo el control y manteniendo los codos en un ángulo natural (no ensanchados).", "- Fase de prensado: Empuje las manijas hacia la posición inicial extendiendo los brazos y apretando el pecho en la parte superior del movimiento.", "- Empuje las manijas hacia la posición inicial extendiendo los brazos y apretando el pecho en la parte superior del movimiento.", "- Repetir: realice la cantidad deseada de repeticiones, manteniendo la forma adecuada en todo momento.", "### Consejos para una máxima eficacia", "- Concéntrese en la contracción muscular: apriete el pecho en la parte superior de cada presión para una activación máxima.", "- Controle lo negativo: baje las manijas lentamente para mejorar el tiempo bajo tensión y estimular un mayor crecimiento muscular.", "- Combine con otros ejercicios para el pecho: combínelo con movimientos de presión planos e inclinados para lograr un desarrollo integral del pecho.", "- Ajuste el agarre: experimente con diferentes agarres (neutrales o por encima de la cabeza) para variar ligeramente la activación muscular.", "- Respire adecuadamente: inhale mientras baja las manijas y exhale mientras las empuja hacia la posición inicial.", "### Errores comunes a evitar", "- Arqueando la espalda: Mantenga la espalda firmemente presionada contra el respaldo para evitar tensión en la zona lumbar.", "- Bloquear los codos: evite bloquear completamente los codos en la parte superior para mantener la tensión en los músculos del pecho.", "- Altura del asiento incorrecta: asegúrese de que las manijas estén alineadas con su pecho para optimizar la activación muscular y evitar movimientos incómodos.", "- Acelerar el movimiento: realice el ejercicio lentamente y con control para maximizar la participación de los músculos y reducir el riesgo de lesiones.", "- Sobrecargar la máquina: utilice un peso manejable para mantener la forma adecuada y evitar depender del impulso."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000046557344', 'Máquina de press de pecho acostada', 'Lying Chest Press Machine', 'Pecho', '["- Ajuste la altura del asiento para que las manijas se alineen con el nivel de la mitad del pecho cuando esté sentado.", "- Siéntese con la columna firmemente apoyada en el respaldo y los pies apoyados en el suelo.", "- Agarre las manijas con un agarre por encima, asegurándose de que sus muñecas permanezcan rectas.", "- Posición inicial Sostenga las manijas con los brazos extendidos pero los codos ligeramente doblados para evitar bloquearse. Involucre su núcleo y mantenga los hombros hacia abajo y hacia atrás.", "- Sostenga las manijas con los brazos extendidos pero los codos ligeramente doblados para evitar bloquearse.", "- Involucre su núcleo y mantenga los hombros hacia abajo y hacia atrás.", "- Fase de descenso Lleve lentamente las manijas hacia su pecho, manteniendo un movimiento controlado. Deténgase cuando sus codos estén al nivel del pecho o ligeramente por debajo.", "- Lleve lentamente las manijas hacia su pecho, manteniendo un movimiento controlado.", "- Deténgase cuando sus codos estén al nivel del pecho o ligeramente por debajo.", "- Presionando PhaseEmpuje las manijas hacia la posición inicial extendiendo los brazos y apretando el pecho en la parte superior del movimiento.", "- Empuje las manijas hacia la posición inicial extendiendo los brazos y apretando el pecho en la parte superior del movimiento.", "- Repetir: realice la cantidad deseada de repeticiones mientras mantiene el control y la forma adecuada.", "### Consejos para una máxima eficacia", "- Concéntrese en la contracción muscular: apriete el pecho en la parte superior de la prensa para maximizar la participación de los músculos.", "- Controle la fase excéntrica: baje las manijas lentamente para aumentar el tiempo bajo tensión y promover el crecimiento muscular.", "- Combínelo con pesas libres: combínelo con ejercicios como el press de banca o el vuelo con mancuernas para un entrenamiento de pecho completo.", "- Varíe las posiciones de agarre: use diferentes agarres (estrechos o anchos) para apuntar a diferentes áreas del pecho.", "- Respire adecuadamente: exhale mientras presiona las manijas hacia arriba e inhale mientras las baja."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001892588897', 'Fila invertida de tabla', 'Table Inverted Row', 'Espalda', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000264894869', 'Elevaciones de rodillas laterales colgantes', 'Hanging Side Knee Raises', 'Abdomen', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001124440036', 'Encogimiento de rodillas sobre fitball (Knee Tuck)', 'Stability Ball Knee Tuck', 'Abdomen', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001851833240', 'Máquina de hiperextensión inversa', 'Reverse Hyperextension Machine', 'Espalda', '["El músculo principal que activa la máquina de hiperextensión inversa es el glúteo mayor. Es uno de los ejercicios que puedes incluir en tus entrenamientos para tensar y tonificar los glúteos, mejorar la movilidad de la cadera y fortalecer la zona lumbar."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001879147833', 'Encogimiento de hombros en máquina Smith', 'Smith Machine Shrug', 'Hombros', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001492056133', 'Dedos de los pies a la barra', 'Toes to Bar', 'Abdomen', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-002144947796', 'Limpiaparabrisas colgante', 'Hanging Windshield Wiper', 'Abdomen', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000707393803', 'Elevaciones de rodillas colgantes con peso', 'Weighted Hanging Knee Raises', 'Abdomen', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001312456851', 'Press inclinado con mancuernas y agarre cerrado', 'Close-grip Incline Dumbbell Press', 'Pecho', '["Ajuste un banco a una inclinación de aproximadamente 30 a 45 grados.", "Siéntate en el banco con una mancuerna en cada mano, apoyándolas sobre tus muslos.", "Recuéstese en el banco y junte las mancuernas sobre su pecho, con las palmas una frente a la otra en un agarre neutral."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000830526274', 'Elevación de pantorrillas con barra de pie', 'Standing Barbell Calf Raise', 'Pantorrillas', '["Configuración: Coloque una plataforma elevada resistente o pise el piso. Cargue una barra y colóquela en la parte superior de la espalda, como en una sentadilla trasera.", "Posición de los pies: Súbase a la plataforma de modo que solo las puntas de los pies estén en contacto. Tus talones deben colgar del borde para permitir un rango completo de movimiento.", "Alineación del cuerpo: Párate erguido, mantén el core apretado, el pecho erguido y los hombros hacia atrás. Mantenga una columna neutra en todo momento.", "Levante los talones: empuje las puntas de los pies para elevar los talones lo más alto posible, contrayendo completamente los músculos de las pantorrillas.", "Pausa en la parte superior: Mantenga la posición superior durante 1 a 2 segundos para maximizar la tensión.", "Baja lentamente: Baja los talones por debajo del nivel de la plataforma de forma controlada, logrando un estiramiento completo en las pantorrillas.", "Repetir: Realiza el número deseado de repeticiones con precisión y equilibrio."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000242177272', 'Prensa hexagonal de en máquina Smith', 'Smith Machine Hex Press', 'Pecho', '["- Colóquese en el banco debajo de la barra de la máquina Smith.", "- Utilice un accesorio de agarre en V, agarrando las manijas con las palmas una frente a la otra y los nudillos alineados.", "- Asegúrese de que sus muñecas estén en una posición neutral, lo que ayuda a reducir la tensión y mejora la potencia de presión.", "- Empuje la barra hacia arriba para desbloquearla de su posición de reposo.", "- Sostenga la barra con los brazos extendidos, directamente encima de su pecho.", "- Comienza el movimiento bajando lentamente la barra hacia tu pecho.", "- Concéntrese en mantener un ritmo controlado, permitiendo que las manijas de agarre en V se acerquen a su pecho.", "- Una vez que el agarre en V toque ligeramente su pecho, presione explosivamente la barra hacia arriba usando los músculos del pecho.", "- Imagínese empujar el suelo lejos de usted, ejerciendo la máxima fuerza con su pecho.", "- En la parte superior del movimiento, cuando los brazos estén completamente extendidos, haga una pausa y apriete los músculos del pecho durante un segundo.", "- Esta contracción intensifica el compromiso y promueve la activación muscular.", "- Vuelva a bajar lentamente la barra, concentrándose en la fase excéntrica (negativa) del levantamiento.", "- Controla el descenso y mantén la tensión en los músculos del pecho en todo momento.", "- Realice el número deseado de repeticiones manteniendo la forma y el control adecuados.", "### Consejos para el éxito:", "- Mantenga un ritmo controlado durante las fases excéntrica y concéntrica del movimiento para maximizar la participación muscular.", "- Concéntrese en su patrón de respiración, inhalando durante la fase excéntrica (descenso) y exhalando durante la fase concéntrica (presión).", "- Mantenga los omóplatos retraídos y presionados durante todo el ejercicio para garantizar una activación óptima del pecho.", "### Errores comunes a evitar", "- Codos ensanchados: Mantenga los codos pegados al cuerpo para evitar tensiones innecesarias en los hombros.", "- Ancho de agarre incorrecto: Usar un agarre demasiado ancho reduce la activación interna del pecho; mantenga un agarre estrecho.", "- Sobrecargar la barra: utilice un peso manejable para garantizar la forma adecuada y evitar depender del impulso.", "- Arqueando la espalda: Mantenga la espalda plana sobre el banco para evitar tensiones en la parte baja de la espalda.", "- Repeticiones apresuradas: realice el ejercicio lentamente y con control para maximizar la participación de los músculos."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000257001513', 'Jalón al pecho unilateral en polea', 'Cable One Arm Lat Pulldown', 'Espalda', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000664535271', 'Curl Zottman', 'Zottman Curl', 'Otros', '["Párese con los pies separados a la altura de los hombros y sostenga un par de mancuernas a los costados, con las palmas hacia adentro.", "Doble las mancuernas hacia los hombros, manteniendo los codos cerca de los costados y girando las palmas hacia arriba (supinación).", "En la parte superior del movimiento, sostenga las mancuernas en posición supina durante un segundo, luego gire las palmas hacia abajo (pronación) y baje lentamente las pesas hasta la posición inicial.", "Repita hasta obtener el número deseado de repeticiones."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000709872839', 'Flexión de rodillas', 'Kneeling Push-up', 'Pecho', '["- Comience sobre manos y rodillas sobre una superficie cómoda, como una colchoneta.", "- Coloque las manos ligeramente más separadas que el ancho de los hombros, asegurándose de que los dedos apunten hacia adelante.", "- Coloca las rodillas en el suelo y mantén los pies relajados.", "- Posición inicial: Alinee su cuerpo desde la cabeza hasta las rodillas en línea recta. Involucre su núcleo para evitar que la espalda baja se hunda o se arquee.", "- Alinee su cuerpo desde la cabeza hasta las rodillas en línea recta.", "- Involucre su núcleo para evitar que la espalda baja se hunda o se arquee.", "- Fase de descenso: doble los codos y baje el pecho hacia el suelo mientras mantiene los codos en un ángulo de aproximadamente 45 grados con respecto al cuerpo. Descienda hasta que el pecho esté justo por encima del suelo o tan bajo como lo permita su movilidad.", "- Doble los codos y baje el pecho hacia el suelo mientras mantiene los codos en un ángulo de aproximadamente 45 grados con respecto al cuerpo.", "- Desciende hasta que tu pecho esté justo por encima del suelo o tan bajo como te permita tu movilidad.", "- Fase de empuje: Empuje con las manos para extender los brazos y volver a la posición inicial. Concéntrese en apretar el pecho y mantener la línea recta del cuerpo.", "- Empuja con las manos para extender los brazos y volver a la posición inicial.", "- Concéntrate en apretar el pecho y mantener una línea recta del cuerpo.", "- Repetir: realice el número deseado de repeticiones manteniendo la forma adecuada.", "### Consejos para una máxima eficacia", "- Involucre su núcleo: mantenga su núcleo apretado para mantener una línea corporal recta y evitar arquear excesivamente la parte inferior de la espalda.", "- Controle el movimiento: realice las fases de descenso y empuje lentamente para maximizar la activación y el control de los músculos.", "- Centrarse en la calidad: priorice la forma adecuada sobre el número de repeticiones para reducir el riesgo de lesiones.", "- Utilice una colchoneta para mayor comodidad: Proteja sus rodillas realizando el ejercicio sobre una superficie suave o una colchoneta de ejercicios.", "- Progrese gradualmente: a medida que desarrolle fuerza, haga la transición a variaciones de flexiones más desafiantes, como flexiones inclinadas o flexiones estándar.", "### Errores comunes a evitar", "- Caderas o espalda caídas: Mantenga el cuerpo en línea recta desde la cabeza hasta las rodillas para evitar forzar la zona lumbar.", "- Codos ensanchados: Evite que los codos se ensanchen excesivamente para proteger sus hombros. Apunte a un ángulo de 45 grados desde su torso.", "- Repeticiones superficiales: baje el pecho lo más cerca posible del suelo para lograr un rango de movimiento completo.", "- Colocación inadecuada de las manos: asegúrese de que sus manos estén ligeramente más separadas que el ancho de los hombros y alineadas con el pecho.", "- Aguantar la respiración: Mantenga una respiración constante durante todo el ejercicio para mejorar el rendimiento y evitar la fatiga."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000200788603', 'Curl de concentración de piernas y bíceps', 'Biceps Leg Concentration Curl', 'Bíceps', '["El curl de concentración de bíceps con piernas es un ejercicio de aislamiento que se puede realizar con el peso corporal sin necesidad de equipo.", "La flexión de concentración de piernas es un excelente movimiento del brazo para estimular las fibras musculares en la parte superior del músculo braquial y el bíceps. Debido a que giras el brazo hacia el cuerpo cuando haces flexiones de concentración, es útil centrarse más en la cabeza larga del bíceps, que constituye la masa del pico del bíceps."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000352501855', 'Curl inverso con mancuernas', 'Dumbbell Reverse Curl', 'Otros', '["Párese con los pies separados a la altura de los hombros y sostenga un par de mancuernas frente a los muslos, con las palmas hacia abajo (agarre en pronación).", "Mantenga los codos cerca de los costados y levante lentamente las mancuernas hacia los hombros flexionando los codos. Mantenga las muñecas rectas y las palmas hacia abajo durante todo el movimiento.", "Haz una pausa en la parte superior del movimiento y aprieta los antebrazos y los bíceps durante un segundo.", "Baja lentamente las mancuernas hasta la posición inicial extendiendo los codos y manteniendo el control del peso.", "Repita hasta el número deseado de repeticiones."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000768663324', 'Curl de concentración con agarre cerrado sentado', 'Seated Close-Grip Concentration Curl', 'Otros', '["Siéntese en un banco o silla con los pies apoyados en el suelo y sostenga una barra con un agarre por debajo (con las palmas hacia arriba) con las manos separadas entre 6 y 8 pulgadas.", "Apoye los codos en la parte interna de los muslos y permita que la barra cuelgue hacia el suelo.", "Manteniendo la parte superior de los brazos inmóviles, doble la barra hacia los hombros y apriete los músculos del bíceps mientras levanta.", "Haga una pausa por un momento en la parte superior del movimiento, luego baje lentamente la barra hasta la posición inicial.", "Repita para el número deseado de repeticiones."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000114954502', 'Declinado vuelo en polea', 'Decline Cable Fly', 'Pecho', '["Coloque las poleas en una máquina de cable en una posición alta, por encima del nivel de los hombros.", "Conecte manijas en D a cada cable.", "Párate en el medio de la máquina de cable con un mango en cada mano.", "Incline el torso ligeramente hacia adelante y extienda los brazos hacia los lados con una ligera flexión de los codos."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001137107200', 'Curl con barra inclinada boca abajo', 'Prone Incline Barbell Curl', 'Otros', '["Ajuste un banco inclinado a un ángulo de 45 grados.", "Acuéstese boca abajo en el banco, con el pecho y el estómago presionando contra la inclinación.", "Sostenga una barra con un agarre hacia abajo, con las manos separadas al ancho de los hombros.", "Deje que sus brazos cuelguen hacia el suelo, manteniendo los codos cerca del cuerpo.", "Doble la barra hacia los hombros, manteniendo los codos inmóviles.", "Aprieta los bíceps en la parte superior del movimiento, luego baja lentamente la barra hasta la posición inicial."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000023969841', 'Remo con máquina con agarre inverso', 'Reverse Grip Machine Row', 'Espalda', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000836541820', 'Curl de bíceps sentado', 'Seated Biceps Curl', 'Bíceps', '["Comience con pesas livianas: cuando comience con la flexión de bíceps sentado, es importante comenzar con pesas livianas. Esto le ayudará a concentrarse en la forma y la técnica adecuadas y a evitar lesiones.", "Siéntate derecho: cuando realices la flexión de bíceps sentado, es importante sentarte derecho en el banco con los pies firmemente plantados en el suelo. Esto le ayudará a involucrar su núcleo y mantener la forma adecuada durante todo el ejercicio.", "Mantenga los codos hacia adentro: mientras levanta el peso, es importante mantener los codos cerca del cuerpo. Esto le ayudará a trabajar los músculos bíceps de forma más eficaz y evitará tensión en los hombros.", "Utilice un rango completo de movimiento: al realizar la flexión de bíceps sentado, es importante utilizar un rango completo de movimiento, levantando el peso completamente hacia los hombros y luego bajándolo nuevamente a la posición inicial.", "Mantenga la posición durante uno o dos segundos, mientras contrae los músculos bíceps. Baje lentamente las mancuernas hasta la posición inicial, mientras mantiene el control y los codos cerca de los costados. Repita hasta el número deseado de repeticiones."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000200053905', 'Press de banca inclinado en máquina Smith', 'Smith Machine Incline Bench Press', 'Pecho', '["- Ajuste el banco inclinado a un ángulo de 30 a 45 grados y colóquelo debajo de la barra de la máquina Smith.", "- Siéntese en el banco con los pies apoyados en el suelo, la espalda firmemente presionada contra el banco y la barra alineada con la parte superior del pecho.", "- Agarre la barra un poco más ancha que el ancho de los hombros, con las palmas hacia adelante.", "- Desenganche la barra girando las muñecas para soltar los ganchos de seguridad.", "- Fase de descenso: baje lentamente la barra hacia la parte superior del pecho, manteniendo los codos en un ángulo de 45 grados con respecto al torso. Deténgase cuando la barra esté justo encima o toque ligeramente el pecho.", "- Baje lentamente la barra hacia la parte superior del pecho, manteniendo los codos en un ángulo de 45 grados con respecto al torso.", "- Detente cuando la barra esté justo encima o toque ligeramente tu pecho.", "- Fase de prensado: Empuje la barra hacia arriba hasta la posición inicial con un movimiento controlado. Extienda completamente los brazos sin bloquear los codos.", "- Empuja la barra hacia arriba hasta la posición inicial con un movimiento controlado.", "- Extienda completamente los brazos sin bloquear los codos.", "- Repetir: Realiza el número deseado de repeticiones con movimientos suaves y controlados."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001448058465', 'Curl con barra EZ con agarre inverso', 'Reverse Grip EZ-Bar Curl', 'Otros', '["Párese derecho con los pies separados a la altura de los hombros y agarre la barra EZ con agarre inverso. Tus manos deben estar ligeramente más estrechas que el ancho de los hombros.", "Permita que sus brazos se extiendan completamente, manteniéndolos cerca de su cuerpo. Esta es tu posición inicial.", "Mantenga la parte superior de los brazos inmóviles, exhale y doble la barra hacia arriba contrayendo los bíceps. Concéntrate en apretar los músculos en la parte superior del movimiento.", "Haga una pausa breve en la parte superior del curl, luego baje lentamente la barra hasta la posición inicial mientras inhala.", "Repita hasta el número deseado de repeticiones."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001415176451', 'Curl de predicador en polea unilateral', 'Single Arm Cable Preacher Curl', 'Otros', '["Ajuste el accesorio de curl predicador de la máquina de cable para que el asiento y el reposabrazos estén en una posición cómoda para usted.", "Elija el peso adecuado y coloque un asa en el cable.", "Siéntese en el asiento y coloque el brazo sobre el reposabrazos con el codo ligeramente doblado y la mano sujetando el asa.", "Manteniendo el codo inmóvil, doble el mango hacia el hombro, contrayendo el músculo bíceps.", "Haga una pausa por un momento en la parte superior del movimiento, luego baje lentamente el mango hasta la posición inicial.", "Repita el ejercicio durante el número deseado de repeticiones, luego cambie de brazo y realice el mismo movimiento con el otro brazo."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001266572046', 'Curl con mancuernas en martillo Scott', 'Dumbbell Scott Hammer Curl', 'Otros', '["El ejercicio se realiza parándose detrás del banco del predicador y colocando la parte posterior de los brazos sobre el banco. Sosteniendo las mancuernas con un agarre neutral, con las palmas una frente a la otra, doblará las pesas hacia los hombros mientras mantiene la parte superior de los brazos inmóviles.", "Aprieta los bíceps en la parte superior del movimiento y luego baja lentamente las mancuernas hasta la posición inicial.", "Repita para la cantidad deseada de repeticiones y series."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000794628764', 'Giro oblicuo sentado', 'Seated Oblique Twist', 'Abdomen', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001353196159', 'Extensión de tríceps con mancuernas sentado a un brazo', 'Seated One-Arm Dumbbell Triceps Extension', 'Tríceps', '["- Configure la posición Siéntese en un banco resistente con respaldo para garantizar una postura adecuada. Sostenga una mancuerna en una mano con un agarre neutral (con la palma hacia adentro). Extienda el brazo por encima, manteniendo el codo cerca de la cabeza.", "- Siéntese en un banco resistente con respaldo para garantizar una postura adecuada.", "- Sostenga una mancuerna en una mano con un agarre neutral (con la palma hacia adentro).", "- Extienda el brazo por encima de la cabeza, manteniendo el codo cerca de la cabeza.", "- Posición inicial La parte superior del brazo debe permanecer perpendicular al suelo. Mantenga el núcleo enganchado y la columna en posición neutral para mayor estabilidad.", "- La parte superior de tu brazo debe permanecer perpendicular al suelo.", "- Mantenga su núcleo comprometido y la columna neutral para mayor estabilidad.", "- Ejecución Baje lentamente la mancuerna detrás de la cabeza doblando el codo. Mantenga el codo inmóvil mientras permite que la mancuerna descienda tanto como lo permita su movilidad. Haga una breve pausa en la parte inferior, luego presione la mancuerna hacia la posición inicial extendiendo el codo.", "- Baje lentamente la mancuerna detrás de su cabeza doblando el codo.", "- Mantenga el codo inmóvil mientras permite que la mancuerna descienda tanto como lo permita su movilidad.", "- Haga una breve pausa en la parte inferior, luego presione la mancuerna hacia la posición inicial extendiendo el codo.", "- Repeticiones y series Realice de 3 a 4 series de 10 a 15 repeticiones por brazo.", "- Realiza de 3 a 4 series de 10 a 15 repeticiones por brazo.", "### Consejos para una forma adecuada", "- Mantenga el codo inmóvil durante todo el movimiento para maximizar la activación del tríceps.", "- Baje la mancuerna de forma controlada para evitar una tensión excesiva en el codo.", "- Involucre su núcleo para mantener una postura estable y evitar movimientos innecesarios.", "- Utilice un peso cómodo que permita un rango completo de movimiento sin comprometer la forma.", "- Evite arquear excesivamente la espalda para mantener la alineación adecuada de la columna.", "### Errores comunes a evitar", "- Ensanchar el codo hacia afuera, lo que reduce la activación del tríceps y aumenta la tensión del hombro.", "- Usar demasiado peso, lo que lleva a una forma inadecuada y a un mayor riesgo de lesiones.", "- Inclinarse excesivamente hacia atrás, lo que puede tensar la zona lumbar.", "- No bajar la mancuerna del todo, limitando la efectividad del ejercicio.", "- Acelerar el movimiento, reduciendo el compromiso muscular."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001470399900', 'Teaser (Pilates)', 'Teaser Pilates', 'Espalda', '["Teaser es un ejercicio clásico de Pilates para todo el cuerpo. Demuestra fuerza, flexibilidad, control y equilibrio. Este ejercicio trabaja para fortalecer todo el cuerpo e incorpora muchos músculos, incluidos todos los músculos abdominales, extensores de la columna y flexores de la cadera. El objetivo del Teaser es la fuerza y ​​la activación de los abdominales, los flexores de la cadera y los músculos anteriores de la pierna. Controlar el movimiento desafía estos músculos junto con los estabilizadores de la columna, la parte interna de los muslos, la parte inferior de las piernas y los hombros."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000318562479', 'Remo en polea con agarre cerrado', 'Close Grip Cable Row', 'Espalda', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001316307823', 'Empuje de cadera con peso corporal', 'Bodyweight Hip Thrust', 'Piernas', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000557490195', 'Fondos en banco en el suelo', 'Bench Dips on Floor', 'Otros', '["Baje el cuerpo doblando los codos hasta que la parte superior de los brazos quede paralela al suelo.", "Mantenga los codos doblados hacia adentro y evite abrirlos hacia afuera.", "Haga una breve pausa al final del movimiento.", "Empuja con las palmas de las manos para estirar los brazos y volver a la posición inicial.", "Repita de 10 a 15 repeticiones durante 3 a 4 series."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001362774412', 'Jalón al pecho con barra en V', 'V-bar Lat Pulldown', 'Espalda', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000213981347', 'Pulldown de brazo recto con cuerda', 'Rope Straight Arm Pulldown', 'Espalda', '["El pulldown con cuerda con el brazo estirado entrena los dorsales a través de un largo rango de movimiento y es útil para las personas que tienen problemas para sentir cómo trabaja su espalda en los ejercicios de pulldown convencionales. Los movimientos del cable proporcionan una tensión constante durante todo el movimiento. El uso de cables te permite trabajar tanto la parte concéntrica como la excéntrica del ejercicio. Más tensión equivale a más activación muscular."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001409472347', 'Remo con barra a un brazo', 'One-Arm Barbell Row', 'Espalda', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001085627154', 'Crunch de bicicleta con banda de resistencia', 'Resistance Band Bicycle Crunch', 'Cardio', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001430272382', 'Correr hacia atrás', 'Backward Running', 'Cardio', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000479842674', 'Levantamiento turco', 'Turkish Get-up', 'Otros', '["Paso 1: Acuéstese en el suelo con la rodilla derecha doblada y el pie derecho apoyado en el suelo. Mantenga la pierna izquierda estirada para la posición inicial.", "Paso 2: Sostenga una pesa rusa o una mancuerna en su mano derecha y mantenga la muñeca, el codo y el hombro alineados verticalmente. Mueva el brazo izquierdo hacia un lado con la mano apoyada en el suelo para mantener el equilibrio.", "Paso 3: Contrae los abdominales, respira y levanta el torso del suelo, asegurándote de mantener el brazo derecho recto y la pesa rusa sobre la articulación del hombro. Empújate con el brazo izquierdo hasta que tu torso esté vertical y estés sentado.", "Paso 4: Con la pesa rusa todavía sobre tu hombro derecho y la mano izquierda sosteniéndote, dobla la pierna izquierda y coloca la rodilla en el suelo, levantándote. Mantenga la espalda recta mientras levanta el torso y retira la mano izquierda del suelo.", "Paso 5: Cuadre las caderas para crear una posición de estocada sólida, respire otra vez y levante la rodilla izquierda, pisando el pie izquierdo. Mientras haces eso, ponte de pie extendiendo las rodillas y las caderas. Mantenga la pesa rusa sobre su hombro y no doble el codo.", "Paso 6: Invierta el movimiento lanzándose hacia atrás, levantando el pie izquierdo del suelo, aterrizando sobre la rodilla izquierda y girando la pierna izquierda detrás del cuerpo.", "Paso 7: A partir de ahí, coloque la mano izquierda en el suelo, extienda la pierna izquierda frente a usted y siéntese sin extender la rodilla derecha. Mantenga la pesa rusa sobre su hombro derecho.", "Paso 8: Doble el brazo izquierdo para bajar aún más el torso y acuéstese boca arriba con cuidado en la posición inicial sin doblar el brazo derecho."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-002008260279', 'Remo en polea inclinado', 'Incline Cable Row', 'Espalda', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001924555378', 'Puente lateral', 'Side Bridge', 'Abdomen', '["### Posición inicial:", "- Acuéstese de lado con el antebrazo en el suelo.", "- Coloque el codo directamente debajo del hombro.", "- Apila las piernas una encima de la otra, con los pies alineados.", "- Mantenga el cuerpo en línea recta desde la cabeza hasta los talones.", "### Bajar las caderas:", "- Baje lentamente las caderas hacia el suelo de forma controlada.", "- Mantenga la alineación de los hombros y evite colapsar sobre el codo.", "### Levanta las caderas:", "- Involucre los oblicuos para levantar las caderas nuevamente.", "- Regrese a una posición del cuerpo recta sin extenderse demasiado.", "### Continuar el movimiento:", "- Repita el movimiento controlado de descenso y elevación durante el número deseado de repeticiones.", "- Mantenga el movimiento suave y estable.", "### Cambiar de lado:", "- Complete todas las repeticiones de un lado antes de cambiar de lado."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000945065287', 'Extensión de tríceps con palanca', 'Lever Triceps Extension', 'Tríceps', '["### ", "- Ajuste la máquina Configure la altura del asiento para que sus brazos se alineen correctamente con las palancas de la máquina. Ajuste la pila de pesas a un nivel de resistencia manejable.", "- Ajuste la altura del asiento para que sus brazos se alineen correctamente con las palancas de la máquina.", "- Ajuste la pila de pesas a un nivel de resistencia manejable.", "- Colóquese Siéntese con la espalda firmemente contra la almohadilla y los pies apoyados en el suelo. Sujete las manijas de la máquina con las palmas hacia abajo y los codos doblados a aproximadamente 90 grados.", "- Siéntese con la espalda firmemente apoyada en la almohadilla y los pies apoyados en el suelo.", "- Agarre las manijas de la máquina con las palmas hacia abajo y los codos doblados a aproximadamente 90 grados.", "- EjecuciónEmpuje las manijas hacia abajo extendiendo los codos hasta que los brazos estén completamente rectos. Haga una breve pausa en la parte inferior para maximizar la contracción muscular. Vuelva lentamente a la posición inicial, controlando el movimiento.", "- Empuje las manijas hacia abajo extendiendo los codos hasta que los brazos estén completamente rectos.", "- Haga una pausa breve en la parte inferior para maximizar la contracción muscular.", "- Vuelve lentamente a la posición inicial, controlando el movimiento.", "- Repeticiones y series Realice de 3 a 4 series de 10 a 15 repeticiones para obtener resultados óptimos.", "- Realice de 3 a 4 series de 10 a 15 repeticiones para obtener resultados óptimos.", "### Consejos para una forma adecuada", "- Mantenga los codos inmóviles para enganchar completamente los tríceps.", "- Utilice un rango completo de movimiento, asegurándose de extender los brazos por completo.", "- Controla el movimiento para evitar utilizar el impulso.", "- Mantenga la espalda contra la almohadilla para mantener la estabilidad.", "- Elija un peso moderado para evitar tensiones en los codos y los hombros.", "### Errores comunes a evitar", "- Inclinarse excesivamente hacia adelante, lo que reduce la activación del tríceps.", "- Usar demasiado peso, lo que provoca una forma inadecuada y tensión en las articulaciones.", "- Permitir que los codos se muevan hacia afuera, lo que desvía la atención del tríceps.", "- Hacer rebotar el peso hacia arriba y hacia abajo, lo que reduce la efectividad.", "- No extender los brazos por completo, lo que limita la participación de los músculos."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001230948288', 'Elevación lateral unilateral inclinado sobre el cable', 'One-Arm Bent Over Cable Lateral Raise', 'Espalda', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000419644766', 'Cable doblado sobre fila', 'Cable Bent Over Row', 'Espalda', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000553345434', 'Plancha con elevación de brazos y piernas', 'Plank With Arm And Leg Lift', 'Abdomen', '["A diferencia de otros ejercicios de plancha, es un tipo de plancha más difícil que se realiza levantando brazos y piernas en direcciones opuestas al mismo tiempo.", "Las planchas son un ejercicio versátil que se dirige a muchos de los grupos de músculos más importantes del cuerpo, por lo que cualquier persona puede aplicarlas para mejorar la resistencia y la fuerza general del cuerpo.", "Como movimiento multifuncional, la plancha no solo apunta a los músculos abdominales sino también a la columna y la cadera. Plank fortalece y tonifica todo el cuerpo, mejora la postura y el equilibrio, reduce la grasa corporal y puede ayudar a acelerar el metabolismo.", "Plank es un ejercicio eficaz que aumenta la estabilidad en las zonas del core, la columna y la cadera proporcionando una contracción isométrica. Puedes agregarlo a tus entrenamientos para dar forma y fortalecer los músculos de la cadera, el tronco y las piernas."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001416678285', 'Estiramiento de flexión lateral de pie', 'Standing Side Bend Stretch', 'Espalda', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000673908738', 'Plancha frontal con lastre', 'Weighted Front Plank', 'Abdomen', '["Es una variación de la tabla que se realiza agregando peso. Es sobre todo preferido por los atletas avanzados. Como movimiento multifuncional, la plancha no solo apunta a los músculos abdominales sino también a la columna y la cadera. Plank fortalece y tonifica todo el cuerpo, mejora la postura y el equilibrio, reduce la grasa corporal y puede ayudar a acelerar el metabolismo.", "Plank es un ejercicio eficaz que aumenta la estabilidad en las zonas del core, la columna y la cadera proporcionando una contracción isométrica. Puedes agregarlo a tus entrenamientos para dar forma y fortalecer los músculos de la cadera, el tronco y las piernas.", "La plancha frontal con pesas es un ejercicio versátil que se dirige a muchos de los grupos de músculos más importantes del cuerpo, por lo que pueden ser aplicados por atletas avanzados para aumentar la resistencia y la fuerza general del cuerpo."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001676646446', 'Press por debajo con barra EZ', 'EZ Bar Underhand Press', 'Hombros', '["Cargue un peso adecuado en la barra de curl EZ.", "Párese con los pies separados a la altura de los hombros.", "Agarre la barra EZ con un agarre por debajo, con las manos ligeramente más estrechas que el ancho de los hombros."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001369668819', 'Puente de una sola pierna', 'Single Leg Bridge', 'Piernas', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
