INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000299834304', 'Jalón al pecho con agarre neutro y doble cable en el suelo', 'Double Cable Neutral Grip Lat Pulldown On Floor', 'Espalda', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001144267150', 'Elevación en T inclinada con mancuernas', 'Dumbbell Incline T-Raise', 'Hombros', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001065755573', 'Flexiones de manos', 'Handstand Push-Up', 'Pecho', '["- Encuentre una pared como apoyo (para principiantes) Mire hacia una pared y coloque las manos en el suelo separadas a la altura de los hombros. Levante las piernas hasta colocarse en posición de parada de manos con los talones tocando la pared para mantener el equilibrio.", "- Mire hacia una pared y coloque las manos en el suelo separadas a la altura de los hombros.", "- Levante las piernas hasta ponerse en posición de parada de manos con los talones tocando la pared para mantener el equilibrio.", "- Opción independiente (para atletas avanzados) Comience en posición de parada de manos sin soporte en la pared. Involucre su núcleo y glúteos para mantener el equilibrio.", "- Comience en posición de pino sin apoyo en la pared.", "- Involucre su núcleo y glúteos para mantener el equilibrio.", "- Baja el cuerpo doblando los codos hasta que tu cabeza toque suavemente el suelo.", "- Mantenga los codos en un ángulo de 45 grados para proteger sus hombros.", "- Empuja hacia atrás hasta la posición inicial extendiendo los brazos completamente.", "- Repita de 4 a 12 repeticiones dependiendo de su nivel de fuerza.", "### Consejos para una forma adecuada", "- Involucre su núcleo para mantener el equilibrio y el control.", "- Mantenga las manos separadas a la altura de los hombros para mayor estabilidad.", "- Muévase con un movimiento controlado para evitar una tensión excesiva en los hombros.", "- Apunte los dedos de los pies y apriete los glúteos para mantener una línea corporal recta.", "- Utilice una colchoneta acolchada debajo de la cabeza por seguridad si es necesario.", "### Errores comunes a evitar", "- Arquear excesivamente la zona lumbar: esto reduce la estabilidad y aumenta el riesgo de lesiones.", "- Ensanchar los codos: esto genera una tensión innecesaria en los hombros.", "- Caer demasiado rápido: el control es clave para evitar lesiones.", "- No involucrar el núcleo: un compromiso débil del núcleo conduce a un equilibrio y una técnica deficientes.", "- Falta de movilidad: la movilidad insuficiente del hombro hace que el movimiento sea ineficaz."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000790905612', 'Pájaro / vuelos posteriores con mancuernas inclinadas', 'Incline Dumbbell Reverse Fly', 'Hombros', '["El vuelo inverso con mancuernas es un ejercicio de pesas libres que se dirige principalmente a los hombros traseros. Es un ejercicio eficaz que puedes incluir en tu programa para aislar los músculos posteriores del hombro y fortalecer los músculos del manguito rotador.", "También activa los músculos trapecios y puede beneficiar las molestias causadas por la debilidad muscular, como la postura postural y la protrusión del omóplato, al afectar los músculos infraespinoso y subescápula que cubren la escápula."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000069408815', 'Estiramiento de espalda y pectorales', 'Back and Pec Stretch', 'Espalda', '["- Busque un banco resistente, una plataforma elevada o una mesa a la altura de la cintura. Asegúrese de que la superficie sea estable y segura.", "- Párese y colóquese Párese aproximadamente a un pie de distancia del banco, frente a él. Coloque las manos a la altura de los hombros en el borde de la superficie.", "- Párese aproximadamente a un pie de distancia del banco, frente a él. Coloque las manos a la altura de los hombros en el borde de la superficie.", "- Bisagra en las caderas Retroceda lentamente mientras dobla las caderas. Baje el torso hasta que quede paralelo al suelo o ligeramente por debajo.", "- Da un paso atrás lentamente mientras doblas las caderas. Baje el torso hasta que quede paralelo al suelo o ligeramente por debajo.", "- Realice el estiramiento. Mantenga los brazos rectos y permita que el pecho se hunda hacia abajo. Tu cabeza debe permanecer alineada con tus brazos, o puedes dejarla caer ligeramente para un estiramiento más profundo.", "- Mantenga los brazos rectos y permita que su pecho se hunda hacia abajo. Tu cabeza debe permanecer alineada con tus brazos, o puedes dejarla caer ligeramente para un estiramiento más profundo.", "- Respirar y sostenerMantener el estiramiento durante 20 a 30 segundos mientras respira profunda y controladamente. Concéntrate en sentir cómo se libera la tensión de tu espalda y pecho.", "- Mantenga el estiramiento durante 20 a 30 segundos mientras respira profunda y controladamente. Concéntrate en sentir cómo se libera la tensión de tu espalda y pecho.", "- Siga la misma configuración y posicionamiento que el estiramiento estático. En lugar de mantener el estiramiento, realiza el siguiente movimiento dinámico:", "- Mueva suavemente el torso hacia arriba y hacia abajo, profundizando el estiramiento con cada movimiento hacia abajo. Realice de 10 a 15 repeticiones.", "- Mueva suavemente el torso hacia arriba y hacia abajo, profundizando el estiramiento con cada movimiento hacia abajo.", "- Realiza de 10 a 15 repeticiones.", "### Consejos para el entrenador:", "- Mantenga las rodillas ligeramente dobladas si siente los isquiotibiales tensos.", "- Evite arquear excesivamente la zona lumbar; mantener una columna neutra.", "### Errores comunes a evitar", "- Ampliar la parte baja de la espalda: concéntrese en girar desde las caderas y mantener el núcleo comprometido para proteger la columna lumbar. Deténgase si siente algún dolor agudo.", "- Tensión en los hombros: relaje los hombros y permita que el pecho baje para lograr un estiramiento más profundo y eficaz."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-002010381454', 'Press de pecho con martillo inclinado y palanca', 'Lever Incline Hammer Chest Press', 'Pecho', '["- Ajuste la máquina Configure la altura del asiento para que las manijas se alineen con la parte media y superior del pecho cuando esté sentado. Ajuste la pila de pesas o la carga del plato a una resistencia manejable.", "- Ajuste la altura del asiento de modo que las manijas se alineen con la parte media y superior del pecho cuando esté sentado.", "- Ajuste la pila de pesas o la carga del plato a una resistencia manejable.", "- Colóquese Siéntese en el banco inclinado con la espalda presionada firmemente contra la almohadilla. Sujete las manijas con un agarre neutral (con las palmas hacia adentro). Coloque los pies apoyados en el suelo para mayor estabilidad.", "- Siéntese en el banco inclinado con la espalda presionada firmemente contra la almohadilla.", "- Sujete las manijas con un agarre neutral (las palmas hacia adentro).", "- Coloque los pies apoyados en el suelo para mayor estabilidad.", "- Posición inicial Comience con los brazos doblados y los codos ligeramente por debajo del nivel de los hombros. Mantenga el pecho erguido y los hombros hacia atrás.", "- Comience con los brazos doblados y los codos ligeramente por debajo del nivel de los hombros.", "- Mantenga el pecho erguido y los hombros hacia atrás.", "- Presione las manijas. Exhale y empuje las manijas hacia arriba y ligeramente hacia adentro con un movimiento controlado. Extienda completamente los brazos sin bloquear los codos.", "- Exhale y empuje las manijas hacia arriba y ligeramente hacia adentro con un movimiento controlado.", "- Extienda completamente los brazos sin bloquear los codos.", "- Baje las manijas Inhale y baje lentamente las manijas hasta la posición inicial. Mantenga el control y evite que la pila de pesas se golpee.", "- Inhale y baje lentamente las manijas hasta la posición inicial.", "- Mantenga el control y evite que la pila de pesas golpee.", "- Repetir Realice de 8 a 12 repeticiones para hipertrofia o de 12 a 15 para resistencia, según su objetivo de acondicionamiento físico.", "- Realice de 8 a 12 repeticiones para hipertrofia o de 12 a 15 para resistencia, según su objetivo de acondicionamiento físico.", "### Consejos para una forma adecuada:", "- Evite encogerse de hombros para evitar la sobreactivación de las trampas.", "- Mantenga un ritmo lento y controlado para maximizar el compromiso muscular.", "- Mantenga las muñecas en posición neutra para evitar tensiones innecesarias.", "### Errores comunes:", "- Uso de peso excesivo: priorice la forma sobre el peso para evitar lesiones o un reclutamiento muscular inadecuado.", "- Codos ensanchados demasiado anchos: Mantenga los codos en un ángulo de aproximadamente 45 grados para evitar tensión en los hombros.", "- Rango de movimiento incompleto: baje las manijas completamente para enganchar el cofre en todo su rango."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001967066641', 'Elevación en Y inclinada con mancuernas', 'Incline Dumbbell Y-Raise', 'Hombros', '["Acuéstese boca abajo sobre una pelota de ejercicios o un banco, con el pecho y las caderas apoyados y los pies en el suelo.", "Sostenga una mancuerna liviana en cada mano, con las palmas hacia adentro y los brazos rectos.", "Manteniendo los brazos rectos y la cabeza alineada con la columna, levante los brazos hacia arriba y hacia afuera para formar una \"Y\" con su cuerpo.", "Haga una pausa breve en la parte superior del movimiento, luego baje las pesas a la posición inicial."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000740826219', 'Rompecráneos con mancuernas / Extensión de tríceps acostado', 'Dumbbell Skullcrusher / Lying Triceps Extension', 'Tríceps', '["### Paso 1: Configuración y posición inicial", "- Acuéstese sobre un banco con los pies firmemente plantados en el suelo.", "- Sostenga una mancuerna en cada mano con un agarre por encima de la cabeza, con los brazos extendidos directamente sobre su pecho.", "- Mantenga los codos fijos en su lugar y evite el movimiento excesivo de los hombros.", "### Paso 2: Ejecución", "- Baje lentamente las mancuernas hacia la frente doblando los codos.", "- Mantenga la parte superior de los brazos inmóviles, permitiendo que solo se muevan los antebrazos.", "- Una vez que las mancuernas estén justo encima de tu frente, haz una breve pausa.", "- Extiende los brazos hacia la posición inicial, estirando completamente los codos.", "- Repita de 8 a 12 repeticiones durante 3 a 4 series.", "### Consejos para una forma adecuada", "- Mantenga los codos estables y evite estirarlos.", "- Baje las mancuernas de forma controlada para evitar una tensión excesiva.", "- Utilice un peso cómodo para mantener una buena forma durante todo el movimiento.", "- Evite bloquear los codos en la parte superior para reducir la tensión en las articulaciones.", "- Involucre su núcleo para mantener su cuerpo estable en el banco.", "### Errores comunes a evitar", "- Dejar que los codos se abran: esto reduce la activación del tríceps.", "- Usar demasiado peso, lo que lleva a la pérdida de control.", "- Mover los hombros en exceso, quitando tensión al tríceps.", "- Bajar las mancuernas demasiado rápido, con riesgo de lesionarse.", "- No extender completamente los brazos, limitando la efectividad del movimiento."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001798751525', 'Curl de martillo de cuerda en polea', 'Cable Rope Hammer Curl', 'Otros', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001764586768', 'Crianza de pantorrillas en burro en pareja', 'Partner Donkey Calf Raise', 'Pantorrillas', '["- Colocación de los pies: Párese sobre un bloque o plataforma segura con solo las puntas de los pies apoyadas y los talones colgando del borde.", "- Posición del torso: Inclínese hacia adelante a la altura de las caderas para formar un ángulo de aproximadamente 90°. Coloque las manos sobre un banco, barandilla o plataforma segura para mayor estabilidad. Mantenga la espalda plana y las rodillas completamente extendidas.", "- Carga del compañero: su compañero monta con cuidado sus caderas/zona lumbar y se sienta uniformemente. Deben distribuir el peso sin aplicar presión directa sobre la columna o las costillas.", "- Posición inicial: comience con los talones completamente bajados para lograr un estiramiento profundo de la pantorrilla.", "- Inicie el levantamiento: levante los talones presionando las puntas de los pies y contrayendo las pantorrillas con fuerza.", "- Top Squeeze: manténgalo en la parte superior durante 1 a 2 segundos, concentrándose en la flexión plantar completa.", "- Descenso controlado: Baje los talones por debajo del nivel del bloque bajo control lento, restableciendo el estiramiento.", "- Repetir: complete la cantidad deseada de repeticiones, manteniendo un ritmo y una postura constantes en todo momento.", "### Consejos para una forma adecuada", "- Elija un compañero cercano a su categoría de peso para comenzar y luego aumente.", "- Asegúrese de que la carga se distribuya uniformemente: el compañero debe sentarse sobre las caderas, no sobre la mitad de la espalda.", "- Mantenga las rodillas completamente bloqueadas para priorizar el reclutamiento de gastrocnemios.", "- Evite rebotar o aprovechar el impulso; concéntrese en movimientos lentos y deliberados.", "- Mantenga una columna neutra y una articulación de cadera constante durante toda la serie.", "### Errores comunes a evitar", "- Dejar que la pareja se siente demasiado alto, lo que sobrecarga la columna lumbar y reduce la tensión mecánica en las pantorrillas.", "- Doblar las rodillas, lo que desvía la atención hacia el sóleo y compromete la forma.", "- No utilizar una superficie estable: una plataforma para los pies resbaladiza puede provocar caídas.", "- Sobrecargar demasiado pronto, arriesgarse a lesionarse o romper la forma.", "- Usar los brazos para tirar o empujar, reduciendo el aislamiento de la parte inferior del cuerpo."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000953094261', 'Cruces de palanca', 'Lever Crossovers', 'Pecho', '["- Ajuste la máquina Ajuste la altura del asiento de modo que las manijas se alineen con la mitad de su pecho cuando esté sentado. Ajuste el respaldo para lograr una posición cómoda y estable.", "- Ajuste la altura del asiento de modo que las manijas se alineen con la mitad de su pecho cuando esté sentado.", "- Ajuste el respaldo para lograr una posición cómoda y estable.", "- Elija su pesoSeleccione un peso que le permita completar la cantidad deseada de repeticiones con la forma adecuada.", "- Seleccione un peso que le permita completar la cantidad deseada de repeticiones con la forma adecuada.", "- PosicióneseSiéntese en la máquina con la espalda presionada firmemente contra el respaldo. Coloque los pies apoyados en el suelo, separados aproximadamente a la altura de los hombros.", "- Siéntese en la máquina con la espalda firmemente apoyada contra el respaldo.", "- Coloque los pies apoyados en el suelo, separados aproximadamente a la altura de los hombros.", "- Posición inicial Agarre las manijas firmemente con las palmas hacia adentro. Mantenga los codos ligeramente doblados para proteger sus articulaciones.", "- Agarre las manijas firmemente con las palmas hacia adentro.", "- Mantenga los codos ligeramente doblados para proteger sus articulaciones.", "- Realice el CrossoverExhale mientras baja lentamente los brazos. Concéntrate en apretar el pecho en el punto máximo del movimiento.", "- Exhala mientras bajas lentamente los brazos. Concéntrate en apretar el pecho en el punto máximo del movimiento.", "- Regrese a StartInhale y lentamente permita que las manijas regresen a la posición inicial, manteniendo la tensión en su pecho en todo momento.", "- Inhale y permita lentamente que las manijas regresen a la posición inicial, manteniendo la tensión en el pecho en todo momento.", "- Repetir Realice de 8 a 12 repeticiones para hipertrofia o de 12 a 15 repeticiones para resistencia.", "- Realice de 8 a 12 repeticiones para hipertrofia o de 12 a 15 repeticiones para resistencia.", "### Consejos para una forma adecuada", "- Mantenga una ligera flexión de los codos para evitar extender demasiado las articulaciones.", "- Muévase de manera lenta y controlada para maximizar la tensión en los músculos del pecho.", "- Evite inclinarse hacia adelante o hacia atrás durante el movimiento; mantenga la columna neutra.", "### Errores comunes a evitar", "- Usar peso excesivo: Seleccionar un peso demasiado pesado puede comprometer la forma y reducir la efectividad del ejercicio.", "- Extender demasiado los codos: estirar completamente los brazos aumenta el riesgo de tensión en las articulaciones.", "- Confiar en el impulso: evitar movimientos bruscos; Utilice movimientos controlados para una participación muscular óptima."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001364989709', 'Tirón entre piernas en polea (Pull Through)', 'Cable Pull Through', 'Espalda', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000886168254', 'Rotación externa con mancuernas apoyadas en banco', 'Bench Supported Dumbbell External Rotation', 'Hombros', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001563069461', 'Extensión a dos brazos inclinada con mancuernas', 'Dumbbell Incline Two-Arm Extension', 'Otros', '["### Paso 1: Configuración y posición inicial", "- Coloque un banco inclinado entre 30 y 45 grados.", "- Siéntate en el banco con una mancuerna en cada mano, con las palmas una frente a la otra. (Se puede hacer con una sola mancuerna)", "- Presione las mancuernas sobre su cabeza hasta que sus brazos estén completamente extendidos.", "- Mantenga su núcleo comprometido y la espalda firmemente contra el banco.", "### Paso 2: Ejecución", "- Baje lentamente las mancuernas detrás de la cabeza doblando los codos.", "- Mantenga la parte superior de los brazos inmóviles mientras los antebrazos se mueven hacia abajo.", "- Baja las mancuernas hasta que sientas un estiramiento en el tríceps.", "- Haga una pausa breve y luego extienda los brazos hasta la posición inicial.", "- Aprieta los tríceps en la parte superior y luego repite de 8 a 12 repeticiones durante 3 a 4 series.", "### Consejos para una forma adecuada", "- Mantenga los codos juntos para maximizar la activación de los tríceps.", "- Baja las mancuernas lentamente y de forma controlada para evitar lesiones.", "- Utilice un peso cómodo que permita un rango completo de movimiento sin tensión excesiva.", "- Evite arquear la espalda; mantenga la columna neutral contra el banco.", "- Inhale mientras baja las mancuernas y exhale mientras las vuelve a subir.", "### Errores comunes a evitar", "- Ensanchar los codos, lo que reduce el compromiso de los tríceps.", "- Usar demasiado peso, lo que lleva a un control deficiente y riesgo de lesiones.", "- Dejar caer las mancuernas demasiado bajo, ejerciendo una tensión innecesaria sobre los hombros.", "- Arquear la espalda excesivamente, lo que puede provocar molestias o lesiones.", "- Acelerar el movimiento, reduciendo la efectividad y aumentando el riesgo de lesiones."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000690211612', 'Remo en polea alta unilateral de rodillas', 'Kneeling Single Arm High Pulley Row', 'Espalda', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001991256632', 'Flexión lateral de tronco con barra', 'Barbell Side Bend', 'Abdomen', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001551411186', 'Giro inclinado', 'Bent Over Twist', 'Abdomen', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001301736044', 'Extensión de tríceps por encima de la cabeza con barra EZ sentado', 'Seated EZ-Bar Overhead Triceps Extension', 'Tríceps', '["### Paso 1: Configuración y posición inicial", "- Siéntese en un banco plano con respaldo para mantener la estabilidad.", "- Agarre la barra EZ con un agarre firme y por encima de la cabeza (con las palmas hacia adelante).", "- Levanta la barra por encima de tu cabeza, manteniendo los brazos completamente extendidos.", "- Asegúrese de que sus codos estén cerca de su cabeza y su núcleo esté comprometido.", "### Paso 2: Ejecución", "- Baje lentamente la barra EZ detrás de su cabeza doblando los codos.", "- Mantenga la parte superior de los brazos inmóviles mientras mueve solo los antebrazos.", "- Baja la barra hasta que sientas un estiramiento profundo en el tríceps.", "- Haga una pausa breve, luego presione la barra para regresar a la posición inicial extendiendo los codos.", "- Repita de 8 a 12 repeticiones, completando de 3 a 4 series.", "### Consejos para una forma adecuada", "- Mantenga los codos cerca de la cabeza para maximizar la participación de los tríceps.", "- Utilice un movimiento controlado, evitando sacudidas bruscas o movimientos de rebote.", "- Involucre su núcleo para mantener una postura erguida.", "- Inhala mientras bajas la barra y exhala mientras extiendes los brazos.", "- Elija un peso adecuado para mantener la técnica adecuada.", "### Errores comunes a evitar", "- Ensanchando los codos hacia afuera, reduciendo la activación de los tríceps.", "- Usar peso excesivo, lo que lleva a una mala forma y a un mayor riesgo de lesiones.", "- Arquear la zona lumbar, lo que puede provocar molestias.", "- Dejar caer la barra demasiado bajo, ejerciendo una tensión innecesaria sobre los hombros.", "- Moverse demasiado rápido, disminuyendo la participación y el control de los músculos."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001467434406', 'Extensión de tríceps con mancuernas en pronación unilateral', 'One-Arm Pronated Dumbbell Triceps Extension', 'Tríceps', '["### Paso 1: Configuración y posición inicial", "- Acuéstese en un banco con una mancuerna en una mano.", "- Sostenga la mancuerna con un agarre en pronación (con la palma hacia adelante).", "- Extiende el brazo hacia arriba, colocando la mancuerna por encima del hombro.", "- Mantenga el codo inmóvil, con la parte superior del brazo perpendicular al suelo.", "### Paso 2: Ejecución", "- Baje lentamente la mancuerna doblando el codo y llevándolo hacia el costado de la cabeza.", "- Mantenga el codo en su lugar mientras se mueve el antebrazo.", "- Baja la mancuerna hasta que sientas un estiramiento profundo en el tríceps.", "- Haga una pausa breve y luego extienda el brazo hasta la posición inicial.", "- Repita de 8 a 12 repeticiones, luego cambie de brazo. Completa de 3 a 4 series.", "### Consejos para una forma adecuada", "- Mantenga el codo estable para garantizar la activación adecuada del tríceps.", "- Utilice un movimiento controlado para evitar el impulso y la tensión.", "- Mantenga una posición neutra de la muñeca para reducir la tensión en las articulaciones.", "- Involucre su núcleo para evitar movimientos excesivos o arqueamiento.", "- Inhala mientras bajas la mancuerna y exhala mientras la extiendes.", "### Errores comunes a evitar", "- Permitir que el codo se desplace hacia afuera, reduciendo el aislamiento del tríceps.", "- Usar peso excesivo, lo que puede provocar un mal control y lesiones.", "- Apresurarse en el movimiento, disminuyendo el compromiso muscular.", "- Arquear la zona lumbar, lo que puede provocar molestias o tensión.", "- Dejar caer la mancuerna demasiado bajo, lo que genera una tensión innecesaria en el hombro."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001199069481', 'Buenos días con la en máquina Smith', 'Smith Machine Good Morning', 'Espalda', '["Párate frente a la máquina Smith con los pies separados a la altura de los hombros y la barra apoyada sobre tus hombros.", "Mantén el pecho erguido y el core comprometido.", "Doble lentamente las caderas, empujando los glúteos hacia atrás y bajando el torso hacia el suelo.", "Bájate hasta que tu torso quede paralelo al suelo.", "Haga una pausa breve en la parte inferior del movimiento, luego levante lentamente el torso hasta la posición inicial.", "Repita hasta el número deseado de repeticiones."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001166968795', 'Remo con mancuernas sentado inclinado sobre el deltoides posterior', 'Dumbbell Seated Bent Over Rear Delt Row', 'Espalda', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001054769292', 'Press de banca con mancuernas y agarre inverso', 'Reverse Grip Dumbbell Bench Press', 'Pecho', '["Elija sus mancuernasSeleccione un peso que le permita mantener la forma adecuada durante todo el ejercicio.", "Seleccione un peso que le permita mantener la forma adecuada durante todo el ejercicio.", "Colóquese Recuéstese en un banco plano con los pies apoyados en el suelo. Sostenga una mancuerna en cada mano con un agarre inverso (con las palmas hacia la cara).", "Recuéstese en un banco plano con los pies apoyados en el suelo.", "Sostenga una mancuerna en cada mano con agarre inverso (con las palmas hacia la cara)."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
