INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000616745918', 'Extensión de tríceps inclinada en polea', 'Cable Incline Triceps Extension', 'Tríceps', '["### Paso 1: Configuración y posición inicial", "- Ajuste un banco inclinado a un ángulo de 45 a 60 grados y colóquelo cerca de una polea de cable baja.", "- Conecte una barra recta o un mango de cuerda a la máquina de cable.", "- Acuéstese boca arriba en el banco y agarre el asa desde abajo, con las manos separadas a la altura de los hombros.", "- Extiende los brazos hacia arriba, colocándolos perpendiculares al suelo.", "### Paso 2: Ejecución", "- Baje lentamente el mango detrás de su cabeza doblando los codos.", "- Mantenga la parte superior de los brazos inmóviles mientras permite que solo se muevan los antebrazos.", "- Baje el mango hasta que sienta un estiramiento profundo en el tríceps.", "- Haga una breve pausa y luego extienda los brazos para volver a la posición inicial.", "- Repita de 8 a 12 repeticiones, completando de 3 a 4 series.", "### Consejos para una forma adecuada", "- Mantenga los codos juntos para maximizar la activación de los tríceps.", "- Mueva solo los antebrazos, manteniendo la parte superior de los brazos inmóviles.", "- Utilice un tempo controlado para evitar que el impulso se apodere de usted.", "- Mantenga una posición neutra de la muñeca para evitar tensiones innecesarias.", "- Involucre su núcleo para estabilizar su cuerpo durante todo el movimiento.", "### Errores comunes a evitar", "- Ensanchando los codos hacia afuera, reduciendo el compromiso de los tríceps.", "- Usar peso excesivo, lo que lleva a comprometer la forma.", "- Bajar el mango demasiado rápido aumenta el riesgo de lesiones.", "- Arquear la zona lumbar, lo que puede provocar molestias.", "- No extenderse completamente, limitando la activación muscular."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000420996741', 'Prensa Svend', 'Svend Press', 'Pecho', '["- Seleccione un disco de pesas Comience con un disco liviano (de 5 a 10 kg o de 10 a 25 libras) y aumente a medida que desarrolle fuerza y ​​control.", "- Comience con una placa liviana (de 5 a 10 kg o de 10 a 25 libras) y aumente a medida que desarrolle fuerza y ​​control.", "- Agarre la placa Sostenga la placa de pesas entre las palmas y presione firmemente para mantenerla en su lugar. Tus dedos deben apuntar hacia afuera.", "- Sostenga la placa de pesas entre las palmas y presione firmemente para mantenerla en su lugar. Tus dedos deben apuntar hacia afuera.", "- Posición inicial: Párese erguido con los pies separados a la altura de los hombros y el core enganchado. Sostenga la placa contra el centro de su pecho, manteniendo los codos doblados y cerca de los costados.", "- Párate erguido con los pies separados a la altura de los hombros y el core comprometido.", "- Sostenga el plato contra el centro de su pecho, manteniendo los codos doblados y cerca de los costados.", "- Presione la placa hacia adelante Extienda lentamente los brazos hacia adelante mientras presiona las palmas de las manos contra la placa para mantenerla estable. Concéntrese en apretar los músculos del pecho mientras presiona.", "- Extienda lentamente los brazos hacia adelante mientras presiona las palmas de las manos contra el plato para mantenerlo estable.", "- Concéntrate en apretar los músculos del pecho mientras presionas.", "- Haga una pausa y apriete Al final del movimiento, haga una pausa de 1 a 2 segundos y contraiga los músculos del pecho.", "- Al final del movimiento, haga una pausa de 1 a 2 segundos y contraiga los músculos del pecho.", "- Regrese al inicio Lleve lentamente la placa hacia su pecho, manteniendo la tensión en su pecho en todo momento.", "- Lentamente, lleve la placa de regreso a su pecho, manteniendo la tensión en su pecho en todo momento.", "### Consejos para una forma adecuada", "- Mantenga la tensión en el pecho: mantenga una presión constante sobre la placa de pesas para asegurarse de que los músculos del pecho estén activos en todo momento.", "- Evite el uso de Momentum: muévase de manera lenta y controlada para maximizar la activación muscular.", "- Involucre su núcleo: mantenga sus abdominales contraídos para mantener una postura estable y evitar un arqueo excesivo de la espalda baja.", "- Concéntrese en el rango de movimiento: extienda completamente los brazos mientras presiona la placa, pero no bloquee los codos.", "### Errores comunes a evitar", "- Permitir que la placa se deslice: presione firmemente las palmas de las manos contra la placa para evitar perder el control.", "- Confiar en los brazos en lugar del pecho: concéntrate en apretar los músculos del pecho para iniciar el movimiento, en lugar de dejar que tus brazos se hagan cargo.", "- Arqueando la espalda: Mantenga una columna neutral involucrando los músculos centrales durante todo el ejercicio.", "- Usar demasiado peso: comience con un disco más liviano para garantizar la forma y el compromiso muscular adecuados."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
