INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001837619528', 'Hiperextensión torcida', 'Twisting Hyperextension', 'Abdomen', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000648494974', 'Press de banca alternativo con mancuernas', 'Alternate Dumbbell Bench Press', 'Pecho', '["- Elija mancuernas adecuadas Seleccione mancuernas que le permitan mantener la forma adecuada durante todo el ejercicio.", "- Selecciona mancuernas que te permitan mantener la forma adecuada durante todo el ejercicio.", "- Instale el banco Acuéstese sobre un banco resistente con los pies firmemente plantados en el suelo.", "- Acuéstese sobre un banco resistente con los pies firmemente plantados en el suelo.", "- Colóquese Sostenga una mancuerna en cada mano con los brazos extendidos directamente sobre los hombros, con las palmas hacia adelante.", "- Sostenga una mancuerna en cada mano con los brazos extendidos directamente sobre los hombros, con las palmas hacia adelante.", "- Posición inicial Baje una mancuerna lentamente hacia el costado de su pecho mientras mantiene el otro brazo extendido por encima de su hombro.", "- Baje una mancuerna lentamente hacia el costado de su pecho mientras mantiene el otro brazo extendido por encima de su hombro.", "- Presione la mancuerna hacia arriba y exhale mientras presiona la mancuerna hacia la posición inicial.", "- Exhala mientras presionas la mancuerna de regreso a la posición inicial.", "- Cambiar de brazo Baje la mancuerna opuesta mientras mantiene el primer brazo extendido en la parte superior.", "- Baja la mancuerna opuesta manteniendo el primer brazo extendido en la parte superior.", "- Repeticiones alternas Continúe alternando brazos durante el número deseado de repeticiones, manteniendo el control durante todo el movimiento.", "- Continúe alternando brazos durante el número deseado de repeticiones, manteniendo el control durante todo el movimiento.", "- Finalización Una vez que termines tu serie, baja con cuidado ambas mancuernas hasta tu pecho y siéntate con control.", "- Una vez que termines tu serie, baja con cuidado ambas mancuernas hasta tu pecho y siéntate con control.", "### Consejos para una forma adecuada", "- Involucre su núcleo: mantenga su núcleo apretado para evitar que su torso gire durante el movimiento alterno.", "- Controle el movimiento: evite las prisas; Baje y presione las mancuernas de manera lenta y controlada.", "- Mantenga la alineación: sus muñecas deben permanecer alineadas con sus antebrazos y sus codos deben permanecer en un ángulo de 45 grados con respecto a su torso.", "- Rango completo de movimiento: baje la mancuerna hasta que esté al nivel de su pecho para garantizar un rango completo de movimiento.", "- Base estable: Mantenga los pies firmemente plantados en el suelo para proporcionar una base estable para el elevador.", "### Errores comunes a evitar", "- Rango de movimiento desigual Asegúrese de que ambos brazos sigan el mismo rango de movimiento para evitar desequilibrios musculares.", "- Asegúrese de que ambos brazos sigan el mismo rango de movimiento para evitar desequilibrios musculares.", "- Repeticiones apresuradas Realice cada repetición lenta y deliberadamente para maximizar la participación de los músculos.", "- Realice cada repetición lenta y deliberadamente para maximizar la participación de los músculos.", "- Arqueando la parte baja de la espalda Mantenga la espalda plana sobre el banco involucrando el core y los glúteos.", "- Mantenga la espalda plana en el banco involucrando el núcleo y los glúteos.", "- Ensanchamiento de los codos Evite que los codos se ensanchen demasiado, ya que esto puede tensar los hombros.", "- Evite que los codos se abran demasiado, ya que esto puede tensar los hombros.", "- Uso de peso excesivo Comience con mancuernas más livianas para dominar la forma adecuada antes de aumentar el peso.", "- Comience con mancuernas más livianas para dominar la forma adecuada antes de aumentar el peso."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001233543069', 'Cable vertical con giro de alto a bajo', 'Standing Cable High-To-Low Twist', 'Abdomen', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001592209867', 'Cable vertical con giro de baja a alta', 'Standing Cable Low-To-High Twist', 'Abdomen', '["El ejercicio ejercita los músculos oblicuos, abdominales y lumbares. Los oblicuos son los músculos que conectan los dorsales y los abdominales. Estos músculos ayudan a torcer o girar la parte superior del cuerpo. Este ejercicio, dirigido a los músculos oblicuos, es muy útil para tensar y desarrollar la grasa abdominal."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001826598761', 'Extensión de tríceps con cuerda y cable', 'Cable Rope Triceps Pushdown', 'Tríceps', '["### Paso 1: Configuración y posición inicial", "- Conecte un mango de cuerda a una máquina de cable de polea alta.", "- Seleccione un peso apropiado que permita un movimiento controlado.", "- Párese frente a la máquina con una ligera inclinación hacia adelante, manteniendo los pies separados a la altura de los hombros.", "- Sujete la cuerda con ambas manos, usando un agarre neutral (con las palmas una frente a la otra).", "- Mantenga los codos cerca del torso y active el núcleo.", "### Paso 2: Ejecución", "- Empuja la cuerda hacia abajo extendiendo los codos y manteniendo la parte superior de los brazos inmóviles.", "- Al llegar abajo, separe las asas de la cuerda, enfatizando una contracción completa del tríceps.", "- Mantén la contracción por un segundo, luego regresa lentamente a la posición inicial mientras controlas la resistencia.", "- Repita de 3 a 4 series de 10 a 12 repeticiones con la forma adecuada.", "### Consejos para una forma adecuada", "- Mantenga los codos doblados hacia adentro para maximizar la activación de los tríceps.", "- Utilice un movimiento controlado para evitar balancearse o utilizar el impulso.", "- Involucre su núcleo para mantener la estabilidad durante todo el movimiento.", "- Asegúrese de que el codo esté completamente extendido en la parte inferior para activar todas las cabezas de los tríceps.", "- Separe la cuerda en la parte inferior para una mejor contracción del tríceps.", "### Errores comunes a evitar", "- Ensanchando los codos hacia afuera, reduciendo la activación de los tríceps.", "- Usar peso excesivo, lo que lleva a un control deficiente y una forma inadecuada.", "- Inclinarse demasiado hacia adelante, desviando la atención del tríceps.", "- No extender completamente los brazos, limitando la efectividad del ejercicio.", "- Dejar que la pila de pesas caiga de golpe, lo que reduce la participación de los músculos."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001739917424', 'Giro en polea de pie', 'Standing Cable Twist', 'Abdomen', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001368323992', 'Extensión de tríceps con barra EZ inclinada', 'Incline EZ-Bar Triceps Extension', 'Tríceps', '["### Paso 1: Configuración y posición inicial", "- Coloque un banco inclinado en un ángulo de 30 a 45 grados.", "- Recuéstate en el banco con los pies apoyados en el suelo.", "- Sostenga una barra EZ con un agarre por encima de la cabeza, colocando las manos un poco más juntas que el ancho de los hombros.", "- Extienda los brazos por encima del pecho, manteniendo los codos ligeramente doblados.", "### Paso 2: Ejecución", "- Baje la barra detrás de su cabeza doblando los codos, manteniéndolos estacionarios.", "- Baja la barra hasta que tus codos estén completamente doblados y sientas un estiramiento en tus tríceps.", "- Presione la barra hacia arriba hasta la posición inicial, extendiendo completamente los brazos pero sin bloquear los codos.", "- Realice de 3 a 4 series de 8 a 12 repeticiones con movimiento controlado.", "### Consejos para una forma adecuada", "- Mantenga los codos estables; no dejes que se expandan hacia afuera.", "- Baje la barra detrás de la cabeza en lugar de hacia la frente para una mejor activación muscular.", "- Utilice un peso moderado para mantener el control y evitar tensiones.", "- Mantenga sus muñecas neutrales para evitar tensiones innecesarias.", "- Involucre su núcleo para estabilizar la parte superior de su cuerpo durante el movimiento.", "### Errores comunes a evitar", "- Usar peso excesivo, lo que lleva a un control deficiente y posibles lesiones.", "- Ensanchar los codos hacia afuera, lo que reduce la activación del tríceps.", "- Acercar demasiado la barra a la frente, limitando el estiramiento y la participación de los músculos.", "- No extender completamente los brazos, reduciendo la efectividad del ejercicio.", "- Arquear excesivamente la zona lumbar, provocando tensiones innecesarias."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000477797567', 'Extensión de tríceps en polea de agarre inverso', 'Reverse Grip Cable Triceps Pushdown', 'Tríceps', '["### Paso 1: Configuración y posición inicial", "- Conecte una barra recta o una barra EZ a una máquina de cable de polea alta.", "- Seleccione un peso apropiado que permita un movimiento controlado.", "- Párese frente a la máquina y agarre la barra con un agarre por debajo (supinado), manteniendo las manos separadas aproximadamente al ancho de los hombros.", "- Da un paso atrás ligeramente, manteniendo la columna neutra y una ligera flexión de las rodillas.", "- Coloque los codos cerca de su torso y active su núcleo.", "### Paso 2: Ejecución", "- Empuja la barra hacia abajo extendiendo los codos y manteniendo la parte superior de los brazos inmóviles.", "- Presiona la barra hacia abajo hasta que tus brazos estén completamente extendidos, apretando tus tríceps en la parte inferior.", "- Regresa lentamente la barra a la posición inicial, controlando la resistencia.", "- Repita de 3 a 4 series de 10 a 12 repeticiones con la forma adecuada.", "### Consejos para una forma adecuada", "- Mantenga los codos doblados hacia adentro para maximizar la activación de los tríceps.", "- Utilice un movimiento controlado para evitar balancearse o utilizar el impulso.", "- Involucre su núcleo para mantener la estabilidad durante todo el movimiento.", "- No bloquees completamente los codos en la parte inferior del movimiento.", "- Mantenga una ligera inclinación hacia adelante para mantener el equilibrio y una postura adecuada.", "### Errores comunes a evitar", "- Ensanchando los codos hacia afuera, lo que reduce el compromiso de los tríceps.", "- Usar peso excesivo, lo que lleva a un control deficiente y una forma inadecuada.", "- Inclinarse demasiado hacia adelante, desviando la atención del tríceps.", "- No extender completamente los brazos, limitando la efectividad del ejercicio.", "- Apresurarse en las repeticiones, reduciendo la activación y el control de los músculos."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001373162491', 'Extensión de tríceps por encima de la cabeza en polea alta', 'High Pulley Overhead Tricep Extension', 'Tríceps', '["### Paso 1: Configuración y posición inicial", "- Conecte una cuerda o un mango de barra recta a una polea alta en una máquina de cable.", "- Párese de espaldas a la máquina, agarrando el mango con ambas manos.", "- Da un paso ligeramente hacia adelante, manteniendo los pies separados a la altura de los hombros para mantener el equilibrio.", "- Levante la manija por encima de su cabeza, colocando los codos cerca de las orejas y doblados a 90 grados.", "### Paso 2: Ejecución", "- Extiende los brazos hacia adelante y hacia arriba, estirando los codos hasta que los brazos estén completamente extendidos.", "- Aprieta tus tríceps en la parte superior del movimiento.", "- Regrese lentamente a la posición inicial, asegurando un movimiento controlado.", "- Repita de 8 a 12 repeticiones, completando de 3 a 4 series.", "### Consejos para una forma adecuada", "- Mantenga su núcleo comprometido para estabilizar su cuerpo.", "- Mantenga los codos cerca de la cabeza para involucrar completamente los tríceps.", "- Evite utilizar el impulso; Controla el peso en todo el rango de movimiento.", "- No arquees demasiado la zona lumbar; Mantenga una columna neutral.", "- Utilice un peso que permita la forma adecuada sin tensión excesiva.", "### Errores comunes a evitar", "- Ensanchando los codos, reduciendo el compromiso de los tríceps.", "- Inclinarse demasiado hacia adelante, provoca una tensión innecesaria en la zona lumbar.", "- Usar demasiado peso, lo que lleva a una forma inadecuada.", "- Acelerar las repeticiones y reducir el tiempo bajo tensión.", "- No extender completamente los brazos, limitando la efectividad del ejercicio."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001051747855', 'Elevación de pantorrilla en posición de sentadilla', 'Squat Hold Calf Raise', 'Piernas', '["- Posición inicial: Párese con los pies separados a la altura de los hombros y los brazos extendidos hacia adelante o juntos a la altura del pecho para mantener el equilibrio.", "- Descender a sentadilla: bájese hasta ponerse en cuclillas paralelas, manteniendo las rodillas alineadas con los dedos de los pies, la espalda recta y el pecho erguido.", "- Establezca la sujeción: mantenga la posición en cuclillas; sus muslos deben estar paralelos al piso o tan bajos como le resulte cómodo.", "- Levante los talones: mientras realiza la sentadilla, levante los talones del suelo presionando las puntas de los pies.", "- Pausa y descenso: manténgalo en la parte superior brevemente, luego baje los talones nuevamente bajo control.", "- Repita: realice múltiples elevaciones de pantorrillas mientras mantiene la posición en cuclillas durante toda la serie.", "### Consejos para una forma adecuada", "- Mantenga las rodillas alineadas con los dedos de los pies; evite el colapso hacia adentro (valgo).", "- Mantenga el torso erguido con el núcleo comprometido durante toda la posición en cuclillas.", "- Concéntrese en el equilibrio manteniendo la mirada hacia adelante y los brazos extendidos para lograr estabilidad.", "- Controle la elevación del talón con movimientos deliberados y contracción total de la pantorrilla.", "- No rebotes: realiza cada repetición con intención y control.", "### Errores comunes", "- Romper la forma de sentadilla: levantar o dejar que las caderas se desplacen hacia arriba anula el propósito de la sujeción isométrica.", "- No bajar completamente los talones: acortar el rango de movimiento reduce la activación de la pantorrilla.", "- Las rodillas se hunden: provoca tensión en las articulaciones y reduce la eficacia; manténgalas orientadas hacia afuera.", "- Contener la respiración: la respiración adecuada favorece la estabilidad y la resistencia.", "- Falta de equilibrio: apresurar las repeticiones o colocar mal los pies puede causar tambaleos o movimientos ineficaces."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001088851059', 'Dominadas al revés', 'Upside Down Pull-up', 'Espalda', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001306770245', 'Salto de pliegue', 'Tuck Jump', 'Cardio', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000101442794', 'Zancada caminando con peso corporal', 'Bodyweight Walking Lunge', 'Cardio', '["- Posición inicial: Párese erguido con los pies separados a la altura de las caderas, los brazos a los costados o las manos en las caderas.", "- Paso adelante: Da un paso controlado hacia adelante con una pierna, bajando las caderas hasta que ambas rodillas se doblen a 90 grados.", "- Fase de descenso: mantenga el torso erguido y el núcleo enganchado mientras la rodilla trasera se cierne justo sobre el suelo.", "- Empuje a través del talón: presione a través del talón de su pie delantero para elevarse y llevar la pierna trasera hacia adelante para dar el siguiente paso.", "- Continúe caminando: alterne las piernas con un movimiento suave y continuo hasta completar todas las repeticiones.", "### Consejos para una forma adecuada", "- Mantenga el pecho elevado y la columna neutra durante todo el movimiento.", "- Tome medidas deliberadas y controladas para mantener el equilibrio.", "- Asegúrese de que la rodilla delantera permanezca alineada sobre el tobillo y no colapse hacia adentro.", "- Involucre el núcleo para estabilizar su cuerpo y evitar que se tambalee.", "### Errores comunes", "- Sobrepasar o subestimar: conduce a una mala alineación y reduce la eficacia.", "- Inclinarse demasiado hacia adelante: genera un exceso de tensión en la zona lumbar.", "- Dejar que la rodilla colapse hacia adentro: aumenta el riesgo de tensión en las articulaciones y reduce la activación de los glúteos."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000071611325', 'L-sentarse', 'L-Sit', 'Abdomen', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000026798339', 'Nadar', 'Swimming', 'Hombros', '["El ejercicio de natación es muy útil para fortalecer la espalda superior e inferior. Estarás ejercitando los músculos superficiales de la espalda con cada movimiento que hagas. Este ejercicio también mejora los músculos de la cadera, la postura y la flexibilidad."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000098535349', 'Sentadilla con elevación de rodilla', 'High Knee Squat', 'Piernas', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001953895685', 'Paso de boxeador (Boxer Shuffle)', 'Boxer Shuffle Cardio', 'Cardio', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000560715818', 'Flexión de brazos cruzados', 'Cross Arm Push-up', 'Pecho', '["Comience en una posición de tabla alta: comience en una posición de tabla alta con las manos separadas al ancho de los hombros y los pies juntos.", "Cruza los brazos sobre el pecho: Cruza los brazos de modo que tu mano derecha quede frente a tu pecho izquierdo y tu mano izquierda frente a tu pecho derecho.", "Baje el cuerpo: baje el cuerpo doblando los codos, manteniendo la espalda recta y el núcleo comprometido hasta que el pecho casi toque el suelo.", "Empuje hacia arriba: Empuje hacia atrás hasta la posición inicial, manteniendo los brazos cruzados sobre el pecho.", "Repetir: repite el movimiento durante el número deseado de repeticiones."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000386912648', 'Sentarse en la pared', 'Wall Sit', 'Piernas', '["Sentarse en la pared es un ejercicio avanzado desarrollado para dar forma, tensar y fortalecer los músculos de la cadera, las piernas y el tronco. Para llevar el ejercicio a un nivel superior, puedes dificultar el movimiento tomando una pesa en la mano. Además, el ejercicio puede ayudar a aumentar la resistencia de los músculos de las piernas al proporcionar una contracción isométrica."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001440100924', 'Golpes', 'Punches', 'Cardio', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001558739412', 'Boxeo jab', 'Jab Boxing', 'Cardio', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001667284004', 'Uppercut derecho', 'Right Uppercut', 'Cardio', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000283303672', 'Extensión de tríceps concentración en polea', 'Cable Concentration Tricep Extension', 'Tríceps', '["### Paso 1: Configuración y posición inicial", "- Conecte una sola manija a una máquina de cable a la altura de los hombros o ligeramente por encima.", "- Seleccione un peso apropiado que permita un movimiento controlado.", "- Arrodíllate sobre una rodilla mientras mantienes la espalda recta y el core comprometido.", "- Agarre el mango con una mano, manteniendo el codo doblado y cerca del torso.", "- Asegúrese de que la parte superior de su brazo permanezca estacionaria durante todo el ejercicio.", "### Paso 2: Ejecución", "- Extiende tu brazo hacia abajo, alejando el mango de tu cuerpo.", "- Concéntrese en enderezar completamente el codo mientras mantiene fija la parte superior del brazo.", "- Mantenga la contracción durante un segundo para maximizar la activación del tríceps.", "- Regrese lentamente a la posición inicial de forma controlada.", "- Repita de 3 a 4 series de 10 a 12 repeticiones por brazo.", "### Consejos para una forma adecuada", "- Mantenga el codo inmóvil para enganchar completamente el tríceps.", "- Mantenga un núcleo fuerte para evitar el movimiento excesivo del cuerpo.", "- Utilice un tempo controlado para maximizar el tiempo bajo tensión.", "- Asegure la extensión completa del codo para trabajar los tríceps en un rango completo de movimiento.", "- Evite inclinarse hacia adelante o hacia atrás, ya que esto puede reducir la efectividad.", "### Errores comunes a evitar", "- Permitir que el codo se mueva, lo que reduce el aislamiento del tríceps.", "- Usar peso excesivo, lo que lleva a una forma e impulso inadecuados.", "- No extender completamente el brazo, limitando la activación muscular.", "- Acelerando el movimiento, disminuyendo el tiempo bajo tensión.", "- Inclinarse demasiado hacia adelante, desviando la atención del tríceps."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001714587427', 'Patada de gancho', 'Hook Kick', 'Cardio', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
