INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001883153477', 'Press con mancuernas con agarre cerrado', 'Close-Grip Dumbbell Press', 'Pecho', '["- Configuración: Acuéstese en un banco con una mancuerna en cada mano. Coloque las mancuernas directamente sobre su pecho, con las palmas una frente a la otra (agarre neutral) y los codos doblados en un ángulo de 90 grados.", "- Acuéstese en un banco con una mancuerna en cada mano.", "- Coloque las mancuernas directamente sobre su pecho, con las palmas una frente a la otra (agarre neutral) y los codos doblados en un ángulo de 90 grados.", "- Ejecución: Comienza el movimiento extendiendo los brazos completamente y presionando las mancuernas directamente hacia arriba. Mientras presionas, concéntrate en apretar las mancuernas con fuerza. Imagina que estás tratando de aplastarlos o apretarlos durante todo el movimiento. Mantén los codos cerca del cuerpo durante todo el levantamiento, manteniendo un agarre firme. Haz una pausa por un momento en la parte superior del movimiento, manteniendo la tensión en los tríceps.", "- Comienza el movimiento extendiendo los brazos completamente y presionando las mancuernas directamente hacia arriba.", "- Mientras presionas, concéntrate en apretar las mancuernas con fuerza. Imagina que estás tratando de aplastarlos o apretarlos durante todo el movimiento.", "- Mantenga los codos cerca del cuerpo durante todo el levantamiento, manteniendo un agarre firme.", "- Haga una pausa por un momento en la parte superior del movimiento, manteniendo la tensión en el tríceps.", "- Fase de descenso: baje lentamente las mancuernas hasta la posición inicial, manteniendo el control y apretando las mancuernas tanto como sea posible.", "- Baje lentamente las mancuernas hasta la posición inicial, manteniendo el control y apretando las mancuernas tanto como sea posible.", "- Repetir: Realice el número deseado de repeticiones, manteniendo la forma y el control adecuados durante toda la serie.", "- Realice el número deseado de repeticiones, manteniendo la forma y el control adecuados durante toda la serie.", "### Consejos para una forma adecuada:", "- Mantenga los codos cerca del cuerpo para maximizar la activación de los tríceps.", "- Mantenga una posición neutra de la muñeca para evitar tensiones innecesarias.", "- Utilice un movimiento controlado en lugar de depender del impulso.", "- Mantenga los hombros retraídos y comprometidos para evitar tensiones innecesarias en las articulaciones.", "### Errores comunes:", "- Ensanchar los codos: esto cambia el énfasis hacia el pecho y reduce la activación del tríceps.", "- Usar demasiado peso: Levantar mancuernas excesivamente pesadas puede comprometer la forma y provocar lesiones.", "- Arquear la parte baja de la espalda: Arquearse demasiado puede ejercer una tensión innecesaria en la columna.", "- Acelerar el movimiento: Realizar el ejercicio demasiado rápido reduce el tiempo bajo tensión y limita la activación muscular."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001769932187', 'Máquina de crunch completo', 'Full Crunch Machine', 'Cardio', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001372506579', 'Peso muerto a una pierna con peso corporal', 'Bodyweight Single Leg Deadlift', 'Piernas', '["El peso muerto con una sola pierna es un ejercicio eficaz para fortalecer, tonificar, tensar los músculos de los glúteos y mejorar el equilibrio.", "El peso muerto con una sola pierna trabaja secundariamente los músculos centrales, mientras los abdominales y oblicuos se contraen para estabilizar el cuerpo. Este ejercicio también trabaja los músculos erectores de la columna en la espalda que ayudan a sostener la columna y brindan flexibilidad al doblarse en múltiples direcciones.", "El peso muerto con una sola pierna puede mejorar el equilibrio y corregir los desequilibrios de fuerza en las caderas. Cada vez que te paras sobre una pierna, utilizas los mismos músculos para mantener el equilibrio y la estabilidad que a menudo se utilizan para desarrollar fuerza. ¡Mejorar la capacidad de cada pierna para trabajar y producir fuerza te ayudará a disparar tus números de sentadilla trasera y peso muerto!"]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
