INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001961850181', 'Jalón al pecho con agarre cerrado', 'Close Grip Lat-Pulldown', 'Espalda', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000149554583', 'Press con agarre cerrado con una sola mancuerna', 'Single Dumbbell Close-grip Press', 'Pecho', '["### Paso 1: Configuración y posición inicial", "- Acuéstese en un banco plano, asegurándose de que sus pies estén firmemente plantados en el suelo.", "- Sostenga una mancuerna con ambas manos, sujetándola por los lados de las placas de pesas.", "- Coloque la mancuerna sobre su pecho, manteniendo los codos doblados.", "### Paso 2: Ejecución", "- Baja la mancuerna lentamente hacia tu pecho, manteniéndola bajo control.", "- Mantenga un núcleo apretado y evite el ensanchamiento excesivo de los codos.", "- Una vez que la mancuerna llegue justo por encima de tu pecho, haz una breve pausa.", "- Presiona la mancuerna hacia arriba, extendiendo los brazos completamente mientras aprietas los tríceps.", "- Repita de 3 a 4 series de 8 a 12 repeticiones.", "### Consejos para una forma adecuada", "- Mantenga los codos pegados al cuerpo para maximizar la participación de los tríceps.", "- Mantenga un movimiento controlado para evitar utilizar el impulso.", "- Involucre su núcleo para mantener su cuerpo estable en el banco.", "- No extienda demasiado los codos en la parte superior para evitar tensión en las articulaciones.", "- Utilice un peso que pueda controlar para lograr una forma adecuada y un rango de movimiento completo.", "### Errores comunes a evitar", "- Ensanchar los codos, lo que reduce la activación de los tríceps y aumenta la tensión en los hombros.", "- Usar demasiado peso, lo que provoca un control deficiente y posibles lesiones.", "- Hacer rebotar la mancuerna contra el pecho, lo que reduce la participación de los músculos.", "- No extender completamente los brazos, limitando la activación de los tríceps.", "- Acelerar las repeticiones y reducir el tiempo bajo tensión."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001005140133', 'Zancada inversa', 'Reverse Lunge', 'Piernas', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
