INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001456469076', 'Elevación de piernas con correas abdominales', 'Ab Straps Leg Raise', 'Abdomen', '["Este ejercicio que trabaja los flexores de la cadera mejora los músculos centrales, especialmente los músculos abdominales inferiores. Es uno de los ejercicios abdominales efectivos que activa todo el núcleo ejercitando no solo los abdominales inferiores sino también los músculos abdominales superiores."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001811822458', 'Flexión de palmada', 'Clap Push-Up', 'Pecho', '["- Posición inicial: Comience en una posición de flexión regular con las manos colocadas en el suelo ligeramente más separadas que el ancho de los hombros. Su cuerpo debe formar una línea recta desde la cabeza hasta los talones. Involucre sus músculos centrales para mantener la estabilidad.", "- Comience en una posición de flexión regular con las manos colocadas en el suelo ligeramente más separadas que el ancho de los hombros.", "- Tu cuerpo debe formar una línea recta desde la cabeza hasta los talones. Involucre sus músculos centrales para mantener la estabilidad.", "- El Descenso: Baje el pecho hacia el suelo doblando los codos. Mantén el cuerpo en línea recta durante todo el descenso. Bájate tanto como lo harías en una flexión estándar, con el pecho cerca del suelo.", "- Baje el pecho hacia el suelo doblando los codos. Mantén tu cuerpo en línea recta durante todo el descenso.", "- Bájate tanto como lo harías en una flexión estándar, con el pecho cerca del suelo.", "- El aplauso: empuja explosivamente el suelo con las manos, generando suficiente fuerza hacia arriba para levantar la parte superior del cuerpo del suelo. Mientras estás en el aire, junta rápidamente las manos frente al pecho y aplaude. Esto requiere velocidad y coordinación. Intente aplaudir lo más cerca posible del pecho.", "- Empuja explosivamente el suelo con las manos, generando suficiente fuerza hacia arriba para levantar la parte superior del cuerpo del suelo.", "- Mientras estás en el aire, junta rápidamente las manos frente al pecho y aplaude. Esto requiere velocidad y coordinación.", "- Intenta aplaudir lo más cerca posible de tu pecho.", "- El aterrizaje: Después de aplaudir, extienda inmediatamente los brazos para detenerse y volver a la posición de flexión. Aterrice con las manos un poco más separadas que el ancho de los hombros, listo para la siguiente repetición. Aterrice con los codos doblados para absorber el impacto y proteger sus muñecas y codos.", "- Después de aplaudir, extiende inmediatamente los brazos para sostenerte y volver a la posición de flexión.", "- Aterriza con las manos un poco más separadas que el ancho de los hombros, listo para la siguiente repetición.", "- Aterriza con los codos doblados para absorber el impacto y proteger tus muñecas y codos.", "- Repetir: Realice múltiples repeticiones de la flexión con palmada, concentrándose en la potencia explosiva y un aterrizaje controlado. Aumente gradualmente el número de repeticiones a medida que se sienta más cómodo con el ejercicio.", "- Realice múltiples repeticiones de la flexión con palmada, concentrándose en la potencia explosiva y un aterrizaje controlado.", "- Aumente gradualmente el número de repeticiones a medida que se sienta más cómodo con el ejercicio.", "### Consejos para una forma adecuada:", "- Mantenga un núcleo fuerte para evitar la flacidez o el arqueamiento de la espalda baja.", "- Usa tu pecho, hombros y tríceps para generar poder explosivo.", "- Aterriza suavemente con los codos doblados para reducir la tensión en las articulaciones.", "- Mantenga su respiración controlada: inhale mientras baja y exhale mientras empuja hacia arriba.", "### Errores comunes:", "- Empuje incompleto: no generar suficiente fuerza puede resultar en aplausos incompletos o aterrizajes fallidos.", "- Mala colocación de las manos: Colocar las manos demasiado anchas o demasiado estrechas puede reducir la potencia y aumentar el riesgo de lesiones.", "- Dejar caer las caderas: Permitir que las caderas se doblen tensa la zona lumbar y reduce la eficiencia.", "- Bloquear los codos al aterrizar: esto aumenta la tensión en las articulaciones y puede provocar lesiones."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001165233164', 'Bajada a una pierna', 'Single Leg Step Down', 'Piernas', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-002136829707', 'Sentadilla con cinturón', 'Belt Squat', 'Piernas', '["Asegure el cinturón de sentadillas alrededor de su cintura y fíjelo al peso de la máquina o al pasador de carga.", "Sube a las plataformas de modo que el peso cuelgue entre tus piernas y tus pies estén separados a la altura de los hombros.", "Mantente erguido y fortalece tu núcleo. Comienza el descenso empujando las caderas hacia atrás y doblando las rodillas.", "Baje hasta que sus muslos estén al menos paralelos al suelo.", "Empuja con los talones para volver a la posición de pie, manteniendo el torso erguido.", "Repita para las repeticiones deseadas, manteniendo una columna neutral y un ritmo controlado."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001882201642', 'Rotación externa del cable en media rodilla', 'Half Kneeling Cable External Rotation', 'Hombros', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
