INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001986383878', 'Rotación interna del hombro sentado en polea', 'Cable Seated Shoulder Internal Rotation', 'Hombros', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000578035461', 'Flexión de diamantes de rodillas', 'Kneeling Diamond Push-Up', 'Pecho', '["### ", "### Paso 1: Configuración y posición inicial", "- Comience arrodillado en el suelo o sobre una colchoneta para mayor comodidad.", "- Coloque sus manos directamente debajo de su pecho, formando una forma de diamante tocando los pulgares y los dedos índice.", "- Mantenga su núcleo comprometido y mantenga una línea recta desde las rodillas hasta la cabeza.", "### Paso 2: Ejecución", "- Baje el pecho hacia el suelo, manteniendo los codos pegados al cuerpo.", "- Detente cuando tu pecho casi toque tus manos.", "- Empuje hacia atrás hasta la posición inicial extendiendo completamente los brazos mientras mantiene la tensión en los tríceps.", "- Repita de 3 a 4 series de 10 a 15 repeticiones, dependiendo de su nivel de condición física.", "### Consejos para una forma adecuada", "- Mantenga su núcleo comprometido para evitar que la parte baja de la espalda se arquee o se hunda.", "- Mantenga un ritmo controlado para maximizar la activación muscular.", "- No dejes que tus codos se ensanchen; manténgalos cerca de sus costados para una mejor participación de los tríceps.", "- Respira adecuadamente, inhalando mientras bajas y exhalando mientras empujas hacia arriba.", "- Ajuste ligeramente la colocación de su mano si siente molestias en la muñeca.", "### Errores comunes a evitar", "- Permitir que la parte baja de la espalda se hunda, lo que reduce el compromiso del core y puede causar tensión.", "- Ensanchar los codos, lo que lleva a una forma inadecuada y una activación reducida de los tríceps.", "- Acelerar las repeticiones, disminuir el tiempo bajo tensión y la efectividad.", "- No bajar lo suficiente, lo que limita el rango de movimiento y la activación muscular.", "- Colocar las manos demasiado separadas, desviando la atención del tríceps.", "### "]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-002103084767', 'Jack Burpees', 'Jack Burpees', 'Cardio', '["Jack Burpees es uno de los ejercicios para todo el cuerpo más efectivos que ayudan a quemar calorías rápidamente mientras se enfocan en todos los músculos del cuerpo. Jack Burpees son un ejercicio pliométrico. Los ejercicios pliométricos son movimientos aeróbicos explosivos que aumentan la velocidad, la rapidez y la potencia y trabajan todo el cuerpo.", "Este ejercicio se dirige a los músculos abdominales, los músculos de la cadera y los flexores de la cadera y también trabaja los muslos, los tendones de las rodillas, los cuádriceps y los hombros.", "Los saltos son beneficiosos para la salud porque combinan el acondicionamiento cardiovascular con el trabajo de fuerza. Dado que los saltos elevan tu frecuencia cardíaca, también pueden mejorar tu condición cardiovascular. Comience lentamente hasta que se acostumbre al ejercicio y aumente gradualmente hasta hacer más repeticiones."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
