INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000316411622', 'Flexiones con barras de flexiones', 'Push-up With Push-up Bars', 'Pecho', '["- Coloque las barras Coloque las barras de flexión a la altura de los hombros sobre una superficie estable. Asegúrese de que estén seguros y no se resbalen.", "- Coloque las barras de flexión a la altura de los hombros sobre una superficie estable. Asegúrese de que estén seguros y no se resbalen.", "- Agarre las barras Sujete las barras firmemente con un agarre neutral, manteniendo las muñecas rectas y alineadas con los antebrazos.", "- Sostenga las barras firmemente con un agarre neutral, manteniendo las muñecas rectas y alineadas con los antebrazos.", "- Posición inicial Asuma una posición de tabla alta con las manos agarrando las barras, los brazos completamente extendidos y el cuerpo en línea recta desde la cabeza hasta los talones.", "- Asuma una posición de tabla alta con las manos agarrando las barras, los brazos completamente extendidos y el cuerpo en línea recta desde la cabeza hasta los talones.", "- Baje su cuerpo Inhale mientras dobla los codos, bajando el pecho hasta que esté justo por debajo de la altura de sus manos. Mantenga los codos en un ángulo de 45 grados con respecto al torso.", "- Inhala mientras doblas los codos, bajando el pecho hasta que esté justo por debajo de la altura de tus manos. Mantenga los codos en un ángulo de 45 grados con respecto al torso.", "- Push Back UpExhale mientras presiona a través de las barras para regresar a la posición inicial.", "- Exhala mientras presionas a través de las barras para volver a la posición inicial.", "- Repetir Realice de 10 a 15 repeticiones durante 2 a 3 series, manteniendo la forma adecuada en todo momento.", "- Realice de 10 a 15 repeticiones durante 2 a 3 series, manteniendo la forma adecuada en todo momento.", "### Consejos para una forma adecuada", "- Involucre su núcleo: mantenga sus abdominales contraídos para evitar que sus caderas se hunda o se levanten.", "- Controle el movimiento: evite las prisas; Concéntrese en un descenso y ascenso lento y controlado.", "- Posición del codo: Mantenga los codos en un ángulo moderado (no ensanchados) para proteger sus hombros.", "- Columna Neutral: Mantenga una línea recta desde la cabeza hasta los talones.", "- Respiración: Inhale mientras baja y exhale mientras empuja hacia arriba.", "### Errores comunes", "- Caderas caídas: Dejar caer las caderas puede tensar la zona lumbar. Mantenga su núcleo comprometido para evitar esto.", "- Codos ensanchados: Permitir que los codos se ensanchen excesivamente puede generar una tensión indebida en los hombros.", "- Rango de movimiento inadecuado: no bajar el pecho por completo disminuye la efectividad del ejercicio.", "- Acelerar el movimiento: realice cada repetición con control para maximizar la participación de los músculos y reducir el riesgo de lesiones."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001546749330', 'Curl con barra en Z con agarre cerrado', 'Close Grip Z-Bar Curl', 'Otros', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000379613930', 'Cable de palanca jalón tras nuca', 'Lever Cable Rear Pulldown', 'Espalda', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001385844280', 'Aperturas en polea declinada unilateral', 'One Arm Decline Cable Fly', 'Pecho', '["- Ajuste la máquina de cable a una posición baja. Conecte una sola manija al cable.", "- Instale un banco inclinado (alrededor de 15 a 30 grados) cerca de la máquina de cable.", "- Asegure sus pies en las almohadillas del banco para mantener la estabilidad.", "- Agarre el asa con una mano y recuéstese en el banco, manteniendo la mano que no trabaja sobre el torso o agarrando el banco como apoyo.", "- Posición inicial: Extienda el brazo recto por encima del pecho con una ligera flexión del codo. Mantenga la palma hacia adentro (pronación neutra o leve).", "- Extienda el brazo recto por encima del pecho con una ligera flexión del codo.", "- Mantenga la palma de la mano hacia adentro (pronación neutra o ligera).", "- Fase de descenso (movimiento excéntrico): baje lentamente el brazo formando un amplio arco hacia un lado. Deténgase cuando sienta un estiramiento profundo en el pecho (el codo debe estar ligeramente por debajo del nivel del hombro).", "- Baje lentamente el brazo formando un amplio arco hacia un lado.", "- Deténgase cuando sienta un estiramiento profundo en el pecho (el codo debe estar ligeramente por debajo del nivel del hombro).", "- Fase de elevación (movimiento concéntrico): Involucre su pecho y levante su brazo formando un arco suave. Apriete su pectoral en la parte superior del movimiento.", "- Enganche su pecho y levante el brazo formando un arco suave.", "- Aprieta tu pectoral en la parte superior del movimiento.", "- Repita hasta el número deseado de repeticiones (8-15 repeticiones es un buen rango).", "- Cambie de lado y realice el mismo movimiento en el otro brazo.", "### Errores comunes a evitar", "- Usar demasiado peso: priorice el control y la conexión mente-músculo.", "- Bloquear el codo: mantenga una ligera flexión para evitar tensión en las articulaciones.", "- Dejar caer el brazo demasiado bajo: deténgase al nivel del pecho o ligeramente por debajo.", "- Acelerar el movimiento: actúe con un tempo lento y controlado.", "- Girar el torso: mantenga el núcleo comprometido para mantener la estabilidad.", "### Variables de entrenamiento y modificaciones", "- Hipertrofia (crecimiento muscular) → 3-4 series de 8-12 repeticiones", "- Resistencia y estabilidad → 3 series de 12-15 repeticiones", "- Excéntrico lento (fase negativa) → 3-4 segundos", "- Concéntrico rápido (fase de elevación) → 1-2 segundos", "- Realice primero el vuelo con cable en un banco plano o en una máquina.", "- Utilice un peso más ligero con mayores repeticiones para controlar.", "- Realice primero con ambos brazos antes de pasar a unilateral.", "- Aumente el ángulo de descenso a 30-45° para una mayor activación de los pectorales inferiores.", "- Utilice un ritmo excéntrico lento (4-5 segundos) para un mayor daño muscular.", "- Súper serie con press declinado con mancuernas para aumentar la intensidad."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001849051473', 'Extensión de tríceps sobre la cabeza unilateral y cable', 'Cable One-Arm Overhead Triceps Extension', 'Tríceps', '["### Paso 1: Configuración y posición inicial", "- Conecte una sola manija a la polea baja de una máquina de cable.", "- Párese con los pies separados a la altura de los hombros y agarre el asa con una mano.", "- Aléjese de la máquina y levante la manija por encima de su cabeza, manteniendo el codo doblado y cerca de la cabeza.", "- Involucre su núcleo y mantenga una columna neutral durante todo el ejercicio.", "### Paso 2: Ejecución", "- Extienda el brazo enderezando el codo hasta que el brazo esté completamente extendido por encima de la cabeza.", "- Aprieta tus tríceps en la parte superior del movimiento.", "- Baje lentamente la manija hasta la posición inicial, manteniendo el control en todo momento.", "- Repita de 3 a 4 series de 10 a 15 repeticiones antes de cambiar de brazo.", "### Consejos para una forma adecuada", "- Mantenga el codo fijo en su lugar para evitar utilizar el impulso.", "- Mantenga un movimiento controlado en lugar de sacudir el peso.", "- No arquees la zona lumbar; Involucre su núcleo para lograr estabilidad.", "- Utilice un peso de ligero a moderado para centrarse en la forma adecuada y la contracción muscular.", "- Mantenga su muñeca neutral para evitar tensiones.", "### Errores comunes a evitar", "- Ensanchar el codo en lugar de mantenerlo cerca de la cabeza.", "- Usar demasiado peso, lo que lleva a una forma inadecuada y un rango de movimiento reducido.", "- Inclinarse hacia atrás, lo que aleja la tensión del tríceps.", "- Apresurarse en el movimiento sin el control adecuado."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-002088244100', 'Curl Scott con mancuernas', 'Dumbbell Scott Curl', 'Otros', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001398411749', 'Tirador frontal del cable cruzado', 'Cross Cable Face Pull', 'Hombros', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000587900655', 'Extensión de tríceps con barra de pie', 'Standing Barbell Triceps Extension', 'Tríceps', '["### Paso 1: Configuración y posición inicial", "- Párese a la altura de los hombros y mantenga los pies firmemente plantados para mantener el equilibrio.", "- Sostenga una barra con un agarre por encima de la cabeza (con las palmas hacia adelante), colocando las manos más cerca que el ancho de los hombros.", "- Levante la barra por encima de su cabeza, extendiendo completamente los brazos mientras mantiene los codos cerca de la cabeza.", "### Paso 2: Ejecución", "- Baje la barra lentamente detrás de su cabeza doblando los codos.", "- Mantenga la parte superior de los brazos inmóviles y evite extender los codos hacia afuera.", "- Baja la barra hasta que tus antebrazos queden paralelos al suelo o ligeramente más bajos.", "- Presione la barra hacia arriba extendiendo los codos hasta que los brazos estén completamente estirados.", "- Repita de 3 a 4 series de 8 a 12 repeticiones, manteniendo el control durante todo el movimiento.", "### Consejos para una forma adecuada", "- Mantenga su núcleo comprometido para evitar arquear la espalda baja.", "- Mantenga una posición neutral de la cabeza manteniendo la barbilla ligeramente metida.", "- Utilice un peso moderado para garantizar la forma adecuada y evitar lesiones.", "- Muévete lentamente y con control, especialmente en la fase de descenso.", "- Mantenga los codos cerca de la cabeza para maximizar la activación de los tríceps.", "### Errores comunes a evitar", "- Ensanchar los codos hacia afuera, lo que reduce el compromiso de los tríceps y aumenta la tensión en los hombros.", "- Usar peso excesivo, lo que lleva a una mala forma y a un mayor riesgo de lesiones.", "- Arquear la zona lumbar, lo que genera una tensión innecesaria en la columna.", "- Acelerar el movimiento, reduciendo la tensión muscular y la eficacia.", "- No bajar la barra del todo, limitando el rango de movimiento del ejercicio."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000166257024', 'Fila de escopeta', 'Shotgun Row', 'Espalda', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-002139731027', 'Flexión inversa de codo', 'Elbow Reverse Push-Up', 'Pecho', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000258806776', 'Press con agarre inverso a un brazo con mancuernas', 'Dumbbell One Arm Reverse Grip Press', 'Pecho', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000111054739', 'Press de banca declinado en máquina Smith', 'Smith Machine Decline Bench Press', 'Pecho', '["- Coloque el banco declinado Coloque un banco declinado debajo de la máquina Smith, alineando la barra con la parte inferior del pecho.", "- Coloque un banco declinado debajo de la máquina Smith, alineando la barra con la parte inferior del pecho.", "- Ajuste la barra Asegure la barra a una altura que le permita alcanzarla cómodamente con los brazos extendidos mientras está acostado en el banco.", "- Asegure la barra a una altura que le permita alcanzarla cómodamente con los brazos extendidos mientras está acostado en el banco.", "- Cargue la barra Agregue las placas de peso deseadas, asegurándose de que estén distribuidas uniformemente en ambos lados.", "- Agregue las placas de peso deseadas, asegurándose de que estén distribuidas uniformemente en ambos lados.", "- Asegure los topes de seguridad Coloque los topes de seguridad a un nivel que evite que la barra baje demasiado, protegiéndolo en caso de falla.", "- Establece los topes de seguridad a un nivel que impida que la barra baje demasiado, protegiéndote en caso de fallo.", "- Posición inicial Acuéstese en el banco de descenso y asegure los pies debajo de las almohadillas del banco. Sujete la barra ligeramente más ancha que el ancho de los hombros, con las palmas hacia adelante. Retire la barra extendiendo los brazos completamente y colocándola sobre la parte inferior del pecho.", "- Acuéstese en el banco de descenso y asegure sus pies debajo de las almohadillas del banco.", "- Agarre la barra un poco más separada que el ancho de los hombros, con las palmas hacia adelante.", "- Retire la barra extendiendo los brazos completamente y colocándola sobre la parte inferior del pecho.", "- Baje la barra Doble lentamente los codos para bajar la barra hacia la parte inferior del pecho. Mantenga las muñecas rectas y los codos ligeramente extendidos, formando un ángulo de 45 grados con el torso.", "- Doble lentamente los codos para bajar la barra hacia la parte inferior del pecho.", "- Mantenga las muñecas rectas y los codos ligeramente extendidos, formando un ángulo de 45 grados con el torso.", "- Presione la barra hacia arriba Empuje la barra hacia atrás a la posición inicial extendiendo completamente los brazos. Concéntrese en apretar los músculos del pecho en la parte superior del movimiento.", "- Empuja la barra de regreso a la posición inicial extendiendo completamente los brazos.", "- Concéntrate en apretar los músculos del pecho en la parte superior del movimiento.", "- Repetir Realice de 8 a 12 repeticiones durante 3 a 4 series, manteniendo el movimiento controlado en todo momento.", "- Realice de 8 a 12 repeticiones durante 3 a 4 series, manteniendo el movimiento controlado en todo momento.", "### Consejos para una forma adecuada", "- Involucre su núcleo: mantenga sus abdominales contraídos para mantener la estabilidad en el banco de descenso.", "- Movimiento controlado: evite dejar que la barra caiga demasiado rápido; controlar tanto la fase de descenso como la de elevación.", "- Agarre adecuado: asegúrese de que su agarre sea firme pero no demasiado apretado para reducir la tensión en la muñeca.", "- Ruta de la barra: baje la barra hasta la parte inferior del pecho y presiónela hacia arriba sin bloquear los codos.", "- Topes de seguridad: Configure siempre los topes de seguridad, especialmente al levantar pesos pesados.", "### Errores comunes", "- Ángulo de banco incorrecto: utilizar un ángulo de descenso demasiado pronunciado o demasiado superficial puede reducir la eficacia del ejercicio.", "- Codos ensanchados demasiado anchos: Los codos ensanchados demasiado aumentan el riesgo de tensión en los hombros.", "- Sobrecargar la barra: el uso de peso excesivo puede comprometer la forma y aumentar el riesgo de lesiones.", "- Saltarse las paradas de seguridad: No configurar las paradas de seguridad puede ser peligroso, especialmente cuando se levantan objetos pesados.", "- Alineación inadecuada de la barra: Colocar la barra demasiado alta en el pecho desvía la atención de la parte inferior del pecho."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000265414401', 'Arranque con pesa rusa a un brazo', 'One Arm Kettlebell Snatch', 'Hombros', '["Posición inicial: Párate con los pies separados a la altura de los hombros, las rodillas ligeramente flexionadas y la pesa rusa colocada en el suelo entre tus pies. Tus caderas deben estar ligeramente inclinadas hacia atrás y tu espalda debe estar recta.", "Agarre la pesa rusa: baje con una mano y agarre firmemente el mango de la pesa rusa. Tu palma debe estar mirando hacia tu cuerpo.", "Inicie el movimiento: con un movimiento fluido, conduzca a través de sus caderas y piernas para generar energía. Mientras haces esto, simultáneamente levanta la pesa rusa de manera explosiva, usando el impulso para levantarla hacia tu hombro.", "Rotación: cuando la pesa rusa alcance la altura de los hombros, gire la mano para que la palma quede hacia arriba.", "Bloqueo: una vez que la pesa rusa alcance la altura de los hombros, bloquee el brazo por encima de la cabeza extendiendo completamente el codo.", "Baje la pesa rusa: invierta el movimiento bajando la pesa rusa a la posición inicial con control. Mantenga su núcleo comprometido y su espalda recta durante todo el movimiento.", "Repetir: realice el número deseado de repeticiones en un brazo antes de cambiar al otro brazo."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000114346358', 'Fila de Landmine de un brazo', 'One Arm Landmine Row', 'Espalda', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
