INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000150911721', 'Jalón al pecho cruzado en polea', 'Cable Crossover Lat Pulldown', 'Espalda', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000452165839', 'Plancha frontal con elevación de brazos y piernas', 'Front Plank With Arm And Leg Lift', 'Abdomen', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000151280253', 'Gusano de pulgada', 'Inchworm', 'Abdomen', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001442678500', 'Salsas coreanas', 'Korean Dips', 'Pecho', '["- Busque una estación de barras paralelas o barras para fondos de un ancho cómodo (un poco más ancho que el ancho de los hombros).", "- Agarre las barras con un agarre neutral (las palmas hacia adentro).", "- Levanta las piernas detrás del cuerpo, manteniéndolas rectas (en lugar de dobladas hacia adelante como en los fondos tradicionales).", "- Mantenga su núcleo comprometido y su cuerpo ligeramente inclinado hacia adelante.", "- Fase de descenso (excéntrica) Baje lentamente el cuerpo hacia abajo, permitiendo que los hombros se desplacen ligeramente detrás de las barras. Mantenga los codos pegados al torso para evitar una tensión excesiva. Baje hasta que los hombros estén al mismo nivel o ligeramente por debajo de los codos. Sienta el estiramiento en el pecho y los hombros en la posición inferior.", "- Baje lentamente su cuerpo hacia abajo, permitiendo que sus hombros se desplacen ligeramente detrás de las barras.", "- Mantenga los codos pegados al torso para evitar una tensión excesiva.", "- Baje hasta que sus hombros estén al nivel de los codos o ligeramente por debajo.", "- Siente el estiramiento en tu pecho y hombros en la posición inferior.", "- Fase de prensado (concéntrica) Empújate hacia arriba de manera explosiva, activando tus pectorales, tríceps y hombros. Mantén un movimiento controlado, evitando el balanceo o el impulso. Extiende completamente los brazos en la parte superior mientras mantienes la tensión en los músculos.", "- Empújate hacia arriba de manera explosiva, activando tus pectorales, tríceps y hombros.", "- Mantenga un movimiento controlado, evitando balanceos o impulsos.", "- Extienda completamente los brazos en la parte superior mientras mantiene la tensión en los músculos."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000121361269', 'Hiperextensión inversa con banda de resistencia', 'Resistance Band Reverse Hyperextension', 'Piernas', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000439579461', 'Toque del dedo del pie con banda de resistencia', 'Resistance Band Toe Touch', 'Piernas', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000712716499', 'Giro acostado con lastre', 'Weighted Lying Twist', 'Abdomen', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001822574469', 'Press de hombros sentado con banda de resistencia', 'Resistance Band Seated Shoulder Press', 'Hombros', '["El press de hombros sentado con bandas de resistencia es una alternativa al press de hombros con mancuernas. Dado que las bandas no crean impulso, sus repeticiones con bandas no desgastarán la columna ni las articulaciones. Aunque este ejercicio se centra en los músculos delanteros de los hombros, es un movimiento útil que a menudo se utiliza para fortalecer la parte superior del cuerpo."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001774822472', 'Fondo en barra recta', 'Straight Bar Dip', 'Pecho', '["- Encuentre una barra resistente Utilice una barra de dominadas o cualquier barra horizontal a la altura del pecho.", "- Utilice una barra de dominadas o cualquier barra horizontal a la altura del pecho.", "- Agarre la barra Agarre la barra con un agarre por encima de la cabeza, un poco más ancho que el ancho de los hombros.", "- Agarre la barra con un agarre por encima de la cabeza, un poco más ancho que el ancho de los hombros.", "- Levántate Salta o empuja hacia arriba para que tus brazos estén completamente extendidos y tu cuerpo esté por encima de la barra.", "- Salta o empuja hacia arriba para que tus brazos estén completamente extendidos y tu cuerpo esté por encima de la barra.", "- Baje su cuerpo Inclínese ligeramente hacia adelante, doblando los codos para bajar el pecho hacia la barra. Mantenga los codos cerca de los costados para apuntar a los tríceps y el pecho.", "- Inclínese ligeramente hacia adelante, doblando los codos para bajar el pecho hacia la barra.", "- Mantenga los codos cerca de los costados para apuntar a los tríceps y el pecho.", "- Deténgase en BottomLower hasta que sus hombros estén debajo de sus codos o hasta donde su movilidad lo permita sin molestias.", "- Baja hasta que tus hombros queden por debajo de tus codos o hasta donde tu movilidad te lo permita sin molestias.", "- Push Back UpExtiende los brazos para volver a la posición inicial, manteniendo el core tenso para mantener el equilibrio.", "- Extiende los brazos para volver a la posición inicial, manteniendo el core tenso para mantener el equilibrio.", "- Repetir Realice de 8 a 12 repeticiones durante 2 a 3 series, según su nivel de fuerza.", "- Realice de 8 a 12 repeticiones durante 2 a 3 series, según su nivel de fuerza.", "### Consejos para una forma adecuada", "- Inclínese ligeramente hacia adelante: esto involucra el cofre de manera más efectiva.", "- Involucre su núcleo: apriete los músculos centrales para mantener la estabilidad y evitar el balanceo.", "- Rango completo de movimiento: bájese hasta que sus hombros estén debajo de sus codos para una activación máxima.", "- Movimientos controlados: evite utilizar el impulso; Concéntrese en repeticiones lentas y deliberadas.", "- Ancho de agarre: ajuste el ancho de su agarre para encontrar una posición cómoda que minimice la tensión en la muñeca.", "### Errores comunes", "- Codos ensanchados: Dejar que los codos se ensanchen puede tensar los hombros y reducir el compromiso de los tríceps.", "- Profundidad insuficiente: No bajar lo suficiente reduce la efectividad del ejercicio.", "- Balancear el cuerpo: utilice movimientos controlados para evitar perder el equilibrio o reducir la activación muscular.", "- Posición del cuello: Mantenga el cuello en posición neutra; no lo estire hacia adelante ni lo deje caer excesivamente.", "- Uso excesivo del impulso: evite rebotar en la parte inferior del movimiento."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
