INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000509896551', 'Pullover con mancuernas sobre pelota de estabilidad', 'Dumbbell Pullover On Stability Ball', 'Pecho', '["- Seleccione una mancuerna de peso moderado que permita un movimiento controlado.", "- Siéntese sobre una pelota de estabilidad y camine lentamente con los pies hacia adelante hasta que la parte superior de la espalda y los hombros estén apoyados, con las caderas levantadas en posición de puente.", "- Sostenga la mancuerna con ambas manos, colocándola directamente sobre su pecho con los brazos extendidos.", "- Mantenga una ligera flexión de los codos mientras baja lentamente la mancuerna detrás de la cabeza con un movimiento controlado.", "- Baje el peso hasta que sus brazos estén alineados con sus orejas o sienta un estiramiento cómodo en su pecho y dorsales.", "- Involucre los músculos del pecho y la espalda para llevar la mancuerna a la posición inicial.", "- Repita de 10 a 15 repeticiones, manteniendo el control y la respiración adecuados en todo momento.", "### Consejos para una forma adecuada", "- Mantenga las caderas levantadas en posición de puente para mantener la activación del núcleo.", "- Evite doblar excesivamente los codos para asegurarse de que el movimiento siga siendo un jersey y no una extensión de tríceps.", "- Realice un rango completo de movimiento, pero evite bajar demasiado la mancuerna para evitar tensiones innecesarias en los hombros.", "- Mantenga una columna neutral y active su núcleo para lograr estabilidad.", "- Controla el peso durante todo el movimiento para evitar que el impulso se apodere de ti.", "### Errores comunes a evitar", "- Usar demasiado peso: esto puede comprometer la forma y provocar lesiones.", "- Dejar caer las caderas: esto reduce el compromiso y la estabilidad del núcleo.", "- Acelerar el movimiento: Un ritmo lento y controlado asegura una adecuada activación muscular.", "- Extender demasiado los hombros: ir demasiado hacia atrás puede generar una tensión innecesaria en las articulaciones."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001889212653', 'Sentadilla contra la pared con pelota de ejercicio', 'Exercise Ball Wall Squat', 'Piernas', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000400658662', 'Flexión descenso con pelota de estabilidad', 'Stability Ball Decline Push-Up', 'Pecho', '["- Elija la pelota de estabilidad adecuada Utilice una pelota de estabilidad correctamente inflada que soporte su peso sin tambalearse excesivamente.", "- Utilice una pelota de estabilidad adecuadamente inflada que soporte su peso sin tambalearse excesivamente.", "- Ponte en posición: Coloca el balón detrás de ti y arrodíllate en el suelo. Coloque las manos separadas al ancho de los hombros en el suelo en una posición de flexión.", "- Coloca la pelota detrás de ti y arrodíllate en el suelo. Coloque las manos separadas al ancho de los hombros en el suelo en una posición de flexión.", "- Eleve sus pies Coloque sus pies o espinillas sobre la pelota de estabilidad. Ajuste su posición para que su cuerpo forme una línea recta desde la cabeza hasta los talones.", "- Coloque los pies o las espinillas sobre la pelota de estabilidad. Ajuste su posición para que su cuerpo forme una línea recta desde la cabeza hasta los talones.", "- Baje el pecho Doble los codos para bajar el pecho hacia el suelo, manteniendo el núcleo comprometido y el cuerpo alineado.", "- Doble los codos para bajar el pecho hacia el suelo, manteniendo el núcleo comprometido y el cuerpo alineado.", "- Haga una pausa en la parte inferior. Mantenga brevemente en el punto más bajo sin dejar que su pecho toque el suelo.", "- Mantén la posición brevemente en el punto más bajo sin que tu pecho toque el suelo.", "- Empuje hacia arribaPresione con las palmas de las manos para regresar a la posición inicial mientras mantiene el control sobre la pelota de estabilidad.", "- Presione con las palmas para volver a la posición inicial mientras mantiene el control sobre la pelota de estabilidad.", "- RepetirRealiza el número deseado de repeticiones con movimientos lentos y controlados.", "- Realiza el número deseado de repeticiones con movimientos lentos y controlados.", "### Consejos para una forma adecuada", "- Involucre su núcleo: mantenga sus abdominales contraídos para mantener la estabilidad y evitar la flacidez de las caderas.", "- Movimientos lentos: evite apresurarse; céntrese en repeticiones fluidas y deliberadas para maximizar la efectividad.", "- Ajuste la ubicación de la pelota: coloque la pelota más cerca de sus pies para mayor dificultad o cerca de sus rodillas para mayor estabilidad.", "- Columna Neutral: Mantenga la cabeza alineada con la columna durante todo el ejercicio.", "### Errores comunes", "- Caderas caídas: Involucre sus glúteos y su núcleo para mantener su cuerpo recto.", "- Acelerar el movimiento: Muévase lentamente para mantener el equilibrio y el control.", "- Colocación inadecuada de las manos: asegúrese de que sus manos estén directamente debajo de sus hombros para brindar apoyo.", "- Deslizamiento de la pelota: utilice una superficie antideslizante o realice el ejercicio cerca de una pared para mayor seguridad."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001444097764', 'Balón de estabilidad V-Up', 'Stability Ball V-Up', 'Abdomen', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001665293212', 'Flexiones con pelota de estabilidad', 'Stability Ball Push-Up', 'Pecho', '["- Coloque una pelota de estabilidad en el suelo frente a usted.", "- Colóquese en una posición de tabla alta, colocando ambas manos sobre la pelota separadas aproximadamente al ancho de los hombros.", "- Extiende las piernas detrás de ti, manteniendo el cuerpo en línea recta desde la cabeza hasta los talones. Involucre su núcleo para mantener la estabilidad.", "- Baje lentamente el pecho hacia la pelota doblando los codos, manteniéndolos en un ángulo de 45 grados con respecto al cuerpo.", "- Haga una pausa por un momento cuando su pecho esté justo encima de la pelota.", "- Vuelve a subir a la posición inicial, extendiendo completamente los brazos.", "- Realice de 8 a 15 repeticiones durante 3 a 4 series.", "### Consejos para una forma adecuada", "- Mantenga su núcleo comprometido para evitar que la zona lumbar se hunda.", "- Mantenga una columna neutra y evite arquearse excesivamente.", "- Controla el movimiento para maximizar la activación muscular y evitar que la pelota ruede.", "- Mantenga los codos ligeramente doblados en lugar de ensancharlos para proteger sus hombros.", "- Respire adecuadamente: inhale mientras desciende y exhale mientras vuelve a subir.", "### Errores comunes a evitar", "- Dejar que las caderas se doblen: esto reduce el compromiso del core y puede tensar la zona lumbar.", "- Usar una pelota demasiado pequeña o demasiado inflada puede dificultar demasiado el equilibrio y aumentar el riesgo de lesiones.", "- Acelerar el movimiento: esto reduce la efectividad y aumenta la inestabilidad.", "- Colocar las manos demasiado juntas limita el equilibrio y aumenta la tensión en las muñecas."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001689390851', 'Press de pecho con palanca y un brazo', 'Lever One-Arm Chest Press', 'Pecho', '["Ajuste la máquina Configure la altura del asiento de modo que el mango se alinee con la mitad del pecho.", "Ajuste la altura del asiento de modo que el mango se alinee con la mitad del pecho.", "Elige el PesoSelecciona un peso que te permita realizar el ejercicio con la forma adecuada.", "Selecciona un peso que te permita realizar el ejercicio con la forma adecuada.", "Posiciónese Siéntese erguido con la espalda apoyada en la almohadilla y los pies apoyados en el suelo.", "Siéntese erguido con la espalda apoyada en la almohadilla y los pies apoyados en el suelo.", "Agarre el mango Agarre la palanca con una mano mientras el otro brazo descansa sobre su muslo o costado.", "Agarre la palanca con una mano mientras el otro brazo descansa sobre su muslo o costado."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000354314538', 'Flexiones con balón medicinal unilateral', 'Single-Arm Medicine Ball Push-Up', 'Pecho', '["Elija un balón medicinal estable Utilice un balón medicinal que proporcione un agarre firme y que no ruede excesivamente.", "Utilice un balón medicinal que proporcione un agarre firme y que no ruede excesivamente.", "Ponte en posición Coloque el balón medicinal en el suelo y adopte una posición de tabla alta con una mano sobre el balón y la otra en el suelo.", "Coloque el balón medicinal en el suelo y adopte una posición de tabla alta con una mano sobre el balón y la otra en el suelo.", "Alineación del cuerpo Mantenga el cuerpo recto desde la cabeza hasta los talones, involucrando el núcleo y los glúteos para lograr estabilidad.", "Mantenga el cuerpo recto desde la cabeza hasta los talones, involucrando el núcleo y los glúteos para lograr estabilidad."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
