INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001439983958', 'Extensión de tríceps con pelota de ejercicio', 'Exercise Ball Triceps Extension', 'Tríceps', '["### Paso 1: configuración y posicionamiento", "- Seleccione un par de mancuernas con un peso manejable.", "- Siéntese sobre una pelota de ejercicios y camine con los pies hacia adelante hasta que la parte superior de la espalda y los hombros estén apoyados en la pelota.", "- Involucre su núcleo y glúteos para mantener la estabilidad.", "- Sostenga una mancuerna en cada mano y extienda los brazos hacia arriba del pecho.", "### Paso 2: Ejecución", "- Baje las mancuernas doblando los codos, manteniéndolos cerca de la cabeza.", "- Baje las pesas detrás de su cabeza con un movimiento controlado.", "- Involucra tus tríceps y extiende tus brazos hacia la posición inicial.", "- Repita para las repeticiones deseadas, manteniendo el núcleo contraído para mantener el equilibrio."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000068255285', 'Press de martillo declinado unilateral con mancuernas', 'Dumbbell Decline One-Arm Hammer Press', 'Pecho', '["- Ajuste un banco inclinado a aproximadamente 15 a 30 grados.", "- Asegure sus pies debajo de las almohadillas del banco para mantener la estabilidad.", "- Sostenga una mancuerna en una mano con un agarre neutral (las palmas hacia adentro).", "- Coloque la mancuerna al nivel de los hombros con el codo doblado a 90 grados.", "- Mantenga su núcleo apretado y la espalda baja apoyada contra el banco.", "- Presione la mancuerna hacia arriba en línea recta hasta que su brazo esté completamente extendido.", "- Evite la rotación excesiva y mantenga la mano que no trabaja apoyada en el torso o en el banco como apoyo.", "- Baje lentamente la mancuerna hasta la posición inicial, asegurando un control total.", "- Mantenga un ritmo constante para mantener la tensión en la parte inferior del pecho y los tríceps.", "- Complete las repeticiones deseadas en un brazo antes de cambiar al otro.", "- Realice repeticiones iguales en ambos lados para mantener el equilibrio muscular.", "### Consejos para una forma adecuada", "- Mantenga el núcleo comprometido: ayuda a prevenir la rotación y estabiliza el movimiento.", "- Mantenga un ritmo controlado: evite apresurarse en las repeticiones para maximizar la activación muscular.", "- Utilice un rango completo de movimiento: extienda y baje completamente la mancuerna para lograr un compromiso óptimo del pecho.", "- Evite arquear la espalda: mantenga la columna neutra para evitar tensiones innecesarias.", "- Comience con un peso moderado: concéntrese en la técnica antes de aumentar la resistencia.", "### Errores comunes a evitar", "- Usar peso excesivo: puede comprometer la forma y provocar lesiones.", "- Permitir que la mancuerna se desplace hacia afuera: reduce el compromiso del pecho y aumenta la tensión en los hombros.", "- No involucrar el núcleo: puede causar inestabilidad y reducir la efectividad del ejercicio.", "- Presionar demasiado rápido: limita la participación de los músculos y aumenta el riesgo de lesiones.", "- Saltarse los calentamientos: no preparar los hombros y los tríceps puede provocar molestias."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000619300913', 'Flexión de banco con pica', 'Bench Pike Push-up', 'Pecho', '["- Coloque un banco, una caja o una plataforma resistente frente a usted.", "- Coloque los pies en el banco con las manos en el suelo, ligeramente más separadas que el ancho de los hombros.", "- Doble el cuerpo según la altura de la mesa de café y mantenga las caderas erguidas.", "- Mire ligeramente hacia adelante para mantener una posición neutral del cuello.", "- Doble los codos y baje la cabeza hacia el suelo con un movimiento controlado.", "- Mantenga su núcleo comprometido y evite arquear la espalda baja.", "- Apunte a un ángulo de 90 grados en los codos a medida que su cabeza se acerque al suelo.", "- Empuja con las palmas de las manos para estirar los brazos y volver a la posición inicial.", "- Mantenga los hombros comprometidos y controle el movimiento en todo momento.", "- Repita hasta el número deseado de repeticiones.", "- Principiantes: tres series de cinco a ocho repeticiones.", "- Intermedio: tres o cuatro series de ocho a doce repeticiones.", "- Avanzado: cuatro series de quince repeticiones o más", "### Consejos para una forma adecuada", "- Mantenga las caderas elevadas: mantenga las caderas elevadas y la parte superior del cuerpo en línea recta para apuntar eficazmente a los hombros durante el ejercicio.", "- Muévase lentamente y con control: no apresure el movimiento para evitar lesiones.", "- Involucre su núcleo: mantenga los abdominales contraídos para estabilizar el cuerpo.", "- Coloque sus manos correctamente: las manos deben estar ligeramente más anchas que el ancho de los hombros.", "- Respire adecuadamente: inhale mientras baja, exhale mientras presiona hacia arriba.", "### Errores comunes a evitar", "- Dejar caer las caderas: reduce la activación del hombro y lo convierte en una flexión regular.", "- No bajar lo suficientemente profundo: limita la efectividad; Apunte a una flexión del codo de 90 grados.", "- Acelerar el movimiento: puede provocar una mala forma y una disminución del compromiso muscular.", "- Colocar las manos demasiado abiertas: puede reducir el compromiso de los hombros y causar tensión.", "- Arquear la parte baja de la espalda: indica un compromiso deficiente del núcleo y puede provocar lesiones."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001027615389', 'Toques de pie de pie', 'Standing Toe Touches', 'Espalda', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
