INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-002039688661', 'Salto Split con mancuernas', 'Dumbbell Split Jump', 'Piernas', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001531086617', 'Sentadilla frontal en banco con barra', 'Barbell Bench Front Squat', 'Piernas', '["Coloque un banco detrás de usted y cargue una barra en una posición frontal sobre sus hombros.", "Párese erguido con los pies separados a la altura de los hombros y los dedos de los pies ligeramente hacia afuera.", "Apoye su núcleo, mantenga el pecho erguido y retraiga los omóplatos.", "Comienza el descenso empujando la cadera hacia atrás y flexionando las rodillas, bajando hasta que los glúteos toquen ligeramente el banco.", "Haga una breve pausa en el contacto sin sentarse del todo, manteniendo la tensión en las piernas.", "Conduce con los talones para volver a la posición de pie mientras mantienes el torso erguido."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
