INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000325616603', 'Flexiones con lastre', 'Weighted Push-up', 'Pecho', '["### Guía paso a paso", "- Configuración: Comience en una posición de flexión tradicional con las manos ligeramente más separadas que el ancho de los hombros y los pies juntos o separados al ancho de las caderas.", "- Agregue peso: Pídale a un compañero que coloque una placa de peso en la parte superior de su espalda o use un chaleco con peso para una distribución uniforme. Asegúrese de que el peso sea estable y no se mueva durante el movimiento.", "- Engage Core: apriete el core, apriete los glúteos y mantenga el cuerpo recto desde la cabeza hasta los talones.", "- Fase de descenso: baje lentamente el pecho hacia el suelo doblando los codos hasta que alcancen un ángulo de 90 grados.", "- Press Up: Empuje con las palmas de las manos para extender los brazos y volver a la posición inicial.", "- Repetir: realice el número deseado de repeticiones manteniendo la forma adecuada.", "### Consejos para una forma adecuada", "- Mantenga la columna neutra y evite arquear o hundir la zona lumbar.", "- Involucre su núcleo y glúteos para una mejor estabilidad.", "- Controla el movimiento en lugar de apresurarte en las repeticiones.", "- Asegúrese de que el peso esté colocado de forma segura sobre su espalda para evitar el desequilibrio.", "- Utilice un observador o un chaleco con peso si entrena solo.", "### Errores comunes a evitar", "- Mala distribución del peso: colocar el peso demasiado alto o demasiado bajo en la espalda puede provocar un desequilibrio.", "- Caderas caídas: un compromiso central débil puede provocar una mala postura y un mayor riesgo de lesiones.", "- Apresurarse en las repeticiones: moverse demasiado rápido reduce la activación y eficacia de los músculos.", "- Rango de movimiento limitado: no bajar correctamente puede dificultar la participación de los músculos.", "- Usar demasiado peso: comience con una resistencia ligera y progrese gradualmente para evitar lesiones."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000972641046', 'Giro del brazo cruzado con asiento en polea', 'Cable Seated Cross Arm Twist', 'Abdomen', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
