INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001832418941', 'Puente de glúteos con barra en banco', 'Barbell Glute Bridge On Bench', 'Piernas', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000503875222', 'Estiramiento inverso de muñeca', 'Reverse Wrist Stretch', 'Antebrazos', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000794231595', 'Burpees con mancuernas', 'Dumbbell Burpees', 'Cardio', '["Posición inicial: Sostenga una mancuerna en cada mano, de pie con los pies separados al ancho de los hombros.", "Sostenga una mancuerna en cada mano, de pie con los pies separados a la altura de los hombros.", "Póngase en cuclillas y coloque mancuernas: bájese hasta ponerse en cuclillas mientras sostiene las mancuernas a los costados.", "Baje a una posición en cuclillas mientras sostiene las mancuernas a los costados.", "Posición de plancha: Coloque las mancuernas en el suelo frente a usted y salte o retroceda los pies hasta la posición de plancha, manteniendo el cuerpo en línea recta.", "Coloque las mancuernas en el suelo frente a usted y salte o retroceda los pies hasta la posición de tabla, manteniendo el cuerpo en línea recta.", "Flexiones (opcional): Realice una flexión manteniendo la espalda recta. Este paso es opcional pero puede incluirse para un desafío adicional.", "Realice una flexión manteniendo la espalda recta. Este paso es opcional pero puede incluirse para un desafío adicional.", "Saltar o dar un paso adelante: salte o dé un paso con los pies hacia las manos y regrese a la posición en cuclillas.", "Salta o retrocede con los pies hacia las manos y vuelve a la posición en cuclillas.", "Ponte de pie y presiona: levántate explosivamente desde la posición en cuclillas y presiona las mancuernas sobre tu cabeza.", "Levántese explosivamente desde la posición en cuclillas y presione las mancuernas sobre su cabeza.", "Repetir: Regrese a la posición inicial y repita la secuencia durante el número deseado de repeticiones.", "Regrese a la posición inicial y repita la secuencia durante el número deseado de repeticiones."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-002003372906', 'Curl de bíceps con palanca', 'Lever Biceps Curl', 'Bíceps', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000585376335', 'Sentadilla con salto con mancuernas', 'Dumbbell Jump Squat', 'Piernas', '["Párese erguido con los pies separados a la altura de los hombros, sosteniendo una mancuerna en cada mano a los costados.", "Apoye su núcleo y bájese hasta ponerse en cuclillas, manteniendo el pecho hacia arriba y la espalda en posición neutral.", "Explota hacia arriba, saltando del suelo lo más alto que puedas mientras sostienes las mancuernas.", "Aterriza suavemente sobre las puntas de tus pies, e inmediatamente vuelve a ponerte en cuclillas para la siguiente repetición.", "Repita las repeticiones, manteniendo el control tanto durante el despegue como durante el aterrizaje."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000731650985', 'Press de hombros con palanca inversa', 'Lever Reverse Shoulder Press', 'Hombros', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-002048187447', 'Elevación lateral trasera acostada con mancuernas', 'Dumbbell Lying Rear Lateral Raise', 'Espalda', '["La elevación lateral trasera acostada con mancuernas es un ejercicio que se utiliza para fortalecer los músculos posteriores y laterales del hombro y los grupos de músculos más pequeños adjuntos a ellos. Levantar demasiado peso en este movimiento puede no ser saludable, hacer el ejercicio con pesas livianas y con muchas repeticiones puede ser más beneficioso para los músculos deltoides y del manguito rotador."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000158895962', 'Máquina de giro de pie', 'Standing Twist Machine', 'Abdomen', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
