INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000575307200', 'Dominadas en L', 'L-Sit Pull-Up', 'Espalda', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001568844411', 'Toques del dedo del pie sentado', 'Seated Toe Touches', 'Espalda', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001884038402', 'Dominada supina', 'Chin-Up', 'Espalda', '["Cuando se trata de ejercicios compuestos, uno de los mejores ejercicios que me viene a la mente es probablemente el movimiento de dominadas. La principal diferencia entre dominadas y dominadas es cómo se agarra la barra. En este ejercicio, las palmas miran hacia el cuerpo. Las dominadas pueden ser un movimiento más fácil para los principiantes que las dominadas.", "La dominada es un ejercicio de cadena cerrada que trabaja casi todos los grupos de músculos de la parte superior del cuerpo y proporciona tanto hipertrofia como fuerza con el peso corporal. El ejercicio de dominadas se centra en los músculos de la espalda y los bíceps. Es uno de los ejercicios más eficaces para desarrollar y fortalecer los músculos de la espalda y las alas.", "Desempeña un papel importante en el aumento de la potencia y la fuerza del cuerpo: dado que las dominadas son un ejercicio compuesto, trabaja los músculos de la parte superior del cuerpo en perfecta armonía. El ejercicio de dominadas realizado con el peso corporal favorece la fuerza general del cuerpo y la fuerza central. Proporciona un cuerpo más fuerte y sólido.", "Proporciona beneficios cardiovasculares: las dominadas aumentan el ritmo cardíaco. Cuando este tipo de ejercicio se realiza rápidamente y sin períodos de descanso entre ellos, proporciona un excelente entrenamiento cardiovascular además de la capacidad de desarrollar fuerza.", "Aumenta la fuerza de agarre: Cuando sostienes un objeto en tu vida diaria, te permite agarrarlo con más firmeza. Por ejemplo; Puedes sentir esto incluso al abrir un frasco.", "Las dominadas fortalecen tus brazos: si no puedes hacer el ejercicio de dominadas, esto probablemente sea una indicación de que tus brazos están débiles. Brazos y muñecas trabajan activamente en todo tipo de dominadas. La fuerza de los brazos aumenta más cada vez que levantas el peso corporal. Aumentar el número de dominadas significa el desarrollo y fortalecimiento de tus brazos.", "Desarrolla los músculos de las alas: Es eficaz para trabajar y moldear las partes del cuerpo, que se encuentran en las partes superiores derecha e izquierda y que se denominan músculos de las alas. Si quieres un cuerpo cónico en V, puedes hacerlo con un movimiento de dominadas."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000809893397', 'Giro 360', 'Swing 360', 'Espalda', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
