INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000161638608', 'Paseo del pato', 'Duck Walk', 'Cardio', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001427053533', 'Sentadilla Zercher', 'Zercher Squat', 'Piernas', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001687854893', 'Press de hombros con pesa rusa', 'Kettlebell Shoulder Press', 'Hombros', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001904029762', 'Burpees', 'Burpees', 'Cardio', '["Aptitud cardiovascular: los burpees elevan el ritmo cardíaco rápidamente, proporcionando un entrenamiento cardiovascular eficaz. Esto ayuda a mejorar su salud cardiovascular, resistencia y resistencia.", "Entrenamiento de cuerpo completo: los burpees involucran múltiples grupos de músculos, incluidos el pecho, los brazos, los hombros, el core, los glúteos y las piernas. Esta activación integral lo convierte en un ejercicio que ahorra tiempo para trabajar varios grupos de músculos simultáneamente.", "Quema de calorías: debido a su naturaleza de alta intensidad, los burpees pueden ayudar a quemar una cantidad significativa de calorías en un corto período de tiempo. Esto los hace beneficiosos para quienes buscan perder peso o mantener un peso saludable.", "Desarrollo de fuerza: los burpees requieren que te muevas de una posición de tabla a una sentadilla y luego saltes, incorporando fuerza tanto en la parte superior como en la inferior del cuerpo. Esto ayuda a desarrollar fuerza y ​​resistencia muscular con el tiempo.", "Agilidad y coordinación mejoradas: Los movimientos dinámicos involucrados en los burpees mejoran la agilidad y la coordinación, a medida que pasas rápidamente por diferentes posiciones.", "No se requiere equipo: Los burpees se pueden realizar solo con el peso del cuerpo, lo que los convierte en un ejercicio conveniente y accesible que se puede realizar en cualquier lugar sin necesidad de equipo.", "Eficiente en el tiempo: Los burpees son un ejercicio que ahorra tiempo y se pueden incluir en rutinas de entrenamiento en intervalos de alta intensidad (HIIT), proporcionando un entrenamiento efectivo en un período corto.", "Impulso metabólico: la naturaleza intensa de los burpees puede elevar su metabolismo, lo que lleva a una mayor quema de calorías incluso después de haber terminado su entrenamiento. Esto se conoce como efecto afterburn o consumo excesivo de oxígeno post-ejercicio (EPOC).", "Versatilidad: los burpees se pueden modificar para adaptarse a diferentes niveles de condición física. Los principiantes pueden comenzar con variaciones básicas y progresar gradualmente a versiones más desafiantes a medida que mejoren su fuerza y ​​resistencia.", "Fitness funcional: Los movimientos de los burpees imitan las actividades cotidianas, lo que los hace valiosos para desarrollar el fitness funcional. Esto puede mejorar su capacidad para realizar las tareas diarias con facilidad."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000209893657', 'Despliegue con barra', 'Barbell Rollout', 'Abdomen', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001971849541', 'Giro de las Landmine', 'Landmine Twist', 'Abdomen', '["El giro de minas terrestres es un ejercicio de fortalecimiento del núcleo que trabaja los oblicuos y los abdominales que llegan hasta la zona lumbar. Los oblicuos son los músculos que conectan los dorsales y estos músculos ayudan a flexionar o rotar la parte superior del cuerpo. Dirigido a los músculos oblicuos, este ejercicio ayuda a aumentar la fuerza y ​​la estabilización de los músculos centrales."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001441015383', 'Crunch de rana', 'Frog Crunch', 'Cardio', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001399399867', 'Flexiones unilateral', 'Single-Arm Push-up', 'Pecho', '["- Elija una superficie estable Realice el ejercicio sobre una superficie plana y no resbaladiza para garantizar el equilibrio.", "- Realice sobre una superficie plana y no resbaladiza para garantizar el equilibrio.", "- Posiciónese Asuma una posición de flexión con los pies ligeramente más separados que el ancho de los hombros para mayor estabilidad.", "- Asuma una posición de flexión con los pies ligeramente más separados que el ancho de los hombros para mayor estabilidad.", "- Coloque una mano detrás de la espalda Coloque la mano de apoyo debajo del pecho, ligeramente desplazada hacia la línea media de su cuerpo.", "- Coloque su mano de apoyo debajo de su pecho, ligeramente desplazada hacia la línea media de su cuerpo.", "- Baje su cuerpo Doble el codo para bajar el pecho hacia el piso, manteniendo el cuerpo alineado. Involucre su núcleo para evitar la rotación del torso o la flacidez de las caderas.", "- Doble el codo para bajar el pecho hacia el suelo, manteniendo el cuerpo alineado.", "- Involucre su núcleo para evitar la rotación del torso o la flacidez de las caderas.", "- Haga una pausa en la parte inferior. Mantenga brevemente en el punto más bajo para maximizar la activación muscular.", "- Mantenga brevemente en el punto más bajo para maximizar la activación muscular.", "- Empuje hacia arribaPresione a través de su palma para regresar a la posición inicial.", "- Presione con la palma de la mano para volver a la posición inicial.", "- Repetir Realice el número deseado de repeticiones en un lado, luego cambie al otro brazo.", "- Realice la cantidad deseada de repeticiones en un lado, luego cambie al otro brazo.", "### Consejos para una forma adecuada", "- Mantenga una línea recta del cuerpo: mantenga su cuerpo alineado desde la cabeza hasta los talones durante todo el movimiento.", "- Involucre su núcleo: apriete sus abdominales para evitar que sus caderas se doblen o se tuerzan.", "- Movimientos controlados: Evite apresurarse; Concéntrese en movimientos suaves y deliberados.", "- Postura amplia para mayor estabilidad: Mantenga los pies lo suficientemente anchos para proporcionar equilibrio.", "- Comience con progresiones: domine variaciones más fáciles antes de intentar la flexión completa con un solo brazo.", "### Errores comunes", "- Rotar el torso: Evite que los hombros o las caderas se tuerzan; manténgase pegado al suelo.", "- Descuidar el compromiso central: un núcleo débil puede conducir a una forma inadecuada y una eficacia reducida.", "- Acelerar el movimiento: tómate tu tiempo para mantener el control y centrarte en las repeticiones de calidad.", "- Rango de movimiento desigual: asegúrese de que ambos brazos tengan la misma profundidad y esfuerzo para un desarrollo equilibrado.", "- Arqueando la parte baja de la espalda: mantenga los glúteos comprometidos para evitar la hiperextensión."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000065056087', 'Sentadilla hack inversa', 'Reverse Hack Squat', 'Piernas', '["Entre en la máquina de sentadillas de cara a las almohadillas y coloque los hombros debajo de los reposahombros.", "Coloque los pies ligeramente hacia adelante y separados a la altura de las caderas sobre la plataforma para los pies.", "Apoye su núcleo y agarre las manijas laterales.", "Desenganche la máquina levantándose ligeramente y soltando el seguro.", "Baje el cuerpo doblando las rodillas y las caderas hasta que los muslos queden al menos paralelos a la plataforma para los pies.", "Conduce sobre tus talones para volver a la posición superior. Repita para las repeticiones deseadas."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001945750541', 'Despliegue con rueda abdominal', 'Ab Wheel Rollout', 'Abdomen', '["El ejercicio de despliegue de la rueda abdominal es un ejercicio eficaz ya que trabaja todos los músculos de la parte superior del cuerpo, especialmente los flexores de la cadera y los músculos centrales. En comparación con los ejercicios abdominales tradicionales como abdominales o abdominales, los ejercicios con rodillo abdominal son más desafiantes y efectivos.", "El ejercicio de despliegue de Ab Wheel es un movimiento compuesto. Esto significa que activa varios grupos de músculos a la vez. El despliegue de la rueda abdominal puede brindarle un mejor entrenamiento abdominal que los ejercicios de flexión tradicionales, permitiéndole desarrollar abdominales más fuertes y definidos."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001313703639', 'Rodillas altas contra la pared', 'High Knees Against Wall', 'Cardio', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000014848108', 'Flexiones Plus', 'Push-Up Plus', 'Pecho', '["- Posición inicial: Comience en una posición de tabla alta, con las manos separadas al ancho de los hombros y directamente debajo de los hombros. Mantenga el cuerpo en línea recta desde la cabeza hasta los talones, involucrando el núcleo y los glúteos.", "- Comience en una posición de tabla alta, con las manos separadas al ancho de los hombros y directamente debajo de los hombros.", "- Mantenga su cuerpo en línea recta desde la cabeza hasta los talones, involucrando su núcleo y glúteos.", "- Fase de descenso: baje lentamente el pecho hacia el suelo doblando los codos. Mantenga un movimiento controlado, manteniendo los codos en un ángulo de 45 grados con respecto al torso.", "- Baje lentamente el pecho hacia el suelo doblando los codos.", "- Mantenga un movimiento controlado, manteniendo los codos en un ángulo de 45 grados con respecto al torso.", "- Empujar hacia arriba: Empújese hacia atrás hasta la posición inicial de tabla.", "- Empújate de nuevo hasta la posición inicial de tabla.", "- Protracción escapular: una vez en la parte superior, extienda los brazos un poco más redondeando la parte superior de la espalda y alejando los omóplatos entre sí. Mantenga la posición durante un segundo para sentir el compromiso del serrato anterior.", "- Una vez arriba, extiende los brazos un poco más redondeando la parte superior de la espalda y separando los omóplatos.", "- Mantenga presionado por un segundo para sentir el compromiso en su serrato anterior.", "- Reiniciar: Regrese a la posición neutral de la tabla y repita.", "- Regrese a la posición de tabla neutral y repita.", "### Consejos para una forma adecuada", "- Mantenga la alineación: evite dejar que las caderas se hundan o se levanten durante el movimiento.", "- Movimiento controlado: concéntrese en un ritmo lento y controlado para maximizar la activación muscular.", "- Involucre su núcleo: mantenga su núcleo apretado para evitar un arqueo excesivo en la zona lumbar.", "- Respiración: exhale mientras empuja hacia arriba y extiende la escápula; Inhala mientras bajas.", "### Errores comunes", "- Saltarse la prolongación: no agregar la protracción escapular anula el beneficio principal del ejercicio.", "- Caderas caídas: Esto compromete la integridad de la tabla y aumenta el riesgo de tensión en la espalda baja.", "- Ensanchamiento del codo: Permitir que los codos se ensanchen excesivamente puede estresar los hombros."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001300684785', 'Propulsor de pesas rusas', 'Kettlebell Thruster', 'Hombros', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001196660311', 'Sentadilla frontal con barra', 'Barbell Front Squat', 'Piernas', '["Coloque la barra en una rejilla para sentadillas a la altura del pecho y colóquese debajo de ella con la barra apoyada sobre los hombros y la clavícula.", "Cruza los brazos sobre la barra o utiliza un agarre limpio con los codos apuntando hacia adelante y el pecho a la altura.", "Da un paso atrás y párate con los pies separados a la altura de los hombros y los dedos ligeramente hacia afuera.", "Apoye su núcleo y comience el movimiento doblando las caderas y las rodillas simultáneamente.", "Baje hasta ponerse en cuclillas mientras mantiene los codos en alto y el torso erguido.", "Desciende hasta que tus muslos queden paralelos al suelo o ligeramente por debajo.", "Conduce con los talones para volver a la posición de pie mientras mantienes la tensión central y la postura."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001956299276', 'Arranque con mancuernas a un brazo', 'One Arm Dumbbell Snatch', 'Hombros', '["El arranque con mancuernas con un brazo es un ejercicio funcional diseñado para aumentar la fuerza en la parte superior e inferior del cuerpo. Este ejercicio ayuda a desarrollar tu coordinación y explosividad y fortalece tus hombros, espalda baja, isquiotibiales, glúteos y dorsales."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000195656121', 'Prensa a una pierna', 'Single Leg Press', 'Piernas', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001964406209', 'Zancada con Landmine', 'Landmine Lunge', 'Piernas', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001003477709', 'Flexiones de manos apoyadas en la pared', 'Wall-Supported Handstand Push-Ups', 'Pecho', '["- Realice estiramientos de muñeca, hombros y tríceps para aumentar la movilidad.", "- Activa el core con agarres en plancha y flexiones en pica.", "- Coloque las manos separadas a la altura de los hombros en el suelo, a una distancia de entre 6 y 12 pulgadas de la pared.", "- Ponte en posición de parada de manos, manteniendo el núcleo contraído y las piernas rectas.", "- Apoye los talones ligeramente contra la pared para apoyarse.", "- Doble los codos y baje la cabeza hacia el suelo con un movimiento controlado.", "- Mantenga los codos en un ángulo de 45 grados para proteger sus hombros.", "- Baja hasta que tu cabeza toque ligeramente el suelo o una colchoneta.", "- Involucra tus hombros, tríceps y core para regresar a la posición inicial.", "- Mantén los brazos rectos y los hombros activos en la parte superior.", "- Mantenga el control durante todo el movimiento para evitar el desequilibrio.", "### Consejos para una forma adecuada", "- Mantenga un núcleo apretado: ayuda a estabilizar su cuerpo y previene el arqueamiento.", "- Mantenga los codos en un ángulo de 45 grados: reduce la tensión en los hombros.", "- Utilice movimientos controlados: evite apresurarse para mantener la fuerza y ​​el control.", "- Involucre sus glúteos y piernas: ayuda con el equilibrio en la posición de parada de manos.", "- Respire adecuadamente: inhale mientras baja, exhale mientras empuja hacia arriba.", "### Errores comunes a evitar", "- Arquear la zona lumbar: provoca una mala alineación y aumenta el riesgo de lesiones.", "- Abrir demasiado los codos: ejerce una tensión innecesaria sobre los hombros.", "- Depender demasiado de la pared: puede crear inestabilidad y dificultar el progreso hacia las flexiones de brazos independientes.", "- No controlar el descenso: caer demasiado rápido puede tensar el cuello y los hombros.", "- Saltarse los calentamientos: no preparar los hombros y las muñecas puede provocar molestias y lesiones."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001765180121', 'Alpinista vertical', 'Vertical Mountain Climber', 'Cardio', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001865988758', 'Estiramiento de los isquiotibiales de pie', 'Standing Hamstring Stretch', 'Piernas', '["- Posición inicial: Párese erguido con los pies juntos o separados a la altura de las caderas y los brazos relajados a los lados.", "- Apoye y alinee: Involucre ligeramente su núcleo y mantenga una columna neutral mientras se prepara para girar hacia adelante.", "- Inclínese hacia adelante: lleve la pierna derecha un paso hacia adelante. Gire lentamente las caderas y baje el torso hacia las piernas. Deje que sus brazos cuelguen o alcancen los dedos de los pies.", "- Fase de estiramiento: Mantenga las rodillas rectas o ligeramente flexionadas (si es necesario). Relaja tu cuello y deja que tu cabeza cuelgue libremente.", "- Mantenga la posición: permanezca en el estiramiento durante 20 a 30 segundos, respirando profundamente y evitando rebotes.", "- Regresar al inicio: enrolle lentamente vértebra por vértebra hasta que esté de pie nuevamente. Repita con la otra pierna.", "### Consejos para una forma adecuada", "- Bisagra en las caderas, no en la parte baja de la espalda, para evitar tensiones y asegurar un estiramiento adecuado.", "- Mantenga las rodillas suaves si su flexibilidad es limitada para evitar tirar de los tendones.", "- Exhala mientras te inclinas hacia adelante para liberar la tensión muscular.", "- Evite redondear demasiado la parte superior de la espalda; apunte a una extensión larga de la columna.", "- Realice sobre una superficie plana para un mejor equilibrio y control.", "### Errores comunes", "- Bloquear las rodillas: puede generar una tensión excesiva en las articulaciones y reducir la efectividad del estiramiento.", "- Redondear la espalda agresivamente: reduce el estiramiento de los isquiotibiales y corre el riesgo de sufrir tensión en la columna.", "- Contener la respiración: restringe la relajación y puede elevar la tensión.", "- Rebotes o sacudidas: aumenta el riesgo de lesiones y no es apropiado para estiramientos estáticos.", "- Esforzarse demasiado: el estiramiento debe ser intenso pero nunca doloroso."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000732739915', 'Extensión de una sola pierna', 'Single Leg Extension', 'Piernas', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001084721221', 'Prensa de piernas en máquina Smith', 'Smith Machine Leg Press', 'Piernas', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000491578911', 'Elevación lateral frontal con banda', 'Band Front Lateral Raise', 'Espalda', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001909704975', 'Peso muerto con barra trampa', 'Trap Bar Deadlift', 'Piernas', '["Configuración: Coloque la barra de trampa en el suelo y cárguela con las placas de peso deseadas. Entre en la barra de trampa de modo que esté parado en el centro, con las manijas a cada lado de usted. Sus pies deben estar separados al ancho de las caderas y los dedos de los pies deben apuntar hacia adelante o ligeramente hacia afuera.", "Coloque la barra trampa en el suelo y cárguela con las placas de peso deseadas.", "Entra en la barra trampa para quedarte en el centro, con las manijas a cada lado.", "Tus pies deben estar separados a la altura de las caderas y los dedos de los pies deben apuntar hacia adelante o ligeramente hacia afuera.", "Agarre: Doble las caderas y las rodillas para bajar el cuerpo. Mantenga la espalda recta y el pecho erguido. Bájese y agarre las manijas de la barra trampa con ambas manos, asegurándose de que las palmas estén una frente a la otra. Sus manos deben colocarse aproximadamente al nivel de las caderas o ligeramente más abajo.", "Doble las caderas y las rodillas para bajar el cuerpo. Mantenga la espalda recta y el pecho erguido.", "Baje y agarre las manijas de la barra trampa con ambas manos, asegurándose de que las palmas estén enfrentadas.", "Tus manos deben estar colocadas aproximadamente al nivel de las caderas o ligeramente más abajo.", "Levantamiento: Apoye su núcleo para mantener una columna estable. Empuje con los talones y levántese, extendiendo las caderas y las rodillas simultáneamente. Mantenga la espalda plana y evite curvarla. Mientras levanta la barra trampa, manténgala cerca de su cuerpo. Sus brazos deben colgar hacia abajo desde sus hombros. Párese completamente erguido con las caderas y las rodillas bloqueadas, manteniendo una columna neutral.", "Apoye su núcleo para mantener una columna estable.", "Empuja los talones y levántate, extendiendo las caderas y las rodillas simultáneamente. Mantén la espalda plana y evita arquearla.", "Mientras levantas la barra trampa, mantenla cerca de tu cuerpo. Tus brazos deben colgar hacia abajo desde tus hombros.", "Párese completamente erguido con las caderas y las rodillas bloqueadas, manteniendo la columna neutra.", "Bajar: para bajar la barra trampa, invierta el movimiento. Primero empuje las caderas hacia atrás y luego doble las rodillas. Baje la barra suavemente hasta el suelo, asegurándose de que no choque ni rebote.", "Para bajar la barra trampa, invierta el movimiento. Primero empuja las caderas hacia atrás y luego dobla las rodillas.", "Baje la barra suavemente hasta el suelo, asegurándose de que no choque ni rebote.", "Repetir: Realice la cantidad deseada de repeticiones para su entrenamiento.", "Realice el número deseado de repeticiones para su entrenamiento."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-002059679397', 'Press de pecho de pie con banda', 'Band Standing Chest Press', 'Pecho', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000792919769', 'Sentadilla con camarones', 'Shrimp Squat', 'Piernas', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000652549527', 'Elevación de pantorrilla sentado con peso', 'Weighted Seated Calf Raise', 'Pantorrillas', '["- Configuración: siéntese erguido en un banco con una mancuerna apoyada sobre los muslos, justo por encima de las rodillas.", "- Posición del pie: Coloque las puntas de los pies sobre una plataforma elevada con los talones colgando del borde. Mantenga los pies separados a la altura de los hombros.", "- Posición inicial: Sujeta la mancuerna de forma segura con las manos. Mantenga su núcleo apretado y su torso erguido.", "- Levante los talones: presione las puntas de los pies para levantar los talones lo más alto posible, apretando las pantorrillas en la parte superior.", "- Pausa en la parte superior: mantenga la contracción máxima durante 1 a 2 segundos para una activación máxima.", "- Baje lentamente: baje los talones hasta que estén justo debajo de la plataforma para sentir un estiramiento profundo en las pantorrillas.", "- Repetir: realice el número deseado de repeticiones de forma controlada y deliberada.", "### Consejos para una forma adecuada", "- Mantenga las rodillas dobladas a 90 grados durante todo el ejercicio para aislar el sóleo.", "- No rebotes: utiliza movimientos lentos y controlados en todo el rango.", "- Asegúrese de que la mancuerna esté estable sobre sus muslos para evitar que ruede o se desequilibre.", "- Concéntrese en la contracción total y en un fuerte apretón en la parte superior de cada repetición.", "- Utilice una toalla o almohadilla debajo del peso si siente molestias en los muslos.", "### Errores comunes", "- Usar demasiado peso: Reduce el control y aumenta el riesgo de lesiones.", "- Acortar el rango de movimiento: Limita la activación muscular; asegúrese de levantar y estirar completamente.", "- Permitir que el peso se mueva o se tambalee: distrae del movimiento y afecta la forma.", "- Moverse demasiado rápido: el impulso reduce la eficacia y aumenta la tensión en las articulaciones.", "- No ocupar la primera posición: perderse la contracción que maximiza el crecimiento."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000051604686', 'Rotación externa del cable de 90 grados', '90-Degree Cable External Rotation', 'Hombros', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-002055809952', 'Rotación interna del cable de 90 grados', '90-degree Cable Internal Rotation', 'Hombros', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001046614310', 'Péndulo de hombro', 'Shoulder Pendulum', 'Hombros', '["Párate junto a una superficie estable, como una mesa o silla, y coloca tu mano sobre ella para apoyarte.", "Doble ligeramente las rodillas e inclínese hacia adelante, manteniendo la espalda recta.", "Deje que el brazo del lado que desea estirar cuelgue libremente.", "Mueva suavemente el brazo hacia adelante y hacia atrás como un péndulo, permitiéndole moverse de manera natural y relajada.", "Comience con pequeños cambios y aumente gradualmente el rango de movimiento a medida que se sienta más cómodo.", "Realice el movimiento de balanceo durante unos 10 a 15 segundos.", "Cambia de lado y repite el ejercicio con el otro brazo."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000666698277', 'Curl de piernas con toalla', 'Towel Leg Curl', 'Piernas', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000812381154', 'Press de pecho con pesa rusa en el suelo', 'Kettlebell Chest Press on the Floor', 'Pecho', '["### Guía paso a paso", "- Configuración: Acuéstese boca arriba con las rodillas dobladas y los pies firmemente plantados en el suelo. Sostenga una pesa rusa en cada mano con un agarre neutral (las palmas una frente a la otra).", "- Acuéstese boca arriba con las rodillas dobladas y los pies firmemente plantados en el suelo.", "- Sostenga una pesa rusa en cada mano con un agarre neutral (con las palmas una frente a la otra).", "- Posicionamiento: Mantenga los codos doblados en un ángulo de aproximadamente 45 grados con respecto al torso. Asegúrese de que la parte superior de sus brazos descanse sobre el piso y que sus muñecas estén alineadas con los codos.", "- Mantenga los codos doblados en un ángulo de aproximadamente 45 grados con respecto al torso.", "- Asegúrese de que la parte superior de sus brazos descanse sobre el piso y que sus muñecas estén alineadas con sus codos.", "- Fase de prensado: Presiona las pesas rusas hacia arriba hasta que tus brazos estén completamente extendidos. Mantén el movimiento controlado y evita bloquear los codos.", "- Presione las pesas rusas hacia arriba hasta que sus brazos estén completamente extendidos.", "- Mantenga el movimiento controlado y evite bloquear los codos.", "- Fase de descenso: baje lentamente las pesas rusas hasta que la parte superior de sus brazos toque el suelo. Mantenga la tensión en el pecho y los tríceps durante todo el movimiento.", "- Baje lentamente las pesas rusas hasta que la parte superior de sus brazos toque el suelo.", "- Mantenga la tensión en el pecho y los tríceps durante todo el movimiento.", "- Repetir: Realice el número deseado de repeticiones manteniendo la forma adecuada.", "- Realice el número deseado de repeticiones manteniendo la forma adecuada."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-002069429061', 'Press de pecho con pesa rusa unilateral', 'One-Arm Kettlebell Chest Press', 'Pecho', '["- Configuración: Acuéstese en un banco o en el piso con las rodillas dobladas y los pies firmemente plantados. Sostenga una pesa rusa en una mano, manteniendo la muñeca recta y la palma hacia adelante.", "- Acuéstese sobre un banco o en el suelo con las rodillas dobladas y los pies firmemente plantados.", "- Sostenga una pesa rusa en una mano, manteniendo la muñeca recta y la palma hacia adelante.", "- Posición inicial: Presione la pesa rusa directamente sobre su pecho, bloqueando su codo. Asegúrese de que la pesa rusa descanse contra la parte posterior de su antebrazo para mayor estabilidad.", "- Presione la pesa rusa directamente sobre su pecho, bloqueando su codo.", "- Asegúrese de que la pesa rusa descanse contra la parte posterior de su antebrazo para mayor estabilidad.", "- Fase de descenso: baje lentamente la pesa rusa hacia el pecho, manteniendo el codo en un ángulo de 45 grados con respecto al torso. Concéntrese en controlar el descenso para activar los músculos estabilizadores.", "- Baje lentamente la pesa rusa hacia su pecho, manteniendo el codo en un ángulo de 45 grados con respecto al torso.", "- Concéntrese en controlar el descenso para activar los músculos estabilizadores.", "- Fase de prensado: empuja la pesa rusa hacia la posición inicial en línea recta. Exhala mientras presionas hacia arriba y mantienes el control durante todo el movimiento.", "- Empuja la pesa rusa hacia la posición inicial en línea recta.", "- Exhala mientras presionas hacia arriba y mantienes el control durante todo el movimiento.", "- Cambiar de brazo: complete las repeticiones deseadas y luego cambie al otro brazo.", "- Complete las repeticiones deseadas y luego cambie al otro brazo.", "### Consejos para una forma adecuada", "- Mantenga su núcleo apretado: Involucre su núcleo para evitar que su torso se tuerza o arquee.", "- Agarre estable: asegúrese de que el mango de la pesa rusa permanezca estable y seguro en su mano.", "- Movimiento controlado: Evite apresurarse; controlar tanto la fase de descenso como la de elevación.", "- Respiración: Inhala mientras bajas la pesa rusa y exhala mientras la vuelves a subir.", "- Posición de los hombros: Mantenga los omóplatos retraídos y presionados contra el banco o el suelo.", "### Errores comunes", "- Arquear la espalda: Arquear la zona lumbar reduce el compromiso central y aumenta el riesgo de lesiones.", "- Acelerar el movimiento: realizar el ejercicio demasiado rápido puede comprometer la forma y reducir la efectividad.", "- Mal agarre: Un agarre débil puede provocar inestabilidad y reducir la seguridad del ejercicio.", "- Ensanchamiento del codo: Permitir que el codo se ensanche excesivamente puede estresar la articulación del hombro."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000058109983', 'Press de banca declinado con barra', 'Decline Barbell Bench Press', 'Pecho', '["### ", "### Guía paso a paso", "- Configuración: Ajuste un banco declinado en un ángulo de 15 a 30 grados. Acuéstese y asegure los pies debajo de las almohadillas para los pies para mantener la estabilidad.", "- Ajuste un banco inclinado a un ángulo de 15 a 30 grados.", "- Acuéstese y asegure sus pies debajo de las almohadillas para mantener la estabilidad.", "- Agarre y posicionamiento: Agarre la barra con un agarre por encima de la cabeza, con las manos ligeramente más separadas que el ancho de los hombros. Saque la barra y sosténgala con los brazos completamente extendidos sobre el pecho.", "- Agarre la barra con un agarre por encima de la cabeza, con las manos un poco más separadas que el ancho de los hombros.", "- Retire la barra y sosténgala con los brazos completamente extendidos sobre el pecho.", "- Fase de descenso: baje lentamente la barra hacia la parte inferior del pecho, manteniendo los codos en un ángulo de aproximadamente 45 grados. Baje hasta que la barra toque ligeramente el pecho sin rebotar.", "- Baje lentamente la barra hacia la parte inferior del pecho, manteniendo los codos en un ángulo de aproximadamente 45 grados.", "- Baja hasta que la barra toque ligeramente tu pecho sin rebotar.", "- Fase de prensado: empuja la barra hacia arriba con un movimiento controlado hasta que tus brazos estén completamente extendidos. Involucra tu pecho, hombros y tríceps para completar el levantamiento.", "- Empuja la barra hacia arriba con un movimiento controlado hasta que tus brazos estén completamente extendidos.", "- Involucre su pecho, hombros y tríceps para completar el levantamiento.", "- Repetir: Realiza de 3 a 5 series de 6 a 12 repeticiones, dependiendo de tus objetivos de entrenamiento.", "- Realiza de 3 a 5 series de 6 a 12 repeticiones, dependiendo de tus objetivos de entrenamiento.", "### Consejos para una forma adecuada", "- Mantenga las muñecas rectas y evite doblarlas excesivamente para evitar lesiones.", "- Mantenga el compromiso central para estabilizar su cuerpo durante todo el movimiento.", "- Evite hacer rebotar la barra contra su pecho, ya que esto reduce la efectividad y aumenta el riesgo de lesiones.", "- Utilice un observador si levanta pesos pesados ​​para garantizar la seguridad.", "- Exhala mientras presionas hacia arriba e inhala mientras bajas la barra.", "### Errores comunes a evitar", "- Arquear la espalda excesivamente: Mantenga la columna neutra para evitar tensión en la zona lumbar.", "- Ancho de agarre inadecuado: un agarre demasiado estrecho o demasiado ancho puede limitar la eficacia y provocar tensión en la muñeca o el hombro.", "- Acelerar el movimiento: baje y presione la barra con control para maximizar la participación de los músculos.", "- Levantar demasiado peso y demasiado pronto: comience con un peso moderado para perfeccionar su forma antes de aumentar la resistencia.", "- Falta de rango completo de movimiento: no bajar la barra hasta el pecho reduce la efectividad del ejercicio."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
