INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000684303069', 'Glúteos con rodillo de espuma', 'Foam Roller Glutes', 'Piernas', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000663302130', 'Press de banca con agarre ancho', 'Wide Grip Bench Press', 'Pecho', '["### Guía paso a paso", "- Configuración: Acuéstese en una estación de press de banca con los pies firmemente plantados en el suelo. Coloque los ojos directamente debajo de la barra antes de quitarla.", "- Acuéstese sobre una estación de press de banca con los pies firmemente plantados en el suelo.", "- Coloque sus ojos directamente debajo de la barra antes de quitarla.", "- Agarre y posicionamiento: Sujete la barra a una distancia mayor que el ancho de los hombros (aproximadamente 1,5 a 2 veces el ancho de los hombros). Mantenga las muñecas rectas y asegúrese de que la barra se asiente cómodamente en sus palmas.", "- Sujete la barra a una distancia mayor que la anchura de los hombros (aproximadamente 1,5 a 2 veces el ancho de los hombros).", "- Mantenga las muñecas rectas y asegúrese de que la barra quede cómodamente en sus palmas.", "- Retire la barra: enganche la parte superior de la espalda y el core, luego presione la barra para sacarla del soporte. Sostenga la barra con los brazos completamente extendidos sobre el pecho.", "- Involucra la parte superior de la espalda y el core, luego presiona la barra para sacarla de la rejilla.", "- Sostenga la barra con los brazos completamente extendidos sobre su pecho.", "- Fase de descenso: baje lentamente la barra hacia la parte media e inferior del pecho mientras mantiene los codos en un ángulo de aproximadamente 75 grados. Mantenga el control y evite que la barra rebote en el pecho.", "- Baje lentamente la barra hacia la parte media e inferior del pecho mientras mantiene los codos en un ángulo de aproximadamente 75 grados.", "- Mantenga el control y evite hacer rebotar la barra en su pecho.", "- Fase de press: empuja la barra hacia arriba hasta la posición inicial, extendiendo completamente los brazos. Concéntrate en contraer el pecho en la parte superior del movimiento.", "- Empuja la barra hacia arriba hasta la posición inicial, extendiendo completamente los brazos.", "- Concéntrate en contraer el pecho en la parte superior del movimiento.", "- Repetir: Realiza de 3 a 5 series de 6 a 12 repeticiones, dependiendo de tus objetivos de entrenamiento.", "- Realiza de 3 a 5 series de 6 a 12 repeticiones, dependiendo de tus objetivos de entrenamiento."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001278483905', 'Quads con rodillos de espuma', 'Foam Roller Quads', 'Piernas', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001873066189', 'Zancada en máquina Smith', 'Smith Machine Lunge', 'Piernas', '["Configuración: Ajuste la barra de la máquina Smith a una altura adecuada. Debe colocarse aproximadamente al nivel del pecho o de los hombros. Cargue una cantidad adecuada de peso en la barra.", "Ajuste la barra de la máquina Smith a una altura adecuada. Debe colocarse aproximadamente a la altura del pecho o de los hombros.", "Cargue una cantidad adecuada de peso en la barra.", "Posición inicial: Párese con los pies separados a la altura de las caderas, de espaldas a la máquina Smith. Colóquese de manera que la barra descanse sobre la parte superior de la espalda y los hombros.", "Párese con los pies separados a la altura de las caderas, de espaldas a la máquina Smith.", "Colóquese de manera que la barra descanse sobre la parte superior de la espalda y los hombros.", "Colocación del pie: Da un paso hacia adelante con un pie, asegurándote de que esté a una distancia cómoda de la máquina Smith. La distancia dependerá de la longitud de tu propia zancada. Mantén los pies en posición dividida, con un pie hacia adelante y el otro hacia atrás.", "Da un paso adelante con un pie, asegurándote de que esté a una distancia cómoda de la máquina Smith. La distancia dependerá de tu propia longitud de zancada.", "Mantenga los pies en una postura dividida, con un pie hacia adelante y el otro hacia atrás.", "Movimiento de estocada: Baje el cuerpo doblando ambas rodillas, asegurándose de que la rodilla delantera esté directamente encima del tobillo y la rodilla trasera apunte hacia el suelo. Trate de bajar la rodilla trasera hacia el suelo sin dejar que se toque. Mantenga el torso erguido y mantenga una línea recta desde la cabeza hasta las caderas.", "Baje el cuerpo doblando ambas rodillas, asegurándose de que la rodilla delantera esté directamente encima del tobillo y la rodilla trasera apunte hacia el suelo.", "Trate de bajar la rodilla trasera hacia el suelo sin dejar que se toque.", "Mantenga el torso erguido y mantenga una línea recta desde la cabeza hasta las caderas.", "Empujar hacia atrás: Empuje con el talón del pie delantero para volver a la posición inicial. Continúe alternando piernas durante el número deseado de repeticiones.", "Empuja con el talón de tu pie delantero para volver a la posición inicial.", "Continúe alternando piernas durante el número deseado de repeticiones."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000826431792', 'Rodillo de espuma en la parte superior de la espalda', 'Foam Roller Upper Back', 'Espalda', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001823982693', 'Flexiones unilateral con soporte', 'One Arm Push Ups With Support', 'Pecho', '["### Guía paso a paso", "- Configuración: Busque un banco resistente, una caja o una superficie elevada para apoyarse. Colóquese en una posición de flexión con los pies ligeramente más separados que el ancho de los hombros para mantener el equilibrio.", "- Busque un banco, una caja o una superficie elevada resistente como apoyo.", "- Colóquese en una posición de flexión con los pies ligeramente más separados que el ancho de los hombros para mantener el equilibrio.", "- Colocación de la mano: Coloque el brazo de trabajo firmemente en el suelo, alineado con el pecho. Coloque la mano de apoyo en el banco o en una superficie elevada.", "- Coloque su brazo de trabajo firmemente en el suelo, alineado con su pecho.", "- Coloque su mano de apoyo sobre el banco o superficie elevada.", "- Fase de descenso: Involucre el núcleo y los glúteos para mantener la alineación del cuerpo. Baje lentamente el cuerpo hacia el suelo mientras mantiene los codos en un ángulo de 45 grados.", "- Involucre su núcleo y glúteos para mantener la alineación del cuerpo.", "- Baje lentamente el cuerpo hacia el suelo mientras mantiene los codos en un ángulo de 45 grados.", "- Fase de prensado: Empuje a través del brazo que trabaja, manteniendo el core apretado para mantener la estabilidad. Extienda el brazo completamente y regrese a la posición inicial.", "- Empuje a través de su brazo de trabajo, manteniendo su núcleo apretado para mantener la estabilidad.", "- Extiende tu brazo completamente y regresa a la posición inicial.", "- Repeticiones y series: Realice de 3 a 4 series de 6 a 12 repeticiones por lado, dependiendo de su nivel de condición física.", "- Realiza de 3 a 4 series de 6 a 12 repeticiones por lado, dependiendo de tu nivel de condición física.", "### Consejos para una forma adecuada", "- Involucre su núcleo para evitar que sus caderas se caigan.", "- Mantenga su cuerpo en línea recta desde la cabeza hasta los talones.", "- Controla el movimiento para evitar utilizar el impulso.", "- Reduzca gradualmente el apoyo para avanzar hacia una flexión completa con un brazo.", "- Mantenga un patrón de respiración constante durante todo el ejercicio.", "### Errores comunes a evitar", "- Dejar caer las caderas: Mantenga una línea recta del cuerpo para evitar la tensión en la parte baja de la espalda.", "- Depender demasiado del brazo de soporte: el brazo de trabajo debería hacer la mayor parte del trabajo.", "- Encogerse de hombros: Mantenga los hombros bajos y comprometidos.", "- Apresurarse en las repeticiones: concéntrese en movimientos lentos y controlados para una máxima activación muscular.", "- No cambiar de lado: Entrena ambos brazos de manera uniforme para evitar desequilibrios musculares."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000321618924', 'Retracción escapular sentado', 'Seated Scapular Retraction Exercise', 'Hombros', '["Aumenta el rango de movimiento (ayuda a aumentar su capacidad de alcanzar)", "Ayuda a reducir el dolor en el hombro y el cuello.", "mejora tu postura", "Aumenta tu resistencia para mantener ciertas posiciones por más tiempo."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
