INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000248486016', 'Sudadera con capucha y brazo doblado con barra inclinada', 'Barbell Decline Bent Arm Pullover', 'Espalda', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000559361537', 'Masaje de pantorrillas con rodillo de espuma (Foam Roller)', 'Foam Roller Calves', 'Pantorrillas', '["Configuración: siéntese en el suelo con las piernas extendidas y coloque un rodillo de espuma horizontalmente debajo de las pantorrillas.", "Apoye la parte superior del cuerpo: coloque las manos en el suelo detrás de usted y levante ligeramente las caderas para que su peso se traslade al rodillo de espuma.", "Comience a rodar: ruede lentamente desde la parte inferior de la pantorrilla (justo encima del tobillo) hasta la parte superior (debajo de la rodilla) utilizando pequeños movimientos hacia adelante y hacia atrás.", "Aplique presión: para aumentar la presión, cruce una pierna sobre la otra para colocar más peso en la parte inferior de la pantorrilla.", "Apunte a los puntos gatillo: si encuentra un punto sensible o tenso, haga una pausa y manténgalo presionado durante 10 a 20 segundos hasta que se reduzca la tensión.", "Repita: continúe rodando durante 20 a 40 segundos por pierna, cambiando de lado según sea necesario."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001681236953', 'Peso muerto con piernas rígidas', 'Stiff Leg Deadlift', 'Piernas', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001310400144', 'Rotación de espalda de rodillas', 'Kneeling Back Rotation', 'Espalda', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001699477773', 'Rotación externa del pie con banda', 'Banded Foot External Rotation', 'Piernas', '["- Configuración: Siéntese en un banco o silla con las rodillas dobladas a 90 grados y los pies apoyados en el suelo.", "- Colocación de la banda: coloque una banda de resistencia alrededor de ambos pies, creando una tensión de ligera a moderada entre ellos.", "- Anclar el pie opuesto: Mantenga un pie inmóvil para anclar la banda, presionándola contra el piso para mayor estabilidad.", "- Gire el pie de trabajo: gire lentamente el pie de trabajo hacia afuera, moviéndolo contra la resistencia de la banda. Sólo deben moverse el pie y el tobillo; evite el movimiento de la rodilla o la cadera.", "- Pausa al final del rango: Mantenga la posición de rotación externa durante 1 a 2 segundos para la activación.", "- Regresar bajo control: Lleve lentamente el pie a la posición inicial sin dejar que la banda se rompa.", "- Repetir: realice la cantidad deseada de repeticiones y luego cambie al otro lado.", "### Consejos para una forma adecuada", "- Mantenga quietas la pierna y la rodilla; aísle el movimiento únicamente al tobillo y al pie.", "- Comience con una resistencia ligera, centrándose en el movimiento controlado y la participación de los músculos.", "- Mantenga una postura erguida para apoyar la alineación de la columna durante la posición sentada.", "- No apresure el movimiento: cuanto más lento, más eficaz será para la activación muscular.", "- Respire constantemente para ayudar a mantener la estabilidad central y la relajación.", "### Errores comunes", "- Mover la rodilla o el muslo en lugar de aislar el tobillo.", "- Usar una resistencia excesiva de la banda que compromete la forma y el control.", "- Realizar repeticiones rápidas o entrecortadas, reduce la efectividad y corre el riesgo de sufrir tensión.", "- Descuidar la fase de retorno: la parte excéntrica es clave para el fortalecimiento.", "- Permitir que los dedos dominen el movimiento en lugar de rotar todo el pie/tobillo."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000178543165', 'Deslizamientos en pared para serrato con rodillo', 'Serratus Wall Slide With Foam Roller', 'Hombros', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001204089119', 'Declinado el banco de agarre cercano al triturador de cráneos', 'Decline Close-Grip Bench To Skull Crusher', 'Otros', '["### Paso 1: configurar el equipo", "- Ajuste un banco inclinado a un ángulo moderado (alrededor de 15 a 30 grados).", "- Asegure sus pies debajo de las almohadillas de soporte para mayor estabilidad.", "- Elija un peso adecuado utilizando una barra o barra de curl EZ.", "### Paso 2: Posición inicial", "- Recuéstese en el banco de descenso mientras sostiene la barra con un agarre firme (al ancho de los hombros o un poco más estrecho).", "- Extiende tus brazos completamente, manteniendo la barra directamente sobre tus hombros.", "- Involucre su núcleo y mantenga los codos doblados para mantener el control.", "### Paso 3: realice el press de banca con agarre cerrado", "- Baje la barra lentamente hasta la parte inferior del pecho mientras mantiene los codos cerca del cuerpo.", "- Presione la barra hacia arriba hasta la posición inicial, concentrándose en el compromiso de los tríceps.", "### Paso 4: transición al triturador de calaveras", "- Una vez en la posición superior de la prensa, cambie a la trituradora de cráneo doblando los codos y bajando la barra hacia la frente.", "- Mantenga los codos inmóviles y evite ensancharlos.", "- Extiende tus brazos nuevamente a la posición inicial y repite el movimiento.", "### Paso 5: mantener el control y repetir", "- Realiza de 8 a 12 repeticiones por serie, asegurando movimientos controlados.", "- Concéntrate en la activación del tríceps durante todo el ejercicio."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
