INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000365586094', 'Colgado pasivo en barra (Dead Hang)', 'Dead Hang', 'Espalda', '["Agarre una barra de dominadas con las manos separadas a la altura de los hombros y las palmas hacia afuera o hacia usted.", "Cuelga libremente con los brazos completamente extendidos y los pies alejados del suelo.", "Involucre ligeramente los hombros (evite encogerlos por completo).", "Mantenga el núcleo tenso y las piernas rectas o ligeramente dobladas.", "Mantenga esta posición durante 20 a 60 segundos o el mayor tiempo posible con buena forma."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
