INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000889858136', 'Dominada isométrica', 'Isometric Pull-Up', 'Espalda', '["Agarre la barra de dominadas con las manos separadas a la altura de los hombros y las palmas hacia afuera (pronación).", "Tire hacia la posición deseada (arriba, media o casi abajo).", "Mantenga la posición activando la espalda, los brazos y los músculos centrales.", "Mantenga una postura quieta sin balancearse ni moverse durante 10 a 30 segundos.", "Baje con control o bájese con seguridad si está fatigado.", "Repita para varias series, según su objetivo de entrenamiento."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
