INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000208700464', 'Sentadilla frontal en polea', 'Cable Front Squat', 'Piernas', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001786116572', 'Press de pecho con palanca declinada', 'Lever Decline Chest Press', 'Pecho', '["### Guía paso a paso", "- Ajuste la máquina: ajuste la altura del asiento de modo que las manijas se alineen con la parte inferior del pecho cuando esté sentado. Ajuste el respaldo para brindar el soporte adecuado.", "- Ajuste la altura del asiento de modo que las manijas se alineen con la parte inferior del pecho cuando esté sentado.", "- Ajuste el respaldo para brindar el soporte adecuado.", "- Establezca su posición: siéntese con la espalda firmemente contra la almohadilla y los pies apoyados en el piso. Agarre las manijas con un agarre neutral o en pronación (según el diseño de la máquina). Mantenga los codos en un ángulo de 45 grados para reducir la tensión en los hombros.", "- Siéntese con la espalda firmemente apoyada en la almohadilla y los pies apoyados en el suelo.", "- Agarre las manijas con un agarre neutral o en pronación (según el diseño de la máquina).", "- Mantenga los codos en un ángulo de 45 grados para reducir la tensión en los hombros.", "- Presione el peso: exhale y empuje las manijas hacia adelante con un movimiento controlado hasta que sus brazos estén completamente extendidos. No bloquee los codos en la parte superior del movimiento.", "- Exhala y empuja las manijas hacia adelante con un movimiento controlado hasta que tus brazos estén completamente extendidos.", "- No bloquees los codos en la parte superior del movimiento.", "- Controle el descenso: inhale y baje lentamente el peso hasta la posición inicial. Asegúrese de que los músculos del pecho estén completamente comprometidos durante todo el movimiento.", "- Inhala y baja lentamente el peso hasta la posición inicial.", "- Asegúrese de que los músculos de su pecho estén completamente comprometidos durante todo el movimiento.", "- Repita para las repeticiones deseadas: Realice de 3 a 4 series de 8 a 12 repeticiones, dependiendo de sus objetivos de entrenamiento.", "- Realiza de 3 a 4 series de 8 a 12 repeticiones, dependiendo de tus objetivos de entrenamiento.", "### Consejos para una forma adecuada", "- Mantenga un ritmo controlado para maximizar la activación muscular y evitar el impulso.", "- Mantenga la espalda firmemente contra la almohadilla para evitar tensiones en la zona lumbar.", "- Ajuste la altura del asiento correctamente para apuntar eficazmente a la parte inferior del pecho.", "- Involucre su núcleo y mantenga los hombros hacia abajo para evitar una tensión excesiva en los deltoides frontales.", "- Utilice un rango completo de movimiento, pero evite bloquear los codos en la parte superior.", "### Errores comunes a evitar", "- Posición incorrecta del asiento: si el asiento está demasiado alto o bajo, puede desviar el énfasis de la parte inferior del pecho.", "- Uso de peso excesivo: Levantar demasiado peso puede comprometer la forma y aumentar el riesgo de lesiones.", "- Bloquear los codos: bloquear completamente los codos reduce la tensión en el pecho y aumenta la tensión en las articulaciones.", "- Descuidar la respiración adecuada: exhalar en la prensa e inhalar en el descenso ayuda a mantener la estabilidad central.", "- Confiar en el impulso: el uso de un movimiento controlado maximiza la participación de los músculos y reduce el riesgo de lesiones."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-002137683760', 'Curl de bíceps alternativo con barra', 'Barbell Alternate Biceps Curl', 'Bíceps', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001447871935', 'Vacío abdominal en cuadrupedia (4 puntos)', '4 Point Tummy Vacuum Exercise', 'Abdomen', '["Comience con las manos y las rodillas: Colóquese en el suelo sobre las manos y las rodillas, con las muñecas directamente debajo de los hombros y las rodillas debajo de las caderas.", "Colóquese en el suelo sobre manos y rodillas, con las muñecas directamente debajo de los hombros y las rodillas debajo de las caderas.", "Mantenga una columna neutra: mantenga la espalda recta y el cuello en una posición neutra. Evite arquear o redondear excesivamente la espalda.", "Mantenga la espalda recta y el cuello en posición neutra. Evite arquear o redondear excesivamente la espalda.", "Respire profundamente: Inhale profundamente por la nariz, expandiendo el diafragma.", "Inhala profundamente por la nariz, expandiendo tu diafragma.", "Exhale mientras tira del ombligo hacia la columna: mientras exhala, contraiga los músculos abdominales y tire del ombligo hacia la columna. Imagínese levantando sus órganos abdominales y empujando su ombligo hacia arriba y hacia adentro.", "Mientras exhala, contraiga los músculos abdominales y tire del ombligo hacia la columna. Imagínese levantando sus órganos abdominales y empujando su ombligo hacia arriba y hacia adentro.", "Mantener la contracción: Mantener la contracción durante unos segundos mientras se continúa respirando normalmente. Concéntrese en mantener la tensión en los músculos abdominales profundos.", "Mantenga la contracción durante unos segundos mientras continúa respirando normalmente. Concéntrese en mantener la tensión en los músculos abdominales profundos.", "Suelta y repite: Relaja la contracción e inhala. Repita el proceso durante varias repeticiones.", "Relaja la contracción e inhala. Repita el proceso durante varias repeticiones."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001663083175', 'Postura del pez', 'Fish Pose', 'Hombros', '["### Instrucciones paso a paso", "- Comience en posición reclinada: Acuéstese boca arriba con las piernas extendidas y los brazos apoyados al lado de su cuerpo.", "- Acuéstese boca arriba con las piernas extendidas y los brazos apoyados al lado de su cuerpo.", "- Coloque las manos debajo de las caderas: deslice las manos con las palmas hacia abajo debajo de las nalgas para obtener apoyo. Mantenga los codos juntos y enganchados.", "- Deslice las manos con las palmas hacia abajo debajo de las nalgas para obtener apoyo.", "- Mantenga los codos juntos y comprometidos.", "- Levante el pecho: presione a través de los antebrazos y los codos para levantar la parte superior del pecho hacia el techo. Deje que la cabeza caiga suavemente hacia atrás, con la corona tocando ligeramente el suelo.", "- Presione con los antebrazos y los codos para levantar la parte superior del pecho hacia el techo.", "- Deje que su cabeza caiga suavemente hacia atrás, con la corona tocando ligeramente el suelo.", "- Mantenga la postura: respire profundamente y mantenga la postura durante 15 a 30 segundos (o más para una práctica restaurativa).", "- Respire profundamente y mantenga la respiración durante 15 a 30 segundos (o más para prácticas restaurativas).", "- Libere la postura: exhale, baje lentamente el pecho y lleve la cabeza hacia la colchoneta. Retire las manos de debajo de las caderas y relájese en Savasana.", "- Exhala, baja lentamente el pecho y lleva la cabeza hacia la colchoneta.", "- Retire las manos de debajo de las caderas y relájese en Savasana.", "### Consejos para una forma adecuada", "- Involucre su núcleo para evitar una tensión excesiva en la parte baja de la espalda.", "- Mantenga las piernas activas apuntando los dedos de los pies o presionándolos suavemente contra la colchoneta.", "- No fuerce la cabeza hacia atrás; déjela caer naturalmente, manteniendo la comodidad en el cuello.", "- Respire profundamente para mejorar el estiramiento y mejorar la expansión pulmonar.", "- Modifique con accesorios si tiene molestias en el cuello o la espalda.", "### Errores comunes a evitar", "- Arqueando la parte baja de la espalda: evite la compresión excesiva involucrando su núcleo.", "- Forzar el cuello: mantenga el peso distribuido uniformemente entre los antebrazos, no sobre la cabeza.", "- Contener la respiración: mantenga una respiración profunda y constante para mejorar la relajación.", "- Colapsar los hombros: levante activamente el pecho para maximizar los beneficios de apertura del corazón."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
