INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000609906297', 'Press de suelo unilateral y barra', 'Barbell One Arm Floor Press', 'Pecho', '["### Paso 1: configuración", "- Coloque una barra cargada en el suelo con un peso ligero.", "- Acuéstese con el cuerpo perpendicular a la barra, con la barra colocada por encima de un hombro.", "- Doble ligeramente las rodillas o mantenga las piernas extendidas para aumentar el desafío central.", "- Agarre la barra con una mano en un agarre neutral o por encima de la manga.", "- Use su mano libre para ayudar a levantar la barra a su posición si es necesario.", "### Paso 2: Ejecución", "- Presione la barra hacia arriba extendiendo el brazo, asegurándose de que la barra permanezca equilibrada y alineada sobre su hombro.", "- Haga una breve pausa en la parte superior, manteniendo la muñeca apilada sobre el codo y la barra centrada.", "- Baja lentamente la barra hasta que tus tríceps toquen ligeramente el suelo.", "- Mantenga el codo cerca del costado durante el descenso.", "- Complete las repeticiones deseadas, luego cambie de brazo y repita."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000304975795', 'Salto al cajón a una pierna', 'Single Leg Box Jump', 'Piernas', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001368622793', 'Aperturas en polea inclinado', 'İncline Cable Fly', 'Pecho', '["En ejercicios de musculación centrados en la parte superior del cuerpo o la parte superior del pecho, se suele utilizar como movimiento final al final del ejercicio después de realizar movimientos como press de banca con barra o mancuernas.", "El ejercicio de vuelo con cable inclinado te ayudará a desarrollar pectorales completamente definidos. Es uno de los mejores ejercicios que debes hacer si quieres tener un músculo superior del pecho definido y más definido.", "Las investigaciones muestran que realizar un vuelo con cable inclinado con un ángulo de banco de 30 y 45 grados es lo mejor para la parte superior del pecho. Para obtener la mejor eficiencia del movimiento de press inclinado con mancuernas, debes ajustar el banco en un ángulo de 30 a 45 grados y sentir que los músculos de la parte superior del pecho están trabajando."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-002066026137', 'Postura del arco', 'Bow Pose', 'Espalda', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001679700545', 'Curl de muñeca neutro con lastre', 'Weighted Neutral Wrist Curl', 'Antebrazos', '["Siéntate en un banco con las rodillas dobladas y los pies planos.", "Sostenga una placa de pesas verticalmente (agarre del aro) en una mano usando un agarre neutral, con el pulgar hacia arriba.", "Apoye el antebrazo sobre el muslo, permitiendo que la muñeca cuelgue un poco más allá de la rodilla.", "Deje que la placa baje lentamente extendiendo la muñeca hacia abajo.", "Vuelva a doblar la placa hacia arriba, flexionando la muñeca mientras mantiene el antebrazo quieto.", "Haga una breve pausa en la parte superior, luego repita de 10 a 15 repeticiones lentas y controladas por brazo."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001591156084', 'Press de hombros con discos (Plate Loaded)', 'Plate Loaded Shoulder Press', 'Espalda', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
