INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001848566312', 'Lanzamiento de abdominales con balón medicinal', 'Medicine Ball-Sit-up Throw', 'Espalda', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001799928976', 'Postura de gato vaca', 'Cat Cow Pose', 'Espalda', '["Esta sencilla postura potencia tu cerebro y mejora la concentración, la coordinación y la estabilidad mental. La postura del gato vaca mejora la circulación sanguínea entre las vértebras de la columna y ayuda a aliviar el dolor de espalda y el estrés. Mejora la postura y el equilibrio.", "El estiramiento gato-vaca ayuda a aliviar el estrés causado por los cólicos menstruales, el dolor lumbar y la ciática. El movimiento también estira los músculos de las caderas, la espalda, el abdomen, el pecho y los pulmones. Masajea y estimula los órganos del abdomen, como los riñones y las glándulas suprarrenales."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-002134843082', 'Estiramiento de pantorrilla con caída de un solo talón', 'Single Heel Drop Calf Stretch', 'Pantorrillas', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
