INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001301443029', 'Estiramiento de pantorrilla con pierna recta y zancada', 'Lunging Straight Leg Calf Stretch', 'Pantorrillas', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000489678262', 'Estiramientos de pies y tobillos', 'Foot and Ankles Stretches', 'Piernas', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000742957449', 'Estiramiento del tibial posterior', 'Posterior Tibialis Stretch', 'Piernas', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001585331983', 'Dorsiflexión del tobillo de pie', 'Standing Ankle Dorsiflexion', 'Piernas', '["- Posición inicial: Párese erguido con los pies separados a la altura de las caderas y los brazos relajados a los lados o colocados sobre las caderas.", "- Coloque los pies: mantenga los talones firmemente plantados en el suelo, con el peso corporal distribuido uniformemente.", "- Levante los dedos de los pies: levante activamente el antepié y los dedos de los pies hacia arriba del suelo, tirando de ellos hacia las espinillas. Tus talones deben permanecer bajos.", "- Pausa en la parte superior: Mantenga la posición superior durante 1 a 2 segundos, sintiendo la contracción a lo largo de la parte delantera de la espinilla.", "- Baje lentamente: lleve los dedos de los pies y el antepié al suelo con control.", "- Repita: realice de 10 a 20 repeticiones según su objetivo, concentrándose en la activación y el equilibrio.", "### Consejos para una forma adecuada", "- Mantenga el cuerpo erguido; evite inclinarse hacia atrás para engañar al rango.", "- Involucra activamente los músculos de las espinillas en lugar de depender del impulso.", "- Utilice una pared o superficie para mantener el equilibrio si es necesario, especialmente al empezar.", "- Levante los dedos de los pies lo más alto posible sin forzar ni levantar los talones.", "- Controla el descenso, no dejes que los dedos de tus pies caigan.", "### Errores comunes", "- Inclinarse hacia atrás para ayudar al levantamiento con impulso.", "- Levantar los talones: esto anula el efecto del entrenamiento de dorsiflexión.", "- Usando solo el dedo gordo del pie, active todo el antepié para una activación equilibrada.", "- Acelerar las repeticiones: esto reduce el control y el reclutamiento muscular.", "- Actuar descalzo sobre suelos duros puede resultar incómodo; use un tapete si es necesario."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000777492225', 'Estiramiento de pantorrilla de pie contra la pared', 'Standing Wall Calf Stretch', 'Pantorrillas', '["- Configuración: Párese frente a una pared, aproximadamente a un brazo de distancia. Coloque las manos en la pared a la altura de los hombros.", "- Paso atrás: mueva una pierna detrás de usted, manteniendo los dedos apuntando hacia adelante y el talón firmemente apoyado en el suelo.", "- Colocación del pie: Coloque un pie ligeramente hacia adelante con los dedos contra la pared.", "- Siente el estiramiento: inclínate suavemente hacia la pared hasta que sientas un estiramiento a lo largo de la parte inferior de la pantorrilla y el tendón de Aquiles.", "- Mantenga: mantenga el estiramiento durante 20 a 30 segundos, respirando profundamente.", "- Cambiar de lado: Repita en la pierna opuesta. Realiza 2 o 3 rondas por lado.", "### Consejos para una forma adecuada", "- Mantenga el talón firmemente plantado para maximizar el estiramiento.", "- Evite dejar que la rodilla colapse hacia adentro; Síguelo sobre los dedos de los pies.", "- El movimiento debe ser lento y controlado, sin rebotes.", "- Ajuste la distancia a la pared para mayor comodidad e intensidad.", "- Mantenga una postura erguida para evitar tensiones en la zona lumbar.", "### Errores comunes", "- El talón se levanta del suelo: reduce la eficacia del estiramiento.", "- Enderezar la rodilla: desplaza el estiramiento hacia el gemelo en lugar del sóleo.", "- Forzar la rodilla hacia adelante puede causar molestias en la articulación del tobillo.", "- Torcer el pie: reduce la participación de los músculos específicos."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000058662946', 'Rotación de pie y tobillo (Movilidad)', 'Foot and Ankle Rotation', 'Piernas', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001025279606', 'Estiramiento de pantorrillas en posición estática', 'Calves Stretch Static Position', 'Pantorrillas', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001062452817', 'Estiramiento del tendón de Aquiles de pie hacia arriba', 'Standing Toe Up Achilles Stretch', 'Piernas', '["- Configuración: Párese frente a un escalón, plataforma o superficie elevada.", "- Posición del pie: Coloque la punta de un pie en el borde del escalón y el otro pie un paso atrás, manteniendo el talón firmemente en el suelo. Mantenga los dedos de los pies apuntando hacia adelante.", "- Inclínese hacia adelante: cambie el peso de su cuerpo hacia el pie elevado hasta que sienta un estiramiento a lo largo del tendón de Aquiles y la parte inferior de la pantorrilla.", "- Doble ligeramente la rodilla: esto aumenta la concentración en el sóleo y al mismo tiempo estira el tendón de Aquiles.", "- Mantenga el estiramiento: manténgalo durante 20 a 30 segundos, respirando profundamente.", "- Cambiar de lado: Repita en la pierna opuesta.", "### Consejos para una forma adecuada", "- Mantenga el talón hacia abajo para mantener la eficacia del estiramiento.", "- Mantenga el torso erguido para evitar tensión en la zona lumbar.", "- Doble ligeramente la rodilla para enfatizar el sóleo; manténgalo recto para una mayor afectación de los gastrocnemios.", "- Evite inclinarse excesivamente; aplique un estiramiento suave y controlado.", "### Errores comunes", "- Dejar que el talón se levante: Elimina la tensión del tendón de Aquiles y la pantorrilla.", "- Estiramiento excesivo: puede tensar el tendón de Aquiles; mantenlo suave.", "- Alineación incorrecta de los dedos: los dedos deben apuntar hacia adelante para obtener el máximo beneficio.", "- Contener la respiración: Respirar profundamente ayuda a que los músculos se relajen."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000256953451', 'Estiramiento del flexor del dedo de pie', 'Standing Toe Flexor Stretch', 'Piernas', '["- Configuración: dirígete a una pared.", "- Coloque el pie: Párese frente a la pared y coloque los dedos del pie que desea estirar contra ella.", "- Anclar el talón: Mantenga el talón firmemente plantado en el suelo.", "- Avance: mueva suavemente su peso hacia adelante hasta que sienta un leve estiramiento en la pantorrilla o el tendón de Aquiles.", "- Mantenga el estiramiento: mantenga la posición durante 30 segundos, respirando profundamente durante todo el ejercicio.", "- Cambiar de lado: repita con el otro pie.", "### Consejos para una forma adecuada", "- Mantenga el talón hacia abajo en todo momento para garantizar un estiramiento adecuado de la dorsiflexión.", "- Permita que la rodilla se desplace hacia adelante pero sin colapsar hacia adentro.", "- Mantenga el movimiento lento y evite los rebotes.", "- Comience cerca de la pared y aumente gradualmente la distancia con el tiempo para obtener mayores ganancias de movilidad.", "### Errores comunes", "- El talón se levanta del suelo: reduce la eficacia del estiramiento.", "- Dedos de los pies inclinados hacia afuera: cambia la mecánica del estiramiento.", "- Estiramiento excesivo: puede provocar tensión en el tendón de Aquiles.", "- Inclinarse con las caderas en lugar de doblar la rodilla reduce la participación de la dorsiflexión."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000360784165', 'Estiramiento de pantorrillas a una pierna', 'Single Leg Calves Stretch', 'Pantorrillas', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001447455550', 'Sentadilla con salto con barra', 'Barbell Jump Squat', 'Piernas', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000159441020', 'Elevaciones frontales con mancuernas apoyadas en el pecho', 'Chest Supported Dumbbell Front Raises', 'Pecho', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000111947890', 'Estiramiento de la pantorrilla hacia atrás del talón agachado', 'Crouching Heel Back Calf Stretch', 'Espalda', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-002121901269', 'Estiramiento de la pantorrilla del gastrocnemio de pie', 'Standing Gastrocnemius Calf Stretch', 'Pantorrillas', '["Párate frente al banco: Colócate frente a un banco, caja o plataforma elevada.", "Doble ligeramente las caderas: inclínese un poco hacia adelante para lograr un mejor equilibrio.", "Coloque su pie: doble la rodilla y coloque el talón de un pie en el banco.", "Sostenga los dedos de los pies: use una mano para agarrar los dedos de los pies.", "Estiramiento: Extienda la rodilla doblada para realizar el estiramiento, luego tire suavemente los dedos de los pies hacia usted para estirar los músculos de la pantorrilla.", "Mantener la posición: Mantenga el estiramiento durante 20 a 30 segundos, respirando constantemente.", "Cambiar de lado: Repita con la otra pierna."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-002130532145', 'Remo vertical con mancuernas a un brazo', 'One-Arm Dumbbell Upright Row', 'Espalda', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
