INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-002141114434', 'Elevación en Y del cable', 'Cable Y Raise', 'Hombros', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-002075005095', 'Pino de pie (Handstand)', 'Handstand', 'Otros', '["- Estire y movilice las muñecas, los hombros y el core.", "- Realice planchas, flexiones de brazos y encogimientos de hombros para activar músculos clave.", "- Parada de manos asistida por la pared: frente a una pared, patee y use la pared para mantener el equilibrio.", "- Parada de manos independiente: Ponte en posición de parada de manos y mantén el equilibrio sin ayuda.", "- Coloque las manos en el suelo separadas a la altura de los hombros.", "- Levanta una pierna mientras mantienes el core apretado y los brazos rectos.", "- Involucra tus hombros, core y glúteos para estabilizar la posición.", "- Mantenga las piernas rectas y los dedos de los pies en punta.", "- Equilibre haciendo pequeños ajustes manuales si es necesario.", "- Concéntrese en la respiración lenta y controlada para mantenerse relajado.", "- Baje una pierna a la vez hasta el suelo.", "- Si pierde el equilibrio, meta la barbilla y gire hacia adelante para evitar lesiones.", "### Consejos para una forma adecuada", "- Mantenga su núcleo comprometido: evita que la espalda baja se arquee y mantiene la alineación.", "- Coloque los hombros sobre las manos: garantiza estabilidad y equilibrio.", "- Apunte los dedos de los pies y apriete los glúteos: ayuda a mantener una línea recta.", "- Utilice los dedos para mantener el equilibrio: presionar el suelo con las yemas de los dedos ayuda a controlar el movimiento.", "- Entrene contra una pared primero: genera confianza y resistencia antes de pasar a la parada de manos independiente.", "### Errores comunes a evitar", "- Arquear la espalda baja: puede provocar pérdida del equilibrio y tensión en la columna.", "- Doblar los brazos: reduce la estabilidad y aumenta el riesgo de colapso.", "- No involucrar al núcleo: conduce a problemas de alineación y equilibrio deficientes.", "- Patear demasiado fuerte: aumenta la posibilidad de caerse.", "- Descuidar la fuerza de la muñeca: las muñecas débiles pueden tener dificultades para soportar el peso corporal."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000226571714', 'Caminata sobre manos (Handstand Walk)', 'Handstand Walk', 'Cardio', '["- Mantenga una parada de manos independiente durante al menos 10 a 15 segundos", "- Realizar parada de manos asistida por la pared durante 30 segundos.", "- Tener suficiente fuerza en los hombros, movilidad de las muñecas y estabilidad central.", "### 1. Comience con un paseo por la pared", "- Comience en una posición de flexión con los pies contra la pared.", "- Suba lentamente los pies por la pared mientras mueve las manos hacia la pared.", "- Mantenga la posición de parada de manos para controlar el equilibrio.", "### 2. Practica cambiar de peso", "- Mientras está parado de manos, practique cambiar el peso de una mano a la otra para imitar el movimiento de caminar.", "### 3. Utilice un observador o un tapete de seguridad", "- Haz que un compañero te ayude o practica sobre una superficie blanda para evitar caídas.", "### 4. Iniciar la caminata", "- Comience inclinándose ligeramente hacia adelante, dejando que el impulso lo guíe.", "- Avanza una mano a la vez, manteniendo la tensión central.", "- ", "### 5. Céntrese en los pasos controlados", "- Evite las prisas; Tome pasos pequeños y controlados para mantener el equilibrio."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000952888692', 'Toques de los pies acostados', 'Lying Toe Touches', 'Abdomen', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000439615643', 'Flexiones en pica entre sillas', 'Pike Push-Up Between Chairs', 'Pecho', '["- Coloque dos sillas o plataformas resistentes separadas un poco más que el ancho de los hombros.", "- Asegúrese de que las sillas sean estables y no se muevan durante el movimiento.", "- Coloque sus manos sobre las sillas y coloque sus pies en el suelo.", "- Mantenga las caderas elevadas para que su cuerpo forme una V invertida.", "- Mire ligeramente hacia adelante para mantener una posición neutral del cuello.", "- Doble los codos y baje la cabeza entre las sillas con un movimiento controlado.", "- Mantenga su núcleo apretado y evite arquear la espalda baja.", "- Baje lo más profundo posible mientras mantiene la forma adecuada.", "- Empuja con las palmas de las manos para estirar los brazos y volver a la posición inicial.", "- Involucre sus hombros y tríceps para completar el movimiento.", "- Repita hasta el número deseado de repeticiones."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000248348794', 'Pasamanos (Climbing Monkey Bars)', 'Climbing Monkey Bars', 'Espalda', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001347130274', 'Giro espinal en supino (Estiramiento)', 'Supine Spinal Twist', 'Abdomen', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-002006559870', 'Sentadilla frontal con barra', 'Barbell Pin Front Squat', 'Piernas', '["Coloque los imperdibles en una rejilla eléctrica justo debajo de la posición inferior de la sentadilla frontal. Coloca la barra sobre los alfileres.", "Pase por debajo de la barra, asumiendo una posición frontal con los codos en alto y el pecho erguido.", "Apoye su núcleo y coloque los pies separados al ancho de los hombros con los dedos ligeramente hacia afuera.", "Conduce hacia arriba a través de tus talones, levantando la barra de los pasadores hasta que alcances una posición de pie completamente.", "Baje la barra bajo control nuevamente sobre los pasadores para completar una repetición. Haga una breve pausa antes de la siguiente repetición.", "Repita durante la cantidad deseada de repeticiones, manteniendo un núcleo fuerte y una postura erguida."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001049595036', 'Sentadilla con patada lateral y toque del talón', 'Heel Touch Side Kick Squat', 'Piernas', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
