INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001838740038', 'Estiramiento envolvente con palmadas en la espalda', 'Back Slaps Wrap Around Stretch', 'Espalda', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001936683964', 'Lanzamiento con pelota de reacción', 'Reaction Ball Throw', 'Espalda', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001942095912', 'Sentadilla Split ATG', 'ATG Split Squat', 'Piernas', '["Configuración Párese en una postura dividida larga con un pie hacia adelante y el otro extendido detrás de usted. Mantenga el talón delantero plano sobre el suelo y el talón trasero elevado, descansando sobre los dedos de los pies.", "Párese en una postura larga y dividida con un pie hacia adelante y el otro extendido detrás de usted.", "Mantenga el talón delantero plano sobre el suelo y el talón trasero elevado, apoyado sobre los dedos de los pies.", "Ejecución Comience el movimiento doblando ambas rodillas, bajando las caderas hacia abajo. Permita que la rodilla delantera se mueva hacia adelante sobre los dedos de los pies, manteniendo el talón firme. Simultáneamente, deje que la rodilla trasera caiga hacia abajo y hacia atrás, sintiendo un estiramiento a través de los flexores de la cadera. Vaya tan profundo como su movilidad lo permita mientras mantiene una buena postura. Presione con el pie delantero para regresar a la posición inicial. Repita de 8 a 12 repeticiones por pierna, manteniendo el control en todo momento.", "Comience el movimiento doblando ambas rodillas y bajando las caderas hacia abajo.", "Permita que su rodilla delantera avance sobre los dedos de los pies, manteniendo el talón apoyado en el suelo.", "Al mismo tiempo, deje que la rodilla trasera caiga hacia abajo y hacia atrás, sintiendo un estiramiento a través de los flexores de la cadera.", "Llega tan profundo como tu movilidad te lo permita manteniendo una buena postura.", "Presione con el pie delantero para volver a la posición inicial.", "Repita de 8 a 12 repeticiones por pierna, manteniendo el control en todo momento."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
