INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000996193176', 'Carrera en bicicleta estacionaria', 'Stationary Bike Run', 'Cardio', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001682950536', 'Prensa de Landmine arrodillada', 'Kneeling Landmine Press', 'Hombros', '["Configuración: Asegure un extremo de la barra en un accesorio para minas terrestres o contra una superficie estable. Cargue el extremo libre con un peso adecuado.", "Asegure un extremo de la barra en un accesorio para minas terrestres o contra una superficie estable.", "Cargue el extremo libre con un peso adecuado.", "Posición inicial: Arrodíllese sobre ambas rodillas con el torso erguido, de cara a la mina terrestre. Sujete la barra con ambas manos o con una sola mano, colocándola al nivel del pecho. Mantenga los codos ligeramente doblados hacia adentro para enganchar la parte superior del pecho.", "Arrodíllese sobre ambas rodillas con el torso erguido, de cara a la mina terrestre.", "Sujeta la barra con ambas manos o con una sola mano, colocándola a la altura del pecho.", "Mantenga los codos ligeramente doblados para enganchar la parte superior del pecho.", "Movimiento de presión: active su núcleo y presione la barra hacia adelante y ligeramente hacia arriba. Extienda el brazo por completo, pero no bloquee el codo por completo.", "Involucre su núcleo y presione la barra hacia adelante y ligeramente hacia arriba.", "Extienda el brazo por completo pero no bloquee el codo por completo.", "Fase de descenso: Lleve lentamente la barra a la posición inicial, manteniendo el control. Mantenga el pecho ocupado durante todo el movimiento.", "Lleve lentamente la barra a la posición inicial, manteniendo el control.", "Mantenga su pecho comprometido durante todo el movimiento.", "Patrón de respiración: Exhale mientras empuja el peso hacia adelante. Inhale mientras baja la barra.", "Exhala mientras empujas el peso hacia adelante.", "Inhala mientras bajas la barra."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
