INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001605057627', 'Empuje de cadera en la máquina de extensión de piernas', 'Hip Thrust on The Leg Extension Machine', 'Piernas', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000062899632', 'Soporte frontal (Front Rack) PVC estiramiento', 'Front Rack PVC Stretch', 'Hombros', '["Agarre un tubo de PVC a la altura de los hombros, con las palmas hacia arriba (agarre en supinación).", "Levante el tubo hasta el nivel del pecho, imitando la posición de la rejilla delantera.", "Levanta los codos hasta que queden paralelos al suelo.", "Tire de la barra ligeramente hacia el cuello o la clavícula, manteniendo las muñecas extendidas y los hombros en rotación externa.", "Mantenga la posición durante 20 a 30 segundos, manteniendo la parte superior de la espalda erguida y la caja torácica hacia abajo.", "Repita durante 2 o 3 series, respirando profundamente para mejorar la relajación y el rango de movimiento."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
