INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001734060526', 'Flexiones de antebrazo', 'Forearm Push-up', 'Antebrazos', '["### Paso 1: configuración", "- Comience en una posición de plancha con el antebrazo con los codos directamente debajo de los hombros.", "- Mantenga los antebrazos apoyados en el suelo con las palmas hacia abajo o en una posición neutral.", "- Involucre su núcleo, glúteos y piernas para mantener una línea corporal recta desde la cabeza hasta los talones.", "### Paso 2: Ejecución", "- Baje el cuerpo doblando los codos, llevando el torso hacia el suelo mientras mantiene los antebrazos en el suelo.", "- Mantenga un núcleo firme y una columna neutra para evitar un arqueamiento o flacidez excesivos.", "- Presione con los antebrazos y los codos para volver a la posición inicial.", "- Repita durante la cantidad deseada de repeticiones mientras mantiene el movimiento controlado."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001868352046', 'Flexión de codo', 'Elbow Flexion', 'Otros', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001836555921', 'Pullover con brazo doblado EZ-Bar', 'EZ-Bar Bent Arm Pullover', 'Espalda', '["Elija una EZ-Bar con un peso cómodo.", "Acuéstese en un banco con los pies plantados en el suelo para mayor estabilidad.", "Sostenga la EZ-Bar con un agarre por encima del ancho de los hombros, manteniendo las manos en las secciones en ángulo de la barra."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000085308639', 'Rotación interna de hombro', 'Shoulder Internal Rotation', 'Hombros', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
