INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001725264880', 'Columpios laterales de piernas (Calentamiento)', 'Lateral Leg Swings', 'Espalda', '["Párese erguido cerca de una pared o poste para mantener el equilibrio, con los pies separados a la altura de los hombros.", "Cambie el peso a una pierna, manteniendo la pierna de apoyo ligeramente flexionada.", "Balancee la pierna opuesta de lado a lado frente al cuerpo en un arco controlado.", "Mantenga el torso erguido y evite torcer la columna o los hombros.", "Realice de 10 a 15 movimientos por pierna, aumentando gradualmente el rango de movimiento con cada repetición."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000161041182', 'Almeja Acostada De Lado De La Banda', 'Band Side Lying Clam', 'Piernas', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
