INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001774002621', 'Aperturas de muslo con banda', 'Banded Thigh Fly', 'Pecho', '["Abre lentamente las piernas hacia afuera contra la resistencia de la banda.", "Haga una pausa cuando sienta un estiramiento profundo en la parte interna de los muslos.", "Con control, vuelve a juntar las piernas hasta la posición inicial.", "Repita de 10 a 15 repeticiones para tres series."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
