INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001121693439', 'Paso lateral 1-2 (Coordinación)', '1-2 Stick Drill', 'Cardio', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001689138939', 'Patada de tríceps en polea bajo', 'Low Cable Tricep Kickback', 'Tríceps', '["### Paso 1: configuración", "- Coloque una empuñadura monomando en la polea inferior de una máquina de cable.", "- Seleccione un peso de ligero a moderado para mantener el control.", "- Párese frente a la máquina de cable, sujetando el mango con una mano.", "- Da un paso atrás y gira las caderas para que tu torso quede ligeramente inclinado hacia adelante.", "- Mantenga el codo cerca del torso y dóblelo en un ángulo de 90 grados.", "### Paso 2: Ejecución", "- Extienda el brazo hacia atrás, enderezando completamente el codo mientras mantiene la parte superior del brazo inmóvil.", "- Aprieta tus tríceps en la parte superior del movimiento.", "- Regrese lentamente a la posición inicial, manteniendo la tensión en los tríceps.", "- Repita el movimiento durante el número deseado de repeticiones antes de cambiar de brazo.", "### Repeticiones y Series:", "- Principiantes: 3 series de 10 repeticiones por brazo", "- Intermedio: 3 a 4 series de 12 repeticiones por brazo", "- Avanzado: 4 series de 15 repeticiones por brazo"]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000883675605', 'Curl de bíceps con banda', 'Band Biceps Curl', 'Bíceps', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001804362199', 'Sentadilla frontal con pesa rusa', 'Kettlebell Front Squat', 'Piernas', '["Párese con los pies separados a la altura de los hombros, sosteniendo una pesa rusa en cada mano en la posición frontal cerca de la clavícula.", "Mantenga los codos doblados y las muñecas neutrales mientras ejercita su núcleo.", "Empuje las caderas hacia atrás y doble las rodillas para ponerse en cuclillas.", "Desciende hasta que tus muslos queden al menos paralelos al suelo, manteniendo el pecho hacia arriba y la espalda plana.", "Conduce sobre tus talones para volver a la posición inicial. Repita para el número deseado de repeticiones."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001331367164', 'Remo en polea sentado con giro unilateral', 'Single Arm Twisting Seated Cable Row', 'Espalda', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001437585316', 'Jalón al pecho alterno con banda', 'Band Alternating Lat Pulldown', 'Espalda', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001512961261', 'Banda alternada de remo bajo con giro', 'Band Alternating Low Row with Twist', 'Espalda', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001508480014', 'Cable Torcido De Pie Fila Alta', 'Cable Twisting Standing High Row', 'Espalda', '["Este ejercicio, realizado con máquina de cables o banda de resistencia, es un ejercicio compuesto que trabaja todos los músculos de la espalda.", "El movimiento de rotación en este ejercicio hace que trabajen muchos grupos de músculos. A medida que gira su cuerpo, sus piernas toman más fuerza de sus glúteos para sostener su cuerpo. Mientras tanto, permite que trabajen los músculos de la cadera, los aductores y muchos grupos de músculos más pequeños y profundos. Mientras está de pie, tanto la rotación de la columna como la rotación de la cadera contribuyen a la rotación del cuerpo."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000626502245', 'Press de pecho con inclinación alterna con banda', 'Band Alternate Incline Chest Press', 'Pecho', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000892190383', 'Banda de resistencia trituradora de cráneos', 'Resistance Band Skullcrusher', 'Otros', '["### Paso 1: configuración", "- Asegure una banda de resistencia a un punto de anclaje resistente cerca del suelo.", "- Acuéstese sobre una superficie plana (como un banco, una colchoneta o el piso) con la cabeza colocada cerca del punto de anclaje.", "- Agarre la banda con ambas manos, manteniendo las palmas hacia arriba.", "- Extienda los brazos hacia arriba para que haya una ligera tensión en la banda.", "### Paso 2: Ejecución", "- Doble los codos lentamente y lleve las manos hacia la frente.", "- Mantenga la parte superior de los brazos inmóviles; solo deben moverse los antebrazos.", "- Una vez que tus manos estén cerca de tu cabeza, haz una pausa y siente el estiramiento de tus tríceps.", "- Extiende tus brazos nuevamente a la posición inicial, apretando tus tríceps en la parte superior.", "- Repita para el número deseado de repeticiones.", "### Repeticiones y Series:", "- Principiantes: 3 series de 10 repeticiones", "- Intermedio: 3 a 4 series de 12 repeticiones", "- Avanzado: 4 series de 15 repeticiones"]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000340053804', 'Press de hombros unilateral con banda', 'Band Single Arm Shoulder Press', 'Hombros', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000408778223', 'Rotación externa de cadera sentado con banda', 'Band Seated Hip External Rotation', 'Piernas', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
