INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001216071337', 'Remo colgante con barra', 'Barbell Pendlay Row', 'Espalda', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000623630398', 'Patada lateral de glúteo (Boca de incendio / Fire Hydrant)', 'Fire Hydrant', 'Piernas', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000155571490', 'Extensión de tríceps declinada con mancuernas', 'Decline Dumbbell Triceps Extension', 'Tríceps', '["### Configuración", "- Acuéstese en un banco inclinado con los pies asegurados debajo de las almohadillas para los pies.", "- Sostenga una mancuerna en cada mano con un agarre neutral (con las palmas una frente a la otra).", "- Extienda los brazos completamente por encima del pecho con una ligera flexión de los codos.", "### Ejecución", "- Mientras mantiene la parte superior de los brazos perpendicular al suelo, doble los codos lentamente para bajar las mancuernas hacia los lados de la cabeza.", "- Mantenga los codos fijos en su lugar y no permita que se abran hacia afuera.", "- Baje hasta que sienta un estiramiento profundo en el tríceps.", "- Invierte el movimiento extendiendo los codos y presionando las mancuernas hasta la posición inicial.", "- Repita hasta obtener el número deseado de repeticiones.", "### Repeticiones y series", "- Principiantes: 3 series de 8 a 10 repeticiones", "- Intermedio a avanzado: 3 a 4 series de 10 a 15 repeticiones"]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000923770941', 'Estiramiento piriforme', 'Piriformis Stretch', 'Piernas', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001692582587', 'Subidas al cajón con elevación de rodilla', 'Step Up with Knee Raises', 'Piernas', '["El paso hacia arriba con elevación de rodillas es un ejercicio eficaz para la parte inferior del cuerpo que apunta a las caderas, los cuádriceps y los isquiotibiales. Los ejercicios con peso corporal son muy buenos para desarrollar músculos y fuerza, además de mejorar la coordinación y la condición física.", "Subir con elevación de rodillas es un ejercicio adecuado para principiantes. Puede ayudar a fortalecer los músculos de las piernas, tensar los músculos de la cadera y quemar calorías para perder peso."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000584543716', 'Flexiones de manos entre bancos', 'Handstand Push-ups Between Benches', 'Pecho', '["- Coloque dos bancosColoque dos bancos resistentes o paralelos separados al ancho de los hombros. Asegúrese de que haya suficiente espacio para que su cabeza descienda entre los bancos.", "- Coloque dos bancos resistentes o paralelas separados a la altura de los hombros.", "- Asegúrese de que haya suficiente espacio para que su cabeza descienda entre los bancos.", "- Encuentre un soporte de pared estable cerca de una pared resistente que apoye sus pies.", "- Párese cerca de una pared resistente que apoye sus pies.", "- Colocación de las manos Coloque las manos de forma segura en cada banco, asegurando un agarre firme para evitar resbalones.", "- Coloque sus manos de forma segura en cada banco, asegurándose de un agarre firme para evitar resbalones.", "- Patada para hacer el pino Patada contra la pared, manteniendo el core apretado y las piernas rectas. Asegúrate de que tu cuerpo esté alineado en una posición neutral.", "- Patea contra la pared, manteniendo el core apretado y las piernas rectas.", "- Asegúrese de que su cuerpo esté alineado en una posición neutral.", "- Baje el cuerpo Doble los codos lentamente y bajo control hasta que la cabeza se mueva por debajo del nivel de las manos. Mantenga los codos en un ángulo de 45 grados para reducir la tensión en los hombros.", "- Doble los codos lentamente y bajo control hasta que su cabeza se mueva por debajo del nivel de sus manos.", "- Mantenga los codos en un ángulo de 45 grados para reducir la tensión en los hombros.", "- Empuje hacia arriba Involucre sus hombros y tríceps para presionar hacia atrás a la posición inicial. Mantenga una posición del cuerpo recta, evitando arquear excesivamente.", "- Involucra tus hombros y tríceps para volver a la posición inicial.", "- Mantenga una posición del cuerpo recta, evitando arquearse excesivamente.", "- Repita para las repeticiones deseadas Realice de 3 a 5 series de 4 a 10 repeticiones, según el nivel de fuerza.", "- Realice de 3 a 5 series de 4 a 10 repeticiones, según el nivel de fuerza.", "### Consejos para una forma adecuada", "- Involucre su núcleo para mantener su cuerpo alineado y evitar arquearse.", "- Baje lentamente para maximizar la activación muscular y evitar lesiones.", "- Coloque las manos al ancho de los hombros para mantener una mecánica de presión adecuada.", "- Mantenga los codos en un ángulo controlado para reducir la tensión en los hombros.", "- Utilice un observador o tapetes cuando aprenda por seguridad.", "### Errores comunes a evitar", "- Dejar que la parte baja de la espalda se arquee: un compromiso débil del core puede provocar una mala forma y lesiones.", "- Bajar demasiado rápido: el control es clave para la participación y la seguridad de los músculos.", "- Colocar las manos demasiado separadas: la colocación inadecuada de las manos reduce la eficiencia de la presión.", "- No calentar los hombros: aumenta el riesgo de lesiones.", "- Depender demasiado de la pared: si bien la pared ayuda con el equilibrio, inclinarse excesivamente limita el aumento de fuerza."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000895795006', 'Abrazos de rodillas de pie', 'Standing Knee Hugs', 'Piernas', '["El propósito de abrazar las rodillas es estirar las piernas y los glúteos. Este ejercicio también estirará los músculos isquiotibiales y cuádriceps.", "Antes de comenzar con el entrenamiento de piernas, puedes aplicar este ejercicio después de los ejercicios de calentamiento para estirar las piernas. De este modo, los músculos de las piernas se volverán más flexibles ante las lesiones."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001524104657', 'Saltos snap (Snap Jumps / Medio Burpee)', 'Snap Jumps', 'Abdomen', '["Los saltos rápidos son un ejercicio pliométrico. Los ejercicios pliométricos son movimientos aeróbicos explosivos que aumentan la velocidad, la rapidez y la potencia y trabajan todo el cuerpo.", "Los saltos rápidos se dirigen a los músculos abdominales, los músculos de la cadera y los flexores de la cadera y también trabajan los muslos, los tendones de las rodillas, los cuádriceps y los hombros.", "Los saltos rápidos son beneficiosos para la salud porque combinan el acondicionamiento cardiovascular con el trabajo de fuerza. Dado que los saltos rápidos elevan su frecuencia cardíaca, también pueden mejorar su condición cardiovascular."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001761033388', 'Estiramiento del flexor de la cadera en media rodilla', 'Half Kneeling Hip Flexor Stretch', 'Piernas', '["Es un movimiento de estiramiento que los corredores utilizan con frecuencia. Se practica para mejorar la flexibilidad de los músculos de la parte inferior del cuerpo, incluidos cuádriceps, isquiotibiales, caderas, muslos y pantorrillas. La mejor manera de mantener estos músculos relajados y flexibles es incluyendo estiramientos dinámicos en tu calentamiento y estiramientos estáticos en tu rutina de vuelta a la calma. Estirar los músculos con regularidad puede mejorar su flexibilidad y rendimiento, y también prevenir lesiones y rigidez."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000413259118', 'Puente de glúteos con barra', 'Barbell Glute Bridge', 'Piernas', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001167799787', 'Extensión de cadera en polea', 'Cable Hip Extension', 'Piernas', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001433048679', 'Flexión de manos con Kipping', 'Kipping Handstand Push-up', 'Pecho', '["- Encuentre una pared resistente Utilice una superficie plana y estable que pueda soportar su peso corporal.", "- Utilice una superficie plana y estable que pueda soportar su peso corporal.", "- Colocación de las manos Coloque las manos a la altura de los hombros, a una distancia de entre 6 y 12 pulgadas de la pared.", "- Coloque las manos a la altura de los hombros, a una distancia de entre 6 y 12 pulgadas de la pared.", "- Ponte en posición de parada de manos Ponte en posición de parada de manos, manteniendo el core comprometido y los pies juntos.", "- Ponte en posición de parada de manos, manteniendo el núcleo enganchado y los pies juntos.", "- Baje a la posición inferior Baje su cuerpo bajo control hasta que la parte superior de su cabeza toque ligeramente el piso o una colchoneta. Mantenga los codos en un ángulo de 45 grados para proteger los hombros.", "- Baja tu cuerpo bajo control hasta que la parte superior de tu cabeza toque ligeramente el suelo o una colchoneta.", "- Mantenga los codos en un ángulo de 45 grados para proteger los hombros.", "- Inicie el Kip. Cuando llegue a la posición inferior, lleve las rodillas hacia el pecho en una posición doblada.", "- Cuando llegue a la posición inferior, lleve las rodillas hacia el pecho en una posición doblada.", "- Explota hacia arriba con un impulso de piernas Extiende las piernas con fuerza mientras empujas con los brazos al mismo tiempo. Usa el impulso para impulsar tu cuerpo de regreso a la posición inicial.", "- Extiende las piernas con fuerza mientras empujas con los brazos al mismo tiempo.", "- Utilice el impulso para impulsar su cuerpo de regreso a la posición inicial.", "- Bloqueo en la parte superior Extienda completamente los codos y mantenga una posición firme de parada de manos antes de repetir el movimiento.", "- Extienda completamente los codos y mantenga una posición fuerte de parada de manos antes de repetir el movimiento.", "### Consejos para una forma adecuada", "- Controle el descenso: evite caer demasiado rápido para reducir la tensión en el cuello y los hombros.", "- Utilice un tapete para proteger la cabeza: un tapete acolchado debajo de la cabeza ayuda a reducir el riesgo de impactos y lesiones.", "- Involucre su núcleo: un núcleo apretado mejora el equilibrio y evita arquearse excesivamente.", "- Conduce explosivamente con las caderas: maximiza la potencia coordinando el impulso de tus piernas y caderas con la prensa de brazos.", "- Mantenga una colocación constante de las manos: las manos demasiado lejos o demasiado cerca de la pared pueden provocar inestabilidad y pérdida de control.", "### Errores comunes a evitar", "- No controlar la fase de descenso: caer demasiado rápido aumenta el riesgo de lesiones en la cabeza y el cuello.", "- Ampliar la zona lumbar: un núcleo débil conduce a una mala postura y a una reducción de la eficiencia de la presión.", "- Sincronización de Kip ineficiente: si el impulso de las piernas no está sincronizado con el empuje, el movimiento se vuelve menos efectivo.", "- Depender demasiado del impulso: si bien dar kipping reduce la fatiga, depender completamente del impulso limita las ganancias de fuerza.", "- Colocar las manos demasiado abiertas o demasiado cerca: la colocación incorrecta de las manos puede provocar una mecánica de presión inestable.", "### Consideraciones y precauciones", "- Riesgo de compresión del cuello y la columna: una mala forma o un arqueo excesivo pueden generar tensión en la columna cervical. Utilice siempre movimientos controlados y considere colocar algo acolchado debajo de la cabeza.", "- Requisito de estabilidad del hombro: las personas que carecen de estabilidad o fuerza en el hombro deben dominar primero las HSPU estrictas antes de incorporar los kipping para evitar lesiones.", "- No es ideal para obtener pura fuerza: si el objetivo es la fuerza máxima, las HSPU estrictas, las flexiones de brazos o los press de hombros son mejores opciones."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000746658191', 'Abducción de cadera en polea', 'Cable Hip Abduction', 'Piernas', '["El foco de este ejercicio está en el glúteo medio y el glúteo menor que se encuentra debajo. Si el objetivo es fortalecer y dar forma a la cadera (glúteos superiores y externos), entonces las abducciones de cadera con cable son una excelente opción."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000914201875', 'Elevación del deltoides posterior inclinada con mancuernas y con la cabeza apoyada en el banco', 'Bent-Over Dumbbell Rear Delt Raise With Head On Bench', 'Hombros', '["El levantamiento del deltoides trasero inclinado con mancuernas y la cabeza apoyada en el banco es un ejercicio de pesas libres que se dirige principalmente a los hombros traseros. Es un ejercicio eficaz que puedes incluir en tu programa para aislar los músculos posteriores del hombro y fortalecer los músculos del manguito rotador."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001038591991', 'Patada de glúteo en cuadrupedia (Donkey Kicks)', 'Donkey Kicks', 'Piernas', '["El músculo principal que involucra la patada de burro es el glúteo máximo. Es uno de los mejores ejercicios sin equipo que puedes incluir en tus entrenamientos para tensar y tonificar los glúteos, mejorar la movilidad de la cadera y fortalecer la zona lumbar."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000956526900', 'Carrera con rodillas altas (Skipping)', 'High Knee Run', 'Cardio', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001514607808', 'Elevaciones de piernas en plancha lateral', 'Side Plank Leg Raises', 'Abdomen', '["Los levantamientos de piernas en plancha lateral son un ejercicio básico simple pero eficaz que le ayuda a desarrollar estabilidad y fuerza en todo el cuerpo.", "Los levantamientos de piernas en plancha lateral desarrollan el núcleo, los oblicuos, las piernas, las caderas y los hombros. También es un ejercicio corporal que favorece el aumento de resistencia y fuerza.", "El levantamiento de piernas en plancha lateral trabaja más del 40 por ciento de los músculos superiores e inferiores de la espalda. En este ejercicio, los músculos centrales se contraen isométricamente para proteger la columna lumbar de las fuerzas de rotación y flexión. Mantener estos músculos fuertes puede ayudar a reducir el riesgo de sufrir una lesión en la espalda."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000984133561', 'Empuje de banda', 'Band Pushdown', 'Otros', '["- Configuración Asegure una banda de resistencia a un punto de anclaje elevado, como una puerta o una barra de dominadas. Párese frente al punto de anclaje y sostenga la banda con ambas manos usando un agarre neutral o en pronación. Coloque los pies separados al ancho de los hombros y mantenga las rodillas ligeramente dobladas.", "- Asegure una banda de resistencia a un punto de anclaje elevado, como una puerta o una barra de dominadas.", "- Párese frente al punto de anclaje y sostenga la banda con ambas manos usando un agarre neutral o en pronación.", "- Coloque los pies separados a la altura de los hombros y mantenga las rodillas ligeramente dobladas.", "- Posición inicial Acerque los codos a los costados con los antebrazos paralelos al suelo. Las manos deben estar cerca del nivel del pecho y la parte superior de los brazos inmóviles durante todo el ejercicio.", "- Acerque los codos a los costados con los antebrazos paralelos al suelo.", "- Tus manos deben estar cerca del nivel del pecho y la parte superior de tus brazos inmóviles durante todo el ejercicio.", "- EjecuciónPresione la banda hacia abajo extendiendo los codos hasta que los brazos queden rectosApriete los tríceps en la parte inferior del movimientoRegrese lentamente a la posición inicial con controlRepita durante el número deseado de repeticiones", "- Presione la banda hacia abajo extendiendo los codos hasta que los brazos queden rectos.", "- Aprieta tus tríceps en la parte inferior del movimiento.", "- Regrese lentamente a la posición inicial con control.", "- Repetir hasta el número deseado de repeticiones.", "### Consejos para una forma adecuada", "- Mantenga los codos pegados a los costados para aislar completamente los tríceps.", "- No permita que sus hombros se eleven o se doblen hacia adelante.", "- Involucre su núcleo para evitar el movimiento excesivo del cuerpo.", "- Muévase lenta y deliberadamente para mantener una tensión constante en la banda.", "- Exhala mientras presionas hacia abajo e inhala mientras regresas a la posición inicial.", "### Errores comunes", "- Permitir que los codos se separen del torso.", "- Usar impulso o balanceo del cuerpo para presionar la banda hacia abajo", "- Redondear los hombros o extender demasiado las muñecas", "- Inclinarse demasiado hacia adelante o hacia atrás", "- Dejar que la tensión en la banda se afloje durante el movimiento."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000129083018', 'Abdominales dobles', 'Double Crunches', 'Cardio', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000531959895', 'Abdominales', 'Sit-ups', 'Abdomen', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000477993199', 'Plancha invertida con patadas', 'Reverse Plank Kicks', 'Abdomen', '["Las patadas en plancha inversa son un ejercicio abdominal avanzado. Con este ejercicio podrás aportar más intensidad a los músculos abdominales inferiores y oblicuos. Como movimiento multifuncional, la plancha inversa no solo apunta a los músculos abdominales sino también a la columna y la cadera. Las patadas en plancha inversa fortalecen y tonifican todo el cuerpo, mejoran la postura y el equilibrio, reducen la grasa corporal y pueden ayudar a acelerar el metabolismo.", "Además, los músculos de los hombros y las piernas actúan como estabilizadores en la parte isométrica del movimiento, mientras que los flexores de la cadera participan en la parte dinámica del movimiento."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001303262032', 'Estiramiento lateral interno del muslo', 'Inner Thigh Side Stretch', 'Piernas', '["El grupo de aductores se encuentra en el interior de la pierna y está formado por el pectíneo, el aductor corto, el aductor largo, el aductor mayor y el gracilis. La mejor manera de mantener estos músculos relajados y flexibles es incluyendo estiramientos dinámicos en tu calentamiento y estiramientos estáticos en tu rutina de vuelta a la calma. Estirar los aductores con regularidad puede mejorar su flexibilidad y rendimiento, y también prevenir lesiones y rigidez.", "El estiramiento dinámico previo al entrenamiento mejora la circulación, prepara los músculos para el movimiento y aumenta temporalmente su rango de movimiento."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000098725163', 'Saltos con rodillas altas', 'High Knee Skips', 'Abdomen', '["Puedes utilizar este ejercicio tanto como calentamiento dinámico antes de entrenar como añadirlo a tu rutina de entrenamiento cardiovascular para quemar grasa.", "Los saltos con las rodillas altas son un ejercicio pliométrico. Los ejercicios pliométricos son movimientos aeróbicos explosivos que aumentan la velocidad, la rapidez y la potencia y trabajan todo el cuerpo.", "Los saltos de rodilla altos apuntan a los músculos oblicuos, de las piernas, de la cadera y de los flexores de la cadera y también trabajan los muslos, los tendones de las rodillas, los cuádriceps y los hombros.", "Los saltos son beneficiosos para la salud porque combinan el acondicionamiento cardiovascular con el trabajo de fuerza. Dado que los saltos elevan tu frecuencia cardíaca, también pueden mejorar tu condición cardiovascular."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000539697640', 'Estiramiento de mariposa', 'Butterfly Stretch', 'Pecho', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001926035843', 'Plancha con rodilla al codo (Spiderman Plank)', 'Plank Knee to Elbow', 'Abdomen', '["Plancha de rodilla a codo es un ejercicio cardiovascular y de fortalecimiento central eficaz. Puede ayudarle a fortalecer y desarrollar los músculos de la parte superior e inferior del cuerpo.", "Al ser un movimiento multifuncional, este ejercicio se dirige no solo a los músculos abdominales sino también a la columna y los glúteos. Plank fortalece y tonifica todo el cuerpo, mejora la postura y el equilibrio, reduce la grasa corporal y puede ayudar a acelerar el metabolismo."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001745488555', 'Medios limpiaparabrisas (Half Wipers)', 'Half Wipers', 'Abdomen', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000600002107', 'Plancha abdominal con elevación de pierna', 'Plank Leg Lift', 'Abdomen', '["Como movimiento multifuncional, el levantamiento de piernas en plancha no solo apunta a los músculos abdominales sino también a la columna y la cadera. El levantamiento de piernas en plancha fortalece y tonifica todo el cuerpo, mejora la postura y el equilibrio, reduce la grasa corporal y puede ayudar a acelerar el metabolismo.", "El levantamiento de piernas en plancha es un ejercicio eficaz que aumenta la estabilidad en las zonas de la columna, el core y la cadera al proporcionar una contracción isométrica. Puedes agregarlo a tus entrenamientos para dar forma y fortalecer los músculos de la cadera, el tronco y las piernas."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001816926568', 'Saltos de patinador (Skaters)', 'Skater', 'Piernas', '["El ejercicio del patinador es un ejercicio cardiovascular pliométrico que implica saltar en un patrón que cambia el peso del cuerpo de un lado a otro para crear una zancada de patinaje. Si bien aumenta principalmente la potencia de las piernas, se considera un entrenamiento dinámico para todo el cuerpo, ya que también trabaja el core, el glúteo medio y los aductores de las articulaciones de la cadera.", "El patinador es un ejercicio adecuado para principiantes. Puede ayudar a fortalecer los músculos de las piernas, tensar los músculos de la cadera y quemar calorías para perder peso.", "El ejercicio del patinador se clasifica como un ejercicio aeróbico eficaz que ayuda a fortalecer el corazón y aumentar la fuerza y ​​resistencia muscular. También le ayuda a mejorar su rendimiento físico general, incluida la fuerza, la velocidad, la condición física y la flexibilidad."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000725831733', 'Crunch abdominal con brazos estirados', 'Long Arm Crunch', 'Cardio', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000077195842', 'Plancha abdominal', 'Plank', 'Abdomen', '["Mantenga la columna neutra; participar en la “estabilización abdominal” tirando de los músculos abdominales.", "Baje los omóplatos, activando los músculos dentados anteriores y las partes inferiores de los músculos trapecios.", "No redondees ni dobles la espalda. Mantenga su pelvis en una posición neutral.", "No se encorve ni se encorve. Mantenga el pecho plano y los omóplatos planos.", "No contengas la respiración. Respira libre y naturalmente."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001398390758', 'Giro ruso', 'Russian Twist', 'Abdomen', '["Siéntate en el suelo con las rodillas dobladas y los pies apoyados en el suelo.", "Inclínese ligeramente hacia atrás para que la parte superior de su cuerpo forme una V con sus muslos. Mantenga la espalda recta y active los músculos centrales.", "Junte las manos frente a usted o sostenga una pesa o un balón medicinal con ambas manos. Esto añade resistencia al ejercicio.", "Gira el torso hacia un lado, llevando el peso o las manos al lado de la cadera. Mantenga su núcleo comprometido durante todo el movimiento.", "Regrese al centro y luego gire hacia el otro lado.", "Repita el movimiento de torsión de lado a lado durante el número deseado de repeticiones o tiempo."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000924351840', 'Abdominales navaja (V-ups)', 'Jackknife Sit-ups (V-Up)', 'Abdomen', '["Trabaja todos los músculos abdominales: el ejercicio de abdominales en navaja se dirige al recto abdominal y a los músculos oblicuos. Son una excelente manera de tensar los abdominales inferiores y ayudarlo a obtener abdominales marcados. Es un ejercicio beneficioso para perder grasa y tonificar ya que tiene un efecto intenso sobre los músculos oblicuos.", "Mientras fortaleces tus músculos abdominales, también fortaleces tus flexores de cadera. Cuando te sientas completamente y levantas las piernas hacia las manos, los flexores de la cadera se activan y ayudan. Esto es excelente para trabajar los abdominales inferiores y los flexores de la cadera. Fortalecer su núcleo le ayudará tanto con los deportes como con las actividades diarias. Además, los V-ups fomentan una buena postura y te ayudan a practicar la extensión de la columna."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001961782282', 'Aleteo de piernas (Flutter Kicks)', 'Flutter Kick', 'Abdomen', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000873296365', 'Zancada inclinada hacia adelante con mancuernas', 'Dumbbell Forward Leaning Lunge', 'Piernas', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
