INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001190390866', 'Flexión lateral de tronco de pie', 'Standing side bend', 'Espalda', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-002060120296', 'Press de banca inclinado con agarre cerrado', 'Incline Close-Grip Bench Press', 'Pecho', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001987121556', 'Curl con barra en Z', 'Z-Bar Curl', 'Otros', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000941311941', 'Curl de muñeca inverso', 'Reverse Wrist Curl', 'Antebrazos', '["Es un ejercicio muy eficaz para mejorar la musculatura del antebrazo y la muñeca. Si fortaleces las muñecas y los antebrazos podrás levantar más peso mientras realizas otros ejercicios.", "La razón por la que no puede levantar el peso del cuerpo puede deberse a la debilidad de las muñecas y los brazos. Agregar ejercicios de muñeca y antebrazo a su programa de entrenamiento creará flexores de muñeca fuertes."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000839661597', 'Curl de muñeca', 'Wrist Curl', 'Antebrazos', '["Es un ejercicio muy eficaz para mejorar la musculatura del antebrazo y la muñeca. Si fortaleces las muñecas y los antebrazos podrás levantar más peso mientras realizas otros ejercicios.", "La razón por la que no puede levantar el peso del cuerpo puede deberse a la debilidad de las muñecas y los brazos. Agregar ejercicios de muñeca y antebrazo a su programa de entrenamiento creará flexores de muñeca fuertes."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001965652174', 'Zancada inversa con mancuernas', 'Dumbbell Reverse Lunge', 'Piernas', '["Sostenga una mancuerna en cada mano, con los brazos completamente extendidos a los lados y las palmas hacia adentro.", "Párate erguido con los pies separados a la altura de las caderas y el core comprometido.", "Da un paso con una pierna hacia atrás y baja el cuerpo doblando ambas rodillas hasta que la rodilla trasera quede justo por encima del suelo.", "Mantenga el torso erguido y el talón delantero apoyado en el suelo mientras desciende.", "Empuja con el pie delantero para volver a la posición inicial.", "Repita con la pierna opuesta, alternando o completando todas las repeticiones en un lado."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001056895291', 'Abducciones de cadera en máquina', 'Hip Abduction Machine', 'Piernas', '["Es eficaz para el desarrollo de los músculos de la cadera y los músculos internos y externos del muslo. La máquina Abduktor es popular entre las mujeres porque permite influir activamente en la forma de la cadera. Puedes incluirlo en tus programas de entrenamiento para moldear y tensar los músculos de la cadera."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000197069745', 'Remo vertical con barra', 'Barbell Upright Row', 'Espalda', '["El remo vertical con barra es un ejercicio de la parte superior del cuerpo que se dirige predominantemente al trapecio y los deltoides, que son responsables de agregar ancho a los hombros. Por lo general, se realiza utilizando una barra estándar o una barra EZ.", "El remo vertical con barra es uno de los ejercicios efectivos para construir trampas más grandes, pero también es un movimiento en el que es fácil cometer errores. Una de las formas más sencillas de asegurarse de que su forma sea óptima es evitar el uso de barras que sean demasiado pesadas."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001722393474', 'Patada de glúteos inclinado', 'Bent Over Kickback', 'Espalda', '["### ", "### Configuración", "- Párate con los pies separados a la altura de los hombros, sosteniendo una mancuerna en cada mano.", "- Gire las caderas y doble ligeramente las rodillas, manteniendo la espalda plana y el pecho erguido.", "- Deje que sus brazos cuelguen naturalmente, luego levante los codos para que la parte superior de sus brazos quede paralela a su torso. Tus codos deben permanecer cerca de tus costillas.", "### Ejecución", "- Desde esta posición inicial, extiende los antebrazos hacia atrás estirando los codos.", "- Concéntrate en apretar los tríceps en la parte superior del movimiento.", "- Haga una pausa breve en extensión completa sin bloquear los codos.", "- Regrese lentamente a la posición inicial doblando los codos.", "- Repita para el número deseado de repeticiones."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001507100651', 'Sentadilla búlgara (Split) con peso corporal', 'Bodyweight Bulgarian Split Squat', 'Piernas', '["### Paso 1: configuración y posicionamiento", "- Párese a unos dos pies frente a un banco o plataforma resistente.", "- Extienda el pie trasero hacia atrás y coloque la parte superior del pie sobre el banco.", "- Mantenga el pecho erguido y el núcleo comprometido.", "### Paso 2: Ejecución", "- Baje la rodilla trasera hacia el suelo doblando la rodilla delantera.", "- Desciende hasta que tu muslo delantero quede paralelo al suelo o ligeramente por debajo.", "- Presione con el talón delantero para volver a la posición inicial.", "- Repita para las repeticiones deseadas antes de cambiar de pierna."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-002124122729', 'Prensa de martillo', 'Hammer Press', 'Pecho', '["Se utiliza una prensa de martillo con mancuernas como una forma de realizar el patrón de movimiento de la prensa, centrándose en el aislamiento de la parte interna del pecho. Es una buena manera de contribuir al desarrollo de los pectorales internos. Puedes poner más énfasis en la parte interna del pecho con ejercicios como el press de martillo."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001713333803', 'Máquina de press de pecho', 'Chest Press Machine', 'Pecho', '["La máquina de press de pecho es un ejercicio preferido por los principiantes ya que se centra en todos los músculos pectorales y proporciona una mayor estabilidad. Dirigido a los pectorales, tríceps y deltoides, el ejercicio con máquina de prensa de pecho ayuda a desarrollar la fuerza de la parte superior del cuerpo y aumentar la masa muscular."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001973413859', 'Extensión de piernas con banda sentado', 'Seated Banded Leg Extension', 'Piernas', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000685556308', 'Plancha lateral con rodilla al codo', 'Side Plank Knee to Elbow', 'Abdomen', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-002070748891', 'Sentadilla sumo con mancuernas', 'Dumbbell Sumo Squat', 'Piernas', '["Párese con los pies más anchos que el ancho de los hombros y los dedos apuntando ligeramente hacia afuera.", "Sostenga una mancuerna verticalmente con ambas manos, dejándola colgar entre sus piernas.", "Involucre su núcleo y mantenga su pecho erguido mientras dobla las rodillas y baja las caderas.", "Desciende hasta que tus muslos queden paralelos al suelo, manteniendo las rodillas alineadas con los dedos de los pies.", "Empuja los talones para levantarte y aprieta los glúteos en la parte superior."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-002031440950', 'Despliegue de abdomen suspensión (TRX)', 'Suspended Ab Fall-out', 'Abdomen', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000052531899', 'Press de suelo con barra', 'Barbell Floor Press', 'Pecho', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
