INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-002002413901', 'Sentadilla pistola con apoyo', 'Supported Pistol Squat', 'Piernas', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000998640670', 'Aperturas de pecho del piso de las Landmine', 'Landmine Floor Chest Fly', 'Pecho', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000463469425', 'Propulsor de barra', 'Barbell Thruster', 'Hombros', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000236757263', 'Extensión de tríceps con banda (agarre neutral)', 'Band Pushdown (Neutral Grip)', 'Otros', '["Ancle una banda de resistencia de forma segura sobre el marco de una puerta o barra de dominadas.", "Agarre las asas o los extremos de la banda con un agarre neutral, con las palmas una frente a la otra.", "Da un paso atrás ligeramente para crear tensión en la banda. Mantenga los codos sujetos a los costados y el pecho erguido.", "Empuje las manijas hacia abajo, extendiendo los brazos hasta que estén completamente estirados sin bloquear los codos.", "Haga una pausa en extensión total para apretar los tríceps.", "Regrese lentamente a la posición inicial bajo control, resistiendo el tirón hacia arriba."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000144327329', 'Tirada con mancuernas', 'Dumbbell Pull Through', 'Espalda', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001367883732', 'Sentadilla jefferson', 'Jefferson Squat', 'Piernas', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001100529918', 'Elevación de pantorrilla en burro a una pierna', 'Single Leg Donkey Calf Raise', 'Pantorrillas', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001216989490', 'Barra EZ Tumbado con agarre cerrado Extensión de tríceps detrás de la cabeza', 'EZ Bar Lying Close Grip Triceps Extension Behind Head', 'Tríceps', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001138895731', 'Prensa de martillo rechazada', 'Decline Hammer Press', 'Pecho', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000963846201', 'Extensión de tríceps por encima de la cabeza en polea alta unilateral', 'One Arm High Pulley Overhead Tricep Extension', 'Tríceps', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001576746319', 'Trituradora de cráneos con agarre inverso y barra', 'Barbell Reverse Grip Skullcrusher', 'Otros', '["- Acuéstese sobre un banco con los pies apoyados en el suelo.", "- Sujete una barra recta o EZ con un agarre por encima del ancho de los hombros.", "- Comience con los brazos extendidos, sosteniendo la barra directamente sobre sus hombros.", "- Manteniendo la parte superior de los brazos perpendicular al banco, doble lentamente los codos para bajar la barra hacia la frente o justo encima de ella.", "- Mantenga los codos doblados y estacionarios durante todo el movimiento.", "- Una vez que alcance una curva de 90 grados o un poco más profunda, presione la barra hacia la posición inicial extendiendo los codos.", "- Repita para el número deseado de repeticiones.", "### Consejos para una forma adecuada", "- Mantenga los codos cerca de la cabeza para evitar la afectación de los hombros.", "- Baje la barra con un movimiento controlado para mantener la tensión y evitar lesiones.", "- Evite dejar que la barra se desplace hacia su pecho o cara.", "- Mantenga las muñecas rectas y estables durante todo el levantamiento.", "- Exhala mientras presionas la barra hacia arriba e inhala mientras la bajas.", "### Errores comunes", "- Permitir que los codos se ensanchen excesivamente.", "- Usar impulso o hacer rebotar la barra en la frente", "- Dejar que las muñecas se doblen hacia atrás, lo que reduce el control y corre el riesgo de sufrir tensión.", "- Bajar la barra hacia el pecho en lugar de hacia la frente, lo que desvía el énfasis del tríceps.", "- Usar demasiado peso y comprometer el rango de movimiento o la forma."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001258186360', 'Curl de bíceps con barra EZ y agarre inverso en polea', 'Cable Reverse Grip EZ-bar Biceps Curl', 'Bíceps', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001622134450', 'Extensión de tríceps con barra recostada hacia atrás de la cabeza', 'Barbell Lying Back of the Head Tricep Extension', 'Tríceps', '["- Acuéstese sobre un banco plano, con los pies apoyados en el suelo.", "- Sujete una barra EZ o una barra recta con un agarre en pronación al ancho de los hombros (con las palmas hacia abajo).", "- Comience con los brazos completamente extendidos, sosteniendo la barra directamente sobre sus hombros.", "- Manteniendo los codos apuntando hacia arriba y pegados a la cabeza, doble lentamente los codos para bajar la barra formando un arco detrás de la cabeza.", "- La parte superior de tus brazos debe permanecer estacionaria y perpendicular al suelo.", "- Baje la barra tan atrás como le resulte cómodo, idealmente hasta que esté al nivel o ligeramente por debajo de la altura del banco.", "- Involucre los tríceps para presionar la barra de regreso a la posición inicial sin mover los hombros ni ensanchar los codos.", "- Repita para las repeticiones deseadas.", "### Consejos para una forma adecuada", "- Mantenga los codos estables y cerca de la cabeza durante todo el movimiento.", "- Concéntrese en moverse solo en la articulación del codo para evitar utilizar el impulso.", "- Baje la barra con un movimiento lento y controlado para maximizar el estiramiento.", "- Evite dejar que la barra se desplace demasiado hacia atrás, lo que puede tensar los hombros.", "- Utilice un observador si levanta objetos pesados ​​o si es nuevo en el movimiento.", "### Errores comunes", "- Ensanchando los codos hacia afuera, reduciendo el aislamiento del tríceps.", "- Usar peso excesivo y acortar el rango de movimiento.", "- Permitir que la barra caiga directamente hacia la cara en lugar de detrás de la cabeza.", "- Arquear la espalda baja o moverse en el banco", "- Hacer rebotar la barra fuera de la posición estirada en lugar de controlar el movimiento."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001299802648', 'Cable Cuerda Tumbado Extensión De Tríceps', 'Cable Rope Lying Tricep Extension', 'Tríceps', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000877188244', 'Extensión de tríceps con peso corporal (Skullcrushers)', 'Bodyweight Skull Crushers', 'Otros', '["### Paso 1: configuración", "- Busque una barra estable (como una máquina Smith, una rejilla para sentadillas o barras paralelas).", "- Ajuste la altura de la barra según su nivel de fuerza: las barras más altas son más fáciles y las barras más bajas aumentan la dificultad.", "- Párese frente a la barra, sujétela con un agarre por encima del ancho de los hombros y retroceda a una posición de tabla diagonal.", "### Paso 2: Fase de descenso", "- Mantenga el cuerpo recto desde la cabeza hasta los talones, involucrando el núcleo y los glúteos.", "- Doble los codos y baje la cabeza hacia la barra.", "- Baja bajo control hasta que tu frente esté justo por encima de la barra.", "### Paso 3: Fase de prensado", "- Empuja tus tríceps, extendiendo los codos para volver a la posición inicial.", "- Mantenga los codos cerca del cuerpo para maximizar la activación de los tríceps.", "- Repita para las repeticiones deseadas, manteniendo la forma adecuada en todo momento."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000174992876', 'Extensión alterna de tríceps acostado con mancuernas', 'Alternating Lying Dumbbell Triceps Extension', 'Tríceps', '["Acuéstese en un banco con una mancuerna en cada mano. Extienda ambos brazos rectos sobre el pecho, con las palmas una frente a la otra. Mantenga los codos pegados al torso.", "Acuéstese en un banco con una mancuerna en cada mano.", "Extienda ambos brazos rectos sobre su pecho, con las palmas una frente a la otra.", "Mantenga los codos pegados al torso.", "Ejecución: Baje una mancuerna doblando el codo, llevándolo hacia la oreja o al nivel del hombro. Mantenga la parte superior del brazo inmóvil y perpendicular al suelo. Extienda el brazo hacia la posición inicial contrayendo el tríceps. Repita en el lado opuesto, alternando los brazos en cada repetición. Complete las repeticiones prescritas para ambos brazos.", "Baje una mancuerna doblando el codo y acercándolo al nivel de la oreja o del hombro.", "Mantenga la parte superior del brazo fija y perpendicular al suelo.", "Extiende el brazo de regreso a la posición inicial contrayendo el tríceps.", "Repita en el lado opuesto, alternando brazos en cada repetición.", "Complete las repeticiones prescritas para ambos brazos.", "Respiración: Inhale mientras baja la mancuerna. Exhale mientras extiende el brazo hacia arriba.", "Inhala mientras bajas la mancuerna.", "Exhala mientras extiendes el brazo hacia arriba."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001674327713', 'Extensión de tríceps tendido en polea', 'Cable Lying Triceps Extension', 'Tríceps', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000647734271', 'Pushdown inverso lateral unilateral', 'Side One Arm Reverse Pushdown', 'Otros', '["Párese perpendicular a la máquina de cable, con el hombro izquierdo alineado con la máquina.", "Agarre el mango con la mano derecha, con la palma hacia arriba (agarre en supinación), formando un ángulo de 90 grados frente a su cuerpo. Esta posición le sirve como punto de partida.", "Coloque los pies separados a la altura de los hombros, las rodillas ligeramente dobladas y mantenga una postura estable.", "Involucre sus músculos centrales para lograr estabilidad y mantenga su torso erguido durante todo el movimiento.", "Exhale y comience el ejercicio extendiendo el brazo derecho hacia abajo, empujando el mango hacia el suelo.", "Concéntrate en contraer completamente los tríceps en la parte inferior del movimiento mientras mantienes el control.", "Inhale mientras regresa lentamente a la posición inicial, resistiendo el tirón del peso y manteniendo un movimiento controlado.", "Repita hasta el número deseado de repeticiones en un brazo antes de cambiar al otro brazo."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000378562496', 'Extensión de tríceps cruzada en polea', 'Cable Crossover Triceps Extension', 'Tríceps', '["- Coloque ambas poleas en la posición más alta en una máquina de cruce de cables.", "- Conecte manijas en D individuales a cada cable.", "- Párese en el centro de la máquina y agarre un mango en cada mano con un agarre neutral (con las palmas hacia abajo o ligeramente hacia adentro).", "- Da un paso ligeramente hacia adelante con un pie para mantener el equilibrio e inclínate hacia adelante a la altura de las caderas para alinear los brazos en diagonal con los cables.", "- Comience con los codos doblados y los brazos colocados hacia afuera aproximadamente a la altura de la cabeza.", "- Mientras mantiene los codos fijos en su lugar y la parte superior de los brazos inclinada hacia adelante, extienda ambos brazos hacia abajo y ligeramente hacia adentro frente a su cuerpo.", "- Apriete el tríceps en extensión completa con las manos cerca de la altura de la cadera o delante de los muslos.", "- Vuelva lentamente a la posición inicial bajo control, resistiendo la tensión del cable.", "- Repita para las repeticiones deseadas.", "### Consejos para una forma adecuada", "- Mantenga una ligera inclinación hacia adelante para mantener una tensión constante en los tríceps.", "- Bloquee los codos en posición durante toda la serie para evitar la asistencia de los hombros.", "- Mantenga una columna neutra y evite inclinarse o encogerse de hombros excesivamente.", "- Concéntrese en apretar completamente en la parte inferior y estirar completamente en la parte superior de cada repetición.", "- No deje que los brazos se desplacen demasiado detrás de la cabeza, lo que puede generar tensión en los hombros.", "### Errores comunes", "- Dejar que los codos se abran o se muevan durante la extensión.", "- Inclinarse excesivamente hacia atrás y convertirlo en un movimiento lateral.", "- Usar demasiado peso y comprometer el rango de movimiento", "- No controlar la parte excéntrica de la repetición.", "- Empezando con las manos demasiado bajas, reduciendo el estiramiento en la cabeza larga."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000566423038', 'Extensión de tríceps con barra acostada y agarre cerrado', 'Barbell Lying Close grip Triceps Extension', 'Tríceps', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000031982949', 'Extensión de tríceps en polea de rodillas', 'Kneeling Cable Triceps Extension', 'Tríceps', '["Configuración: Sujete una cuerda o una barra recta a una polea alta. Arrodíllese unos metros frente a la máquina de cable, de espaldas a ella. Sujete las manijas con ambas manos y llévelas detrás de la cabeza. Los codos deben estar doblados, apuntando hacia arriba, con la parte superior de los brazos cerca de las orejas. Mantenga la espalda recta y el core enganchado.", "Conecte una cuerda o una barra recta a una polea alta.", "Arrodíllese unos metros frente a la máquina de cable, de espaldas a ella.", "Sujete las asas con ambas manos y llévelas detrás de la cabeza.", "Los codos deben estar doblados, apuntando hacia arriba, con la parte superior de los brazos cerca de las orejas.", "Mantenga la espalda recta y el core comprometido.", "Ejecución:Extiende los brazos hacia adelante y ligeramente hacia arriba enderezando los codos.Aprieta los tríceps en la parte superior del movimiento.Vuelve lentamente a la posición inicial con control.Repite durante el número de repeticiones deseadas.", "Extiende los brazos hacia adelante y ligeramente hacia arriba enderezando los codos.", "Aprieta el tríceps en la parte superior del movimiento.", "Regrese lentamente a la posición inicial con control.", "Repita para el número deseado de repeticiones.", "Respiración: Inhale durante la fase excéntrica (de descenso). Exhale mientras extiende y presiona las manijas hacia adelante.", "Inhale durante la fase excéntrica (de descenso).", "Exhala mientras extiendes y presionas las manijas hacia adelante."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000870721471', 'Glute Ham Raise (Femorales)', 'Glute Ham Raise', 'Piernas', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000437446451', 'Extensión de tríceps en polea con barra en V', 'V-bar Cable Triceps Pushdown', 'Tríceps', '["- Configure la máquina de cable: conecte la barra en V a la polea alta. Ajuste la pila de pesas a un nivel de resistencia apropiado.", "- Párese erguido y agarre la barra: mire hacia la máquina de cable y agarre la barra en V con ambas manos usando un agarre neutral, con los codos pegados a los costados.", "- Coloque su cuerpo: mantenga el pecho erguido, el núcleo reforzado y los pies separados a la altura de los hombros. Inclínese ligeramente hacia adelante para estabilizar su cuerpo.", "- Empuje la barra hacia abajo: presione la barra hacia abajo extendiendo los codos y manteniendo la parte superior de los brazos inmóviles. Aprieta los tríceps en la parte inferior del movimiento.", "- Controle el retorno: permita que la barra regrese lentamente a la posición inicial sin dejar que los codos se desplacen hacia adelante. Mantenga la tensión en los tríceps en todo momento.", "### Consejos para una forma adecuada", "- Mantenga los codos apretados: sus codos deben permanecer cerca de los costados durante todo el movimiento para aislar completamente los tríceps.", "- Utilice un rango completo de movimiento: extiéndase completamente en la parte inferior y vuelva a estar bajo control para una activación máxima.", "- Refuerza tu núcleo: involucra tu núcleo y tus glúteos para evitar usar el impulso o inclinarte hacia atrás.", "- Evite la flexión de muñecas: mantenga las muñecas rectas y neutrales durante todo el movimiento.", "- Exhala al empujar: exhala mientras presionas la barra hacia abajo e inhala mientras regresas a la cima.", "### Errores comunes", "- Codos ensanchados: esto reduce la tensión en los tríceps y puede trasladar la tensión a los hombros.", "- Usar el impulso: balancear el torso o usar el peso corporal reduce la participación de los músculos y aumenta el riesgo de lesiones.", "- Medias repeticiones: No extender completamente o regresar por debajo del máximo limita la efectividad.", "- Ubicación incorrecta del agarre: Mantener la barra en V demasiado cerca o demasiado abierta puede afectar la comodidad de la muñeca y la activación del tríceps.", "- Bloquear agresivamente: chasquear los codos en la parte inferior puede causar molestias en las articulaciones con el tiempo."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000770367908', 'Press de banca inverso con agarre cerrado', 'Close-Grip Reverse Bench Press', 'Pecho', '["Configuración: Acuéstese en un banco con los pies firmemente plantados en el suelo. Colóquese debajo de un soporte para barra y ajuste la barra para que esté a una altura cómoda y al alcance de su brazo.", "Acuéstese sobre un banco con los pies firmemente plantados en el suelo.", "Colóquese debajo de un soporte para barra y ajuste la barra para que esté a una altura cómoda y al alcance de la mano.", "Agarre y colocación de las manos: Levante y agarre la barra con ambas manos usando un agarre por debajo, también conocido como agarre supinado. Esto significa que las palmas de las manos deben mirar hacia la cabeza y los dedos deben estar alrededor de la barra.", "Levante y agarre la barra con ambas manos usando un agarre por debajo, también conocido como agarre supinado. Esto significa que las palmas de las manos deben mirar hacia la cabeza y los dedos deben estar alrededor de la barra.", "Posición inicial: levante la barra del soporte y sosténgala directamente sobre su pecho con los brazos completamente extendidos.", "Levante la barra del soporte y sosténgala directamente sobre su pecho con los brazos completamente extendidos.", "Ejecución: Inhala y baja la barra hacia tu pecho de forma controlada. Mantenga los codos cerca del cuerpo mientras baja la barra. Baje la barra hasta que toque su pecho o se acerque a él, mientras mantiene un ligero arco en la zona lumbar.", "Inhala y baja la barra hacia tu pecho de forma controlada. Mantenga los codos cerca de su cuerpo mientras baja la barra.", "Baja la barra hasta que toque tu pecho o se acerque a él, manteniendo un ligero arco en la zona lumbar.", "Fase de empuje: Exhala y empuja la barra hacia arriba hasta la posición inicial extendiendo los brazos. Concéntrate en usar tus tríceps para realizar el movimiento.", "Exhala y empuja la barra hacia arriba hasta la posición inicial extendiendo los brazos. Concéntrate en usar tus tríceps para realizar el movimiento.", "Repetir: Realice el número deseado de repeticiones manteniendo la forma y el control adecuados.", "Realice el número deseado de repeticiones manteniendo la forma y el control adecuados."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001085296033', 'Press de banca inverso con agarre ancho', 'Wide-Grip Reverse Bench Press', 'Pecho', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
