INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001630722047', 'Banda de resistencia doblada sobre la aperturas deltónica trasera', 'Resistance Band Bent Over Rear Delt Fly', 'Hombros', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000839570126', 'Columpio con pesa rusa a un brazo', 'One Arm Kettlebell Swing', 'Hombros', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000926666240', 'Plancha a horcajadas', 'Straddle Planche', 'Abdomen', '["- Comience en una posición de flexión con las manos ligeramente hacia afuera para comodidad de la muñeca.", "- Incline su cuerpo hacia adelante mientras contrae los glúteos, el core y los cuádriceps.", "- Poco a poco, levante los pies del suelo mientras extiende las piernas hacia afuera hasta quedar a horcajadas.", "- Mantenga una línea recta desde los hombros hasta los pies mientras equilibra su cuerpo horizontalmente.", "- Mantenga la posición el mayor tiempo posible con control, luego regrese al inicio.", "### Consejos para una forma adecuada", "- Mantenga los brazos completamente bloqueados para evitar tensión en los codos.", "- Prolonga los omóplatos empujando el suelo.", "- Involucre todo su núcleo para evitar la flacidez en las caderas.", "- Concéntrese en la respiración lenta para mantener el control y el equilibrio.", "### Errores comunes", "- Doblar los codos y no mantener el bloqueo del brazo.", "- Dejar que las caderas caigan por debajo del nivel de los hombros.", "- Arquear la espalda baja debido a una activación débil del core", "- Depender del impulso para llegar a la posición en lugar del control."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000665174135', 'Abdominales de mariposa', 'Butterfly Sit-up', 'Pecho', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-002120961490', 'Círculos de cadera (Movilidad)', 'Hip Circles', 'Piernas', '["Párese erguido con las manos en las caderas, las piernas estiradas y los pies separados a la altura de los hombros.", "Comience a rotar las caderas lentamente en el sentido de las agujas del reloj. Mantenga la espalda recta.", "Continúe la rotación de regreso a la posición inicial con un movimiento suave y controlado."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000011484329', 'Estiramiento de hombros inverso de pie', 'Standing Reverse Shoulder Stretch', 'Hombros', '["Los estiramientos de hombros pueden ayudar a aliviar la tensión muscular, el dolor y la tirantez en el cuello y los hombros. Incluir ejercicios y estiramientos específicos para los hombros en su programa de entrenamiento general puede ayudar a aumentar la movilidad y flexibilidad de los hombros. Estos movimientos también pueden fortalecer los hombros, mejorar su función y prevenir lesiones."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000934949499', 'Plancha lateral con rotación de tronco', 'Side Plank Rotation', 'Abdomen', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001165665086', 'Sentadilla por encima de la cabeza con banda de resistencia', 'Resistance Band Overhead Squat', 'Piernas', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
