INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001826166002', 'Deslizamientos de talón en el suelo', 'Hell Slide', 'Abdomen', '["Este movimiento simple y relativamente suave es un buen ejercicio para mejorar la fuerza y ​​la movilidad de los músculos de la cadera y la pelvis. Recuerda siempre realizar la misma cantidad de repeticiones para cada pierna."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001437193496', 'Vacío abdominal en prono (acostado boca abajo)', 'Prone Abdominal Hollowing', 'Abdomen', '["Este sencillo ejercicio le ayuda a desarrollar una buena fuerza y ​​control del suelo pélvico, el transverso del abdomen y los músculos estabilizadores de la columna. Aumente gradualmente el número de repeticiones a medida que avance."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000253612417', 'Estiramiento de hombros y pectorales en la entrada', 'Doorway Pec and Shoulder Stretch', 'Hombros', '["Párese frente a una puerta abierta.", "Levanta los brazos y coloca las manos en el marco de la puerta.", "Da un pequeño paso hacia adelante, inclinando suavemente el peso de tu cuerpo hacia el estiramiento.", "Deberías sentir un estiramiento en el pecho y la parte delantera de los hombros.", "Mantenga el estiramiento durante 15 a 30 segundos, mientras mantiene un patrón de respiración relajado.", "Da un paso atrás lentamente para liberar el estiramiento.", "Repita el estiramiento durante 2 o 3 series."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000082515741', 'Separación de la banda de resistencia', 'Resistance Band Pull Apart', 'Hombros', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
