INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001248448040', 'Crunch con balón medicinal', 'Medicine Ball Crunch', 'Cardio', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-002039315337', 'Flexión dedos', 'Finger Push-up', 'Pecho', '["Comience en una posición de flexión: comience en una posición de flexión con las palmas de las manos en el suelo, los dedos apuntando hacia adelante y el cuerpo en línea recta.", "Coloque las yemas de los dedos: levante lentamente las palmas del suelo y equilibre su peso sobre las yemas de los dedos, manteniendo las muñecas rectas. Cambie su peso hacia las yemas de los dedos, asegurándose de que las palmas ya no toquen el suelo.", "Baja el cuerpo: Doble lentamente los codos y baje el cuerpo hacia el suelo, manteniendo el cuerpo en línea recta.", "Empuje hacia arriba: una vez que su pecho esté cerca del suelo, empuje hacia atrás hasta la posición inicial estirando los brazos.", "Repetir: repita el ejercicio durante la cantidad deseada de repeticiones, asegurándose de mantener la forma adecuada durante todo el movimiento."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001490645823', 'Hip thrust en máquina Smith', 'Smith Machine Hip Thrust', 'Piernas', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001074044239', 'Flexiones de arquero', 'Archer Push-Up', 'Pecho', '["### ", "- Comience en una posición de flexión amplia: comience en una posición de flexión con las manos colocadas más anchas que el ancho de los hombros. Gire los dedos ligeramente hacia afuera.", "- Cambie su peso hacia un lado: baje el pecho hacia el brazo que trabaja, doblando el codo mientras el brazo opuesto permanece extendido y recto.", "- Mantenga el otro brazo recto: a medida que desciende, su brazo extendido debe permanecer recto y actuar como una viga de soporte, deslizándose hacia afuera por el suelo.", "- Alcance un rango completo de movimiento: baje hasta que su pecho casi toque la mano del lado de trabajo mientras mantiene su núcleo apretado y la espalda plana.", "- Empuje hacia atrás hacia la cima: conduzca a través del brazo de trabajo para regresar a la posición inicial, luego repita en el mismo lado o en lados alternos.", "### Consejos para una forma adecuada", "- Mantenga las caderas cuadradas: mantenga la alineación para evitar girar el torso.", "- Controla el descenso: Muévete lenta y deliberadamente para maximizar el tiempo bajo tensión.", "- Refuerza tu núcleo: contrae tus abdominales para mantener una línea recta desde la cabeza hasta los talones.", "- Mantenga activo el brazo extendido: no lo deje flácido. Mantenga la tensión para el equilibrio y la estabilidad.", "- Respire rítmicamente: inhale mientras baja y exhale mientras presiona hacia arriba.", "### Errores comunes", "- Rotar el torso: Girar durante el empujón reduce el efecto unilateral y tensa la columna.", "- No bajar lo suficiente: las repeticiones superficiales reducen las ganancias de fuerza y ​​pierden el estiramiento completo.", "- Dejar que las caderas se hunda: Las caderas caídas pueden comprometer el compromiso central y provocar tensión en la espalda baja.", "- Doblar el brazo de soporte: Mantenga recto el brazo que no funciona para garantizar una mecánica adecuada.", "- Ritmo desigual: Apresurarse en las repeticiones de un lado puede crear desequilibrios de fuerza."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000741828692', 'Flexiones en plancha completa (Full Planche Push-Ups)', 'Full Planche Push-Up', 'Pecho', '["- Comience con una posición de plancha completa: comience con el cuerpo paralelo al suelo, los brazos rectos, los hombros extendidos y los pies alejados del suelo. Mantén todo tu cuerpo rígido.", "- Bajar bajo control: doble lentamente los codos para bajar el pecho más cerca del suelo, manteniendo la posición del cuerpo recto. No dejes caer tus caderas.", "- Mantenga los codos cerrados: a medida que desciende, asegúrese de que los codos permanezcan doblados hacia el torso. Esto protege sus articulaciones y mantiene el movimiento eficiente.", "- Presione hacia arriba: una vez que su pecho se acerque al piso, empuje con las palmas y estire los codos para volver a la posición de plancha completa.", "- Mantenga la tensión de todo el cuerpo: durante todo el movimiento, mantenga los glúteos, los abdominales y los cuádriceps contraídos para mantener una línea recta y horizontal.", "### Consejos para una forma adecuada", "- Prolonga los hombros: empuja activamente los hombros hacia adelante para estabilizar las escápulas y proteger la articulación del hombro.", "- Mantenga el núcleo apretado: contraiga los abdominales y la espalda baja para evitar que las caderas caigan durante la flexión.", "- Mire ligeramente hacia adelante: mire hacia adelante para mantener la alineación y el equilibrio del cuello.", "- Controla el tempo: Realiza el movimiento lentamente y con control para evitar compensaciones de impulso.", "- Calienta bien: asegúrate de que tus muñecas, hombros y núcleo estén completamente activados antes de intentarlo.", "### Errores comunes", "- Permitir que las caderas se doblen: Dejar que las caderas caigan rompe la forma y genera una tensión innecesaria en la columna.", "- Doblar las rodillas: mantenga las piernas estiradas y juntas para mantener la alineación de todo el cuerpo.", "- Codos ensanchados: Los codos que apuntan hacia afuera pueden aumentar la tensión en los hombros y reducir la eficiencia mecánica.", "- Protracción inadecuada del hombro: Sin una posición escapular adecuada, el ejercicio se vuelve inestable e inseguro.", "- Saltarse progresiones: intentar hacer flexiones en plancha completa sin dominar los pasos anteriores puede provocar lesiones."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000757316377', 'Aperturas de pecho alterna con banda de resistencia', 'Resistance Band Alternating Chest Fly', 'Pecho', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
