INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001250410707', 'Empuje de cadera con banda de resistencia', 'Resistance Band Hip Thrust', 'Piernas', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000105642519', 'Empujes de cadera con banda de resistencia sobre las rodillas', 'Resistance Band Hip Thrusts on Knees', 'Piernas', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-002013238593', 'Flexión de nudillos', 'Knuckle Push-Up', 'Pecho', '["Posición inicial: Comience en una posición estándar de flexión de brazos con las manos ligeramente más separadas que el ancho de los hombros. En lugar de colocar las palmas de las manos en el suelo, cierre los puños con las manos, con los nudillos hacia abajo y los pulgares fuera de los puños.", "Comience en una posición de flexión estándar con las manos ligeramente más separadas que el ancho de los hombros.", "En lugar de colocar las palmas de las manos sobre el suelo, forme puños con las manos, con los nudillos hacia abajo y los pulgares fuera de los puños.", "El descenso: Baje el cuerpo hacia el suelo doblando los codos mientras mantiene los puños en contacto con el suelo. Mantenga el cuerpo en línea recta desde la cabeza hasta los talones, manteniendo la forma adecuada de flexión.", "Baje su cuerpo hacia el suelo doblando los codos mientras mantiene los puños en contacto con el suelo.", "Mantenga su cuerpo en línea recta desde la cabeza hasta los talones, manteniendo la forma adecuada de flexión.", "El ascenso: Empuje su cuerpo hacia la posición inicial estirando los brazos mientras sigue usando los nudillos como apoyo. Extienda completamente los codos sin bloquearlos en la parte superior del movimiento.", "Empuje su cuerpo hacia atrás a la posición inicial estirando los brazos mientras sigue usando los nudillos como apoyo.", "Extiende completamente los codos sin bloquearlos en la parte superior del movimiento.", "Repetir: Realice múltiples repeticiones de flexiones de nudillos, concentrándose en mantener una buena forma en todo momento.", "Realice múltiples repeticiones de flexiones de nudillos, concentrándose en mantener una buena forma en todo momento."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001458288158', 'Flexiones con pelota Bosu', 'Bosu Ball Push-Up', 'Pecho', '["### Posición inicial:", "- Coloque la bola Bosu con el lado de la cúpula hacia abajo en el suelo.", "- Coloque las manos en la plataforma plana, ligeramente más separadas que el ancho de los hombros.", "- Extienda las piernas detrás de usted en una posición de flexión estándar, asegurándose de que su cuerpo forme una línea recta desde la cabeza hasta los talones.", "- Involucre su núcleo para mantener la estabilidad.", "### Ejecución:", "- Bajar: Doble lentamente los codos, bajando el pecho hacia la pelota Bosu mientras mantiene el control y la alineación.", "- Posición inferior: bájese hasta que su pecho esté cerca o toque ligeramente la pelota Bosu.", "- Empujar hacia arriba: presione con las manos para enderezar los codos y regrese a la posición inicial. Mantenga su núcleo comprometido y sus movimientos controlados.", "- Repetición: Repita hasta el número deseado de repeticiones.", "### Consideraciones importantes:", "- Equilibrio: La pelota Bosu introduce inestabilidad, así que concéntrate en mantener el equilibrio y el control. Los principiantes pueden comenzar con una colocación más amplia de las manos para mayor estabilidad.", "- Compromiso central: mantenga su núcleo activado durante todo el ejercicio para evitar que las caderas se caigan y mejorar la estabilidad.", "- Alineación del cuerpo: Mantenga una línea recta desde la cabeza hasta los talones. Evite arquear la espalda o dejar caer las caderas.", "- Movimientos controlados: realice el ejercicio de forma lenta y deliberada, evitando el impulso o las repeticiones apresuradas.", "- Posición de la muñeca: asegúrese de que sus muñecas estén directamente debajo de los hombros para reducir la tensión y mejorar la alineación de las articulaciones.", "### Progresión y modificaciones:", "- Realiza flexiones con las rodillas en el suelo para reducir la intensidad.", "- Coloque las manos en el suelo y los pies sobre la pelota Bosu para un desafío alternativo."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
