INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000436259942', 'Bicicleta estática reclinada', 'Recumbent Exercise Bike', 'Cardio', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-002049243848', 'Fondos en anillas', 'Ring Dips', 'Pecho', '["### ", "- Coloque los anillos a la altura del pecho: ajuste los anillos de gimnasia para que cuelguen al nivel del pecho y estén bien sujetos.", "- Monte los anillos: salte o dé un paso en una posición de apoyo, con los brazos rectos, el cuerpo erguido y los anillos cerca de los costados.", "- Bájate con control: dobla los codos e inclínate ligeramente hacia adelante mientras bajas el pecho entre los anillos. Mantenga los codos en un ángulo de aproximadamente 45 grados.", "- Descienda por debajo del nivel del anillo: baje hasta que los hombros caigan justo debajo de los codos, manteniendo la tensión en el pecho y los brazos.", "- Empuje hacia arriba: presione con las palmas y estire los brazos para volver a la posición inicial, bloqueando la parte superior mientras mantiene los anillos cerca.", "### Errores comunes", "- Dejar que los anillos se salgan: Permitir que los anillos se alejen del cuerpo aumenta la inestabilidad y puede provocar una mala forma o lesiones.", "- No profundizar lo suficiente: no bajar por debajo del paralelo limita el rango de movimiento y reduce la activación muscular.", "- Perder la tensión central: Dejar que las caderas se hundan o las piernas se balanceen compromete el equilibrio y la eficacia.", "- Codos ensanchados: Los codos excesivamente ensanchados ejercen una tensión innecesaria en las articulaciones de los hombros.", "- Acelerar el movimiento: utilizar el impulso reduce el desarrollo de la fuerza y ​​aumenta el riesgo de error.", "### Errores comunes a evitar", "- Inclinarse demasiado hacia adelante, lo que hace que la atención se centre en el pecho en lugar de en los tríceps.", "- Ensanchando los codos hacia afuera, reduciendo la activación de los tríceps y aumentando el riesgo de lesiones.", "- No bajar lo suficiente, limitando el rango de movimiento y la efectividad.", "- Usar el impulso, en lugar de movimientos controlados para el compromiso muscular.", "- Bloquear los codos, lo que puede generar una tensión excesiva en las articulaciones."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001666487095', 'Flexiones suspendidas', 'Suspended Push-Up', 'Pecho', '["### ", "- Configure su entrenador de suspensión: ajuste las correas o anillos TRX de modo que las manijas cuelguen justo por encima del suelo a la altura de la espinilla.", "- Ponte en posición de flexión: coloca las manos en las manijas o anillos, luego camina con los pies hacia atrás para formar una tabla. Tus brazos deben estar completamente extendidos, con las muñecas debajo de los hombros.", "- Apoye su núcleo: mantenga la columna neutra, las caderas niveladas y los glúteos comprometidos para resistir el balanceo.", "- Baje el pecho: doble los codos para bajar el pecho entre las manijas, manteniéndolas en un ángulo de 45 grados con respecto al torso.", "- Empuje hacia arriba: Conduzca a través de las palmas de las manos para volver a la posición superior, extendiendo completamente los codos mientras mantiene estables las anillas o correas.", "### Consejos para una forma adecuada", "- Mantenga su núcleo apretado: evite el balanceo fortaleciendo sus abdominales y glúteos durante todo el movimiento.", "- Controla tu descenso: Muévete lenta y deliberadamente para no perder el equilibrio.", "- Alinee sus muñecas y codos: mantenga los codos en una trayectoria de 45 grados para proteger sus hombros.", "- Estabiliza las correas: Intenta evitar que las asas o anillas se separen durante el movimiento.", "- Mantenga la tensión corporal: Mantenga una línea recta desde la cabeza hasta los talones sin caer en las caderas.", "### Errores comunes", "- Dejar que las correas se separen: esto crea inestabilidad y desplaza la carga de manera incorrecta.", "- Caderas caídas: un compromiso central débil puede provocar que la zona lumbar colapse.", "- Encogerse de hombros: esto provoca una mala mecánica y tensión en los hombros.", "- Perder alineación: Permitir que las manos se eleven demasiado o bajen demasiado afecta la tensión y la forma.", "- Apresurar la repetición: los movimientos rápidos reducen el control y aumentan el riesgo de lesiones."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000853057250', 'Flexiones con elevación unilateral', 'Single Arm Raise Push-up', 'Pecho', '["### ", "- Ponte en posición de flexión: comienza en una tabla alta con las manos debajo de los hombros, los pies un poco más anchos de lo habitual para mantener el equilibrio y el cuerpo en línea recta.", "- Bájese: realice una flexión de brazos estándar, bajando el pecho hacia el suelo mientras mantiene los codos en un ángulo de 45 grados.", "- Press Back Up: empuja con las palmas de las manos para volver a la parte superior del movimiento, manteniendo el core apretado.", "- Levante un brazo: en la parte superior, levante una mano del suelo y extiéndala hacia adelante, hacia un lado o ligeramente por encima, según su nivel de habilidad.", "- Mantenga brevemente: haga una pausa de uno o dos segundos mientras mantiene el cuerpo rígido, luego regrese la mano al suelo y repita del otro lado.", "### Consejos para una forma adecuada", "- Mantenga su cuerpo cuadrado: evite rotar las caderas o los hombros durante la elevación del brazo.", "- Ensancha tus pies: una postura más amplia mejora el equilibrio durante el apoyo con un solo brazo.", "- Involucre su núcleo: contraiga sus abdominales y glúteos para mantener una posición de tabla fuerte.", "- Utilice movimientos controlados: evite movimientos bruscos al levantar la mano para mantener la estabilidad.", "- Mire un poco hacia adelante: mantener el cuello neutral favorece la alineación y la postura de la columna.", "### Errores comunes", "- Dejar que las caderas giren: Rotar o hundir las caderas reduce el desafío central y el entrenamiento de estabilidad.", "- Encogerse de hombros: perder tensión en la cintura escapular durante la elevación puede provocar una mala alineación.", "- Levantar el brazo demasiado rápido: los levantamientos repentinos del brazo pueden desequilibrar y reducir el control.", "- Arqueando la zona lumbar: mantenga el core comprometido para evitar la extensión lumbar.", "- Trayectoria inconsistente del brazo: Levantar el brazo demasiado o en diferentes direcciones en cada repetición puede reducir la efectividad."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000199021072', 'Flexiones con mancuernas con agarre cerrado', 'Close-grip Dumbbell Push-Up', 'Pecho', '["### ", "- Configure su mancuerna: coloque una mancuerna en posición vertical en el piso de modo que el mango quede vertical y sea fácil de agarrar con ambas manos. Una mancuerna hexagonal o de goma es lo mejor para la estabilidad.", "- Agarre el mango: Sostenga el mango con ambas manos, apilándolas de forma segura alrededor del centro. Coloque sus pulgares alrededor de la parte superior para mayor control.", "- Extiende a la posición de tabla: da un paso con los pies hacia atrás para que tu cuerpo forme una línea recta desde la cabeza hasta los talones, con los hombros apilados directamente sobre la mancuerna.", "- Baje el cuerpo: doble los codos y manténgalos cerca de las costillas mientras baja el pecho hacia las manos. Mantenga su núcleo apretado para evitar hundirse.", "- Empuje hacia arriba: presione a través de la mancuerna para volver a la posición superior, extendiendo completamente los codos mientras mantiene estable la mancuerna.", "### Consejos para una forma adecuada", "- Utilice una mancuerna estable: elija una mancuerna con una base plana para evitar que ruede o se incline.", "- Mantenga los codos cerca: mantenga una trayectoria estrecha para enfatizar los tríceps y proteger los hombros.", "- Apoye su núcleo: contraiga sus abdominales y glúteos para evitar la flacidez de la cadera o el arco de la espalda.", "- Agarre seguro: envuelva sus manos firmemente alrededor del mango de la mancuerna para mayor estabilidad.", "- Muévete con control: baja y empuja con repeticiones lentas y controladas para una mejor activación muscular.", "### Errores comunes", "- Elección de mancuernas inestables: el uso de mancuernas redondas aumenta el riesgo de vuelco.", "- Ensanchar los codos: reduce la concentración del tríceps y tensa la articulación del hombro.", "- Dejar caer las caderas: un control deficiente del núcleo puede provocar tensión en la espalda baja.", "- Repeticiones parciales: no bajar completamente limita la participación de los músculos y el rango de movimiento.", "- Acelerar el movimiento: las repeticiones rápidas pueden alterar la alineación y el control."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-000817275062', 'Elevación frontal alternativa sentado con mancuernas', 'Dumbbell Seated Alternate Front Raise', 'Hombros', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001980408448', 'Curl de muñeca inverso con barra sobre un banco', 'Barbell Reverse Wrist Curl Over a Bench', 'Antebrazos', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001827323650', 'Aducción de cadera acostada de lado', 'Side Lying Hip Adduction', 'Piernas', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001404440576', 'Flexiones unilateral sobre un balón medicinal', 'Single-Arm Push-Up on a Medicine Ball', 'Pecho', '["### ", "- Coloque un balón medicinal firme en el suelo y arrodíllese junto a él. Utilice una pelota antideslizante de tamaño mediano a grande como apoyo.", "- Coloque una mano directamente encima de la pelota, con los dedos extendidos para agarrarla y la muñeca apilada debajo del hombro.", "- Extiende ambas piernas hacia atrás formando una tabla. Coloque los pies ligeramente más anchos que el ancho de las caderas para mantener el equilibrio.", "- Coloque el brazo que no trabaja detrás de la espalda, con la palma apoyada ligeramente en la parte baja de la espalda o en el glúteo opuesto.", "- Baje el pecho lentamente, doblando solo el brazo que trabaja. Mantenga el codo metido hacia adentro y el cuerpo alineado desde la cabeza hasta el talón.", "- Empuja hacia arriba a través de la pelota para regresar a la posición superior sin dejar que tu cuerpo gire o gire.", "### Consejos para una forma adecuada", "- Amplíe su postura: una base de apoyo más amplia ayuda a equilibrar la carga.", "- Involucre todo su núcleo: evita que el torso gire o se hunda.", "- Utilice un balón medicinal firme: los balones blandos o blandos aumentan la inestabilidad y el riesgo.", "- Bajar bajo control: Evite estrellarse; El descenso lento y uniforme fortalece.", "- Comience con elevación si es necesario: use una inclinación para reducir la carga durante las fases de aprendizaje.", "### Errores comunes", "- Las caderas se tuercen o rotan: esto indica una pérdida de control central y movimiento compensatorio.", "- Ensanchar el codo: desplaza la tensión al hombro y disminuye la activación del tríceps.", "- Profundidad inadecuada: no bajar completamente limita el compromiso y el alcance muscular.", "- Depender del impulso: las sacudidas o los rebotes reducen el control y aumentan el riesgo de lesiones.", "- Usar una pelota demasiado pequeña: una pelota pequeña o inestable hace que la preparación y la ejecución sean inseguras."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-002124073570', 'Elevación lateral unilateral con mancuernas', 'Dumbbell Single Arm Lateral Raise', 'Espalda', '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
