INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-002136604203', 'Lanzamiento por encima de la cabeza con balón medicinal', 'Medicine Ball Overhead Throw', 'Espalda', '["Párese con los pies separados a la altura de los hombros, frente a una pared resistente o a un compañero.", "Sostenga el balón medicinal con ambas manos, sujetándolo firmemente.", "Coloque el balón medicinal sobre su cabeza con los codos doblados hacia atrás."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
