INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-002035612414', 'Golpe con balón medicinal a un brazo', 'One Arm Medicine Ball Slam', 'Hombros', '["Párese con los pies separados a la altura de los hombros y sostenga el balón medicinal con una mano por encima de la cabeza.", "Asegúrese de que su torso permanezca erguido y evite inclinarse hacia atrás excesivamente.", "Golpea el balón medicinal firmemente contra el suelo frente a ti.", "Coge el rebote y vuelve a la posición inicial.", "Realice el ejercicio con ambos brazos para asegurar un desarrollo muscular equilibrado."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
