INSERT INTO exercises (id, name, name_en, category, instructions) VALUES ('00000000-0000-4000-8000-001486016993', 'Pase de pecho con balón medicinal de pie', 'Standing Medicine Ball Chest Pass', 'Pecho', '["Configuración: Párese con los pies separados a la altura de los hombros. Sostenga el balón medicinal con ambas manos al nivel del pecho, con los codos doblados y apuntando hacia afuera. Coloque el balón cerca de su pecho, manteniendo un agarre firme.", "Párese con los pies separados a la altura de los hombros.", "Sostenga el balón medicinal con ambas manos a la altura del pecho, con los codos doblados y apuntando hacia afuera.", "Coloque la pelota cerca de su pecho, manteniendo un agarre firme.", "Ejecución: Comience fortaleciendo su núcleo y activando los músculos de la parte inferior del cuerpo. Empuje la pelota con fuerza lejos de su pecho usando ambas manos simultáneamente. Mientras extiende los brazos, extienda completamente los codos pero sin bloquearlos. El objetivo es soltar la pelota de una manera controlada, impulsándola hacia adelante explosivamente. Continúe con el movimiento de sus brazos y asegúrese de que sus muñecas permanezcan rectas durante todo el movimiento.", "Comience fortaleciendo su núcleo y activando los músculos de la parte inferior del cuerpo.", "Empuja la pelota con fuerza lejos de tu pecho usando ambas manos simultáneamente.", "Mientras extiende los brazos, extienda completamente los codos, pero no los bloquee.", "El objetivo es soltar el balón de forma controlada, impulsándolo hacia adelante de forma explosiva.", "Continúe con el movimiento de su brazo y asegúrese de que sus muñecas permanezcan rectas durante todo el movimiento.", "Recepción: A medida que la pelota se aleja de usted, lleve rápidamente las manos hacia el pecho. Prepárese para atrapar la pelota mientras rebota hacia usted. Atrape la pelota antes de que toque el suelo, absorba el impacto doblando ligeramente los codos y flexionando los hombros.", "A medida que la pelota se aleja de ti, rápidamente lleva las manos hacia el pecho.", "Prepárate para atrapar la pelota mientras rebota hacia ti.", "Atrapa la pelota antes de que toque el suelo, absorbe el impacto doblando ligeramente los codos y flexionando los hombros.", "Repetir: Después de atrapar la pelota, restablece tu posición inicial y repite el movimiento durante el número deseado de repeticiones.", "Después de atrapar la pelota, restablece tu posición inicial y repite el movimiento durante el número deseado de repeticiones."]'::jsonb) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, name_en = EXCLUDED.name_en, category = EXCLUDED.category, instructions = EXCLUDED.instructions;
